insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2019-02-05','(Pedro)Conversación con MªJosé, hermana de Manuel. +++Psiquiatra: Dr. Samino. +++Estuvo el lune en la Comisión para valorar derivación a UME de CSS de Mérida. +++Sale de UHB todos los días de 15 a 20h. y acude con la familia. +++En la UHB refieren que no se relaciona con nadie, no es comunicativo y carece de compañeros. +++FAMILIA: desde que empezó a vivir de alquiler no había tenido contacto alguno con su hermana Mª José hasta noviembre "...se negaba a ello. me decía que le habían dicho que yo no quería que saliera del Centro y que debía estar ingresado...Yo le explicaba que no era verdad, que lo que no quería es que diese un paso tan importante de vivir atendido a valerse por sí solo, pero él no lo entendía...Sin embargo, a raíz de lo sucedido, la relación CON LA FAMILIA HA MEJORADO MUCHO ACTUALMENTE, lo que lleva a Mª José a proponer que, a ser posible, su hermano puda estar en un Centro pero en Badajoz, para mantener más fácilmente el contacto (le explico que eso depende de la valoración de los comapñeros de Salud mental y de la existencia de plazas en cada centro.) +++Mi hermano, si bien piensa en el día a día, ha tenido en un moemnto dado una mayor conciencia de su situación y, si bien quizá niega la realidad que su consciencia le dicta porque no le gusta, en estos mlmentos valora positivamnete la posibilidad de ingresar en un CRR en un futuro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-02-06','Teresa: Una vez firmado contrato SAD por Consoli se envía una copia al SEPAD junto con la comunicacion de cambio de empresa. La copia de los contratos la recogeraFernando Bravo gerente de la empresa la proxima semana. Se envía a la anterior empresa de SAD la comunicacion de cambio de emrpesa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-02-06','(Pedro) Se acepta el cargo de tutor con fecha 06 de febrero de 2019 (llega la aclaración de la sentencia el 04 de febrero de 2019 por fax). +++Pongo el caso enconocimeinto, primero de Soraya y luego de Manuela. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++Conversación con Maite, Directora de la Residencia "Convento de San Francisco" (619-822390). Conoce el caso desde que Rosa era pequeña. +++++Rosa es hija de Mª Luisa Calzas, también tutelada por la Comisión. Sin embargo, desde que nació vivió con su abelo materno y con Dª Benedicta, con quien este se casó en segundas nupcias. Tiene un hermano que se quedó con el padre. Al parecer, Benedicta adoptó a Rosa (aunque nadie parce haber visto la documentación al respecto, por lo que cabe la posibilidad que simplemente la acogiese. +++++Sí que fue su tutora legal a partir de cierto momento y hasta que fue removida del carhgo, pasando este a la Comisión. +++URGENCIA: según conta en la comparecenbcia de Aurora Montero Simón, sobrina de Benedicta, ante la Fiscalía de Plasencia, Dº Benedicta hubo de ser ingresada por motivos de salud y la decisión de la familia es ingresarla en una Residencia para Mayores. La familia QUIERE CERRAR LA CASA, CON LO CUAL ROSA QUEDARÍA EN LA CALLE. Esto iba a ser de un día para otro. +++++Maite ha podido contactar con D. Alonso, sobrino también de Dª Benedicta: intentaron el ingreso en la Hermanitas de los Pobres pero la Residencia no aceptó dicho ingreso, con lo cual ha vuelto a casa con Rosa. La familia sigue con la idea de ingresar a su tía en un centro residencial, para lo que se van a reunir estew fin de semana para tomar una decisión. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Ángela, T. Soc. de Placeat (927-421950). +++++Acudía a Placeat, a C. de Día (pero no acude desde hace un año). Desde Placeat, en 2015, se tramitó solcitud de ingreso en centro por Decreto, junto con la orden judicial para ingreso, pero llegado el momento Dª Benedicta se negó a que ingresara y se quedó con ella. +++++Corrobora lo dicho por Maite. +++++Plantea la posibilidad, dada la premura, de que Rosa se pueda quedar de manera "provisional" en Placeat (ahora han quedado dos plazas vacantes, aunque de hombre). +++++Considera que Rosa no puede vivir sola de ninguna manera y, preguntada sobre si ella quewrría voluntariamente ingresar en un Centro la respeuta es la siguinte: "No creo. Porque ella sabe que en un centro no iba a paoder hacer las cosas como en su casa y a ella le guista entrar, salir, volver tarde por la noche -Maite refiere que es muy "noviera"...-. Claro que si se ve en la calle, quizá acepte porque no le quede más remedio". ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Manuela (Sección de Discapacidad): presentar solcitud actualizada por Decreto, acompañada de Informe Social de Emergencia para reactivar la solictud. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++Llamo a SSB de Plasencia, a Puerto Barroso, (927-428500///Ext. 3-1) pero no consigo que cojan el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2019-02-06','Teresa: Llama TS del SSB de Zafra para comunicarnos que Teresa ha ingresado en una residencia y hay que recoger las llaves del piso que las tiene su vecina. Llamo a futuex para que pase una delegada a recogerlar, futuex me pide que le mande una email con toda la informacion y pasaran lo antes posible ya que ahora mismo en esa zona no tienen delegada','2');
