insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2019-02-06','Teresa: Llama la TS del SSB de Montijo para comunicar que el numero de cuenta que se ha facilitado puedar ser usado para que la empresa de SAD pueda conbrar el servicio, pero la Junta no puede realizar el ingreso de la prestación ya que la pareja de Julio no está como titular en la cuenta // Ana: Tras valorar la situación con Amalia y Alberto y comprobar que Dña. Isabel cobra la PNC en la cuenta conjunta que tiene con D. Julio, será ese número de cuenta conjunta la que se facilitará en la Junta en el alta a terceros para el cobro de la prestación de Isabel. Se intentará averiguar el concepto con el que le harán el ingreso para solicitar transferencia inmediata a la otra cuenta de Julio. // Se comunica a Maite (T.S. SSB Montijo)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2019-01-03','(Pedro)Llama Dª benita, la madre de Carmen. +++Solicita 150€ que quiere que le transfiramos a su cuenta para pasarsela a su nieta de 19 años. +++Se le indica que eso es algo que hemos de hablar con el CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-07','Teresa: Llama Mercedes TS Hospital Perpetuo para comunicar que el Dtr Ledesma le ha comunicado que los traumatologos han decidio no operar de momento a Andrea, le darán cita ambulatoria. Mañana le daran el alta y volvera al CRR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-02-07','Teresa: Se pasa a la asesoria informe social del SSB para solicitar ingreso involuntario en centro residencial discapacidad o piso tutelado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-02-07','Ana: Se realiza llamada a Esther (TS C. Salud de Miajadas)Expresa que no sabe nada de Felipe ya que no ha acudido a su despacho en los dos años que ella lleva prestando alli la atención. Consultará su expediente para facilitarnos la inforación si la hubiera (Informes sociales anteriores, si ha pasado por Salud Mental, etc. Intentará hablar también con su médico de familia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2019-02-07','Teresa: Llama para decir que ha empezado un curso de jardineria y para solicitar que le asignemos mas dinero','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-02-07','(Pedro)Conversación telefónica mantenida con Puerto Barroso, de SSB de Plasencia (927-428500, Ext. 3-1////correo-e: pbarroso@aytoplasencia.es) +++Conocían ya el caso e informa a la Comisión de que Dª Benedicta dispone del SAD municipal y ademas de un persona interna contratada por ella. +++Comunico el riesgo de desprotección que se nos ha comentado a nosotros desde la REsidencia Convento de San Francisco, en cuanto a que la familia quiere cerrar la casa quedando en ese caso desprotegida Dª Rosa. Comenta al respecto que nadie había comunicado a SSB nada al respecto y que, si bien Dª Aurora (sobrina) no es ninguna referencia para los SSB, sí que tienen contacto con otro sobrino de Dª Benedicta, D. Alonso, quien les ha comentado que no habría ningún problema al respecto. +++ENVÍO SOLICITUD DE INFORME SOCIAL POR EMERGENCIA (por correo-e), para tramitar plaza para centro de Discapacidad y solcitar igualmente autorización judicial para dicho ingreso. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Maite (Sección de Discapacidad). Una vez formulada la solcitud de plaza y tras la conversación que han mantenido con Ángela (Placeat) es posible que pueda quedarse en el centro, habilitando una plaza masculina, de las dos vacantes, para ser ocupada por Rosa. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Pongo el caso en conocimeinto de Toni (FUtuex) para que, a la vez que siguen el de la madre, estén pendientes del de Rosa. +++Ya habían estado hablñando de ella con Ángela, T. Social de','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='GUDIÑO'and apellido2='CACERES'),'2019-02-07','Ana: Llaman del servicio de urbanismo, enviarán una notificación para D. Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2019-02-07','Teresa: Llaman de la RM Real de Navalmoral para comunicarnos que el tutelado Marcelo necesita dinero para sus gastos personales ya que es la familia la que esta sufragando estos gastos. Le pido que mande presupusto por email para estudiar la demanda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-02-07','(Pedro) Llamada de ESperanza, T. Soc. del ESM de Mérida (85832).(Correo-e: esperanza.gallego@salud-juntaex.es) +++Llama solictando inofrmación sobre José Mª para citarlo en consulta. Se le envían los informes de contenido social existentes en su expediente. +++Están valorando derivación a CRR. Psiquiatra Dr. Simón.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2019-02-07','Teresa: LLama Sole TS (924237551/924237374) de Nta Sra de la Luz par comunicar citacion del juzgado para Zoraida. Pido me la mande por email y se la paso a la asesoria juridica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN RAMON'and edp.apellido1='SALAZAR'and apellido2='FERNANDEZ'),'2019-02-06','TRASLADO El 06/02/2019. "Se comunica a esa Comisión Tutelar de Adultos que el interno Juan Ramón..., ingresado en este Centro (CSS de Mérida) y tutelado por esa Comisión, será trasladado al Hospital de Mérida, en fecha 06/02/2019."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-07','-LLAMADA DE MERCEDES , NO OPERAN Y MAÑANA DAN ALTA HOSPIT. -REUNION CON CARMEN ( T3 ) BADAJOZ, ME INFORMA QUE SOLO HA DADO 22 PUNTOS , ESTÁ EN LISTA Y NO HAY PLAZAS VACANTES. -LLAMO A CRR BADAJOZ , PREGUNTO POR DIRECTORAS PERO NO ESTÁN. HABLO CON LEONOR ( TERAPEUTA ) PARA AVISARLA DEL POSIBLE ALTA Y QUE VOLVERÁ AL CRR . SI CONSIDERAN QUE NO VA EN CONDICIONES DE PERMANECER ALLÍ QUE CONTACTEN CON LA UNIDAD DE SALUD MENTAL DEL SEPAD SEGÚN PROTOCOLO. ME COMENTA QUE SERVISCOOP ESTÁ HACIENDO ACOMPAÑAMIENTO HOSPITALARIO CON ANDREA . -LLAMO A LA EMPRESA SERVISCOOP ( 924234193) SOLICITO INFORMACIÓN SOBRE EL SERVICIO Y QUIÉN LO HA CONTRATADO . ME INDICAN QUE LO PIDIÓ SU HNA. TOÑI , PARA 24H . SOLICITO QUE HOY SE ACABA EL SERVICIO. PÀSARÁN FACTURA A CTUTELAR . -LLAMO A SU HNA. TOÑI , LE INDICO QUE NO PUEDEN SOLICITAR UN SERVICIO POR SU CUENTA . DICEN QUE HAN INTENTADO CONTACTAR POR TF Y AL NO SER POSIBLE LO HAN HECHO ASÍ. NO ESTÁ DE ACUERDO QUE SU HNA VUELVA AL CRR Y QUE NO LO VA A PERMITIR , SE MUESTRA MUY ENFADADA Y AMENAZANTE. A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-07','(Pedro)Conversdación con Toni (Futuex). +++Enviarán inofrme actualizado.(Ver nota inofrmativa enviada hoy por correo-e).Está en expediente (correos Futuex) +++En la última consulta EN CEDEX, Mª planteó a Mª Carmen (Médico) la posibilidad de AUMENTAR el tratamineto, pero el médico dice que tiene una gran dependencia de las benzodiacepinas.La médico le comentó que si quería aumentar dicho tratamineto debería ingresar voluntariamente, a lo que María se niega. +++Al parecer, en las visitas mantenidas con María, ella quiere seguir consumiendo porros... +++Parece ser que ella ha pedido ingresar de nuevo (confirmar) pero no quiere dejar de consumir droga. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con María. +++Se alegra mucho de la llamada. Dice que ha dejado de fumar porros y de beber alcohol. ]]]] +++Solcita adelantar la cita con su Psiquiatra, Dr. Idilio (ESM de Llerena), prevista para el 25 de marzo, porque siente mucha ansiedad al haber dejado el consumo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento hablar con Marisol, madre de Mª. salta el contestador y dejo mensaje.','2');
