insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-08','(Pedro)Intento hablar con Dª Marisol, madre de María. +++Llamo a los dos teléfonos que tenemos: al 685-889091 (es de María), (donde dejé ayer mensaje en contestador indicando que volvería a llamar) y que responde que no está disponible, y al 696-266658 que no lo cogen. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Marisol (696266658), madre de Maria. +++CONSUMOS: La madre no abona nada. Tanto luz como agua están a nombre de María. SEGURO CANINO: La madre no ha gestionado ni pagado nada al respecto. MULTA: La madre no sabía nada al respecto. SEGURO DE DECESO: Tiene póliza con Generali Seguros. Nº De Póliza (referencia mandato): GO7101000366 DINERO: la madre dice estar pagando algunas deudas de alimentación. Le paga tabaco también. Le pido que no haga nada respecto a María sin contar antes con la Comisión. +++Considera que María está cada vez peor. Cree que debería estar nuevamente ingresada. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Juanma, Enfermero del ESM de LLerena (45654)................Hablará el lunes con el Dr. Idilio sobre el caso y la posibilidad de adelantar la cita. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Pilar, T. Soc. del CEDEX de Zafra. +++Solicito por corre-e información sobre el seguimiento que desde el Cedex se está haciendo de María +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Converewsaación con el Dr. Tomillo (45819), Médico de Familia de María en Monesterio. +++T. Soc. C.salud Mª Ángeles Vicente (45821).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS'and edp.apellido1='PEREZ'and apellido2='GARCIA'),'2019-02-08','(Pedro)Llamada de la Casa de la Misericordia de Pinofranqueado (636638114). Padre Fernando. +++CComunican el FALLECIMIENTO de D. Luis hace aproximadamente una hora por parada cardíaca. +++FAMILIA: tratarán de ponerse en contacto con su hermano para comunicarlo y ver si desean enterrarlo en su locolidad. (Pendiente de la cobertura del Seguro). +++DESCANSE EN PAZ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-02-08','Teresa: Llama la TS de SSB Villafranca para informarnos que Adolfo tiene dependencia pero que a día de hoy no se esta prestando ningun servicio ya que no se ha firamdo la vinculada de SAD con ninguna empresa. Comenta que su hermano ha pedido un cambio de PIA y que dicho PIA lo ha firmado Adolfo. Solicitan solucionemos la vinculada para que le preste el servicio de momento lo va a hacer el ayto de Villafranca a traves del Taller de empleo que tienen.','2');
