insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-02-08','Ana: Llama Chelo (Jefa de sección de Valoraciones - SEPAD)para preguntar por el contrato de SAD con la nueva empresa. Se le comunica que se dió registro de entrada junto con la Comunicación del Cambio de Circustancias ayer día 7. Se lo bajo personalmente a su despacho, guardo copia del oficio firmado en el expte.','2');
