insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2019-02-08','Ana: Rafael llama para comunicar que no pudo acudir a la reunión que tenía concertada con Amalia y Alberto porque dice que llevaba 2 semanas con bronquitis. Solicita que se convoque una nueva reunión y se le avise con mayor antelación, pues para la anterior se "le avisó de un día para otro y así no puede prepararla"','2');
