insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-08','-LLAMO AL HOSPITAL PERPETUO , NO LE DAN EL ALTA HASTA EL LUNES. MERCEDES , LA TS , ESTÁ DE BAJA , SE QUEDA CARMEN LOZANO CON EL CASO. -LLAMO AL CRR BADAJOZ PARA AVISAR DEL CAMBIO . A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-02-08','Ana: Se mantine conversación telefónica con Carmen (Equipo Valoración Dependencia de Plasencia)Al exponerle el caso cree que la mejor opción es hacer una nueva valoración por Emergencia Social y con un Grado mayor promover el ingreso de María Luisa en Centro Residencial. Lo hablará con su jefe el lunes a primera hora e intentará agilizarlo lo más posible para hacerle visita y nueva valoración en una semana. Me pide informes actualizados. // Le envío por correo electrónico el informe social de atención primaria (SSB Y Centro de Salud) y el informe de la última visita de la Delegada Tutelar de FUTUEX. Quedo pendiente de enviar el lunes informe médico. A posteriori se enviará todo con la solicitud oficial para reactivar el expte de Dependencia.','2');
