insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-02-11','Ana: Envío a Carmen (T.S. Equipo de Valoración -Dependencia Plasencia)por email el Informe de Medicina Interna del 17 de enero que estaba pendinte. Nos mantendrán informadas de las actuaciones que vayan realizando. // Se pone para firma la solicitud de revisión de grado de dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-11','Ana: Llama Carmen de Dependencia (Badajoz), ha quedado una plaza de T3 en El Encinar de las Cruces (Don Benito)como las personas que había delante en la lista de espera han rechazado han llegado al puesto de Andrea. Le confirmo el acceso a la misma. Comenzará con los trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='PARRA'and apellido2='ALCANTARA'),'2019-02-11','(Pedro)Llamada de Paqui, Directoira de la Residencia Hernando de Soto (21781). +++No tienen acceso a la cuenta. Están cubrirndo sus gastos con dinero de otros residenctes. +++Enviarán el I. Social solicitado y, además, informe de la situación económica en que se encuentra en el centro (deudas) y un presupuesto de sus gastos y necesidades habituales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-11','(Pedro)Llamada del Dr. Idilio, Psiquitara del ESM de Llerena. (45656). +++Vió por primera vez a María en Dic de 2018 y ya entonces le propueso ingresar en la UHB de Llerena. También le planteó un posible ingreso en la comunidad Terapéutica "Casa Roja", a loc ual se nego también, arguyendo que no podía dejar a su perro solo, y que ella solamente quería que le aumentase la medicación... +++Idilio le dijo que podía ir a verlo en cualquier momento, incluso sin cita previa. Incluso le dió una nueva cita para el 5 de feberero de 2019 a la que no acudió. +++Fue citada nuevamente para el 25 de marzo. Comento a Idilio que ha sido la misma María la que, en conversación con ella el viernes pasado, me planteó el adelanto de dicha cita porque se encontraba con basatante ansiedad. +++ADELANTO DE CITA: puede ser para el 15, 20 o 22 de febrero sobre las 10:00h. +++Idilio valora este caso como muy complejo y preocupante (con lo cual la Comisión está completamente de acuerdo). Le explico los intentos de ingresar a María en la C. terapeútica de L aGarrovilla, su paso por la UME, etc. También le comento las entrevistas mantenidas con ella y con su madre, así como con el DR. Samino y la T. social Carmen (ESM de Badajoz) así como con la Dr.a del CSS de Mérida (UME) Isabel Álvarez y le planteo la conveniencia (en mi opinión) de CONVOCAR UNA SUBCOMISIÓN DE CASOS para dar una salida lo más definitiva posible a la situación de María. +++La opinión del Dr. Idilio es que María debe pasar una larga temporada en un ingreso prolongado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Toni (FUtuex). Podrían acompañar a María al ESM de Llerena el próximo 20 de febrero ( el día 15 tien ya cerradas algunas intervenciones). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a María, para plantearle acuidir al ESM el próximo 20 de febrero. No coge el tel´fono y dejo mensaje en el contestador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-12','- POR LA PLAZA T3 ABONAREMOS 427,39€ , CALCULADO POR CARMEN ( ATS BJOZ ) . -SE INFORMA AL CRR DEL TRASLADO POR UNOS DIAS HASTA QUE SEA FIRMADA LA RESOLUCION QUE PASARÁ A LA RESID. -SE GESTIONA TRASLADO AYER EN AMBULANCIA CON CARMEN LOZANO (46200) A.D','2');
