insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2019-02-11','Ana: Se comunica a Alba (TS del Centro Sociosanitario) que Francisco podrá sacar 60 €/mes dentro de los primeros 5 días del mes a partir del marzo. // En cuanto a la solicitud que hace Francisco de 1000 €, argumentando que es para ayudar a su madre, Alba cree que es para él, no para la madre.','2');
