insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='SERRANO'and apellido2='SUAREZ'),'2019-02-12','Ana: Se pide, vía telefónica, a Natalia (Direcotra de la Residencia Padre Damian de Plasenzuela) que soliciten cita para Antonia al médico de familia para que éste le derive a Neurología y a Psiquiatría para que le hagan valoración y que nos manden a posteriori los informes correspondientes, pues se solicitará una Revisión del Grado de Dependencia con el fin último de solicitarle el recursos residencial más apropiado. // Así mismo se le indica que la próxima vez que se produzca una inicidencia asociada a los problemas de conducta de Antonia llamen al 112 para que valoren la necesidad de ingreso y quede constancia de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-02-12','Ana: Mediante llamada telefónica comunico a PNC de Cáceres que aún no se ha enviado el Alta de terceros que habían solicitado porque el expediente se econtraba en fase de inventario. Ya se ha solictado el alta de terceros al area económica, en cuanto lo tengamos se enviará.','2');
