insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2019-02-12','Aniceto Matamoros Ramírez (647122340-anicetomr@hotmail.com), abogado de los hermanos de Miguel, nos comunica que van a impugnar el testamento otorgado por el padre, así como la venta que le hizo meses antes de su muerte a su pareja Basilia. Una vez se inicie el procedimiento judicical y nos notifiquen, comunicaremos lo que corresponda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2019-02-12','Ana: Llamo a Rosa (Admtva.CSS Plasencia)en relación a la próxima citación de Francisco en el Juzgado de lo Penal. Nos enviará por correo a ctutelar@salud-juntaex.es, el resto de documentación al respecto. Es una citación para un juicio pendiente por Acoso a una chica en Proyecto Hombre. El juicio no se pudo celebrar con anterioridad porque no lo encontraban. // Rosa comenta también que intuye, por la actitud y conducta recientes de Fco., que o bien está consumiendo o bien no está tomando la medicación.','2');
