insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MACIAS'and apellido2='MARTINEZ'),'2019-02-13','Teresa: Me pongo en contacto con la direccion del centro ya que la directora nos manda email solicitando que la llamemos, en la conversacion telefónica nos comenta que se encuentra bien en el centro pero que reclama la atencion de Pedro con sentimiento de abandono por parte de la comision ya que ahora no se le visita como cuando estaba en Plasencia. Comenta la directora que ante situaciones conflictivas le resta autoridad comentando que quien manda sobre el es la comision y no ella. LA directora demanda que Pedro hable con el telefónicamente para aclararle que ahora sus repsonsalbes con los tecnicos del centro y no es necesearia la actauciond de la comisión para resolver los problemas que sucedan en el centro. Le comunico a Pedro la conversacion mantenida con la directora.','2');
