insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-02-12','(MIGUEL)ASISTO A LAS 10H A LA NOTARIA DE AGUSTIN SANABRIA EN BADAJOZ PARA LA FIRMA DEL PODER DE VENTA, PERO SÓLO APARECE SU PRIMO JESÚS PINNA. TRAS LA ESPERA DE TODA LA MAÑANA, FINALMENTE SE INDICA POR MERCEDES AL CTAEX CITA A 18,45H Y TAMPOCO SE PRESENTA. ESTÁ MUY NERVIOSA Y NO COGE TLFNO SEGÚN SU PRIMO. Y A LAS 16,30H CONFIRMA LA NOTARIA SE HA PRESENTADO A INFORMARSE ALLÍ, Y DICE NO CONFIAR NI EN LA COMISIÓN NI EN SU PRIMO, DE QUIÉN DICE LE HA LLAMADO A LA 1H DE LA NOCHE (DE TODO ELLO INFORMADO EL PRIMO JESÚS PINNA POR EL OFICIAL MANOLO, QUIÉN NIEGA DICHA LLAMADA). NO SE PRESENTA A LAS 18:45H PORQUE SEGÚN DICE AL OFICIAL MANOLO HA PERDIDO EL MOVIL EL DÍA ANTERIOR Y TENÍA QUE IR A PONER LA DENUNCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-13','Teresa: Hablo con la madre para comunicarle que tiene su hija cita el dia 20/02/2019, me comenta que no la puede acompañar porque ahora esta en Caceres trabajando me comenta que su hija tiene un numero nuevo de telefono 665064306 (TELÉFONO DE MARÍA). También nos demanda que le restrinjamos el dinero ya que se lo gasta todo en los primeros dias del mes en alcohol. Hablo con Toni futuex para que le acompañen a la consulta, nos comenta que no deja de beber que seria conveniente ingresarla. Quedamos a la espera de ver la decision que toma el doctor el dia 20','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2019-02-13','Ana: Llamo al IMAS (Cáceres) en relación a la solicitud de Autorización que nos solicitan para iniciar la prestación del SAD a Jesús. La solicitu la realizó y firmó el T.S. del SSB, pero como no está firmada por la Representante Legal, solicitan una autorización, además de la orden de domiciliación bancaria del copago (1,674 €/hora - 4 horas/semana)./// Cuando tenga la autorización firmada y registrada se la adelantaré por Correo electrónico para que puedan comenzar con el servicio lo antes posible./// Comunico a Alberto el copago del servicio.','2');
