insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-13','TEresa: recibo llamada de Julieta nos comunica que el perro sigue en la vivienda y que solo le dan de comer que nadie limpia con lo cual patio esta lleno de suciedad, el proximo dia 15/2 le van a hacer una prueba en Badajoz. hoy hemos recibio email de futuex comentando la situacion del perro la cual nadie se hace cargo y llevarlo a la perrera vale 30€, la familia esta dispuesta a limpiar la casa siempre y cuando se le paque por hacerlo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-02-13','(Amalia y Pedro)Visita domiciliaria realizada a Dª Rosario, acompñada de Inmaculada (T. Soc. del SSB de Guadiana). +++Conversación con Dª Rosario, explicando el papel de la CTAEx en relación a ell. +++Itervención con Mireia (cuidadora), "Roda" (cuidadora) y con su vecina " " que también colabora en su atención. +++Mireia: se le explica su situación a nivel laboral y la imposibilidad de seguir manteniendo la misma. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Visitamos el Centro de Día para hablar con el personal que atiende a Dª Rosario. +++Bien integrada, conoce a sus cuidadoras por el nombre, participa en el taller de desarrollo cognitivo. +++Estarán atentos a una posible retención de líquidos que puede estar padeciendo últimamente Dª Rosario. Al parecer, cada vez camina menos y ya acepta mejor la silla de ruedas. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ALTERNATIVAS: +++Mantener a Dªosario en domicilio todo el tiempo que sea posible. +++++No es psoible seguir con Mireia ni las otras dos cuidadoras tienen disponibilidad para asumir esta tarea. Se pedirá presupuesto a una empresa de servicios para su cuidado, con el horario actual (de 17 a 09h) y fines de semana completos (además de posibles incidencias extraordinarias). +++++Iniciar trámites de ingreso en centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-02-13','(Amalia y Pedro)Reunión no programada con Mar, T. Soc. del ESM de Badajoz (Valdepasillas). +++MEDIDAS A CONSIDERAR. +++++Posible convocatoria de subcomisión de casos. +++++tenía cita con Fernando (Psiquiatra) para mayo, pero se la adelantean al 7 de marzo dada la situación (comunicar a Futuex). +++++Insistir desde el Equipo en la conveniencia de ingreso en centro, CON POSIBILIDAD DE INGRESO "DE PRUEBA". +++++Insistir en derivación a CRPS. +++++En caso de que en la consulta se aprecie desetabilización en Dª Mercedes, promover ingreso en UHB e iniciar seguimiento rehabilitador.','2');
