insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-02-14','Ana: Se recibe un correo del Centro de Mayores Sierra de San Pedro con el siguiente contenido:" Buenos dias Pedro. Nos ponemos en contacto contigo desde el Centro de Mayores "Sierra de San Pedro" con el fin de informarte de la evolucion de Maria Cristina Villegas Serrano. Hemos intentado en varias ocasiones hablar con vosotros via telefonica en estos ultimos dias. Desde el pasado Viernes Cristina ha decaido considerablemente. Tiene dificultad para tragar, tiene que tomar los alimentos pasados y con jeringa. Tiene problemas de estabilidad. Encontrandose encamada le cuesta incluso mantener la cabeza recta. Nos hemos puesto en contacto con paliativos para ver que pautas seguir y nos dicen que todo es por la evolucion de su enfermedad. Ahora mismo esta encamada, sin dolor, consciente, habla muy bajito y se estan realizando todas las medidas de confort. Un saudo." // Se recibe también al final de la mañana llamada al respecto de Modesto, director del C.R. para asegurarse de que se ha leído el correo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Montse, Enfermera de la Residencia Sierra de San Pedro. +++Cristina ha dado un "bajón" importante desde el pasado viernes: etsá muy decaída, tiene que estar semitumbada porque no tiene fuerza para mantenerse erguida. La enfermedad está evolucionando muy rápidamente: come todo en puré y con una jeringuilla. En todo momento es consciente de su situación y NO PADECE DOLOR. +++El centro comunicó la situación a Cuidados Paliativos y desde el Servicio le comunicaron que era la evolución normal de la enfermedad. En ningún momento se plantea la alternativa de nuevo ingreso hospitalario y solo se pueden administrar los cuidados paliativos que precise en cada momento. +++Los hermanos lo saben y, a pesar de estar enfadado con la Comisión, Julián reconoce que su hjermana está muy bien atendida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-14','Teresa: Se llama a la perrera muncipal para que vayan a por el perro, se les da el contacto de Juilietta para que se pongan de acuerdo con ella y les habra la puerta. Julieta se va a encargar de la limpieza del piso Se va a dar de baja al aquiler','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-14','Teresa: Julieta nos comunica que el proximo dia 15 va a acompañar a Jose Antonio a una prueba a Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2019-02-14','Ana: Envío a Nazaret (Directora del Centro Hermanos de la Cruz Blanca) por e-mail escaneado Consentimiento Informado de Anestesia Local para Tratamiento Odontológico firmado por Consoli. // Comunica también en otro correo: "...hemos mandado una carta con el original por si nos lo podéis firmar, y también los consentimientos de la nueva de ley de protección de datos. Muchas gracias, un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-02-14','Teresa: Recibo informe de Futuex comentandonos la situacion en la que se encuentra Auroa y su hermano. Ella no colabora en nada y no deja de pedir dinero a su hermano y un prestamista. Ademas ha solicitado un prestamo a VIVUS de 4000 asegura Antonio. Aurora amenza con irse a vivir a Montijo con su pareja. Antonio se encuentra muy nervioso y preocupado por esta situacion y no deja de recibir requerimientos judiciales por impagos. Aurora solo quiere dinero para irse.','2');
