insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2019-02-15','-CONTACTO CON ESTHER ( TS VPO MERIDA 924332454) Y LE COMENTO EL CASO . EL PADRE DE CRISTOFER , JUAN ROLLAN PIÑERO ( 615127248) HA TRAIDO UNAS FACTURAS PENDIENTES DE 1371 € DE LOS AÑOS DEL 2009 AL 2012 QUE PRETENDE QUE PAGUE SU HIJO. ME PIDE QUE LE TRANSMITA QUE SE PASE POR VVDA Y SE LO EXPLICARÁN Y DESCARTO QUE TENGAMOS QUE PAGARLO DESDE CTAEX. - LLAMO AL PADRE Y SE LO COMUNICO . ME DICE QUE YA HA IDO A VVDA Y LE DICEN QUE TIENE QUE PAGARLO SU EXMUJER. A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-02-15','Ana: Se recibe llamada de Maite Cañadas (R.Convento S.Fco.)Comunica que Dª Benedicta finalmente ingresará en la Residencia el sábado por motivos de organización del centro. Alonso Jiménez (Sobrino de Dª Benedicta)se ofrece a llevar personalmente el lunes a Mª Rosa al Centro que le digamos. // Tras varias conversaciones con Puerto Barroso (SSB Plasencia) recibimos por e-mail el informe social solicitado y otros más antiguos que obraban en su expte.// Junto con la solicitud ya firmada y registrada se entrega todo personalmente a Manuela (Jefa de Sección de Discapacidad). A media mañana nos comunican que sí será posible el ingreso en PLACEAT el lunes.// Mantengo conversación con Alonso (sobrino de Benedicta: 609140514), se muestra muy colaborador y solícito, llamará a Ángela de Placeat para coordinarse para el ingreso, él mismo le llevará. Ya lo ha hablado con ella, de hecho ella está presente cuando hablamos y aprovecha para comunicarle que irá al centro que ella quería. // Llamo a FUTUEX: como no está Toni hablo con Sonia, le comunico que ya no tienen que hacerse cargo del traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2019-02-15','Ana: Envío escaneado por e-mail a Guadalupe Cortés (T.S. SSB de Cáceres)la autorización para el inicio de la prestación del SAD y la orden de domiliciación bancaria debidamente firmadas y selladas. Lo llevo a Registro para dar salida y Julio lo enviará por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-15','Teresa: LLaman del hospital de Badajoz para que firmemos consetiemiento informado para una operacion de un nodulo en el pulmon.','2');
