insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-18','Teresa: Hablo con Julieta, mañana ha quedado con la perrara para retirar al peroo de la vivienda. Me comenta que tiene cita para la anestesia el proximo 28 de febrero ya que le van a operar el pulmon, tambien tiene pendite una cita para una espirometria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='GARCIA'and apellido2='PEREZ'),'2019-02-18','Teresa: Me pongo en contacto con Marisol Sanchez a peticion suya y me comenta que deben varias facturas y que necesita dinero para sus gastos personale, le indico que nos mande presupuesto para valorar los gastos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-02-18','Ana: Hablo con Valentina (T.S. de Centro de Salud de Aldea Moret), mantiene la opinión de que no es conveniente ingresar a Paula, ella la ve bien, no cree que esté desmejorada, acude regularmente, aproximadamente 1 vez/mes, a por recetas a consulta con su Médica de Familia, Dra. Mª Marta. La próxima cita está fijada para el día 20 de febrero, por lo que hablará con la Dra. para pedirle que haga la consulta lo más extensa posible y elebore un informe que luego nos remitirá. Valentina refiere que ha citado varias veces a Paula incluso formalmente (con carta), pero ninguna de las veces ha acudido a la cita. Argumenta que por ello no puede elaborar nigún informe social al respecto *A Salud Mental tampoco ha acudido, ni siquiera a seguimiento tras su ingreso en la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA MERCEDES'and edp.apellido1='GONZALEZ'and apellido2='YORK'),'2019-02-18','Ana: Llama Pedro (T.S. del CSS Plasencia)Dice que no aparece ningún recibo de Seguro de Deceso de Manuela, por tanto cree que no tiene seguro, habrá que hacérselo. Se lo comunico a Coral.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-02-18','Ana: Llama Pedro (TS de CSS de Plasencia) Ha envido hace días presupuesto de la óptica. Acordamos que de momento se le autoriza para comprar las gafas graduadas. Las gafas de sol se comprarán más adelante cuando se pueda. El mes que viene enviará otro presupuesto para ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-19','Teresa: Me llama Julieta para decimer que Jose Antonio esta ingresado desde anoche porque le dolia la tripa y con vomitos.Esta su hija con el en el hospital pues ella a las 9:30 tiene que estar en Don Benito para abrir la casa al operario de la perrera municipal para que se lleven el perro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-19','Teresa: Recibo informe de la trabajadora social del Cedex el cual da positivo en cannabis en dos de los tres controles que se le ha realizado en el mes de enero siendo negativo el utlimo con fecha 31/01/2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-02-19','Teresa: Llama por telefono para pedir dinero porque va a ser su cumpleaños. Se le pregunta por el contrato del aquiler para perdri la ayuda. Me dice que está a nombre de su padre y me facilita el numero de telefono de la arrendadataria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-02-18','Ana: Se produce el ingreso de María Rosa en el Centro Residencial de PLACEAT. Ángela Bueno (Directora de dicho centro) remite por correo electrónico los 3 documentos que se deben remitir desde la CTAEX debidametne firmados y sellados: Pacto de Asistencia RAL, Autorización Actividades de Ocio y Declaración de Igreso Voluntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-02-18','Información remitida por correo-e de D. Francisco Villegas (hermano): +++SEGURO DE DECESO: +++++COMPAÑIA SANTALUCIA +++++CONTACTO: YOLANDA. Tel. 690.235.213. y 927.42.14.90///email: agencia592@agencia.santalucia +++++Plasencia.-Avdª de la Salle,49-Bajo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-02-19','Ana: Tras varios intentos de llamada el día 18, consigo contactar telefónicamente hoy con Marisa Olivera (TS del ESM de Coria). Dice que no ha solicitado plaza en CRR para Mª Ángeles, porque acordó con Amalia que ésta le llamaría para confirmar si la solicitaba. Le pido que inicie los trámites para la solicitud de la misma. Afirma que hoy mismo se pondrá con la parte que le corresponde y hablará con el Psiquiatra para que haga la suya. Espera poder tramitarlo todo esta misma semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2019-02-19','Ana: Hablo con Beatriz (Residencia Real de Navalmoral). Dado que en el correo que enviaron no especificaron cuantía, acordamos que se autorizarán 50 €/mes para sus gastos ordinarios. Cuando necesiten dinero con caracter puntual para ropa, acompañamientos al hospital, etc, lo solicitarán por adelantado mediante e-mail. /// Se lo comunico a Alberto (Área económica)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2019-02-19','Ana: Llamo a Rosa (Admtvo.del CSS de Plasencia) le pregunto si ya han solicitado el Empadronamiento de Jose María en el CSS. Me comunica que ella se lo dijo a Pedro-T.S., quién hoy no está, y no sabe si lo habrá hecho. LLamará hoy mismo al Ayto. para consultarlo y sino lo pasará a dirección para que lo empadronen.// A media mañana llama Rosa, confirma que no se le ha empadronado aún, pero que *hoy mismo harán las gestiones para que lo empadronen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-02-19','Teresa:Se piden inforem a la TS y al centro de salud para valorar el ingreso en centro de forma involuntaria','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-02-19','Ana: Llamo a Ángela (Directora de PLACEAT: 927421950, Ext.102). María Rosa ayer se quedó un poco triste en el momento de su ingreso, pero hoy estaba algo más contenta. Al parecer hay cierto recelo por parte de las compañeras, que opinan que "les puede quitar el novio", pues ella es muy mona y noviera.// Alonso ayer cuando acompañó a María le dejó allí la Cartilla de María Rosa, una vez Ángela le preguntó en qué cuenta había que cargar el cobro del Servicio Residencial. **En la cuenta hay movimientos de extracción después de la aceptación de la Tutela por parte de CTAEX// En cuanto a los ingresos de María Rosa hay que verlo, Alonso le ha afirmado que no es hija adoptiva, con lo cuál no se podría solicitar pensión de orfandad por su abuelo ya fallecido, pero sí podríamos ver si puede pedirse por su padre biológico que falleció en diciembre. Iremos viendo las distintas posibilidades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-02-19','Teresa: Me pongo en contacto con Rosa la TS del SSB de Villanueva para solicitar iformacion sobre Aurora, me comenta que ella ya no la lleva pero que junto con la compañera va a realizar una visita y me envía informe social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-02-19','Ana: Llamo al CRR de Plasencia, hablo con Paula (T.O.) para preguntar por Mª Concepción. Al parecer le dieron el alta en UHB el día 23 de enero. Desde entonces está de nuevo en el CRR y su evolución es positiva. No obstante, todavía está en periodo de "evaluación" para valorar su estabilidad clínica y si necesitara UME, pues recientemente ha comenzado a exteriorizar el duelo por la pérdida de familiares hace 2 años, cuestión que ha provocado en cierta medida su descompensación más reciente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2019-02-19','Teresa: Se recibe escrito pidiendo autorizacin por parte de un señor que tiene a su suegra en la misma residencia en la que se encuetra Blas para llevar a Blas de visita al pueblo Puebla de la Calzada de manera desinteresada. Hablo con el director del centro y me comenta que el solo conoce a este señor de verlo en la residencia que pare un señor educado . El director tiene sus dudas sobre que vaya al pueblo ya que Blas alli ha tenido algunos conflictos debido a su discapacidad pues se reian de el. En una ocasion lo llevaron acompañado de la TS y la terapetua y la visita fue bien. Mario el director comenta que podemos probar a ver que tal y en funcio de eso establacer el numero de visitas ya que tanto a nosotros como al centro le parece excesivo ir una vez al mes como nos demanda este señor en el escrito. Se valorara la salida y nos podremos en contacto de nuevo para autorizarla o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-02-19','Ana: Se recibe un correo de Toni (FUTUEX)con el siguiente contenido: "Buenos dias nos informaron ayer desde el área de ts del centro de salud de la Data, en Plasencia, dos citas previstas para el 28 de Febrero con la internista y para el 22 de Marzo en Salud mental, para la tutelada Maria Luisa Calzas, nosotros desde el equipo tratararemos de acompañarla a las mismas, especialmente la que tiene con la internista donde se valoron las pruebas médicas y donde dado que el ingreso hospitalario no se ha objetivado se tratará de obtener un informe por escrito, que pueda ser necesario de cara a solicitar el internamiento involuntario de la misma en un centro residencial, dado que a través de los servicios sanitarios, hasta el momento, no va a resultar efectivo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='VEGA'and apellido2='FUENTES'),'2019-02-19','Tersa: Se envia consentimiento informado para limpieza quirurgica de artritis a la trabajadora social ( M jose) del hospital complejo hospitalario universitario de Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='VEGA'and apellido2='FUENTES'),'2019-02-19','-HA INGRESADO EN HUB BJOZ POR UN PROBLEMA EN UN PIE . ENVIAMOS CONSENTIMIENTO INFORMADO . LLAMO A LA RESIDENCIA PARA PREGUNTAR POR ÉL . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2019-02-20','-ANABEL DEPENDENCIA VUELVE A PEDIR PIA+ ALTA 3º , DICE QUE NO LO TIENE. SE LO PASO A ANA PARA QUE MIRE EN EL EXPENDIENTE PAPEL , YA SE ENVIÓ . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2019-02-20','Ana: Cintia (C.O. Asociación Vera) se pone en contacto a través de e-mail pues no han recibido aún el consentimiento informado y la solicitud de inclusión en lista de espera que se le remitió por correo certificado. Se le envía por fax, pues mañana tienen la cita. En los próximos días suponemos recibirán los originales enviados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2019-02-19','Ana: Desde Aprosuba 8 (Montijo) nos remiten la tarjeta de familia numerosa de Alejandro, para que se la enviemos al centro correspondiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-20','Teresa: Llama Julieta me comenta que ya se han llevado el perro, que el viernes va a limpiar la vivienda.Me comenta que en el baño se sale el agua que lo va a mirar porque se lo ha dicho la cuñada de Jose Antonio. Tiene cita para espirometría, analiticas y preanestesia en esta semana. Ha permanecido ingresaso una noche en observacion por un problema intestinal pero ya tiene el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2019-02-20','Teresa: Me llama Ramon porque la llegua tiene la mano inflamada y cojea. Me pongo en contacto con el veterinario para comentarselo y que me facilite factura y numero de cuenta para pagarle. Mañama llamara para decirme el presupuesto Le pregunto si tien seguro de la llegua y me dice que sí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2019-02-20','Ana: Se da registro de salida y se remite por correo original debidamente firmado y sellado del Consentimiento de la nueva de ley de protección de datos para la Casa Familiar Virgen de la Montaña.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-02-20','Teresa: ha llamado Antonio , dice que su hna Aurora ha pedido un taxi y va a Cordoba a por su novio . Le he dicho que el taxi no lo vamos a pagar como ella pretende . Dice que le ha llegado otra carta de Cofidis. el Tf de Antonio 649999360 .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2019-02-20','Ana: Se da registro de salida y se pone para envío por carta certificada los documentos pendientes (Consentimiento de la nueva de ley de protección de datos para la Casa Familiar Virgen de la Montaña y Consentimiento Informado) junto a la tarjeta individual de familia numerosa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2019-02-20','Teresa: Hablo con Toni TS del Hospital de Llerena,(34367) no tiene informacion sobre el tutelado. Le pido informe social para valorar posible ingreso en centro. Me facilita telefeno de Constanza jefa de servicio ( 47157)para solicitar informe clinicos. Me comunico con Constancia y me comenta que no hay informacin suya, el 17 de diciembre fue atendido por urgencia y se le dio el alta ese mismo dia. Me facilita telefono del psiquiatra Rubén Catalan (45965) una vez hablo con el para solicitar informe me pide que se lo haga por escrito . Hablo con Feafes y me dice que hace mucho que no acude al centro, que no saben nada de el ya que el mismo renuncio ir al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-02-20','Ana: Nos entregan la resolución de adjudicación de plaza por emergencia social para María Rosa en el centro PLACEAT en el servicio de Residencia de Apoyo Limitado. Se archiva en expte. físico. /// Se adelanta escaneados por correo electrónico a Ángela (PLACEAT) los documentos pendientes debidamente firmados y sellados. Se pone para registro de salida el oficio y en cuanto esté se enviará todo por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-20','Teresa:Llamo a la residencia el encinar de las crucez (924812599) para preguntar que tal se esta adaptando a la residencia. La TS me comenta que va bien. El dia del ingreso vino acompañada por su hijo y por su madre. No han vuelto a irmas pero si mantinen contacto telefonico. Nos comenta que llego con un paquete de tabaco pero consiguieron quitarselo. Nos mandara presupuesto para ropa y cosas de aseo ya que ella gastos personales de otro tipo no genera; y facturas ya que han hecho uso de los 90€ que llevaba en el momento del ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-02-20','Ana: Se realiza llamada al Centro Penitenciario de Zuera (Zaragoza). Blanca T.S. ya no lleva este expte. pues Rafael ha cambiado de módulo, ahora se encuentra en el 10 y su T.S. de Referencia es María Eugenia. (volver a llamar al final de la mañana, pues ésta no se encuentra). ** Nos comunica que de forma provisional Rafael está en el módulo de ingresos por cumplimiento de una sanción./// Llamo varias veces a Mª Eugenia al final de la mañana pero no consigo contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-02-20','Ana: Recibo llamada de Marisa (T.S. ESM Coria)me comunica que ha hablado con Lola (T.S. EVD Coria) todavía se puede solicitar en el PIA plaza en CRR. //// Llamo a Lola (34172)Acordamos que como aún no se ha enviado la "No aceptación" del PÍA de Ayuda a Domicilio, nos enviará uno nuevo para la Aceptación de plaza en CRR. /// Se recibe la negociación del CRR a través de e-mail, se pone para firma de la Directora Gerente, en cuanto la tengamos firmada se la remito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2019-02-20','Teresa: llaman de la gerencia territorial para comentar que me llamra la tecnico PIA para negociar el recurso actualmente se encuentra en asilo de ancianos Jesus Nazaremo de Cabeza del Buey.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-02-20','-Esperanza , TS , ESM Mérida necesita copia del D.N.I( en el expediente hay ) ,copia de la tarjeta sanitaria , certificado de pensión que recibe el tutelado, certificado de empadronamiento. Que ya ha recibido de la coordinación de la Comisión informe sobre José María, pero que ahora necesita estos documentos para poder finalizar su informe completo. que sería conveniente tenerlo entregado la próxima semana el día que José maría pueda pasar por su despacho del centro de salud allí en Mérida Norte. -Julio está intentando conseguir por CIVITAS algo . - Le enviaré todo a Esperanza y le pediré que llame a J.Mª para darle cita. ( Amalia )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-02-20','(Pedro)Visita realizada a Dª Cristina en la Residencia "Sierra de San Pedro". +++ESTADO FÍSICO: muy, muy delgada, débil y con un hilillo de voz apenas perceptible. Se encuentra encamada: no quiere levantarse aunque la Fisioterapéuta la atiende diariamente. Hasta hace unos días ella se levantaba de la cama y caminaba de aquí para allá. Pero desde la semana pasada ya no quiere levantarse. +++ESTADO MENTAL: "QUIERO RECUPERARME..." +++FAMILIA: cuenta que han ido a verla sus hermanos, D. JUlián y D. Francisco. Preguntada por si le gustaría volver a ver a su herma José Pedro contesta enseguida que sí. +++Vamos a intentar que D. José Pedro pueda ir a verla lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2019-02-20','Teresa: me pongo en contacto con la TS de la RM el cuartillo (927005280), me comenta que la tutelada demanda tabaco, fuma poco pero no tiene dinero para comprar, nos solicita tener unos 15/20 euros al mes para que pueda comprar tabaco ya que esto hace que se mantenga tranquila. Tambine valoramo la posibilida de un traslado a otro centro ya que este centro es para personas depèndientes de Grado III y ella es bastante dependiente, estimamos que en un centro de validos haria mas vida social. Lo van a valorar y volveran a ponernos en contacto Paso prespuesto a Alberto para tabaco','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-02-20','Ana: Se realiza llamada telefónica a Ana María Clemente, T.S.Centro Neuropsiquiátrico Ntra. Sra. del Carmen - Zaragoza(Tlf. 976770635 -Ext.60274). El viernes envió por email Informe Social solicitado en enero a la TS que le sustituyó, se imprime y se guarda en expte. físico y pc. Cuando tenga el informe médico también nos lo hará llegar. /// Plantea la posibilidad de cambio de recurso de Miguel. La llamaré de nuevo el viernes para valorar la situación con más calma una vez leído el informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-02-21','-EN RESPUESTA A EMAIL DIRIGIDO A MI NOMBRE , LLAMO A LA TS DEL ESM , DICE QUE ESTABA PTE DE HACER LA DERIVACIÓN A CRR A LA ESPERA DE RECIBIR NUESTRA RESPUESTA. EN ENERO YA SE LA DÍ , COMO RECOGO EN INCIDENCIA EN LA INTRANET. ME COMENTA QUE YA HA HABLADO CON ANA Y ESTÁ CON LOS TRÁMITES. AMALIA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-02-18','Ana: Comunican mediante email el alta de Miguel desde la unidad de quemados del Hospital Miguel Servet, hoy mismo vuelve al centro de neuropsiquiatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2019-02-20','José Florencio envía por fax citación del HIC para consulta programada del S. de Aparato Digetivo: Sala Consulta I Digestivo/ Pabellón ambulatorio HIC 6ª Puerta P602. +++FECHA: 11 DE MARZO DE 2019. +++HORA: 10:20H.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='VEGA'and apellido2='FUENTES'),'2019-02-20','Se recibe para su firma y se envia consentimiento informado del hospital complejo hospitalario universitario de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2019-02-20','(Pedro) Conversación con Fernando, Administartivo del IML de Badajoz (924-286590). +++Tras el reconocimiento forense, se solicitaron pruebas de Toxicología e Histopatología. Los resultados de las primeras ya les han llegado, pero no los de las segundas (pueden llegar a tardar hasta un año en tenerlos). +++Una vez todos los resultados estén disponibles, el Forense remitirá su Informe al Juzgado de 1ª Instancia nº 3 de Mérida. +++SE ha de solcitar al propio Juzgado.','2');
