insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2019-02-19','solicitado por fax al juzgado que se nombre abogado de oficio, para la comparecencia del 18-3-2019','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-02-21','(Pedro)Conversación con Nuria (54513), T. Soc. Dependencia Trujillo. +++PIA?...No cree que el SAD sea un servicio oportuno para Juan. +++Considera, como en la CTAEx , que Juan debería estar ingresado en un centro. +++La sentencia dicta una curatela en el ámbito de la salud y tratamineto. Solicitar una ampliación de la incapacidad solo para ingreso no parece correcto, cuando desde el punto de vista de la salud está estable y cumple con el tratamineto. +++CONVRESACIÓN CON NURIA, Enferemera del ESM de Trujillo. +++++Mañana tiene consulta Juan. Es de la misma opinión. Solcito inofrme de evoclución dedse que dejo el CRR de Mérida. Acude a las citas corecctamente y a ponerse el inyectable también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2019-02-21','Teresa: Nos llega informe con fecha 14/12/18 por la situacion conductual del tutelado en el centro en el que se encuentra. Nos comenta que la relacion con los residentes es de voces e insultos y con algun que otro altecardo fisico. Se muestra muy agresivo y no colabora en nada, su relacion con los trabajadores y compañeros es practicamente nula Actualmente se encuentra en silla de ruedas y es totalmente dependietne para las ABVD ademas presenta dificultad en el lenguaje lo que contribuye a la poca relacion con el resto depersonase del centro y a que aumente su agrevisividad y enfados. Recibe muy pocas visitas de su madre debido a la edad que tiene pero si llaman habitualmente al centro auque no puede hablar con su hijo en la mayoria de las ocasiones porlos problemas de lenguaje que presenta los cuales le impiden mantener una conversacion ****************************************************************** El centro va a continua ayudandole en lo que pueda pero proponen que están abiertos a que si hubiera algun recurso residencial para el que se pueda valorar por la comision.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-02-21','Teresa: Telefono de contacto mancomunidad tajo salor 609 382 439 educadora social María Psicóloga Sonia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-02-20','miguel, enviado borrador de ratificación a la notaria de agustin sanabria (manolo vaquera) a efectos de que nos de el visto bueno y se pueda fijar fecha de firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2019-02-21','Teresa: Hablo con la TS modulo de discapacidad del centro penitenciario (918750000) FAX918750031. Nos comenta que se está adaptando bien, que paricipa en curso de formación. Tiene idea de volver a Extremadura pero en principio va a pasar alli unos años según la TS. También nos comenta que quiere recuperar la tutela pero ella le comenta que de momento eso ahora no es posible. Con respecto a que la tutela pase a la comunidad de Madrid nos dice que ellla no tiene conocimiento de ese deseo. ************************************************************ me manda certificado periodos ingreso para PNC de vida me la enviara por email.+************************ Me comenta si autorizo la compra de un abrigo y un reproductor de CD, queda en hablar con Juana para realizar esta gestion.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2019-02-21','Ana: En el expediente físico no está la Acetpación del PIA ni el Alta de 3º. Intento localizar a Anabel Teomiro, pero no obtengo respuesta a las llamadas.','2');
