insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2019-02-21','-CONVERSACION CON LOLI OLIVERA , LE HAN DADO EL ALTA EL LUNES PERO NI ELLOS NI DESDE AP3 , HABLÉ AYER CON LA TS , NOS LO HAN COMUNICADO . ME INDICA QUE ISABEL DE AP3 NOS VA A ENVIAR DOCUMENTACIÓN . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-02-21','MIGUEL, NOS CONFIRMA TONI DE FUTUEX QUE HAN ASISTIDO CON ÉXITO TANTO A FORENSE COMO A LA COMPARECENCIA ANTE LA JUEZ DEL JUZGADO DE PLASENCIA, DONDE SE VA A CONCEDER INTERNAMIENTO INVOLUNTARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-02-20','MIGUEL, HABIENDONOS LLEGADO CITACIÓN PARA COMPARECENCIA DE MEDIDAS URGENTES A ADOPTAR (INTERNAMIENTO INVOLUNTARIO) EN EL JUZGADO DE PLASENCIA, Y TRAS CONVERSACIÓN CON EL JUZGADO (JUAN CARLOS) INDICANDONOS QUE NO PUEDE SER APLAZADO POR TRATARSE DE MEDIDAS URGENTES. ANTE LA IMPOSIBILIDAD DE NUESTRA ASISTENCIA HABLA PEDRO CON FUTUEX QUIENES LA ACOMPAÑARÁN CON SU HIJO TANTO ANTE LA REVISIÓN DEL FORENSE COMO A LA COMPARECENCIA ANTE LA JUEZ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2019-02-21','Ana: Puesto que se necesita el DNI de Desideria para la apertura de una cuenta bancaria en la que figure ella sola como titular (junto con la Directora Gerente) se le pidió a Ángel, su marido, el DNI, pero éste ha enviado una fotocopia, no el original. /// Se va a intentar en el banco con una fotocopia compulsada, pero se necesita alguien que la coteje. /// Se pide a Toni (FUTUEX)que acudan al domicilio para "cotejar" la fotocopia del DNI y poder compulsarla desde aquí. Si el marido se lo permite le harán una foto con el móvil. /// Se le envía a Toni escaneada por email la fotocopia que han enviado aquí para al menos contrastar esa. ///////// Ana Pérez, Psiquiatra CSS Plasencia - UME, ha llamado y hablado con Belén, quisiera hablar con alguien del Área social, llamo varias veces sin respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2019-02-21','(Pedro)Conversación con Carmen Jerez (ESM Plasencia) (74947), miembro de la Subcomisión de Casos de Área (correo-e: carmen.jerez@salud-juntaex.es +++Quieren convocar la Subcomisión para valorar alternativas de recurso para Jairo. +++PENDIENTE DE CONFIRMAR: 13 de marzo de 2019. Se pide que la hora de convocatoria permita regresar dentro del horario laboral.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-21','Teresa: Hoy acude a cita acompañada por delega de futuex, nos manda informe. Cuando van al domicilio a por ella no les abre porque no encuetra la llaves ya consiguen que le abran y su estado es lamentable, huele mal y esta con ropa sucia en un estado que imprsiona consumo. El psiquiatra le comenta que debe ingresar, ella accede al ingreso siempre y cuando alguien se ocupe de su perro. Me voy a poner en contacto con la perrera para ver si puede estar el perro durante un tiempo y asi ahorrarnos el coste de una guarderia canina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2019-02-21','Ana: Se realiza llamada a Rosa (CSS Plasencia). Comunica que ayer en el Ayto. les dijeron que no podrían empadronar a José María pues no sabían dónde estaba empadronado hasta la fecha. Desde el CSS hacen averiguaciones y en el Ayto. de Cilleros le confirman que está allí empadronado. Lo comunican al Ayto. de Plasencia y le dicen que hasta el próximo martes día 26 no tendrán el certificado de empadronamiento. Cuando por fin lo tengan nos lo enviarán por registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2019-02-21','Ana: Se recibe correo de Pilar, T.S. del Ayto. de Valencia de Alcántara, en el que comunica: "Ponemos en conocimiento que la tutelada Dña. Rosa Gómez Nevado con domicilio en la Residencia de Mayores San Pedro de Alcántara de nuestra localidad ( valencia de alcántara) , tiene una cita médica en el Hospital San Pedro de Alcántara en Cáceres el día 27 de Febrero , a las 10:00 horas. Desde la dirección del Centro Residencial se llamará a su sobrino para que la acompañe en el trayecto." /// Mediante conversación telefónoca Pilar comunica que el sobrino ha confirmado que le acompañará. /// Mañana nos enviarán consentimientos informados para pruebas, nos la remitirá ella misma (Pilar) o la T.S. del Hptal., con quién se pondrá en contacto hoy mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-02-21','(Pedro)Se realizan las gestiones oportunas para que José Pedro pueda visitar a su hermana en la residencia Sierra de San Pedro. +++Quedo con Puerto (Directora Hogar de Nazaret en Plasencia) en que la visita se hará el 27 de febrero. +++++Han hablado ya con un taxista con vehículo adaptado y el coste será, ida y vuelta de unos 120-130€. +++Hablo con Toni (Futuex) y podrán hacer el acompañamiento ese día. Quedará con puerto en la hora. +++Hablo con Modesto, Admisitrativo de Sierra de San Pedro: aviso de la visita del hermano el próximo día 27 de feberero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MODESTA'and edp.apellido1='GARCIA'and apellido2='PIÑERO'),'2019-02-21','Ana: Llama Pedro (TS CSS Plasencia) solicita el número de cuenta de Modesta para pasarle el cargo del servicio de Podología (7 €) // Hablo con Alberto (Área económica) y le envío por correo el número de cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-21','Teresa: Hablo con TS del SSB y va a hablar con una protectora de animales para ver posibilidad de acoger el perro de María temporalmente hasta que María se encuentre bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-02-21','Ana: Realizo varias llamada a Mª Eugenia, TS módulo 10 del C. Penitenciario de Zuera, pero no consigo contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-02-22','Ana: Llamo a Mª Eugenia, TS módulo 10 del C. Penitenciario de Zuera (976738757), sólo realizan informe para organismos oficiales y solicitados por escrito. Pide que se envíe a A/A del Director del C. Penitenciario por fax. 976698456. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++SE solcita vía fax informe de la situación de D. Rafael.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-02-22','Ana: Realizo llamada al C. Neuropsiquiátrico Ntra. Sra. del Carmen, Zaragoza. Ana - T.S. comunica que hoy mismo enviará el informe médico. Como ha estado 11 meses de baja no puede aportar más información. /// El Dr. Larrubia, Psiquiatra, expresa "Miguel es una persona que sin tener un retraso mental actúa como si lo tuviera, por impulsos. No hay ninguna patología mental. Su capacidad es muy limitada, es una persona muy primitiva. Hace lo primero que se le ocurre sin nintún tipo de planificación ni objetivos. La segunda vez que ingresó, comenzó a adaptarse bastante bien, pero progresivamente ha ido a peor, con exigencias y peores comportamientos. No es capaz de razonar. La dinámica en el centro está totalmente rota". En cuanto al recurso que necesitaría sería "una especie de hptal. psiquiátrico de los de antes, con una alta supervisión, alta contención y unas normas muy claras, que no lo le den mucha medicación" /////// Al final de la mañana recuerdo por e-mail a Anabel (TS) que nos remita cuando pueda el informe médico pendiente, pues aún no lo hemos recibido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2019-02-22','Ana: Hablo con Ana Pérez, Psiquiatra del CSS de Plasencia (24172) Informa que Ángel, marido de Desideria, acuidó ayer a hablar con ella, debido a su delirio compartido (piensa que los demás les estafan y les roban) se muestra siempre muy desconfiado y pensaba que con la apertura de la cuenta bancaria de Desideria la mitad de su pensión iría a la cuenta de ésta. Puesto que la psiquiatra le explicó que eso no era así y su abogada le había explicado lo mismo, se quedó mucho más tranquilo./// *Acordamos que el próximo lunes, cuando acuda al CSS, Ana le acompañará a registro y enviarán la fotocopia compulsada. //////// Ángel también se encuentra en régimen de hospitalización parcial, además de la enfermedad mental presenta un pequeño retraso, pero siempre que no se descompense, funciona muy bien, lleva muy bien las cuentas, las compras y todo lo referente a la casa. Desde que residen en el domicilio de Plasencia están los dos más estables y compensados.////// En cuanto a la abogada, piensa dejarla una vez hayan finalizado la compraventa de la vivienda de Valrío.///////////// Llamo a Futuex,comunico a Toni que en pricipio ya no hará falta que acudan al domicilio a cotejar el DNI de Desideria','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-22','Teresa: Llama TS del centro para informar que Andrea ha ingresado anoche por insuficiencia respiratoria, la familia demanda un cuidador. Hablo con Julieta para que la atienda de 9 de la mañana a 9 de la noche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-02-22','(Pedro)Converesación con Luis Sancho, Director-Psicólogo del CRR de Cáceres. +++En relación a la denuncia presentada por Dª Antonia el pasado verano (aunque el acta de la mimsa es de 30 de octubre de 2018) y la comunicación del Juzgado de 1ª instancia nº 2 de Cáceres solcitando inofrmación al CRR es de septiembre). +++Luis ya contestó al Juzgado el 11 de febrero de 2019, ya que hasta entonces no habían recibido notificación alguna de la denuncia. +++INGRESO EN UHB: 21 de DICIEMBRE de 2018. ALTA: 16 de ENERO de 2019. +++INGRESO EN UME: 16 de ENERO de 2019. Berta, su Psiquiatra, manifiesta buena evolución y prevé el alta para finales de febrero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2019-02-22','-VUELVO A PEDIR CONTRATO A LA EMPRESA Y EL MODELO ALTA 3º PARA ENVIARLO JUNTO AL PIA QUE TENGO EN BADAJOZ A SONIA VENEGAS . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-22','Teresa: Hablo con el TS y me comenta que la por el tipo de perro que es no es posible que vaya la protectora, me comenta que una vecina se puede hacer cargo poro esa idea no la vemos viable. La idea es que se vaya a una perrera municipal para ahorrar los costes de una guarderia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2019-02-22','(Pedro)Converescaión con Soraya. +++Tras consultarlo con el CADEX, no da perfil de discapacidad debido a las conductas que en la esfera de la sexulaidad presenta. +++Se solicitará consulta en el ESM. Pedir a Futuex que solcite derivación a través de su médico de familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-02-22','Ana: Valentina Sánchez, TS C.S. Aldea Moret, nos remite por fax Informe de la Dra. María Martha Hack, en el que hace constar que Paula, continúa con su delirio bien estructurado, acude siempre a la consulta aseada y en buen estado, toma la medicación según lo tiene pautado y acude a por recetas como lo tiene pautado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-02-19','Ana: Toni - FUTUEX, remite por e-mail informes de la última visita a Paula, en el que la delegada no se muestra de acuerdo con la TS del SSB, no observa pérdida de peso, ni abandono físico, ni desmejora, de hecho afirma que tenía el mismo aspecto que cuando la vio en verano en la calle. La casa, a excepción de las manchas de humo (que no sabe si son antiguas o recientes) está limpia y ordenada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2019-02-22','Ana: Contacto por teléfono con Anabel Teomiro, TS EVD Cáceres (22050). Acordamos, y así lo hace, que enviará de nuevo por mail la Aceptación del PIA y el Alta de Terceros. /// Cuando lo recibo lo pongo para firma de la Directora Gerente, se lo comunico a Juana (Área económica) para que cuando esté firmado el Alta a terceros lo lleven al banco lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2019-02-22','SE acepta el cargo de tutor con fecha de hoy, 22 de febrero de 2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2019-02-25','(Pedro)Llamada de Gema, T. Soc. Comunidad Terapéutica de la Garrovilla (85704). +++INGRESO en la C.T: 20 de junio...ALTA prevista para la semana que viene, aunque podría estar hasta el 20 de marzo. Dado que no conocemos el caso y nos piden recurso para él, solicto se prolongue todo lo psoible su estancia en la Comunidad para tener algo más de tiempo y disponer del recurso adecuado cuando salga. +++YA ESTUVO en los pisos tutelados de la Red de Salud Mental, pero los abandonó. Gema refiere que TIENE SOLCITADA plaza en este recurso desde hace tiempo, ya que cambió de opinión y quiso volver al recurso. +++PROPUESTA de la C.T: consideran que la red de salud mental es más apropiada como recurso que la de drogodependencias, por su "fragilidad" y porque "tiene muchos pájaros en la cabeza, quiere ser independiente..." +++Solicito nos envíen los Informe disponibles sobre él y su evolución en la Comunidad: enviarán Informe Psiquiático e historia de la evolución en el Centro. Solicito también Informe Psicolgico (Carmen, la Coordinadora y Psicóloga no estará hasta la semana que viene)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-02-25','Ana: Se recibe por e-mail el Informe del Médico Psiquiatra (Dr. Larrubia) del C. Neuropsiquiátrico Ntra. Sra. del Carmen - Zaragoza. Proponen el cambio de centro a otro Dispositivo Psiquiátrico de similares características.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-25','Teresa: Llamo a Julieta para ver como se encuentra Andrea. Me comenta que se va evolucionando bien. Han pasado a visitarla sus hijos y una tia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-02-25','(Pedro)Llamada de Isidoro, Director de la Residencia "Sierra de San Pedro". +++ESte fin de semana Dª Cristina ha empeorado. LO comunica a los efectos de la conveniencia o no para su hermano, D. Pedro José, de ir a visitarla el próximo miércoles. +++++DE momento mantenemos la visita, porque fue una petción de Dª Cristina el querer ver a su hermano y también deseo de este de realizar dicha visita. +++Lo pongo en conocimiento de Puerto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2019-02-25','(Pedro)Mª José envía por correo-e informe de alta de la UHB con fecha de 18 de febrero de 2019. +++SE traslada a URH de Mérida a la espera de plaza en CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-02-25','(Pedro)Conversación con Puerto, Directora del Hogar de Nazaret. +++La pongo al día de la conversación mantenida con el Director de la Residencia "Sierra de San Pedro" respecto al empeoramiento de Dª Cristina, con el fin de que informe a D. José Pedro de la gravedad de su estado para que cuando vaya a verla el impacto para él sea el menor posible. +++Ya con anetrioridad le han ido hablando de la sitruación de su hermana, "...que él entiende y se emociona cunado se lo decimos...". +++También Puerto considera que conviene mantener la visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-02-25','-TF MIRIAM 645-049410 -TF ELO : 620-134670/924-471194 LA INTERNA DICE QUE MAÑANA SE VA HASTA EL JUEVES DIA 7 , ELO NO PUEDE HACER EL SERVICIO Y RODICA TAMPOCO . SI LA EMPRESA NO ENCUENTRA A NADIE PASARÍA A PLAZA RESIDENCIAL PRIVADA EN ESTANCIA TEMPORAL ?? NO TENEMOS AUTORIZACIÓN DE INGRESO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2019-02-22','miguel, a petición de la letrada de la Junta de Extremadura, Elena Sánchez Simón, a efectos de personarse en la causa como acusación particular, la remito todo lo solicitado, sentencia de incapacitación, informes del colegio ntra sra de la Luz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-25','Teresa: Hablo con vivienda (924332456) para averiguar en concepto de que se paga la cantidad de 71.98€, me comentan que tiene una vivienda en propiedad de VVP que este concepto corresponde al precio que está pagando en forma de prestamo a la junta de extremadura por la compra de esta vivienda la cual compro en noviembre de 2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-02-25','Ana: Se realizan varias llamadas: Raquel, TS ESM de Trujillo (L-X-V en Cáceres:53334 y M-J en Trujillo:54509) dice que ella apenas ha tratado con él. Pero mira en el sistema y dice que aunque nunca ha establecido relación terapéutica con el Psiquiatra, sí que ha acudido a la última cita médica y se ha puesto el inyectable. /////////////// Nuria, Enfermera ESM (54508) Confirma la asistencia de Juan de un tiempo a esta parte. Le ha solicitado el Informe al Psiquiatra, en cuanto lo tengan nos lo harán llegar.//////////////////////// Clara, TS del C.Salud de Guadalupe (53107) expresa que últimamente Juan no va a su despacho, sí que lo ve en los pasillos. La última vez que intentó hablar con él éste le dijo "Tú lo que quieres es que me vaya del pueblo". Las veces que le ha planteado el SAD no ha querido. No obstante dice que volverá a hablar con él al respecto. Le pido que nos elabore al menos un pequeño informe una vez que consiga hablar con él./////////////////// Raquel Moreno, TS Ayto. de Guadalupe (927366527 y Lunes- Ayto. Alía: 927366527) Dice que ya envió un informe para la rendición anual, no obstante lo actualizará y nos lo envirá de nuevo. Expresa que la casa no reune condiciones mínimas de habitabilidad, es muy antigua y está muy deteriorada, motivo por el cual no han valorado el SAD municipal, en esas condiciones no puede entrar nadie a limpiar. Él por su parte está intentando conseguir la remoción de la Curatela y dice que ya le ha valorado el médico forense. Raquel refiere que "es muy inteligente, que sabe muy bien lo que tiene que hacer, para los juicios y demás se asea y se viste bien. Está acudiendo a las citas médicas y tomando la medicación, está más tranquilo y tiene menos conflictos en el pueblo". Pero no se sabe qué come o cena, no tiene red apoyo en el municipio (ni siquiera con familiares directos) ni relaciones sociales de ningún tipo. Le preguntará si está dispuesto a asistir al Centro de Día de Guadalupe (ahora hay 4 plazas libres).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2019-02-25','miguel, llega email de Ana (prima de Soledad "curatelada" y gregorio "tutelado" para nos pongamos en contacto con ellos para vender una vivienda. Tras consulta al expte y conversación con ella le confirmo que vayan tramitando la venta ya que tenemos las dos autorizaciones de Soledad y Gregorio. Solicito vía fax al Jzdo nº6 testimonio del auto de autorización original de Gregorio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-25','Teresa: Me llam Jose TS del SSB me comunica que María se encuentra en urgencias y que va a ingresar. Jose esta buscando donde dejar el perro. He llamado a su madre y me dice que ell no puede hacerse cargo del perro, y que una residencia vale mucho dinero. Ella insiste en que el perro no le aporta ningun benefici. Comenta que hay un hombre interesado con comprar el perro pero que María no quiere desacerse del perro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2019-02-25','(Pedro)Reunión con Gisela (CRR de Mérida). +++Se trata de una tutela nueva de la que hemos hecho el inventario la semana pasada. +++Por la inofrmación de Gisela es una persona bastante autónoma que ha ido a sacar el dinero esta mañana y no ha podido hacerlo. +++ENVIARÁ PRESUPUESTO de GASTOS de D. Ángel para autorizar el reintegro: considera que puede ir solo a sacarlo, lo cual especificará en el correo que nos envíe con el presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2019-02-25','Teresa: Hablo con la Carmen TS del hospital perpetuo socorro (924215125) para pedirle que me facilite un informe clinico por parte del doctor gutierrez ya que ha fecha de hoy aun le sigue tratando en salud mental. Carmen me comenta que va a tardar en poder hacerme el informe que le solicito. Le pido que me mande ultimos informes de las visitas auunque le insisto que lo que nos interesa es la opinion del doctor para que nos indique que recurso considera el más idoneo para Adrian. ************************************************************* Hablo con futuex para que le deriven a salud mental desde su medico de cabecera, me comenta que este miercoles tiene cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2019-02-25','(Pedro)Soraya me informa que han empezado a abonar los 30.000€, a razón de 1000€/mes.','2');
