insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-26','Teresa: Llama la cuñada del tutelado para preguntar que hace con sus enseres personales. Le indico que aqui no tenemos donde guardar esas cosas que le lleve lo que pueda a la residencia y el resto que decida ella si lo puede guardar o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RODRIGUEZ'and apellido2='PARRILLA'),'2019-02-26','Teresa: Nos llaman de plena inclusion (655574533) para informar que ha fallecido el padre del tutelado. Está el tanatorio de Azuaga pero me comenta que el funeral va a ser en Girona. Desde la residencia no ven conveniente realizar ese viaje tan lejos asi que solo autorizamos que vaya a despedirse de el al tanatorio. El hermao se encarga del desplazamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARCOS'and edp.apellido1='SUERO'and apellido2='CAMACHO'),'2019-02-26','-enivo a Pnc DECLARACION INDIVIDUAL + MODELO ALTA 3º . AD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-02-26','(Pedro)Informo del fallecimiento de la hermana de D. José Pedro a Puerto. +++Planteo la posibilidad de que acuda esta tarde al entierro: le darán la noticia y le plantearán si desea acudir al entierro. +++En caso de que así lo desee, el ecntro no dispone de personal para acompañarlo, por lo que lo plantearé a Futuex. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada a Futuex (Toni): aunque sea por la tarde, harán un aexcepción y acompañarán a Jose Pedro al entierro. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva conversación con Puerto. +++Los hermanos de José Pedro han llamado (ni siquiera han venido para darle la noticia) y no han querido decírdselo ellos. +++Tras recibir la noticia, se ha sentido muy triste, además de por no poder verla antes. +++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2019-02-26','MIGUEL, LLEGA CONCESIÓN DE ABOGADO DE OFICIO DE LA COMISIÓN PROVINCIAL DE ASISTENCIA JURIDICA GRATUITA DE CÁCERES. ACORDAMOS CON LA APAREJADORA, Mª JOSÉ DE LA MANCOMUNIDAD TRASIERRA TIERRAS DE GRANADILLA PARA QUE ACTUALICE LA TASACIÓN HECHA EN EL 2014.Y QUE INCLUYA LAS FINCAS RÚSTICAS A EFECTOS DE INTENTAR LA VENTA DE TODO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2019-02-27','(Pedro)Conversación con Gema, de CT La garrovilla. +++Informo de la conversación manetnida con Soraya sobre la disponibilidad del recurso residencial en la red de Salud Mental. SE en cuentra en la posición 10 para pisos tutelados en esta red y en estos momentos no hay vacantes. Con la finalidad de que no salga de CT y deba pasar un tiempo sin supervisión permanente y directa, se propone pasar a pisos supervisado de la red de Drogedependencias, propuesta esta que incluso desde el ESM de Coria del pasado 12 de febrero se propone seguir en la red de drogodependencias dado que sus prolemas están ma´s relacionados con el consumo que que con el TMG. gema valora positivamente esta alternativa, previa a la obtención de plaza en la red de Salud Mental. +++Gema lo comentará con Carmen, la Coordinadora. A la espera de hablar con ella. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Carmen, coordfinadora de la Comunidad Terapéutica de "La Garrovilla" (85705). +++Manifiesta la escasez de recursos exietentes en la Red de Drogodependenciias, pero entiende la nedcesidad de que haya continuidad en el paso de un recurso a otro para garantizar en la medida de lo posible la supervisión del caso y mantener todo lo que sea posible los "logros" alcanzados.Hará las gestiones para derivar a pisos supervisados de Drogodependencias, donde el máximo de estancia son 6 meses. +++La Comisión seguirá pendiente del nº de orden en los pisos supervisados de Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2019-02-27','Ana: Contacta a través de email MARÍA ÁNGEL GORDO IGLESIAS (927424142 / 657455503), Abogada del turno de oficio designada para Francisco. Se le facilita también por mail el contacto del CSS y nombre de la Trabajadora Social de referencia del mismo, pues requiere conocer "aspectos esenciales para el correcto ejercicio de su defensa".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-02-27','(Pedro)Convereascaión con el Dr. Idilio. +++Ya ha estado hablando con la UHB de Llerena para tratar de mantener el ingreso todo lo posible "...pero es una Unidad pequeña, en la que suelen estar una semana más o menos...y el caso de María consideran que es más de carácter social que sanitario..." +++Va a convocar la subcomisión de casos que le planteé en nuestra anterior conversación y citarán a la Comisión Tutelar. +++La Comisión mantiene la necesidad de que María permanezca ingresada en un recurso de la red de Salud Mental.','2');
