insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2019-02-27','Ana: Rosa, Admtva. CSS Plasencia, nos adelanta por email el Certificado de Empadronamiento de José María. Hoy mismo lo remitirá por registro único. //////////////////// Tras contactos previos con la Asociación Vera y el CSS, se acuerda enviar por mensajería las 2 cajas de ropa que aún tiene José María en la Residencia al domicilio de su familia en Cilleros. Se solicitan presupuestos a dos empresas y se decide contratar el servicio, y así se hace, por Envialia. Se les envía email con datos necesarios. Desde Envialia nos remitirán la factura y nº de cuenta para la transferencia. //////// Comunico tanto a Teresa (Directora de Asoc. Vera - 927460598) como a Julia, madre de Jose Mª (927512108 / 688381229) que el envío de las cajas se hará en los próximos días a través de la empresa Envialia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-02-27','Teresa: Hablo con la TS del hospital de Villanueva (924386800) para comentar la posiblibidad de pasar la herramienta para plaza sociosanira, ahora mismo no se encuentra ingresao me remite al centro de salud para que se la pasen alli o sino una vez le operen en Badajoz gestionarlo desde alli. ************************************************************ Se esta gastando mucho dinero en cuidados ademas del coste de la residencia privada. En el precio de la residencia no entra los acompañamientos a las citas medicas. Queso pendiente de hablar con la TS del centro de salud dias de atencion Lunes- martes y Jueves. ******************************************************* Hoy cita en badajoz para espirometría Mañana cita en badajoz para preanestesia Pendiente operacion nódulo pulmorar esta tratandose con quimio.','2');
