insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-02-27','Ana: Esther Moraga (T.S. C.Salud de Miajadas) remite Informe de la Dr. Mª Alegría Domínguez de la Concha, en el que hace constar que Felipe "sólo acude a consutla a por recetas de su tratamiento... viene con cita y no presentando ninguna alteración en su comportamiento mientras dura su estancia en el centro"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-02-25','Ana: Se recibe llamada María - Programa de Familia Mancomunidad Tajo-Salor (659926956). Comenta que llevan 5 años trabajando con la familia y están preoucpados por Felisa y por la posibilidad de que pierda su vivienda. **Felisa tiene un hijo (Aitor) de 17 años tutelado por la Junta de Extremadura, residente en la actualidad en el C.A.M. de Trujillo. Hace unos años Aitor agredió a su madre y cumplió condena en el CMMJ Marcelo Nessi. ** Felisa actualmente tiene pareja (Jesús) con el que reside en Casar de Cáceres, localidad en la que ella se siente más agusto e integrada, tiene más vida social y siente el apoyo de la familia del novio. Pero Felisa tiene un dinero ahorrado en su cuenta y la familia de Jesús comienza a reclarmarle que aporte económicamente. *** En Casar de Navas del Madroño tiene una vivienda social, pero corre el riesgo de perderla si no vuelve a dicho domicilio o al menos pasa allí varios días en semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-02-27','Ana: Como se valoró en la reunión de equipo llamo a Toni (FUTUEX), para que vayan a visitarla y puedan trabajar con ella el hecho de que puede perder su vivienda social. Toni dice que la familia de Jesús (novio) manipula bastante a Felisa y tienen gran interés (no sabe aún muy bien por qué) en que Felisi se quede en El Casar. **Ya hace tiempo que vienen trabajando con Felisa en las visitas la posibilidad de que pierda la vivienda, y que Felisa es consciente de ello, pero parece no importarle. Volverán a visitarle y tratar el tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-02-26','Ana: En la reunión de equipo se decide solicitar que se convoque una subcomisión de caso, dado que no existe consenso entre las distintas profesionales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-02-27','Ana: contacto con Pilar, T.S. del ESM (54698). Dice que desde que a Paula le dieron el alta en la UHB, la única vez que estuvo hospitalizada, no ha vuelto a saber nada de ella. A la cita que se le dió tras su ingreso no acudió. Por tanto expresa que ella no puede convocar la subcomisión de casos.////// Me remite, para obtener más información, al hptal. virgen de la Montaña (Lola/ Mª José: 56823/56950)/////// Hablo con Mª José, TS HVM, no está al corriente del caso, intentará averiguar todo lo posible y si hay informes médicos o sociales en el expte. nos los enviará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-02-28','Teresa: Me llama Julieta para comunicarme que han aislado a Andrea ya que le han visto que tiene una bacteria, le van a dar antibiotico y mejorara con esao, con respecto a la insuficiencia respiratoria esta mucho mejor. La familia le ha dicho que se quede tanmbién por la noche pero como eso no le hemos autorizado la familia ha buscado una chica para que le acompañe durante la noche.','2');
