insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2019-02-28','PAGOS EN EFECTIVO: los conceptos que aparecen a continuación se abonarán a través del reintegro semanal de Alberto, que se autogestionará y redistribuirá a conveniencia. - BUTANO: 1 bombona x 2 meses: 16 €/2 meses= 8 €/mes. - TABACO: 60 €/mes. - COMIDA: 50 €/semana 217 €/mes. - LIMIEZA: 10 €/semana 44 €/mes. - GASTOS BOLSILLO: 82 €/mes. TOTAL GASTOS EFECTIVO 411 €/mes. DOMICILIACIONES: - INTERNET Y MÓVIL: 48 €/mes. (este importe incluye internet vivienda y consumos teléfono fijo y móvil) - SEGUROS (HOGAR/DEC.) 20 €/mes. (calculado para seguro hogar de 130 €/año y seguro deceso 103 €/año) - CONSUMOS/OTROS (IBI/LUZ/AGUA) 90 €/mes. (se trata de una ESTIMACIÓN: si supera este importe habrá que revisar a la baja el reintegro). TOTAL GASTOS DOMICILIADOS 158 /mes. El REINTEGRO SEMANAL autorizado, a partir del próximo 18/02/2019, pasará a ser de 95 €/semana. Otras cuestiones: - Se ha abonado a la cuenta de tu padre el pago de la bicicleta, el móvil y la televisión de Alberto. - Se está gestionando el pago de la multa. - Las deudas con vosotras 2 (hermanas), se abonarán el mes que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-02-28','Ana: Se recibe la llamada de Carmen Martín (T.O. EVD Plasencia - 24109) Expresa que en base a los informes que tienen y la anterior valoración, en principio no va a subir de grado, por lo que se plantean desestimar la revisión. Con Grado I no puede entrar en ningún centro residencial para mayores, y por Salud Mental, puesto que tiene más de 60 añós tampoco puede entrar.*** Van a esperar a ver los resultados que le den hoy en la cita que tiene en Medicina Interna y sobre todo a la del día 22 de marzo en Salud Mental, a ver si los informes aportan algo nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2019-02-28','-HABLO CON PNC BJOZ Y PNC MERIDA . ESTÁ APROBADO EL CPTO ATP CON EFECTOS OCTUBRE DEL 2018. EN ENERO SE LE HA INGRESADO 956€. LO COMUNICO A APROSBUBA 3 PARA REGULARIZAR LA CUANTIA DE LA PLZA QUE AHROA PASARÁ AL 75% DE LOS INGRESOS. AD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2019-02-28','INGESTAS GRAVES REMEDIOS CHAVES MASERO direcciontecnica@aprosuba3.org lun 25/02, 12:11Comisión Tutelar de Adultos; Hola, buenos días. Comunicar incidencias de Remedios Chaves Masero, que como sabéis, desde el lunes pasado, día 18 de febrero, está nuevamente en Residencia San Javier de Aprosuba 3. El sábado 23 de febrero a las 8:30 horas ingirió un lazo del pelo de su compañera de dormitorio que ésta lo tenía guardado en la mesilla de noche. Acudió por urgencias al hospital Perpetuo Socorro para valoración, acompañada por una trabajadora de residencia. Tras realizarle radiografía y tenerla en observación, fue enviada a casa sin extraerle el objeto, pues consideraron que no corría peligro. Hoy lunes, día 25 de febrero, a las 8:35 horas, ha vuelto a realizar ingesta. Esta vez ha roto la tapa de un bote de gel y la ha ingerido, quedando atascada en la garganta y quedándose sin respiración. Los trabajadores han avisado a ambulancia UVI, y a la vez le han comenzado a realizar la maniobra de Heimlich, consiguiendo que lo expulsara justo en el momento que han llegado los médicos. La han valorado y tras comprobar que su vida ya no corría peligro, se han ido y ha acudido otra ambulancia para trasladarla al Perpetuo Socorro. Ha ido con ella una trabajadora de Residencia. Tras permanecer dos horas allí, lo único que han hecho ha sido darle agua para ver como la toleraba y en el informe han indicado que le demos durante unos días dieta triturada y fría, porque se ha hecho mucho daño en la mucosa. Destacar que esta última ingesta Remedios ha puesto nuevamente su vida en un grave riesgo de muerte. Seguimos insistiendo en la extrema necesidad de derivación de Remedios a un centro donde puedan tratar su diagnostico de Discapacidad Intelectual con trastorno de conducta (el cual cada vez es más grave). Solo han pasado 5 días desde que salió de UHB y ya ha realizado dos ingestas, una de ellas de extrema','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-02-28','(Pedro)Conversación con Raquel, T. Soc. del ESM de TRujillo (L-X-V en Cáceres:53334 y M-J en Trujillo:54509). +++D. Miguel no ha estado nunca en el ESM, pero sí tiene consultas realizadas en el C.Salud. +++Una vez fijada fecha de reunión, convocarla para tratar el caso. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Ana: Se realiza llamada al Centro de Salud de Trujillo: 927322363 - Ángel, T.S. no se encuentra. ////// Su médico de familia es el Dr. Julián Garrido Montero y su Enfermera es Mª Ángeles Alvarado Solís.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2019-02-28','-PFHC LLEGA RESOLUCION DE LA BAJA , NOS QUEDAMOS CON LA PNC .AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-03-01','Teresa: Ha recibido el alta hospitalaria ya se encuentra en su centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-01','Teresa: Ayer fue atendido en urgencias del hospital de Badajoz ya que fue a hacerse una espirometria y se puso mal, hoy llamo a Julieta y me dice que no llego a ingresar y que ya se encuentra en su centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2019-02-28','(Pedro) Conversación con Mª José y Sandra, Directora y T. Soc. de la Resdiencia de Mensajeros de la Paz en Nuñomoral. +++Los tutelados reclamaban hablar con nosotros y desde el centro piden a la Comisión que reforcemos el papel de este de cara a los tutelados, porque solo parecen quedarse tranquilos cuando "sosis vosotros los que se lo decís..."·. +++CONVERSACIÓN CON JOSÉ ANTONIO: +++++Está muy contento con el centro al que lo hemos llevado y lo primero que hace es decírmelo y darnos las gracias por ello. +++++Le comento que las normas e instrucciones que les den desde el centro es como si se las diéramos desde la Comisión y que unas veces se autorizará lo que piden y otras no "...si son buenas o malas para nosotros...-dice él mismo-". +++++Está encontacto con su padre y hace unos días estuvo en Plasencia para visitarlo. +++++Está entusiasmado por que en este carnaval se va a disfrazar de seta. +++++Su única petición es tener un móvil de tarjeta. Le digo que lo hablaremos con la Dirección. +++++Me pide que le DÉ RECUERDOS A Amalia de su parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MACIAS'and apellido2='MARTINEZ'),'2019-02-28','(Pedro) Conversación con Mª José y Sandra, Directora y T. Soc. de la Resdiencia de Mensajeros de la Paz en Nuñomoral. +++Los tutelados reclamaban hablar con nosotros y desde el centro piden a la Comisión que reforcemos el papel de este de cara a los tutelados, porque solo parecen quedarse tranquilos cuando "sois vosotros los que se lo decís..."·. Además, Francisco en ocasiones se siente por encima de los demas. +++CONVERSACIÓN CON FRANCISCO: +++++Después de saludarme, lo primero que me dice es que se encuentra bien en el Centro, pero que querría irse a Badajoz. +++++Le comento que las normas e instrucciones que les den desde el centro es como si se las diéramos desde la Comisión y que unas veces se autorizará lo que piden y otras no. +++++Ha recuperado el contacto con su hermana Alicia y lo llevan a verla un par de veces al año. La hermana no va a verlo, pero no le importa recibirlo cuando va él. +++++Participa en talleres peero no le gusta demasiado. El que sí le gusta es el de carpintería y el de escritura. Respecto de este último le propongo que nos envíe aquello que escriba para verlo y reforzar un poco su autoestima. +++++Me pide que le DÉ RECUERDOS A Amalia de su parte.','2');
