insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-03-07','Teresa: ME PONGO EN CONTACTO CON LA UHB DE LLERENA 847157) CONSTANZA Y ME COMENTA QUE NO ES RECURSO ADECUADO PARA ELLA YA QUE NO TIENE PATOLOGIA PSIQUIATRICA Y YA ESTA COMPENSADA.INSISTER EN QUE NO HAY CRITERIO QUE JUSTIFIQUE EL INGRESO Y QUE ESTA PONIENDO EN PELIGRO AL RESTO DE PACIENTES POR SU CONDUCTA AGRESIVA. NO VEN QUE SEA ADECUADO NI LA UME NI NA URH, HAN CONVOCADO UNA SUBCOMISIOND DE CASOS PARA TRATAR EL TEMA AL CUAL CONVOCAN A PEDRO, A FUTUEX Y ALGUN JEFE DEL SEPAD DE MOMENTO VA A SEGURI INGRESADA HASTA QUE SE TRATE EL CASO O BIEN EL JUEZ QUE VA A REVISAR EL CASO DICTAMINE .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-06','TERESA: LLAMA JULIETA PARA COMUNICARMOS QUE EL PROXIMO DIA 12 DE MARZO VAN A OPERARLE EN EL INFANTA CRISTINA. EL DIA 19 TIENE QUIMIO EN EL HOSPITAL DE VILLANUEVA ME PONGO EN CONCTACTO CON LA TS DEL HOSPITAL PARA QUE UNA VEZ INGRESADO LE PASE LA HERRAMIENTA PARA SOLICITAR T4 PERO ME COMENTA QUE ESTO SE DEBE PROMOVER DESDE ATENCION PRIMARIA MANIFESTANDO SU MOLESTIA POR HABERLE PROPUESTO ESTE TEMA A ELLA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2019-03-27','TERESA: SE MANDA OFICIO A INSS PARA SOLICITAR CAMBIO DE NUMERO DE CUENTA DE LA PENSION DE ORFANDAD','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2019-03-06','Ana: Se recibe correo y llamada de Piedad, T.S. de Guijo de Granadilla: "BUENOS DIAS, ME PONGO POR ESTE MEDIO EN CONTACTO, YA QUE A TRAVES DE LOS TELEFONOS NO HE SIDO CAPAZ. LA TUTELADA NEMESIA GARCIA PANIAGUA SE ENCUENTRA DESDE HACE AÑOS INGRESADA EN LOS PISOS TUTELADOS DEL MUNICIPIO DE GUIJO DE GRANADILLA, PERO TODOS LOS DIAS SALE Y SE VA A SU CASA. EL PROBLEMA ES QUE SEGUN PASA POR LAS TIENDAS RECOGE TODOS LOS CARTONES QUE HAY EN LA CALLE Y SE LOS LLEVA A SU CASA, AMEN DE LOS GATOS QUE TIENE Y A LOS QUE DA DE COMER. LOS VECINOS SE HAN QUEJADO DE LA ACUMULACION DE BASURA Y DEL MAL OLOR, Y DEL RIESGO DE QUE SE PUEDA PRODUCIR ALGUN INCENDIO. DESDE EL AYUNTAMIENTO SE HA PLANTEADO EL HACERLE LA LIMPIEZA CON EMPRESAS DEDICADAS A ESTE FIN, COMO SE HIZO CON OTRO VECINO DEL PUEBLO, Y LUEGO EL AYUNTAMIENTO LES PASA LA FACTURA. COMO NEMESIA A NIVEL ECONÓMICO TIENE TUTELA, POR LO CUAL NECESITAMOS AUTORIZACION PARA LUEGO HACER EL COBRO DEL SERVICIO DE LIMPIEZA. POR FAVOR PONERSE EN CONTACTO CONMIGO AL TF 670293045 GRACIAS." ////// Se le pide que envíe al correo de la Comisión al menos 2 presupuestos de empresas de limpieza para la aprobación de uno y que se pueda llevar a cabo la limpieza. /////// Se habla con Alberto al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2019-03-06','Buenos días: Me pongo en contacto nuevamente para informar nuevamente de la situación que la madre y sobrino de JOSÉ FLORENCIO GONZÁLEZ MANGAS están viviendo según manifiesta su madre. En la actualidad José Florencio se muestra muy violento, especialmente con su sobrino de 20 años. La madre intenta mediar pero no son capaces de soportar esta situación y temen que la situación de violencia pueda empeorar. José Florencio no está asistiendo a ningún centro y el tratamiento médico no está siendo controlado por nadie. Ruego atiendan la petición para evitar males mayores. Reciba un saludo Ayuntamiento de Barcarrota Fernanda Gervás Pabón (Trabajadora Social) Plaza de España, 1 06160 Barcarrota (Badajoz) 924736026 650661374 De: SSB Barcarrota Enviado: miércoles, 21 de noviembre de 2018 11:27 Para: Comisión Tutelar de Adultos Asunto: Tutelado Barcarrota Buenos días: Se persona en mi despacho en el día de hoy la madre del tutelado JOSÉ FLORENCIO GONZÁLEZ MANGAS. Manifiesta que la convivencia es insostenible no sólo con ella sino con otros familiares (hermanos y sobrino). Así mismo teme que pueda ocasionarse una situación de violencia. Tiene miedo. Recurre a este SSASB y le oriento para que se persone ante Guardia Civil y Comisión Tutelar. Manifiesta haberlo hecho ya muchas veces y que no se le da una solución. Ruego contacten con el/la interesado/a, he intentado hacerlo yo pero no he recibido respuesta. En espera de contestación, recibe un saludo SSASB 058 (Ayuntamiento de Barcarrota) T.S.: Fernanda Gervás Pabón 924736026 650661374','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2019-03-27','TERESA: HABLO CON LA TS VALLE (924677176)ME COMENTA QUE ESTA OCOPANDO PLAZA T3 LE PAGO DE ESTA PLAZA LO ASUME LA JUNTA DE EXTREMADURA. NO TIENE FAMILIARES NI RECIBE VISITAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2019-03-06','Ana: Se recibe llamada de Longina, TS de Madrigalejo (927354002). Necesita que le enviemos los certificados de las dos pensiones que cobra Anita Priscila: PFHC y Orfandan a favor de familiares de militar, para adjuntarlo al expediente y para el cálculo del abono de la plaza en el piso tutelado.////// Le informo que tenemos la de Orfandad. Solicitaremos la otra y una vez tengamos las dos le remitiremos copia de ambas.////// Se le informa telefónicamente de las cuantías para que puedan hacer el cálculo.////// Pendiente de la firma de Pedro(jefe de sección) para enviar la solicitud del Certificado al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-03-07','TERESA: EMAIL QUE RECIBO DE FUTUEXÇ Buenas tardes, Infromar que en el dia de ayer sobre las 13:00 recibimos una llamada de la Dra. Constanza del Hospital de Llerena comentando que el día anterior a última hora habían recibido una llamada de una jueza para decirle que paralizaran el alta de María Murillo. La doctora nos comentó que le estuvo hablando con mucha terminología técnica que ella no entendió muy bien pero que al final de la conversación, la jueza le dijo que mientras ella no diera la orden, María tenía que seguir ingresada. Seguidamente comenta la doctora, que va a convocar una subcomisión de caso para tratar el tema de María y que será el día 20 de Marzo a las 10.00 de la mañana en Llerena. Dice que estarán el CRPS, enfermedad mental, el Dr. Idilio, el médico de cabecera de María de Monesterio, ... y en ese momento nos comenta que quiere que este también la delegada de apoyo que hace el seguimiento, para hablar sobre la xperiencia de trabajo con ella. Nos comenta, por supuesto que quiere convocar a la comisión y que habia llamando todo el día a Pedro, pero no conseguía contactar y que por ese motivo nos informaba para que dieramos traslado, que desde la unidad están tratando de ponerse en contacto para convocar lo de la subcomisión y para preguntarle si desde alli se cree que debería ir alguien más del SEPAD a la reunión. Insiste en que dieramos traslado, que se la contacte en este teléfono: 924 87 71 5 y que luego ella misma mandará la citación para la reunión por el medio que nos resulte más cómodo a cada uno. Y antes de finalizar la conversación comenta que ve rasgos sociópatas en el comportamiento y la actitud de María y que la cree capaz de hacer cualquier tipo de barbaridad. De hecho, María le ha comentado que prefiere estar en la cárcel que en alguna unidad de salud mental, y que si tiene que incendiar el hospital para ello, lo va a hacer. Estamos en contacto, gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-03-06','TERESA: INFORME DE FUTUEX Informe Paloma Rodríguez Jiménez Fecha 05 de Marzo de 2019 Motivo, seguimiento efectuado para comprobar el estado actual de la tutela y su vivienda, de cara a un previsible internamiento involuntario. A Paloma se la visita en su domicilio con cierta regularidad, durante varios años todos los jueves para retirar el dinero, últimamente dado que no tenía efectividad este seguimiento porque seguía gastando descontroladamente la pensión de su padre, y coincidiendo con un recorte de personal, no le hemos acompañado a esta gestión, si bien al resto relacionadas con la administración de medicación y citas médicas y el seguimiento de su estado. Tras la visita de ayer en su domicilio de Jerez, sobre las 09:45h, nos dirigimos a los SSB para hablar con la ts (Mamen), que ya nos estaba esperando. Ella nos comentó que a mediados de Febrero Paloma la había estaba llamando insistentemente porque no tenía comida y pidiéndole que la llevara a Cruz Roja para que le dieran algo, al final el día 15 la llevó diciéndole que era algo excepcional y que no se iba a repetir. Y el 19 de Febrero la estaba llamando otra vez repetidamente para que la volviera a llevar al banco de alimentos porque ya no tenía nada. Mamen le dijo que no era posible y siguió llamando unos días más hasta que dejó de hacerlo. Tal como estaba establecido con su padre con el que convive, ella se ocupaba del pago del alquiler, mediante transferencia que hace directamente la ctaex y el padre aportaba dinero para la comida, entendemos que como viene siendo habitual, Paloma con la connivencia del padre, se gastaría la pensión de este en pocos días y efectivamente se quedarían sin dinero para comida. Mamen nos cuenta que la ha visto por la calle y va con la ropa sucia, sin peinar, y que ha cogido peso. Mamen nos pregunta si vamos a ir a su casa y le contestamos que sí, nos dice que nos quiere acompañar porque hace tiempo que no la visita en su casa. Nosotros llamamos a Paloma para decirle que vamos para allá pero el teléfono sale apagado. Cuando llegamos a su casa vemos a su padre y a ella sentados en el salón, con la mesa de la camilla llena de restos de comida de la noche anterior, colillas y tabaco de liar todo junto. El suelo del salón alrededor de su padre y de ella, está lleno de papel de cocina sucio y repagado. Le decimos que, si ella no hace nada durante el día, y como estamos por allí, se levanta, limpia la mesa con un trapo y barre los papeles del salón. Pero hay ropa tirada al lado de la cama que hay en el salón y más colillas tiradas en el suelo. Paloma va con ropa que está sucia y el pelo lo tiene enmarañado. Le decimos que le toca inyectable ese día y nos dice que no se acordaba y cuando le preguntamos por el teléfono, nos dice que se le ha roto hace un par de días. Nos lo enseña y está inservible. Tanto Mamen como la delegada, le comentan que tiene que hacerse cargo de su casa porque Isabel, la auxiliar de ayuda a domicilio va todos los días y lo deja más o menos ordenado y ellos ensucian muchísimo y no recogen absolutamente nada. Paloma nos dice que está deprimida y que no tiene ganas de hacer nada y con eso se excusa del estado tan lamentable en el que se encuentra la casa. Le decimos que se cambie para ir al médico y se pone otra camiseta que también está sucia pero algo menos que la que se ha quitado. Y le pedimos que se recoja el pelo o se lo peine porque lo lleva mal, y se hace una coleta. Salmos hacia el centro de salud y vamos a la consulta de su médico de familia para que le meta en la cartilla electrónica el inyectable Xeplion 150mg. El médico nos atiende incluso sin tener cita previa y le pregunta a Paloma que como está, ella le dice que bien. Le mete el inyectable en la cartilla y ella quiere irse del centro de salud enseguida, le decimos que vamos a ir a la consulta de Miriam, la enfermera de Salud mental, para ver si le puede poner el inyectable esa misma mañana, aunque se le haya pasado la hora. Pero cuando vamos a su despacho no está, ha salido a desayunar y Paloma absolutamente desesperada no consiente esperar un poco, y decide que se va. La acompañamos a la farmacia para que compre el inyectable porque últimamente no lo compra y va directamente al despacho de Miriam para que se lo dé del botiquín. Cuando la dejamos en casa, entramos para saludar a Isabel y nos encontramos con ella y con una compañera de su empresa que está hablando con Paco , padre de Paloma, de la situación en la que tienen la casa y que Isabel hace lo que puede pero que Paloma tiene que colaborar más. Paco solamente dice que su hija está enferma y no puede hacer nada y que para eso va Isabel. Nosotros le decimos que Paloma está estupendamente y puede dejar todo ordenado y organizado para colaborar lo máximo posible con Isabel. Dejamos allí a Paloma y vamos hacia el centro de salud para hablar con Miriam, nos da una nueva cita para el inyectable de Paloma, el miércoles 6 de Marzo a las 10:00 de la mañana. Nos ve la doctora Virginia, su psiquiatra y entra un momento para saludarnos, nos dice que ha hecho un informe conjunto con Mariola, la trabajadora social del centro de salud, sobre Paloma y sus posibles conductas sexuales inapropiadas. Y que Mariola iba a mandarlo a la Comisión ese mismo día. También nos comenta la doctora Virginia que quería quitarle hace tiempo a Paloma la Fluoxetina y nos da la pauta que tiene que seguir para que se la llevemos a casa antes de irnos. Nos despedimos de Miriam y de Virginia y pasamos por el despacho de Mariola para saber algo más de ese informe que ha hecho junto con la Dra. Virginia, pero se ha marchado a unas visitas y ya no va a volver. Nos pasamos por casa de Paloma para darle la nueva cita del inyectable y para entregarle la nueva posología de la Fluoxetina y comprobamos que la casa está limpia y ordenada. Y les pedimos que la mantengan así hasta el día siguiente, por lo menos. Paloma nos mira con cara de pocos amigos y nos despedimos. Paloma se compromete que va a ir al día siguiente a ponerse la medicación. Hemos tratado de describir de la forma más objetiva posible lo acontecido en el seguimiento, es cierto que la situación de Paloma a nuestro juicio, cada dia, es peor, en cuanto al autocuidado personal y de la vivienda, en cuanto a la administración de la medicación, en cuanto al control y supervisión de su dinero y posiblemente también en lo relativo a conductas sexuales de tipo inapropiado. Desde que se viene haciendo el seguimiento del caso, no se objetiva mejora en cuanto al grado de autonomía o desenvolvimiento en el entorno, más bien, se evidencia lo contrario.','2');
