insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2019-03-07','Ana: Realizo llamada a CSS Plasencia. Rosa, Admtva. comunica que el mismo viernes día 1 por la tarde trasladaron desde el propio hospital a Jose Mª al CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2019-03-07','Ana: Realizo llamada a Raquel, TS de Guadalupe (927367006) en relación a la propuesta por escrito que hace María Rodríguez, vecina de la Tutelada María Sánchez. Raquel expresa que María Rodríguez presenta problemas psicológicos, que siempre anda metida en líos y buscando problemas. La casa está muy deteriorada, el salón se está hundiendo, es muy antigua y nunca se han hecho reforma alguna, no está en condiciones de habitabilidad. Cuando se inició el proceso de incapacitación el Aparejador del Ayto. visitó la vivienda y confirmó lo expueto. Raquel añade que la solicitud de María (Vecina) tiene pinta de esconder algún otro interés, como el de tener acceso a objetos antiguos de la vivienda.///////// Llamaré al Ayto. para solicitar nueva visita del Aparejador para que confirme la necesidad o no de la reforma del muro que comparten ambas viviendas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-03-07','Ana: Se recibe fax de Mª Eugenia, TS del C. Penitenciario de Zaragoza, con el Informe Social de Rafael, pero la segunda página sale cortada. Llamo por teléfono pero no está. Le dejarán nota para que el próximo lunes vuelva a enviárnoslo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-08','Teresa: Me llama Julieta y me comenta que lo ingresan el dia 13 y sera operado el día 14 en el infanta cristina de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2019-03-08','Ana: Realizo llamada a Felipe Sánchez Barba, Alcalde del Ayto. de Guadalupe. Ante la solicitud de que el Aparejador visite la vivienda y determine en qué medida afecta los desperfectos de la vivienda de María a su vecina, dice que él no puede autorizar eso, pues es un problema privado, entre dos particulares. //////////// Llamo a María Rodríguez, vecina, expresa que la casa de María Sánchez está fatal, que el suelo de la sala de estar se está hundiendo, el corral está totalmenten abandonado lleno de hierbas y que le suben ratones a su casa desde la de María. Pregunta que si María Sánchez le autorizara, si podría alquilar y hacerse cargo de la vivienda, se le explica que puesto que María está tutelada, ella no puede tomar esa decisión. Al preguntarle por qué quiere alquilar una vivienda en tan mal estado según ella, dice que no tiene ningún interés especial, que solo para arreglarla y cuidarla. Le digo que eso hoy por hoy no es posible, que lo que sí podría hacerse es arreglar la parte que comparten y pagar a medias los costes, podría enviar a la comisión presupuesto. Expresa que le parece bien y pregunta que entonces a quién tiene que pedir la llave para entrar allí con algún albañil a valorarlo. Le digo que tengo que informarme al respecto y que en cualquier caso ella no puede entrar allí sola con un albañil. La volveré a llamar más adelante para informarle sobre cómo lo podemos hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-03-08','Teresa: Llamo a Jose TS y me comenta que la policia esta intentando localizar a la dueña del perro para que se haga cago de él. Llamop Vasco policia local (618742020) y me comenta que no son capaces de localizar a la dueña del piso ya q no es de la localidad. Le facilito el numero de la marisol la madre de María para que hable con ella pues parece ser que la madre de la dueña del perro está trabajando en el centro penitenciario . ************************************************************ hemos recibido Fax del juzgado en el que nos solicita que le enviemos sentencia de incapacidad ante la situacion actual de Maria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2019-03-08','TERESA: LLAMA RAMON PARA COMUNICAR QUE LA YEGUA HA MUERTO Y QUE NECESITA 60€ PARA ENTERRARLA. EL LUNES PUEDE IR A SACAR EL DINERO PARA PAGAR EL ENTERRAMIENTO','2');
