insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-03-08','-ACOMPAÑAO A MERCEDES A VER UN PISO . EL LUNES NOS CONFIRMARÁN . TENEMOS LA POSIBILIDAD DE VER OTRO PARA EL LUNES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PEDRO'and edp.apellido1='SAHAGUN'and apellido2='CHAMORRO'),'2019-03-08','-VISITA EN R.M. PUENTE REAL EN BADAJOZ. REUNION CON DTOR. Y CON SU HNA. MANUELA. HAGO PTO. DE GASTOS PARA LA PARTE ECO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-08','Ana: Recibo llamada de Pilar Márquez, T.S. del SSB de Valencia de Alcántara (927580326). Ayer por la noche recibió llamada del Alcalde informando que Julián Ramón había llamado a la Guardia Civil porque se había desprendido un trozo del techo de su salón, con miedo a que continuase el derrumbamiento de la vivienda. Iban a llamar a unos albañiles y la preocupación era quién se iba a hacer cargo del pago de la factura. Por la vivienda pasaron también bomberos y policías municipales. ///////// En relación al abono de la factura, como Ramón tiene dinero se autorizará desde aquí.////// A parte de la obra es necesario limpiar el tejado de la casa.///////// Julián Ramón acumula basura en el domicilio, la policía ha tirado algunas cosas sin que él se entere, pues no quiere que se tire nada.//////// Julián Ramón nunca ha permitido la entrada de nadie en su domicilio. No es violento, pero tampoco se relaciona prácticamente con nadie. Sólo transita por la calle en la que vive, que es la calle comercial del municipio. Tan sólo asiste al banco y al supermercado.////// No acude a consulta al Centro de Salud desde hace 30 años, no toma medicación y parece estar totalmente descompensado. /////////Pilar y yo acordamos que ella acudirá al domicilio y si Ramón le permite la entrada, hará fotos y me las enviará. Acudirá o llamará también al C.Salud, para preguntar qué médico/a tiene Ramón asignado y solicitarle que active el 112.////////// La Médica de familia se llama Sandra (927580295). Le ha pedido a Pilar que la policía acompañe a J.Ramón a su consulta para que pueda valorarle.////// Realizo llamada a Sandra, quién dice que ella no conoce al paciente, pues nunca ha pasado por su consulta. Y que si la vivienda está en ese estado no son la condiciones adecuadas para asistir allí a valorarlo, que le tienen que acompañar a su consutla pues ella no va a ir a su casa./////// La policía dice que de ninguna manera J.Ramón se dejará acompañar al médico. //////// La TS del C.Salud no está hoy. Pilar la llamará el lunes. La idea es que ambas hablen con la médica y le ofrezcan acompañarla al domicilio de J.Ramón, dada la negativa de éste de acudir al C.Salud, para que lo valore y active el 112.//////// Si la Dra. no accediera a ello, ellas mismas llamarán al 112.//////// En cuanto a nuestra preocupación de que J.Ramón pase el fin de semana en su vivienda, Pilar pregunta a los albañiles por el riesgo de derrumbe. Le explican que han eliminado todos los elementos de riesgo, que han apuntalado el techo y que esta misma tarde y el lunes seguirán trabajando en el domicilio. A priori, a no ser que hubiera condiciones climatológicas que empeoraran la situación, no es peligroso que se quede allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2019-03-11','-NOS LLEGA ACTA DE LA VISITA DE APROSB3 AL DOMICILIO DE PILAR . AL PARECER EN EL MISMO VIVE SU MADRE, SU NOVIO ACTUAL LOLO Y SU EXNOVIO , HERMANO DEL ANTERIOR ÁNGEL . ÉSTE INSULTA A LA MADRE Y NO SE QUIERE IR DEL DOMICILIO . RECOGO EN EXPEDIENTE EL ACTA DE LA VISITA. ME LLAMANA PARA COMENTAR PREVIAMENTE LA MISMA , LES INDICO QUE ME AVISEN POR SI PUEDO ACOMPAÑARLAS PERO LO HACEN UNA HORA ANTES DE LA VISITA Y NO PUEDO ASISTIR. LA MADRE NO QUIERE DENCUNICAR NI HACER NINGUNA GESTION PARA ECHARLO DE LA CASA . AD.','2');
