insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-11','Teresa: Llama Julieta para comunicar que durante la estancia en el hospital de Badajoz por la operacion que le van a hacer el proximo dia 13 va a ser su hemana quien le acopañe. Si va todo bien el viernes es probable que le de el alta. El próximo día 19 tiene quimio en su hospital de referencia. Hablo con victoria TS hospital para comentarle que desde el infanta me indican que hay que promoverlo desde atencion primaria, ella se va a encargar de hablar con Nieves TS del centro de salud y seguiremos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2019-03-11','Ana: Puesto que ya hemos recibido el Cdo. de Empadronamiento de José María, lo remito junto con el Alta a Terceros, al Serv. Territorial de CC - PNC, a través de Registro Único - Entrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-11','Ana: Recibo llamada de Pilar, TS del SSB Ayto. Valencia del Alcátara. Finalmente ha tenido que activar ella el 112. La TS del C.Salud dice que no es suyo porque está con MUFACE. **Hoy a las 13 h. acudirá la Médida de familia, Sandra, al domicilio. Pilar también acudirá a esa hora y la policía municipal, aunque los agentes esperarán abajo, pues J.Ramón tiende a ponerse nervioso con los policías. Me mantendrán informada al respecto./////////// Derivan a Julián al Hptal. Virgen de la Montaña de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-03-11','Teresa;: Llman de la UHB (47171) para comunicarnos el alta de Maria ya que se encuenta estable. Se nos convoca a una subcomision el proximo dia 20 de marzo. Pido informe de alta a la uhb y pido a futuex que vaya a visitarla','2');
