insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PEDRO'and edp.apellido1='SAHAGUN'and apellido2='CHAMORRO'),'2019-03-07','-HACE 8 AÑOS QUE LE DIAGNOSTICARON COREA H. -GRADO 2 DEPEND, EN T3 EN PUENTE REAL . NO PIDO VALORACION PQ EL RECURSO YA ES EL QUE NECESITA. NO TRASLADO. SE PAGA POR COPAGO 755€. - LA FAMILIA NO HA PODIDO HACER SEGURO DECESOS POR LA ENF. , NO TIENE. - LA NIÑA TIENE 12 AÑOS , LOS APELLIDOS SE LOS CAMBIÓ EL PADRE BIOLOGICO ,NO TENEMOS QUE ABONAR PENSION . - TEMAS EC Y DE PARTICION DE BIENES PENDIENTE , SE LO PASO A LA PARTE ECO.','2');
