insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-03-12','Se recibe llamada de María-Programa de Familia. Expresa que la situación se hace cada vez más insostenible, pues tanto ella como su pareja no dejan de pedir dinero. A pesar de que le explican la realidad parecen no entenderlo (la pensión de Felisi es bajita, el otro ingreso corresponde a la Orfandad de su hijo). María considera que el apoyo de la familia para Felisi no es malo, pero las formas y las exigencias sí lo son. Su pareja ahora está en paro, por eso la cuestión económica ha cobrado mayor relevancia. **Les gustaría que desde la Comisión se mantuviera una reunión con la familia de la pareja para explicarles la situación real, pues no creen que exista realmente nadie en la Comisión que se haga cargo de todo lo referente a Felisa. ///// Por otra parte este fin de semana el hijo de Felisa pasará el fin de semana con ellos, por lo que piden un extra (20-30 €) para hacer frente a los gastos. Les pido que lo soliciten por correo electrónico al Área Económico, no obstante se lo comento a las compañeras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2019-03-12','Miguel, recibimos ayer día 11 de Escalona Diligencia de Ordenación del Jzdo de Cáceres nº6 para subsanar el defecto de realizar Depósito al Recurso que interpuso el procurador Joaquin Floriano Suarez de nuestro tutelado Ventura Gomez Garcia, y siendo el abogado Julián Cambero Valencia. Tras conversación con el Jzdo me confirma que el defecto ha sido subsanado y que continúa el procedimiento judicial.','2');
