insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-03-14','Ana: Previa petición de Alberto (Jefe sección económica) llamo a Mariví Clemente, TS del CSS de Plasencia, para preguntar por la situación económica de Miguel, pues hasta ahora sólo conocemos lo que consta en el Informe Social, que es que tiene una Pensión de Invalidez Absoluta de la que la Seguridad Social le retienen mensulamente una cantidad por distintas deudas y embargos, que tiene tres cuentas bancarias, una en del BBVA (donde le ingresan la pensión) y otras dos negativas en Liberbank y Santander.//////// Mariví me explica que Miguel es bastante autónomo y desde que está en el centro y está compensado, es él mismo quién retira efectivo del cajero, 60 € mensuales para sus gastos de bolsillo y tabaco. Puesto que hace buen uso de ello se le permite que así sea. ***La alarma les salta cuando ven que su hijo ya ha hecho varias retiradas de efectivo de la cuenta sin saberlo su padre, pues el hijo también es titular de la cuenta. //////////** La Comisión aún no tiene acceso a su cuenta ni control sobre ella./////////// Miguel, aunque está en URH no paga la plaza dado que está cumpliendo una Medida de Seguridad de Internamiento por un delito, con fecha de finalización de 25/10/2020. Una vez cumpla la medida, en caso de que el Psiquiatra considere que debe continuar en URH debería comenzar a abonar su plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2019-03-14','-NOS REUNIMOS EN OFICINA CON LALI MARTIN , TIA DE MINERVA Y JORGE. VIVE EN LA ZONA DE SAN JUAN EN MERIDA , EN LA C/ SAN CRISTOBAL Nº 25 EN UNA CASA , AL LADO DE LA DE SU MADRE. EN CASSA DE LA MADRE ES DONDE ESTÁN AHORA LOS CHICOS VIVIENDO . LA MADRE Y LOS 7 HNOS. DE VICTOR SE ENCARGAN DEL CUIDADO DE ELLOS. ESTÁN SACANDO LOS 400€ PQ VICTOR LES HA DADO LA CARTILLA BANCARIA PERO LES HA DICHO QUE NO LO GASTEN. INSISTO EN QUE ESE DINERO ES PARA ELLOS Y LO TIENEN QUE UTILIZAR. MINERVA ESTÁ ACUDIENDO A C.DIA , LA LLEVA A LA PARADA JORGE. LA FAMILIA CONSIDERA QE NO SE TENIAN Q HABER QUEDADO CON LOS PADRES NUNCA, ELLA TIENE EN ACOGIMIENTO AL MENOR CON DISCAPACIDAD Y OTRA HNA. TIENE AL HNO. MAYOR. SOLICITAN QUE DURANTE UNOS MESES SE MANTENGAN EN CASA DE LA ABUELA PQ SU HNO. ESTÁ MUY MAL . - SOLICITO CAMBIO PIA , LOS DOS TIENEN G.1 , Y PIDO PLAZA RESIDENCIAL. HABLARÉ CON MANUELA PARA DETERMINAR SI LO SOLCITO POR EMERG. SOCIAL . QUIERO QUE LOS DOS HERMANOS VAYAN JUNTOS AL MISMO CENTRO. LO PONGO PARA FIRMA CONSOLI A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-14','TERESA: LLAMA JULIETA PARA COMUNICARNOS QUE YA HA SIDO OPERADO JOSE ANTONIO QUE ESTA BIEN Y QUE MAÑANA LE DARAN EL ALTA EN EL HOSPITAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-03-14','Ana: Amalia que comunica que ha recibido la llamada de Juan Jesús, pareja de Felisa (616158973) diciendo que le gustaría ejercer la Tutela de Felisa. Le toma nota y le dice que ya le llamaremos. ///// Preguntaremos a Pedro si él le conoce ////// Llamo a María, del Programa de Familia de la Mancomunidad Tajo Salor (659926956), precisamente se encuentran en casa de Felisi con ella ya despidiéndose, pues han ido a hacerle la visita y a presentarle a la nueva Delegada Tutelar de FUTUEX. Me llamará mañana si puede o el lunes para hablar sobre ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2019-03-14','Buenos días. Os comunico que con fecha 11/03/19 ingresó en nuestro centro vuestro tutelado Jonatan Ramírez Juarez. Nos pide que contactemos con vosotros y que a partir de la fecha remitáis las transferencias económicas de su pensión a la cuenta de Peculio. Para cualquier consulta, no dudéis en contactar con nosotros. Un saludo. Cristina Villalobos Rivero Trabjadora Social Centro Penitenciario de Badajoz C/Carretera de Olivenza km 7,300. C.P. 06011. Badajoz Telf.: 924 289117 Fax: 924 289113 Cristina.Villalobos@dgip.mir.es - YA GESTIONADO POR LA PARTE ECO LA CTA. PECULIO. - INTENTO CONTACTAR CON PAULA PAR VER COMO PODEMOS COMPRARLE ROPA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-03-15','TERESA: RECIBO INFORME DE LA DELEGADA TUTELAR DE LA VISITA REALIZADA EN SU DOMICILIO TRAS EL ALTA: En esta visita María estaba estable, despierta, aseada y con la ropa limpia; totalmente distinta de cómo la vimos la última vez. Ella mismo nos reconoció que estaba ida y que no se encontraba bien, que se había fumado 100€ en porros ella sola y que por eso se encontraba así. Pero ahora estaba muy convencida de que quería cuidarse para poder estar en su casa con su perro. Y sus intenciones son buenas, lo malo es que no creemos que le vayan a durar mucho. Otra cosa es que no quiere bajo ningún concepto ir a algún tipo de centro de salud mental, y menos sin su perro. Nos comentó que a un piso tutelado podría ir si se llevaba a Nerón, sino nada de nada. Y nos dijo que como intentaran sacarla de su casa, se haría de una arma y se liaría a tiros con quien fuera, que prefería estar en la cárcel con delincuentes, y haciendo trapicheos, que en un centro de salud mental. La situación de María es de las mas complejas que hemos tenido porque no permite ayuda profesional, solamente quiere hacer las cosas a su manera y normalmente cuando se le pasa el susto de un ingreso, vuelve a las conductas autodestructivas y al consumo sin control.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2019-03-15','-Hemano Antonio (687-969982)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2019-03-15','-HABLO CON PAULA , JONATHAN ESTÁ INGRESADO POR VIOLENCIA DE GENERO A UNA CHICA , 4 MESES . SE LE PIDE QUE ALLI LE HAGAN EL DNI , PERO LA POLICIA SOLO VA 2 VECES AL AÑO . QUIERE DINERO SE LE EXPLICA QUE YA SE HA HECHO CTA. PECULIO . PARA EL TEMA DE LA COMPRA DE ROPA LLAMO A ANTONIO , NO RECIBO RESPUESTA. SI NO ES POSIBLE A PAULA NO LE IMPORTA. AD.','2');
