insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-03-15','TERESA: LLAMAN CARMEN TERAPEUTA DE DEPENDENCIA PARA COMENATARME QUE HA RECIBIDO UNA PETICION POR PARTE DE LOS PADRES DE BEATRIZ PARA QUE LA CAMBIEMOS A OTRO CENTRO MAS CERCANO. HABLO CON LA TS DEL CENTRO Y ME COMENTA QUE NO HAY BUENA RELACION CON LA MADRE, QUE BEATRIZ ESTA MUY BIEN ADAPTADA EN Y QUE VE MAS UN PERJUCIO QUE UN BENEFICO EL CAMBIARLA DE CENTRO. LLAMO A DEPENDENCIA Y COMUNICO QUE NO VAMOS A HACER NADA CON RESPECTO A ESA PETICION QUE BEATRIZ SE QUEDA DONE ESTA.','2');
