insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2019-03-18','Ana: Hablo con Pilar, TS del CSS de Plasencia (24146), se ha incorporado ya de su baja, Alba es quien le sustituía. Confirma que alguien acompañará hoy a Fco. al juicio.////// Fco. está ingresado en UME, pero no sabe desde cuándo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2019-03-18','Ana: Llama Blanca, del CSS de Mérida. Solicita que le enviemos Solilitud de Revisión de Grado de Dependencia firmado por Consoli, ella ya tiene el Informe Médico para adjuntarlo y enviarlo cuado tenga la solicitud. Pongo el documento para firma de Consoli y le dejo nota a Amalia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-03-15','Ana: Cumplimento y pongo para firma de Consoli la solicitud de Pensión de Orfandad. Hago fotocopias pertinentes y dejo pendiente las compulsas. Cuando tenga todo listo registraré la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2019-03-11','Ana: Recibo llamada de Alba, TS CSS de Plasencia, puesto que Eugenia apenas tiene gastos, no le están sacando dinero que no necesite, pero Eugenia ha ido a hablar con ella y le insiste en que saquen dinero todos los meses para que no le embarguen, pues avaló a alguien para la compra de un coche y dice tener deudas.... Alba no sabe que hay de cierto en todo ello. Lo comento con Alberto, más que nada para que lo tengan en cuenta en el área económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-12','Ana: Llamo a Mª José, TS HPTAL. VIRGEN DE LA MONTAÑA. (56950. Su tlf. personal 615922774) Al parecer *la Psiquiatra que ha atendido a Jullián opina que no es paciente para estar en psiquiatría y le quiere darle el alta. Le tienen en observación. **Los hijos están allí con él./////// Hablo con el Médico de Referencia de Urgencias: Antonio Sánchez (56856). Me explica que en ese hptal. funcionan de otra manera y que si el especialista de la planta correspondiente opina que no hay criterio para ingreso, no se puede ingresar por mucho que él opine lo contrario. Le mantendrán en observación mientras encontramos una alternativa para él. /////// Mª José, TS Hptal. me envía el borrador del Informe Médico de Alta, en que la psiquiatra expresa que NO ENCUENTRA CRITERIOS CLÍNICOS DE INGRESO. Mª José me informa tamibén que es necesario que acuda a Cardiología, pues sí le han detectado problemas coronarios. Por otra parte expresa que Julián está tranquilo, al llegar dijo que era la primera vez que estaba en un hptal y que allí se estaba muy bien. Le pido a Mª José que vuelva a hablar con él para ver si estaría dispuesto a ir a una residencia, al menos mientras arreglan su casa. Julián dice que sí./////// Hablo con Pilar, TS del SSB de Valencia de Alcántara, dice que no hay plazas en ninguna de las dos residencias que hay en el pueblo. Pero sí en la Residencia de San Vicente de Alcántara, a tan sólo 8 km. Añade que la residencia está muy bien y tieen médico propio. //////// Llamo a la Residencia Puente Real de San Vicente de Alcántara (924410835) Vere, Directora dice que sí hay plazas. Acordarmos su ingreso por la tarde, pero tiene que llegar antes de las 18:30, para que esté la enfermera. Me enviará el contrato de la residencia y el consentimiento informado de uso de medidas de sujeción en caso de ser necesario. Hoy mismo solicitaré la firma de la Gerente y se los enviaré.//////// Vuelvo a llamar al HVM, El doctor Anotnio Sánchez solicitará la ambulancia para el traslado, le pido que lleguen a la residencia antes de las 18:00 h.)/////// Envío por email el contrato y el consentimiento informado de medidas de sujeción debidamente firmados y sellados. Dejo pendientes de envío la Autorización de Domiciliación Bancaria que también me han remitido y las copias de la Sentencia de Incapacidad y la Aceptación del Cargo. //////// Cominico el traslado a la Residencia tanto a la TS del SSB como a la del Hptal.////// Con respecto a la ropa y enseres que Julian debe llevar a la residencia, Javier Civantos (658806037), uno de los hijos de Julián, dice que se encargará. //////// Tras varias llamadas sin respuesta a MUFACE, consigo que me atiendan al tlf. Me dicen que los cambios se realizan en enero y junio, que hacerlo ahora supone un cambio extraordinario y que me pasa con la persona encargada de ello. Pero no responden a la llamada y no consigo volver a contactar con nadie. *Para hacer cualquier gestión online solicitan clave que no tenemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-13','Ana: En relación al talonario de MUFACE para las recetas, dice Vere, directora de la Residencia Puente Real de San Vicente, que se encargan de solicitarlo desde allí, tal y como hacen con otros pacientes con seguro privado. Puesto que no he conseguido contactar con Muface para el cambio a la Seguridad Social, Vere solicitará la información por email, a sus contactos habituales y cuándo respondan me informará.///// *En cuanto a la primera noche, Vere expresa que Julian la ha pasado bien, está tranquilo y ha firmado el contrato, no obstante una de las primeras cosas que ha manifestado es que cuando su casa esté arreglada él se irá para allá. ////////// Recibo llamada de Javier, hijo de Julian. Mantenemos conversación de más de 45 minutos, ayer por la tarde acudió a la residencia para llevar las cosas de su padre. Se queja de la residencia, dice que su padre no es tan mayor como para ir allí, que además si es algo temporal que mejor serían en Cáceres, para que ellos estén más cerca. Que además ni la comisión ni nadie se ha preocupado de su padre en más de 20 años y de repente todo el mundo queriendo involucrarse.... Se le deja hablar y además se le explica el funcionamiento de la Comisión y que el principal interés es el bienestar de su padre, quién no ha permitido hasta ahora la entrada de nadie en el domicilio, ni a la Delegada Tutelar, ni al equipo de valoración de dependencia, ni a la TS del SSB, ni a nadie.... Y que si no está de acuerdo con la gestión que solicite la remoción de la tutela al juzgado y la asuma él. A partir de este momento cambia el tono y le explico que lo importante es que todos rememos en la misma dirección por el bien de su padre, que es lo que no preocupa a todos. ///////// En relación a la vivienda, hablo con Pilar, TS del SSB, dice que solicitará al Aparejador Municipal que haga un informe. Me facilita también el nº de tlf. de Paco, albañil y empresario de la empresas Ortés Costa Construcciones (638712004). Llamo a Paco y me comenta que ya están terminando. La vivienda es un segundo piso, debajo hay una vivienda que ahora no está habitada, y debajo de ésta locales comerciales (una farmacia y otro local cerrado). El edificio tiene mal la cubierta y es la comunidad quién tendría que hacerse cargo de éste arreglo, él se encargará de comunicarlo. En cuanto a la casa de Julián tuvieron que tirar y hacer de nuevo el falso techo entero del salón, que estaba para caerse. Sólo falta pintarlo. Según él habría que reformar el techo de otra habitación también. Y sería bueno pintar la vivienda entera. También han tirado basura (botes, plásticos, boslas...), pues la exmujer de Juslián les llamó pidiéndoles ese favor. De momento les pido que finalicen lo que están haciendo y no hagan nada más, hasta que veamos como evoluciona Julián en la Residencia, por si finalmente cambiara de idea y quisiera quedarse allí, además tendremos que valorar en una reunión de equipo en la comisión la situación económica y las distintas posibilidades. Me pide un número de WhatsApp para enviar fotos y presupuesto. Como en este momento no están la compañera del área económica que tiene el número, acordamos que volveré a llamarle para dárselo.','2');
