insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2019-03-18','TERESA: HABLO CON LA TS DEL CENTRO DE SALUD DE SU LOCALIDAD Y ME COMUNICA QUE TIENE CITA EN SALUD MENTAL EL 8 DE MAYO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-14','Ana: Llamo a la Gerencia Territorial de Cáceres del SEPAD, puesto que Julián tiene expediente, aunque caducara en su día la solicitud de valoración de dependencia, sólo es necesario enviar la Solicitud de Valoración de Cambio de Circustancia junto al Informe Médico, para solicitar que reactiven el expediente.//////// Recibo la llama de "Peque", TS del SSB de San Vicente de Alcántara (924040495). Como ya hablé con Vere, directora de la Residencia, aprovechando que Julián está allí ahora, van a solicitar valoración de Dependencia. Le comento que ya he llamado yo a la Gerencia Territorial. Acordamos que le enviaré la solicitud de Cambio de Circustancias firmada por la Directora-Gerente, en la que se comunica cambio de domicilio y solicitando reactiven el expte.///////// Pilar, TS del SSB de Valencia Alcántara, me comunica que el Aparejador le ha dicho que puesto que ya se han hecho obras en el domicilio, ya no puede elaborar un informe al respecto. Me facilita nº de Bombereos (927627528) y Guardia Civil (927582080) para solicitar los partes de incidencia de cuando acudieron al domicilio el jueves día 8.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN JOSE'and edp.apellido1='EXPOSITO'and apellido2='VERDION'),'2019-03-13','FALLECIMIENTO El 13/03/2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-03-18','TERESA:SE RECIBE INFORME CLINICO DEL CENTRO DE SALUD DE JEREREZ DE LOS CABALLEROS. PALOMA VIVE CON SU PADRE, TIENE UN GRADO II DE DEPENDENCIA Y COBRA PNC. SU MADRE FALLECIO A CAUSA DE UNA HEPATOPATIA ALCOHOLICA, TIENE UN HERMANO CON ANTECEDESNTES DE POLICONSUMO. PALOMA TIENE SU DEBUT CON LA ENFERMEDAD EN 2001, EB EB 2005 CUANDO INGRESA EN LA UHB Y RECIBE EL DIAGNOSITCO DE CI LIMITEM TRASTORNO DE LA PESONALIDAD Y TRASTORNO PSICOTICO NO ESPECIFICADO. EN LA ACUTUALIDAD SE LE HACE SEGUIMIENTO POR EL EQUIPO DE SALUD MENTAL DE JEREZ DE LOS CABALLEROS. PALOMA TIENE NULA CONCIENCIA DE ENFERMEDAD Y TIENE FRECUETNES DESCOMPENSACIONES PSICOPATOLOGICAS, PRESENTA ABUSO DE LAS BENZODIACIPINAS Y PRESENTA UNA NULA CAPACIDAD DE AUTOGOBIERNO. DESDE LA COMISION SE LE GESTIONA SU PENSION PERO DISPONE LIBREMENTE DE LA DE SU PADRE CON LO CUAL A MEDIADOS DE MES NO TIENE YA DINERO PARA COMER. SU ASPECTO ES DESALIÑADO, DESPIDE MAL OLOR CORPORAL Y NO SE ORGANIZA PARA LAS TAREAS DOMESTICAS. SUS PRINCIPAELS PREOCUPACIONES GIRAN EN TORNO EL TEMA SENTIMENTAL Y EL TEMA ECONOMICO Y LA SALUD DE SU PADRE LO CUAL UTILIZA PARA JUSTIFICAR QUE DUERMAN JUNTOS EN UNA MISMA CAMA. EN LOS ULTIMOS MESES SE VIENE SOSPECHANDO QUE LA PACIENTE PUEDIERA ESTAR MANTENIENDO RELACIONES SEXUALES A CAMBIO DE BIENES MATERIALES ASI COMO LA PRACTICA DE LA MENDICIDAD POR LOS BARES DEL PUEBLO. ELLA LO NIEGA EN TODO MOMENTO ....................................................... EL EQUIPO PLANTEA UNA REUNION CON LA COMISION PARA COORDINAR EL CASO Y SE EXPONE QUE LO MAS CONVENIENTE PARA LA PACIENTE SERIA PLANTEAR ALGUN TIPO DE RECURSO RESIDENCIAL TIPO CRR O SIMILAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-18','Ana: Realizo llamada a Paco, Empresa Ortés Costa Construcciones (638712004) le facilito nº de tlf. móvil del área económica y dirección de e-mail de la Comisión Tutelar, para que envíe, ya sea por WhatsApp o por mail, las fotos de la cubierta del tejado que hay que reparar y el presupuesto, así como fotos de los techos de las otras habitaciones. Enviará además factura de los trabajos realizados y presupuesto para limpieza de la vivienda. **En cuanto a la Comunidad de propietarios, me informa de que no estaba constituída como tal, que ya se han reunido y se van a constituir como Comunidad. En cuanto finalicen los trámites posibilitarán el arreglo de la cubierta. Por otra parte dice que J. Ramón le llama todos los días, preguntando cómo va la obra y preguntando por medios de transporte para irse a su pueblo. /////////// Realizo llamada a los Bomberos de Diputación, me enviarán un correo electrónico con el modelo de solicitud y las indicaciones para solicitar Informe de las actuaciones llevadas en el domicilio el día 8.////////// Realizo llamada a la Guardia Civil (927582080) de Valencia de Alcántara, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-03-18','Ana: Se da registro de salida a la Aceptación del PIA (Alojamiento de apoyo limitado) de Mª Antonia. Dejo copia registrada en el expte. y se procede a su envío a la Sección de Depend. de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-18','TERESA: HABLO CON JULIETA Y LE DAN EL ALTA HOY EN BADAJOZ. MAÑANA TIENE QUIMIO Y EL PROXIMO 26 DE ABRIL TIENE CONSULTA EN BADAJOZ PARA REVISION DE LA OPERACION. EL 5 DE ABRIL TIENE CITA EN EL HOSPITAL DE VILLANUEVA OCON EL CIRUJANO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-03-18','TERESA: SE RECIBE EMAIL DE FUTUEX EN EL QUE NOS COMUNICA QUE ESTA SOLICITANDO 100€ EXTRAS PERO QUE ESTA CONDICIONADA A QUE ANTES PERMITA RECIBIR LA VISITA DE LA DELEGADA PARA VER A ELLA Y LA VIVIENDA. DICE QUE YA HA LIMPIADO LA CASA QUE VAYAMOS A VERLA, COMENTA QUE YA NO ESTÁ CON LA PAREJA QUE TENIA LA CUAL MANGONEABA SU DINERO. EL HEMANO QUE VIVE CON ELLA EN VARIAS OCASIONES LLAMA A FUTUEX QUEJANDOSE DE ESTA CONVIVENCIA FORZADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-03-18','TERESA: SE RECIBE EMIAL DE FUTUEX EL CUAL NOS INFORMA DE QUE SE DEBE EN LA FARMACIA DE GUILLERMO MERA CERRATO LA CANTIDAD DE 582€ Y QUE YA NO LE SUMINISTRAN MAS. ADEMAS HA GENERADO ESTE GASTO EN SOLO UN MES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-03-18','Ana: Recibo llamada de Mª José, TS del HVM de Cáceres. Ha mirado en el historial de Paula, la última vez que estuvo en el hptal. fue en Junio del 2017 en la consulta del Endocrino. Anterior a eso estuvo en Urgencias a fecha de 10 de Febrero del mismo año. En el informe de alta de dicha vez, desde Psiquiatría exponían que no encontraban Criterios Clínicos para hospitalización. *Me enviará por fax copia del informe.','2');
