insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-03-18','Ana: Llama Ángela, directora de PLACEAT, han ingresado a Mª Rosa en el Hptal. Virgen del Puerto de Plasencia, con fuertes sangrados, tienen que hacerle un legrado, pregunta quién tiene que firmar el consentimiento informado. Le explico el procedimiento, lo enviarán por correo electrónico, se les devolverá firmado mañana a primera hora.','2');
