insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2019-03-19','Ana: Realizo llamada a Teresa Noguera, TS de Novaforma (927223745), expresa que están un poco desesperados con el caso de Felipe. Me pone en situación: reside en Residencia de Apoyo Limitado y asiste a Centro Ocupacional y cada vez que llegan periodos vacacionales o festivos quiere ir a su pueblo (La Haba). La casa que tiene allí no reúne condiciones de habitabilidad, por lo que no puede ir a la misma, además no es el único propietario de la vivienda. Con una de sus sobrinas, copropietaria y con adicción a drogas, ya ha habido problemas con la vivienda.//// **Una de las últimas veces que ha vuelto de su pueblo ha intentado suicidarse. Desde el centro llegaron al acuerdo con él de que *solo no puede ir a su pueblo.**Él piensa que está tutelado, no sabe qué es Curatela.////// Tiene hermanas que viven en Don Benito, que alguna vez han planteado el llevarse unos días a Felipe, pero a la hora de la verdad todo son excusas y no se lo llevan. /////// Propuesta que realizan: Si sus condiciones económicas lo permite, Felipe podría realizar salidas a su pueblo pernoctando en un a pensión y acompañado de un cuidador (que también habría que pagar). Veré la situación económica con Alberto (Responsable Área Económica)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-03-19','Ana: Recibo un correo de Ángela (Directora de PLACEAT: "Buenas tardes , adjunto remito para su firma dos documentos: Consentimiento de intervención quirúrgica para esterilización de María (tengo en mi poder la autorización jurídica a tal efecto) y la solicitud para incluirla en lista de espera. En cuanto los reciba los hago llegar al Doctor. He hablado con el doctor que la ha atendido, tuvieron que hacerla ayer tarde el legrado, todo apunta a un aborto de unas seis semanas (antes de su ingreso aquí).Le han dado el alta hoy. Deciros que tb se quedó una persona con ella toda la noche, dado que así nos lo aconsejaron por tema gotero, a la que hay que abonárselo. Un saludo. Angela Bueno"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-03-20','Ana: Mantengo conversación telefónica con Ángela, directora de PLACEAT, por varias cuestiones relativas a Mª Rosa: Alonso, sobrino de Benedicta, le ha entregado a Ángela una autorización judicial que pidieron en su día, cuando Benedicta tenía la tutela, para practicar la Esterilización a Mª Rosa, por lo tanto lo quieren utilizar para ponerla en lista de espera para la intervención. Me remitirá por correo los documentos originales para la firma de los mismos. En cuanto al CI del Legrado el Médico ha dicho que ya no es necesario pues lo practicó con carácter de urgencia.///// Por otra parte, mientras María ha estado en el hptal. no ha ido a verla nadie de la familia de Benedicta. El acompañamiento nocturno se abonará a la Cuidadora. *Le pido envíe por correo electrónico escrito firmado por la misma, en el que haga constar sus datos, el acompañamiento a María, la fecha exacta, horas y el importe. Le recuerdo que para futuras ocasiones no se puede quedar tantas horas la cuidadora, pues no hay dinero para abonar acompañamientos de esas características. ////// En cuanto a la cuentas de María le indico que ya hay abierta una cuenta nueva con ella y la Directora Gerente como titulares, pero aún no se ha hecho el cambio de la PF de una cuenta a la otra, hoy mismo cumplimentaré la Comunicación de Variacionews al INSS. **No cobrarán aún la residencia hasta que se produzca el cambio.////////En cuanto a los noviazgos de María, refiere que es "muy promiscua", que ya ha finalizado su relación con uno y ahora parece estar con otro chico de Malpartida.////// Considera que el móvil es bueno mantenérselo, para no cortale la comunicación con el exterior, pero plantean el cambiar a otro teléfono sin conexión a Internet, que sólo pueda hacer llamadas. Yo planteo la opción de cambiar a otra tarifa más económica. Estando en el Centro está más controlada que antes y también controlan que tome los anticonceptivos. Irán viendo las distintas opciones y lo iremos valorando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-20','Ana: Recibo llamada de Vere, Directora de la R. Puente Real - San Vicente de Alcántara. Ya hace una semama que se puso en contacto con MUFACE y envió el correo electrónico solicitando la información sobre el procedimiento de Cambio a MUFACE a la Seguridad Social y no ha obtenido respuesta. Me facilita los datos para que yo lo intente desde aquí. Nº tlf. MUFACE Badajoz: 924990500 y la dirección de e-mail: badajoz@muface.es La dirección postal: Avda. de Europa I, 4ª planta. 06004 Badajoz.//////// Por otra parte me informa de que esta tarde Julián R tiene cita en Cardiología en Clideva, al parecer Muface-Asisa no tiene servicio de transporte, por lo que su hijo Javier le acompañará a la cita. La cita de piquiatría la tiene fijada el día 9 de abril. /////// Por lo demás dice que Julián, aunque pregunta por la posibilidad de ir a casa, está tranquilo y se está adaptando bien.','2');
