insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-03-20','Ana: Recibimos por e-mail Solicitud cumplimentada de Valoración de Dependencia junto con Informe Médico remitido por A3 (Plena Iclusión). Además mantengo conversación telefónica con Cati Ferreira, TS de A3, al respecto, le confirmo la recepción del domumento. Hoy mismo lo pongo para la firma de la D-Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-03-20','TERESA: LLAMO A ANTONIO HERMANO DE AURORA ME COMENTA QUE SU HERMANA LE HA QUITADO 300€ QUE TENIA EN UNA CAJA FUERTE, LA HA FORZADOO POR ESO DICE QUE HA SIDO ELLA. ME COMENTA QUE SU HERMANA ANDA CON MALAS COMPAÑIAS, QUE METE AL NOVIO EN CASA Y QUE TRAPICHEA CON MARIHUANA. PASA MUCHAS HORAS FUERA DE CASA Y VUELVE DE MADRUGADA. ANTONIO DICE QUE LA CONVIVENCIA ES INSOPORTABLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-03-21','Ana: Recibo llamada de María del Programa de Familia, para informarme sobre Jesús, pareja de Felisi, y su relación con ella. Se conocieron hace un año aproximadamente, en seguida, en torno a un mes, comenzaron a convivir, hecho que el Programa de Familia valoró como precipitado, pero con el tiempo vieron que Jesús era buena persona y se preocupada por ella y por el hijo de la misma. Al poco de comenzar a investigar más sobre él, Felisi comenzó a establecer contactos con la familia de Jesús y a pasar temporadas en el domicilio familiar en El Casar de Cáceres, cada vez más frecuentes y más largas. En septiembre se produjo una avería en la vivienda de Felisi, como es de protección social no se ha solucionado hasta hace poco, de modo que desde entonces está instalada en El Casar y no tiene intención de volver a su casa. **Jesús fue consumidor y a día de hoy sigue consumiendo porros a diario y aunque ya está mas tranquilo y no se mete en líos y no trapichea para su consumo, NO ESTÁ PREPARADO para asumir la Tutela de Felisi. En cuanto a la vivienda de Felisi, él ha expresado que si pudieran terminar de pagarla (es de alquiler con opción a compra)se iría allí a vivir con Felisi y Aitor (hijo de Felisi) ///// En cuanto a la madre de Jesús, Felisi ha supuesto un apoyo muy importante para ella, pues además de aportar estabilidad a Jesús, le ayuda mucho con su otro hijo, "Manolín" que presenta discapacidad y también fue consumidor, a día de hoy tb consume, xo "su consumo es terapéutico", expresa María. /////// Desde que Jesús no está realizando el curso ni trabajando, la familia está más apurada económicamente, por eso Jesús pregunta por el dinero de la cuenta de Felisi. //// El padre de Jesús "malmete" e influye negativamente sobre Jesús, quién cuando está el padre delante habla fatal. El padre según le convenga dice y actúa.///////Jesús quiere hablar con alguien de la Comisión, por lo que acordamos que le facilite mi número directo y que llame cuando quiera. Aprovecharé para reforzar la idea de la importancia de no abandonar la vivienda y acudir a la misma con frecuencia para que Felisi no la pierda. Le explicaré el funcionamiento de la Comisión e intentaré resolver las dudas que quiera plantear./////////////// En relación a Aitor, hijo de Felisi, María informa de que próximamente mantendrán una reunión con el equipo de Protección de Menores y el CAM de Trujillo para valorar el caso y decidir futuras actuaciones, una de las alternativas es matricularlo el próximo curso en un Centro de Educación Especial en Cáceres, pues presenta Discapacidad Intelectual, y proponerlo para plaza en Piso Semiatónomo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-03-21','TERESA: ME ENVÍA PIA PARA REAPERTUTA DE EXPEDIENTE PARA FIRMAN VINCULADA DE AYUDA A DOMICILIO CON UN GRADO I Y UNA CUANTÍA DE 300€/MES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-21','Ana: Recibo llamada de Peque, TS del Ayto. de San Vicente de Alcántara. El contrato de la Residencia ya ha sido firmado por el Alcalde, me pide la dirección exacta para enviármelo por correo. ///////////// Cumplimento y pongo para la firma de la D-Gerente la solicitud de Informe al SEPEI (Servicio de Prevención y Extinción de Incendios) de la Diputación de Badajoz./////////////// Realizo varias llamadas a MUFACE, cuando obtengo respuesta me informan que un cambio extraordinario a la Seg.Soc. supone mucha burocracia, tendríamos que enviar varios informes médicos y bastante documentación, luego lo remiten a Madrid, donde tendrían que reunirse el equipo encargado de valorarlo y tomar una decisión, tardaríamos en torno a dos meses. Dadas las fechas en las que estamos se decide esperar a primeros de junio, fecha en la que el cambio se hace automáticamente. *El documento a rellenar está en la Web de Muface./// Informo a Vere, Directora Resid., de que esperaremos al cambio ordinario. Quizá al hijo no le importe llevar los documentos personalmente a la oficina de Cáceres, si no quiere/puede se remitirá desde aquí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2019-03-21','Ana: Una vez dado registro de salida al oficio para la Comunicación de Variaciones al INSS (cambio de nº de cuenta), hago copia que adjunto al expte. y se lo paso al Julio para su envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-03-21','Ana: Se recibe escrito del Servicio de Prestaciones Sociales (Dirección General) comunicando que procederán al ingreso de los atrasos (enero y febrero)junto con la nómina del mes de abril.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-21','TERESA: LLAMA JULIETA Y ME COMUNICA QUE HA SIDO INGRESASDO EN EL HOSPITLA DE REFERNCIA POR UNA OBTRUCCION INTESTINAL. VA A PERMANECER VARIOS DIAS HOSPITALIZADO, ME COMENTA QUE SI LE HACE EL ACOMPAÑAMIENTO QUEDO PENDIENTE DE VERLOS CON ALBERTO POQUE LA SITUACION ECONOMICA ES CRITICA. VICTORIA LA TS DEL HOSPIAL LE VA A PASAR LA HERRAMITA PARA PLAZA SOCIOSANITARIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-21','TERESA: HABLO CON VICTORIA TS DEL HOSPITAL ME COMENTA QUE ESTA EVOLUCINANDO MUY BIEN SE LE VA A PASAR LA HERRAMIENTA PERO ES POSIBLE QUE NO DE PUNTUACIÓN, ME COMENTA QUE LE SOLICITE DEPENDENCIA PARA PODER OPTAR TAMBIÉN POR AHI A UNA PLAZA. RELLENO LA SOLICITUD Y SE LA ENVÍO A JULIETA PARA QUE APORTE EL INFORME MÉDICO Y LA ENTREGUE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2019-03-21','Ana: Belé, Área económica, me entrega el Alta a Terceros. Realizo oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-03-21','Ana: Mª Luz Madrigal, Jefa de Sección de Progr. Asistenciales del Área de Salud Mental, pregunta si Mª Ángeles sigue residiendo en el domicilio con su padre, pues mañana tienen la Comisión para valorar el ingreso en CRR. **Le confirmo que sigue en el Domilicio y es recomendable valorar el caso como emergencia social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2019-03-21','Ana: Recibo llamada de Teresa, TS de Novaforma. La madre de Alvaro, ingresada en UME, está estabilizda y desde el CSS, la TS propone que Álvaro vaya a visitarla. Desde Novaforma, no sólo no consideran contraproducente la visita, sino que la valoran como positiva para Álvaro, por tanto se acuerda que se lleve a cabo acompañado de algún cuidador/a.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-03-22','Ana: Carmen Ferrer (Ud.Progr.Asistenciales del SEPAD)viene a preguntar por la Aceptación del PÍA de Antonia, al parecer lo necesita ella que es quién ha iniciado la gestión. Como ya lo he enviado, llamo a la Sección de Depend. Plasencia y solicito a Pablo Cortés, T.S., que nos lo envíe de vuelta cuando lo reciban.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-03-22','TERESA: SE RECIBE INFORME SOCIAL DEL SSB DE JEREZ DE LOS CABALLEROS. PALOMA ACTUALMENTE RECIBE SERVICIO DE AYUDA A DOMICILIO. SE LE VISITA EL 4 DE MARZO Y SE ENCUENTRAN LA VIVIENDA EN PESIMAS CONDICIONES DE LIMIPIEZA. PALOMA TAMBIÉN PRESENTA UN ASPECTO SUCIO Y DESCUIDAODO. CONTINUA LA PROBLEMATICA ECONÓMICA YA QUE NO HAY CONTROL SOBRE LA PENSIÓN QUE PERCIBE EL PADRE NO LLEGANDO EN OCASINES A FINAL DE MES Y TENIENDO QUE ACUDIR A LOS SSB, VECINOS Y PRIMOS PARA QUE LE AYUDEN EN LA ALIMENTACIÓN. LAS RELACIONES ENTRE PADRE E HIJO NO SON MALAS AUQUE HAY CONTINUAS DISCUSIONES ENTRE AMBOS YA QUE PASAN DEMASIADO TIEMPO JUNTOS, PALOMA APENAS SALE DE CASA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-03-22','TERESA: HABLO CON VICTORIA TS DEL HOSPITAL ME COMENTA QUE HA MEJORADO AUN ASI LE VAN A PASAR LA HERRAMIENTA, ME COMENTA QUE SOLICITEMOS TAMBIÉN DEPENDENCIA POR SI MEJORA PARA QUE TENGA OPCION DE PEDIR RESIDENCIA DESDE DEPENDENCIA. ENVIO LA SOLICUTD A JULIETA FIRMADA PARA QUE LA GESTIONE ELLA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2019-03-22','Ana: Se da REGISTRO de ENTRADA al oficio y documentación pte. (Alta a terceros, sentencia y aceptación)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2019-03-22','Ana: Toni- FUTUEX, nos remite por email el informe del Servicio de Psiquiatría de la última consulta a la que ha asistido acompañada por la nueva Delegada Tutelar (08/03/19). En dicha consulta Isabel insistía con el cambio de residencia y las quejas de la residencia en la que está. y textualmente: "A nivel psicopatológico la paciente se encuentra estable, sin clínica afectiva, ansiosa ni psicótica de relevancia. Acude de manera regular a sus citas en el ESM de Plasencia y mantiene una correcta adherencia a los tratamientos pautados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-22','Ana: Recibo llamada de Vere, Directora Resid. San Vicente Alcántara, dice que Julián está insistiendo mucho con el hecho de ir a su domicilio a echar un vistazo y recoger unas cosas y que si no le dejan va a llamar a la policía. Puesto que no es un ingreso involunario, acordamos que dejen de darle largas y le permitan ir en taxi (él ha llamado ya a uno). Hablarán con el taxista para que emita factura a nombre de Juíán R. Vere cree que regresará a la residencia sin problemas. Volveremos a hablar el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCAS'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2019-03-22','TERESA: LLAMA LA TS PARA PEDIR INFORAMCION SOBRES LUCAS Y SUS HERMANOS QUE TAMBIES ESTAN TUTELADOS YA QUE HA FALLECIDO SU HERMANO MAXIMO CON EL CUAL LUCAS ESTABA DE COTITULAR EN UNA CUENTA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-03-22','TERESA: NOS LLAMA LA TS DE PLENA INCLUSION ZAFRA PARA OCOMUNICARNOS QUE JOSEFA ESTA TENIENOD PROBLEMAS DE CONDUCTA. HAN TENIDO QUE LLAMAR AL 112 Y HA ESTADO UNAS HORAS EN LLERENA LE HAN DADO EL ALTA PERO SIGUE CON UNA ACTITUD NADA BUENA. ME PLANTEAN DERIVARLA A LA UDAC PORQUE EL TENERLA ALLI GENERA MUCHA INSEGURIDAD YA QUE TIENE INTENTOS DE SUICIO. LE COMENTO QUE HABLE CON MAITE DE DISCAPACIDAD. QUEDAMOS PENDIENTE ME MANDE INFORME DE ALTA, SEGUIREMOS EN CONTACTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2019-03-25','Ana: Realizo llamada a Teresa, TS Novaforma, le comunico que hemos decidico en equipo que si aún están a tiempo de que Felipe participe en la actividad de La Caixa, se haría una excepción con la Autorización de Dchos de imagen y se autorizaría "sólo y exclusivamente para esa actividad". Si hubiera que modificar el escrito se lo pasaríamos a los asesores jurídicos. Lo consultará, y si aún se puede me enviará al email el documento de autorización. //////// En cuanto a lo de ir a su pueblo, Amalia me comenta que ya lo propusieron en su día, pero que en su pueblo no hay hostales ni pensiones. Por lo tanto podría realizar salidas de un día acompañado de un monitor/cuidador.****Se lo comunico a Teresa-Novaforma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2019-03-25','Ha llamado Miguel, 642632131, para interesarse por el tema de la casa de sus padres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-03-25','-LLAMA SU TIA ASUNCION 924109808 , NOS DICE QUE RAFAEL ESTÁ EN CASA , A LA ESPERA DE FALLO JUDICIAL CON INNUMERABLES CAUSAS PENDIENTES. QUIERE QUE LA JUSTICIA NO LO ENVIA A CTRO. PENITE SI NO A CTRO DESINTOXICACION. LE EXPLICO CÓMO FUNCIONA EL SISTEMA NO QUIERE QUE LE ENVIEMOS DINERO AL CTRO PENIT. EN CUENTA PECULIO PQ ALLI CONSUME MUCHA DROGA QUE SE LO ENVIEMOS A ELLA. LA PARTE ECO CANCELA CTA. PECULIO Y VUELVE ACTIVAR PNC A LA TIA . QUEDO CON ELLA QUE ME AVISARÁ CUANDO INGRESE EN PRISIÓN. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2019-03-25','iCIAR, Llamo a la Residencia. Han enviado certificado de vida a pensiones en Francia. LA hija de M Rosario les llevó a la residencia una carta donde se solicitaba dicho cdo. La trabajadora social lo envía en febrero 19. Confirmo en cuenta que ya se lo están ingresando junto con los atrasos de los meses que no le han ingresado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2019-03-25','Ana: Recibo llamada de Pilar, TS del CSS de Plasencia, solicitando le facilitemos información del estado de la vivienda de Mª José, madre de Álvaro. Le informo que lo último que tenemos al respecto es de un informe de seguimiento de Futuex de abril de 2015, no hay nada actualizado, y lo que en el mismo se expone acerca de la vivienda.','2');
