insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2019-03-25','Ana: Recibo llamada de Pilar, TS del CSS,en relación a la preocupación de Eugenia con el "enbargo pendiente". Consulto a Juana, área económica, me explica que no le están cobrando ningún prestamo y que desde el árae jurídica están trabajando todo lo relacionado con las deudas. **** Se lo transmito a Pilar.','2');
