insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-03-26','TERESA:JOSEFA HA SDO DE NUEVO INGREASADA EL VIERNES A LAS 17:00 HORAS, Hoy lunes tras conversación con Constanza Machío (psiquiatra UHB) se obtiene la siguiente información: En la UHB Josefa se muestra tranquila y contenta, tanto que es posible que el forense rechace el ingreso involuntario. Se le explica que el comportamiento de Josefa en la UHB y el que manifiesta en el centro es absolutamente diferente. El comportamiento que manifiesta en el centro es de tal gravedad que pone en serio peligro la integridad física propia y la de sus compañeros. Es muy posible que el forense ordene dar de alta a Josefa en un periodo muy breve de tiempo, lo que supone, como se ha referido anteriormente, un grave peligro. - Constanza se compromete a hacer derivación directa a la UDAC, ya que en el centro no existe posibilidad ni recursos para el manejo de tales conductas, pero asegura que la lista de espera es muy grande, por lo que con mucha probabilidad esto no va a ser inmediato. Regresará de nuevo al centro antes de producirse tal derivación. Mañana de nuevo nos pondremos vía telefónica en contacto con vosotros y con la unidad de recursos para valorar las opciones que tenemos. INFORME COMPLETO EN EXPEDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-26','Ana: Recibimos presupuestos de arreglo de la cubierta del edificio, cuyo pago corresponde a la comunidad de propietarios, junto con otro presupuesto de arreglo de la vivienda de J.Ramón.//////// Realizo llamada a Paco, Empresa Ortés Costa Construcciones (638712004)en relación al arreglo del techo de la vivienda. Expresa que el problema viene principalmente por una mala construcción, que en parte puede estar influído por el problema de la cubierta, pero influyen otros factores de la construcción. ****Nos enviará por escrito los motivos que desencadenaron el desprendimiento del techo, según su opinión/experiencia como profesional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-03-26','TERESA: ME ENVIA EMAIL DE FUTUEX Buenos dias Teresa, te adjunto el acta de la subcomisión de caso sobre Maria Murillo, aunque obviamente os habrán dado traslado a vosotras también, pero aprovecho para comentar unos aspectos respecto de la "forma" de proceder que no se trataron en la reunión. Y algunos aspectos que han sucedido este fin de semana, la madre de María, ha escrito a mi compañera Susana, increpandola.. a continuación hago una trascripción literal del mensaje "Buenas tardes Susana. Te agradezco mucho que aconsejes a las personas que se preocupan por Maria, que no se involucren, dado que para ello DEBERÍAS estar TÚ. Igualmente comentar que es un caso dificil, por eso la teneis viviendo sola con un perro de presa, debe ser una cuestión de CIVISMO por vuestra parte. A fin de cuentas algun inocente lo pagará" Trascribo de forma literal, con sus enfásis en máyuscula, y con el poco sentido que tiene el mensaje... pero bueno el mensaje en cuestión que no podría ser más que un desagradable y desafortunado asunto, encierra ciertos aspectos que me gustaría exponer. Por una lado la madre de María, asume en mi compañera una seria de cuestiones que no son atribuibles siquiera a un policia, vigilante, o cuidador.. mucho menos a una persona que actúa en nombre de sus tutores para algunos asuntos concretos que ayudan a regir su persona, pero el problema puede ser el efecto nocivo que en este caso su madre, pueda hacer sobre el vínculo que mi compañera está desarrollando con Maria, imagino que si traslada todo esto a su hija, no es muy positivo para la relación establecida entre ellas. Por otro lado, esperemos que ninguno de los profesionales de salud mental que pueden ver a Maria, especialmente el psiquiatra, incluya a mi compañera como miembro de esa comisión que llevó a cabo acuerdos de cara a presentarselos en la consulta a María, por que ahi definitivamente romperiamos también el vinculo existente y Susana tendría que alejarse de este seguimiento, ya que para María el resto son "enemigos" y ya sabeis las amenazas tan graves que puede llegar a efectuar sobre las personas que marcan su tratamiento por ej. o le indican pautas. En definitiva, me ponía en contacto contigo para hablar de como llevar a cabo la cita del próximo 29 de Marzo, para presentarle el contrato terapuetico a Maria, consideramos que Susana no puede asumir un potencial riesgo consistente en una problema de gestión de emociones negativas de María en el desplazamiento con ella sola en el coche, todo esto previsiblemente se puede dar si a María, no le gusta lo que le plantea el doctor Idilio. Es decir que vamos a acompañarla a la consulta, pero entendemos que dado el perfil del que se trata y tal y como dicen los profesionales de salud mental, no es conveniente ir a buscarla y a llevarla de vuelta a Monesterio, en vehiculo privado, como hemos hecho en otras ocasiones. Entiendo que se podría por ej, gestionar un taxi, para que la traslade y luego se abona la factura en cuenta? si tenemos el visto bueno, nosotros nos podriamos ocupar, y como digo la estariamos esperando en el hospital para ir con ella a la consulta del dr. Idilio. O la acompañaríamos en el taxi desde Monesterio. Es una "prevención" que me traslada Susana, mi compañera, y a mi sinceramente me parece correcta, que creo que se está implicando en el caso de un modo correcto, pero obviamente entiende que hay una patología de base, impredecible y potencialmente confictiva, según que temas sean los que se traten con ella. Si te parece, lo podemos hablar mejor por telefono. O quedo a la espera de lo que me comentes, por aqui. GRACIAS ........................................................... HABLO CON TONI DE FUTUEX LE COMENTO LA CONVERSACION MANTENIDA AYER CON LA MADRE DE MARIA. AUTORIZAMOS DESPLAZAMIENTO EN TAXI PARA LA VISITA DEL VIERNES Y SEGUIREMOS EN CONTACTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-03-25','TERESA: SE RECIBE EMAIL A LA ATENCION DE PEDRO DE LA MADRE DE MARIA Buenos días Pedro, como ya te expliqué en su día, María no tiene capacidad alguna, para vivir sola. Tras él ingreso y alta en el hospital de Llerena, su vida a los 4 o 5 días, ha seguido el curso de siempre. La trabajadora Social, Susana, ha ido un día , la acompañó a la biblioteca y punto. La vecina que atendió al perro, se ha puesto en contacto con ella, para explicarle la situación y está ha sido su respuesta: “Muchas gracias guapa! Gracias por la información. Tu habla con ella pero no te involucres mucho porque el caso de Maria es complejo y tiene subidas y bajadas.” Aparte de ser o no ético hablar de una paciente, en lo que no vamos a entrar, a qué se refiere con no involucrarse? Porque está ella y lo abarca telefónicamente todo? Y un “caso complejo” debe ser a que por eso vive sola con un perro de presa. Teresa, de la comisión me dijo que todos los tutelados estaban en un centro, me imagino que se refería a los que no son “casos complejos”. En fin, 11 años y como al principio. Reunión el 14. de la subcomisión de la comisión?? bla, bla, bla. Los jueces opinan que la Comisión es un ente un funcionario, a María le habrá tocado el más nefasto. Un saludo. Marisol. Enviado desde mi iPhone.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2019-03-26','Ana: Realizo llamada a Alicia Toro, TS del SSB de Torreorgaz (927205001), pero no obtengo respuesta./////// Llamo a la Mancomunidad Sierra de Montánchez(927389032) Me informan que puede estar en Torremocha (927127001) o Torrequemada (927205034). La localizo en Torremocha, acordamos que averiguará quién son las personas que constan como titular y autorizado en la cuenta, me enviará una presupuesto de gastos y propuesta para limitar las retiradas de efectivo de la cuenta por parte de María y averiguará si hay alguna empresa externa de ayuda a domicilio con la que pueda contratar el servicio nocturno de puesta de pañal. *Considera que la vecina que "le ayuda" está abusando económicamente de María.****En cuanto al ingreso en residencia, aunque de entrada María dijo que ingresaría cuando abrieran la residencia municipal, justo ayer que fue la apertura se negó a ello y ya han ocupado todas las plazas. No obstante, aunque Alicia considera que sería lo deseable, cree que si se controla el gasto de María y se mantiene la ayuda a domicilio y el resto de apoyos puntuales podría permanecer en su domicilio.///////// Realizo llamada a Toni-FUTUEX, para que hagan una visita a María de manera conjunta con la TS de SSB. Le facilito el contacto de Alicia, la llamarán hoy mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-03-26','Ana: Recibo llamada de Mariví, TS del CSS Plas. Han recibido en el centro dos cartas procedentes del Colegio de Abogados de CC en relación a la solicitud de abogado de oficio, nos lo ha enviado por correo ordinario. Se lo comunicio a los compañeros del Area Jurídica///////Por otra parte informa que el próximo lunes día 1 de abril tendrá lugar el cambio de recurso residencial, trasladarán a Antonia al CRR de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-03-26','Ana: Realizo llamada a Ángeles, TS del Hptal. de Salud Mental-Clínica El Seranil (952513267 - trabajosocial@seranil.com). NO TIENEN MODELO DE SOLICITUD como tal y me pide informes médicos y sociales del paciente para que el equipo terapéutico pueda hacer la valoración. Ella me remitirá por email las normas del centro e información sobre precio y otras cuestiones. **Le envío el correo electrónico acordado./////////////// Puesto que aún no me han llamado del Centro Asistencial de la Hmas. Hospitalaria de Málaga (952256150), llamo de nuevo. Hablo con Estrella, me pide que les remita informes de psiquiatría e informe social a la siguiente dirección egonzalez.malaga@hospitalarias.es. **Procedo al envío.//////////// Realizo llamada al Centro Sociosanitario de las Hermanas Hospitalarias de Palencia (979 165 324). Ana Glez. solicita que le remita por email (informacion.palencia@hospitalarias.es) los informes médicos y sociales de que dispongamos para que puedan valorar la posibilidad de ingreso en su centro. En función de ésto me enviará por correo la aceptación o no del paciente y la información sobre el centro y los precios de la plaza correspondiente.*** Procedo al envío de los informes. //////// Al final de la jornada recibo el siguiente correo de la Clínica El Seranil: "Buanas tardes. Te mando los documentos necesarios para formalizar la plaza que nos solicitais. Antes debe dar el visto bueno el equipo terapeútico y la dirtección del hospital. Un saludo Angeles Tuduri, Trabajadora Social"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2019-03-26','TERESA: RECIBO INFORME CLINICO DEL DOCTOR RUBÉN CATALÁN BARRAGAN PSIQUIATRA. JOSE ANTONIO PADECE TRASTORNO PARANOIDE DE LA PERSONALIDAD Y TRASTORNO ESQUIZOIDE DE LA PERSONALIDAD. HA SIDO ATENDIDO UN UNA UNICA OCASION EL 4/2/19. MALA RELACIÓN FAMILIAR CON DIFICULTAD DE CONTROL DE SINTOMAS CON TRATAMIENTO FAMACOLÓGICO DADO QUE ESTAN ORIGINADOS FUNDAMENTALMENTE POR TRASTORNOS DE PERSONALIDAD Y NO POR DESCOMPENSACIONES AGUDAS DE TRASTORNOS MENTALES. TRATAMIENTO QUETIAPINA Y LORAZEPAN','2');
