insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2019-03-27','TERESA: MANDA EMAIL LA EDUCCADORA DE PLENA INCLUSION ZAFRA COMENTANDO QUE HA EMPEORADO EL ESTADO DE SALUD DE LA TUTELADA Y ESTÁ TENIENDO PROBLEMAS PARA EL CONTROL DE LA DIABETES. NOS SUGIERE PIDAMOS LA TUTELA PARA INGRESO INVOLUNTARIO. LO CONSULTO CON LA ASESORÍA Y ME DICEN QUE ES COMPLICADO QUE NOS DE LA TUTELA. LE INDICO QUE YA ESTÁ EL TRAMITE PARA PASAR A RAL POR DEPENDENCIA QUE VAMOS A INTENTAR QUE SEA DE FORMA VOLUNTARIA','2');
