insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-03-26','Ana: Mantengo conversación con Toni-FUTUEX. El pasado viernes 22 acompañaron a Mª Luisa Calzas a su cita en Psiquiatría. Como no tienen un diagnóstico claro y el discurso que mantuvo en la consulta Mª Luisa fue bastante coherente, la médica se implicó en el caso y les emplazó a que acudieran con el volante a urgencias para ser valorada por Neurólogía e ingresada unos días en UHB y poder valorarla y diagnosticarla. Se acordó el ingreso el lunes 25, pero dicho día no hubo forma de que ingresara, se opuso rotundamente. "Tiene pavor a los médicos", expresa Toni. *Nos remitirá informes por email. ///// Se recibe email con la explicación detallada de los acontecimientos y el Volante para el Servicio de Urgencias escaneado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-03-20','Ana: Recibimos correo por e-mail de Toni-FUTUEX, remiten un informe en que explican que han tendio conocimiento de retiradas excesivas de dinero por parte de Jose Al parecer se las "...entrega a una persona desconocida", él reconoce que se los da a un chico que dice haber conocido en el parque de Cánovas. *Informe impreso en papel en el expte. ///// Comunico a la parte económica para que se limite su cuenta y se controle las retiradas de efectivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-03-26','Ana: Toni-FUTUEX, comunica mediante conversación telefónica que Jose está muy alterado porque ha ido al cajero y no ha podido sacar dinero. Consultaré al área económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-03-27','Ana: Comunico por teléfono a Toni-FUTUEX, que la cuenta de Jose se ha limitado ya. Puede retirar 140 € cada semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2019-03-27','Ana: Mantengo conversación telefónica con Toni-FUTUEX, en relación al informe de la Delegada Tutelar de 04/03/19 enviado por mail previamente (guardado en expte. papel y PC). Sigue sin cuadrarles el tipo de relación que mantiene Ventura con Mª Ángeles (así dice llamarse),persona que desde hace un tiempo convive con él en el mismo domilio) el aspecto de ella es bastante raro, no aporta nada a nivel económico y controla la vida de Ventura en todos los aspectos. Desde FUTUEX seguirán haciendo el seguimiento y nos mantendrán informados.////////////**Por otra parte estamos pendientes del posible DESAHUCIO.','2');
