insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2019-03-28','Ana: Recibimos correo de ASINDI-Plena Inclusión Alcántara: "La familia de Ignacio e Isabel Rodriguez Alcántara ha contactado con nosotros porque les gustaría que pasaran con ellos el sábado día 30 de marzo. Tienen fiesta en el pueblo y quieren reunirse todos. Nosotros consideramos que les viene bien a ambos hermanos, además están muy ilusionados, así es que, si no tenéis inconveniente, prepararemos el viaje en taxi como en otras ocasiones. Se irán por la mañana y regresarán por la tarde el sábado para cenar en ASINDI." Respondo al correo comunicando que no hay inconveniente en que realicen la salida. Recuerdo que deben enviar la factura del taxi a nombre de los hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-03-28','TERESA: ME LLAMAN MERCEDES TS DEL CENTRO PARA COMUNICAR QUE BEA INSISTE EN SALIR EN SEMANA SANTA AL DOMICILIO PATERNO. PIDO A FUTUEX QUE HAGA UNA VISITA AL DOMICILIO PARA VER COMO ESTÁ ANTES DE AUTORIZAR LA SALIDA. LLAMO A LA TS DE HUERTA DE ANIMAS Y ME COMENTA QUE LA TS QUE EASTÁ QUE LLAVE ESA FAMILIA ESTA DE BAJA PERO QUE INTENTARÁ SACAR INFORMACION. QUEDO EN VOLVER A LLAMARLA. (927659391)','2');
