insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2019-03-28','Ana: Miguel, Asesor Jurídico, me comunica que Jesús ha enviado un escrito solicitando una revisión de su estado legal, quisiera ser curatelado en aspectos económicos y control médico. Adjunta el informe de la última consulta en el Servicio de Psiquiatría en el que eñ Dr.Juan Pedro Jiménez Cano también indica "una revisión de la tutela hacia la curatela(económica y cuestiones de salud)"./////// Realizo llamada a Teófilo De Arce Escudero, TS del CRPS de Cáceres (927 23 21 06), pero me dicen que no está. Le dejarán nota para que me devuelvan la llamada. ////// Llamo a Toni - FUTUEX, le solicito que visiten puntualmente a Jesús Romero Pérez para que nos elaboren un informe/nota del estado de su vivienda, capacidad de autonomía y autocuidado que puedan observar. Cuando hable con Teo le solicitaré número de contacto de Jesús para facilitarselo para concertar la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA INES'and edp.apellido1='MORENO'and apellido2='POLO'),'2019-03-28','ACUERDO DEFENSA JUDICIAL Se remite,a Escalona, por correo electrónico y ordinario, por vía de urgencia, el Acuerdo de Defensa Judicial. El Jzdo. sólo concedía 2 días para la aceptación del cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-03-28','Ana: Llamo a Mariví Clemente, TS CSS Plasencia (24142). Le solicito más información acerca de Jesús (familiares directos, contactos de éstos, residencia habitual de Jesús, si las viviendas que tiene en propiedad están habitadas, etc).////// Mariví me remite por fax 2 informes sociales (el mismo que tenemos el del Inventario y uno anterior, de 28/09/17), además me llama con el manos libres/altavoz estando con ella en la consulta Jesús. Jesús refiere que tiene 2 viviendas en propiedad en Cáceres Capital. 1_en la C/Cuesta de la Reina,nº4, que está hipotecada (Préstamo en Liberbank - Oficina de Guadalupe) en la que actualmente no reside nadie. En esta casa sólo se ha quedado a dormir con cierta frecuencia cuando iba a CC. Las llaves están en el CSS. 2_ C/Margallo, nº21, de 120 m2, que adquirió muy barata. Tiene las escrituras a su nombre, pero dice tener un problema; no consigue registrarla porque en el Registro solicitan un justificante de pago del "impuesto de plusvalía" del antiguo propietario. Acudió al Ayto. a solicitarlo y le dijeron que a él no le correspondía solicitarlo y no ha conseguido volver a contactar con el antiguo dueño. De esta casa no tiene hipoteca, pero sí hay pendiete de aprobar el pago de la parte proporcional que le corresponde de unas obras que debe asumir la comunidad de vecinos. En esta vivienda hubo okupas pero a día de hoy cree que no hay nadie. En cuanto a su residencia habitual dice que él vivía en Guadalupe, donde por la herencia de su madre fallecida le corresponde un tanto por ciento de las dos viviendas familiares: 1_en la C/ de la Virgen, 17, en la que él vivía y a la que le gustaría volver una vez cumpla la medida y le den de alta en psiquiatría. 2_C/Alfonso el Oncero. En la que residen su padre y su hermano. *En cuanto a los datos de contacto de los familiares directos de Jesús están en los informes sociales emitidos por Mariví.////////***Jesús dice que le gustaría solicitar otro préstamo para hacer frente a los pagos pendientes, le explico que eso no va a poder ser y que los compañeros tanto de la Sección Económica como de la Jurídica, que tienen conocimiento y experiencia en estos asuntos buscarán la mejor alternativa para él y que probablemente haya que vender alguna de sus viviendas. Expresa que lo entiende y queda conforme.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-03-25','Ana: Las compañeras de la Sección Económica me comunican que la cuenta de Miguel ya está bloqueada, su hijo ya no podrá volver a sacar dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-03-29','Ana: Recibo correo de la Resid.Puente Real-Valencia de Alcántara: "Buenos dias, comunico que hoy viernes 29, sale J. Ramón Civantos a pasar el dia a su casa en Valencia de Alcantara, el taxi lo recoge a las 11h y regresará a las 20h, como le hemos indicado al taxista. Un Saludo. Dirección Residencia Puente Real San Vicente de Alcantara" /////////// Recibo llamada de Javier Civantos, hijo de J.Ramón, interesándose por todo lo relacionado con su padre. Se le pone al día en relación a las obras de la vivienda, las saidas que está realizando a su domicilio, la solicitud de valoración de Dependencia, las gestiones con Muface... Se muestra conforme y agradecido. Ahora ve la estabilidad y cuidados que aportan a su padre el estar en el centro aunque cree que él sigue queriendo volver al domicilio y por su parte expresa que quizá lo ideal sería una alternativa intermedia, como un Centro de Día. No estoy segura de si esta opción existe en Valencia de Alcántara, lo hablaré con Pilar, TS SSB de dicho municipio. /////// Realizo llamada a Pilar, TS (927580326)me confirma que en Valencia Alcántara sí que hay plazas de Centro de Día, pero que ella no considera que sea el recurso adecuado a día, de hoy, en eso estamos de acuerdo, pero quiero tener claras las distintas alternativas para cuando sea neceario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2019-03-28','Ana: A fecha de día 22/03/19 se recibe este correo:Buenos días,Soy Pilar Trabajadora Social del centro residencial Cervantes de Cáceres.Nos ha llegado factura de SUMAN SOCIAL S. L del servicio de Ayuda a domicilio que se le presta a Victoriana Hernandez Garcia con DNI:7387199-J. Necesito saber que hago con dicha factura, porque es la primera que nos llega al centro. Por otro lado el marido de una residente quiere pedir la incapacitacion y me gustaria saber que documentacion hay que hacer. Muchas gracias Pilar Fraile"./////// Realizo llamada a la residencia en relación al mismo, pero Pilar Fraile, TS, no está. Le dejan nota para que me devuelva la llamada. Más tarde me devuelve la llamada (22237): Lo que se aprobó en su día es un servicio de acompañamiento por una Auxiliar (Empresa SUMAN)los martes y jueves de 17:00-18:15, desde diciembre de 2018. Pilar nos remitirá la factura correspondiente al ctutelar@ y llamará a SUMAN para que a partir de ahora envíen todas las facturas aquí directamente.////// ***Pilar trabaja en el CR los Martes y los Viernes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2019-03-29','-DOY AUTORIZACION PARA QUE LA AUXILIAR DE LA R.M. DE SU CONFIANZA LA ACOMPAÑE A SU CITA MEDICA CON PSIQUIATRIA ,ENVIARÁ EL IMPORTE A ABONAR. ASI MISMO , AUTORIZO PARA UNA SALIDA DE UN DIA A SU DOMICILIO A LA ESPERA DE A.JUDCIAL PARA VENDER SU CASA Y PODER TENER MÁS LIQUIDEZ Q LE PERMITA AUMENTAR LAS SALIDAS. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2019-03-29','TERESA: SE RECIBE INFORME DE SITUACION ACTUAL DEL TUTELADO.JORGE ESTA BIEN ADAPTADO NO PRESENTA ALTERACIONES SIGNIFICATIVAS Y PARTICIPA EN TALLERS DEL CENTRO Y SE MUESTRA COLABORADOR (INFORME COMPLETO EN SU EXPDIENTE)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2019-03-29','TERESA: RECIBIMOS INFORME SOCIAL DEL TS DEL SSB DE FUENTE DEL MAESTRE EN EL CUAL NOS COMENTA QUE LA SITUACION ACTUAL EN EL CENTRO RESIDENCIAL NO ES BUENA, MIGUEL ASPIRA A RESIDIR EN OTRO CENTRO MAS CERCANO A SU FAMILIA. MIGUEL REQUIERE UNA OXIGENACIÓN PARA GARANTIZAR UNA MEJOR CONVIENCIA POR LO QUE SE PROPONE HASTA QUE SE PUEDA HACER EL TRASLADO A OTRO CENTRO RECURRIR A LAS HERMANAS PARA FORTALECER LA REALCIONES CON EL PERSONAL DEL CENTRO. .............................................. PROPONE FORTALECER EL NIVEL DE RESPONSABILIDAD DE SUS HERMANAS HACIE EL INCLUSO QUE PASARA UN 10 O 15 DIAS CON ELLAS PROPICIANDO QUE SE LE LOBRE LA REUBIACION EN OTRO CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-03-29','Ana: Mantenemos conversación telefónica conjunta con el altavoz Miguel, Asesor Jurídico, Alberto, Responsable Sección Económica y yo con Mariví, TS del CSS de Plasencia y Miguel Santos, tutelado. Para aclarar más aún las cuestiones relativas a sus propiedades, préstamos, etc. Se acuerda que Miguel Santos pedirá a su hijo que nos haga llegar copia de las escrituras de la vivienda que no tiene registrada y Miguel, Asesor Juríco se encargará de solucionarlo. Por otra parte se pondrán a la venta las dos viviendas de Cáceres, llamarán a las inmobiliarias correspondientes primero para informarse al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2019-03-27','Ana: Recibo e-mail de Alicia Toro, TS SSB con el siguiente contenido: "Buenos dias, Ana. Respecto de los familiares que vienen en la cuenta corriente de MARIA ROMAN JIMENEZ, aclarar que Dº BLAS ROMAN JIMENEZ es su fallecido hermano; y Dº FRANCISCO ROMAN ROMAN su sobrino. Este último vive en Torreorgaz. Y también informarte de acaban de ponerse en contacto conmigo la Delegada Tutelar , llamada GLORIA. Hemos quedado para el jueves de la próxima semana. SAludos. Alicia Toro"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2019-04-01','TERESA: SE ENVIA A PETICION DE LA TS DEL SSB DEL AYTO DE FUELABRADA DE LOS MONTES ESCRITO PARA HACER CONSTAR LA CUANTÍA DE LA QUE DISPONE PARA SUS GASTOS PERSONALES ASI COMO DOCUMENTO DE REVALORACION DE PESNIONES QUE EL FIN DE PODER ACOGERSE AL PROGRAMA DE ALIMENTOS DEL AYUNTAMIENTO','2');
