insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2019-04-01','TERESA:ENVÍO AUTORIZACION MEDICA FIRMADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-04-01','TERESA:ENVÍO AUTORIZACION TERMALISMO PARA PERSONAS CON DISCAPACIDAD FIRMADA Y CONSENTIMIENTO INFORMADO SALIDAS/EXCURSIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-04-01','Ana: Recibo email de la Resid. Puente Real de San Vicente de Alcántara: "Buenos dias Ana, sigue en su línea, cada vez quiere ir mas dias a su casa, hoy ha llamado él al taxista y se acaba de ir, nos dice que regresa por la tarde. Esperemos que aguante, dice que se aburre porque el dormía 4 horas y se cansa de tv. Tablet, radio, teléfono……. El dia 9 tiene consulta de psiquiatría, estamos intentando que le pongan transporte ASISA y su hijo le acompañará. Él sigue insistiendo en ir a su casa, cada vez con mas frecuencia, comenzó con una tarde, después el dia entero y ya me esta hablando de ir a dormir allí. Ya te ire informando. Un saludo Vere" /////////////////////////Recibimos en el ctutelar@ un correo de Paco Ortés (empresario albañil) con el siguiente contenido: "A.A. Departamento económico. Buenos días, según conversación telefónica le detallo a continuación los posibles motivos del derrumbamiento del techo en la vivienda de D. Julián Ramón Civantos, basándome en mi experiencia realizando este tipo de trabajos. El techo del salón estaba realizado con un entramado de madera de vigas y tablillas y enlucido de cal, como se hacía antiguamente, con la diferencia que en este caso se montó la estructura de forma inadecuada estando la viga cargadero por encima y el entramado clavado por debajo. Parece probable que con el paso del tiempo el techo iría cediendo y agrietándose y optaron por hacerle un falso techo de escayola sujeto a ese mismo techo en mal estado con el consecuente agravamiento del problema al añadir más peso. Con los años la estructura de madera se ha ido deteriorando,a mi parecer, tanto por el propio paso de los años como humedad, carcoma, termitas etc. llegando un momento en que los dos techos inferiores se desclavan de la viga cargadero con el consecuente derrumbe. Un saludo. Estoy a su disposición para cualquier aclaración en el tlf: 638 71 20 04. Francisco Ortés"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2019-04-02','Ana: Teresa, TS de Novaforma, comunica que finalmente Felipe se irá a pasar la semana santa (Del 17 - 23) con su hermana Josefa. En el centro les ha sorprendido mucho, para bien y esperan que mantenga este interés y apoyo a su hermano. Pues ha sido muy intermitente. ////// Por otra parte me informa que la Directora del Centro tendrá una reunión con un "amigo" de Felipe, para conocerle y averiguar si hay algún otro interés de fondo. ///////// En cuanto a las posibles salidas futuras acompañado de un cuidador y con pernocta en pensión/hostal, he solicitado a Alberto, Responsable de la Sección Económica, que mire cuál es la situación económica, pues se proponen en el centro que ya que no hay alojamiento en su pueblo pueden buscar alguno en algún pueblo aledaño.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-04-02','TERESA: RECIBO INFORMES DE ALTA TRAS INGRESO EN UHB DE LLERENA Y REGISTRO DE COMUNICACION PROFESIONAL EN EL QUE SE DETALLA EL INGRESO Y ALTA DE LA TUTELADA POR ALTERACIÓN DE LA CONDUCTA. DURANTE LA ESTACIA EN LA UHB SE MUESTRA CALMADA Y CONTENTA Y CON ARREPENTIMIENTO. LA DOCTORA MACHIO SE COMPREMETE A DERIVAR A UDHAC YA QUE EL CENTRO ACTUL NO REUNE LAS CONDICIONES DE SEGURIDAD QUE GARANTICEN LA SEGURIDAD DE JOSEFA Y DE LOS PROFESIONALES QUE ESTAN CON ELLA Y TAMBIÉN PORQUE JOSEFA DEMANDA SALIR DE PLENA INCLUSION ZAFRA PARA VIVIR EN UN LUGAR MAS PROXIMO AL DOMICILIO FAMILIAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-03-27','Ana: Recibo correo del Centro Sociosanitario de Palencia de las Hermanas Hospitalarias con el siguiente contenido:"¡Buenos días Ana! Después de valorar los Informes de D. Miguel; le informamos que podríamos tener disponibilidad de plaza para realizar el ingreso. La tarifa a aplicar es de 250 €/día. Un cordial saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-04-02','TERESA: LLAMA LA MADRE DE BEATRIZ, ANTONIA RUIZ(655287135) PARA COMENTAR QUE QUIER QUE VUELVA SU HIJA A CASA CON ELLA. QUEDA PENDIENTE INFORME DE FUTUEX PARA AUTORIZAR LA SALIDA EN SEMANA SANTA QUE TANTO DEMANDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2019-04-02','-HABLO CON MANUELA , TENGO Q PEDIR REVISION PIA PARA LOS DOS HERMANOS PIDIENDO SI NO LLEGAN A G.II PROMOCION DE LA AUTONOMIA , ESTO YA LO HE HECHO . SI LO PEDIMOS POR DEPENDENCIA EMERGENCIA NECESITAMOS I.SOCIAL DEL SSB EN COORDINACION CON APROSUBA 7 . HAY QUE PEDIR INTERNAM INVOL. SE PODRIA VER MODULO FAMILIAR DEL CAMP SI LA MADRE TIENE VALORADA DISCAPACIADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-04-02','Ana: Recibo llamada de Olga Rubio, TS del C.Salud de Plasencia (74523), para intersarse por el caso de Marisa, se muestra preocupada por ella, hasta ahora ha hecho el seguimiento del caso a través de FUTUEX. Le explico como hemos procedido hasta el momento y que la decisión tomada ayer en reunión de equipo, dada la evolución del caso, es la de solicitar ingreso en Residencia de Mayores por emergencia social por decreto. Seguiremos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-03-28','Ana: Acude Soraya (Jefa de Unidad de Recursos) para interesarse por las gestiones que he realizado en los distintos centros. Le entrego copia de los correos y documentación recibida hasta el momento de las Hermanas Hospitalarias de Palencia y de la Clínca El Seranil de Málaga. De las Hermanas Hospitalarias de Málaga no hemos obtendio respuesta.///// Mas tarde nos solicita información sobre la capacidad económica de Miguel para hacer frente al traslado. Alberto el envía un correo con dicha información y me pone en copia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-04-02','Ana: A fecha de ayer, a las 15:38, recibí correo de la Clínica Seranil con el siguiente contenido: "Buenas tardes Ana. Te envio autorozación trsa valoración del equipo facultativo de la clínica. Estamos en contacto. Un saludo. Angeles." Adjunta la aceptación del ingreso. /////// Le reenvío el correo a Soraya. Esta plaza es más económica. ****Respuesta de Soraya: "La subdireccion de sm consideraba muy deficiente la atencion en esta clinica. En principio parecia mejor opcion las hh de palencia. Dejalo ahi en stand by de momento. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2019-04-02','-CARMEN FERRER ME TRAE SOLICITUD PIA PARA PISO SUPERVISADO QUE SOLICITAN DESDE EL CSS MERIDA. LO PONGO PARA FIRMA Y SE LO DEVOLVERÉ. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-04-03','-HABLO CON SU PRIMO JESUS . EL PRECIO DE LA MUDANZA LO VE CORRECTO PQ ENGLOBA TODO . LA SEÑORA CON LA QUE HA ACORDADO LA MUDANZA NO LE DA CONFIANZA. MERCEDES QUIERE DINERO PARA GASTOS INICIALES Y Q SE LE SUBA LA ASIGANACION. LA GESTION DE AGUA Y LUZ LO VA A HACER MAR DEL ESM . A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-04-02','Ana: Recibo llamada de Maite, CAMP de Plasencia (21661). En la cuenta que comparten las dos hermanas han vuelto a ingresar la dos pensiones de Francisca, fallecida el día 28 de febrero. Esta comunicación la suele hacer el seguro, no sabemos qué habrá pasado. /////// Llamo a Prestaciones de Orfandad - CC, me comunican que lo que ha cobrado es el finiquito (la parte proporcional de la paga extra de este año: 189,01 €, lo correspondiente a diciembre, enero y febrero)//////// Llamo a Prestaciones Familiares - CC: Me comunican que la prestación es de carácter trimestral, tiene derecho a percibirla hasta el 31 de marzo. Comprueba los datos y corrobora que consta de baja desde el día 1 de abril). /////// Llamo a Maite, CAMP Plas., y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2019-04-02','El Juzgado de lo Penal nº 2, de Cáceres, nos requiere para que designemos centro adecuado con su patología, para cumplir con la medida de seguridad de tratamiento médico externo adecuado a su patología, impuesta en sentencia 64/2018. Ponemos en conocimiento del Juzgado que ejercemos una curatela patrimonial y que no tenemos competencias para aspectos relacionados con su persona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2019-04-02','Ana: Recibo llamada de Rosa, Admtvo. CSS Plasencia, Jose María se encuentra ingresado en UHB. Por tanto lo de la autorización de salida, que envió su padre por email, en estos momentos no tiene lugar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-03-21','Ana: Se recibe correo, en el ctutelar@, de Rosa, Admtva. CSS Plasencia con el siguiente contenido: "Buenos días: Adjuntamos solicitud de permiso de salida del paciente, sometido a medida de seguridad en este Centro, J.M. ROMERO MEDIAVILLA. Desde el punto de vista clínico, según el psiquiatra encargado de su seguimiento, no existe inconveniente en conceder dicho permiso, con el compromiso del hijo de reintegrarle al centro y comunicar cualquier incidencia que pudiera producirse. Esperamos su autorización para remisión al Juzgado correspondiente. Un saludo. Rosa Bravo. CSS. Plasencia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-04-02','Ana: Mantengo conversación telefónica con Rosa Bravo, Admtiva. del CSS Plas., en relación al escrito previo del hijo de José Manuel, dice que desde el Juzgazo han autorizado la salida. Me enviará dicha autorización por email para guardarla en el expte./////// Recibimos por email la Diligencia del Juzgado de Vigilancia Penitenciaria de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-04-02','Ana: Realizo llamada a Mª Eugenia, TS del C.Penitenciario de Zaragoza (Zuera), no se encuentra en este momento, le dejarán nota para que me devuelva la llamada. En cuanto a los informes médicos y de otra índole, la persona que me atiende me indica que los solicite a la Oficina de Gestión, al mismo fax que la otra vez: 976698456./////*Se remite por fax nuevo escrito solicitando más informes de Rafael. //////// En relación a la solicitud de ingreso involuntario en CSS, se inició en el 2016, pero Rafael estaba en paradero desconocido. Acuerdo con Ángel, Asesor Jurídico, que cuando reciba el resto de informes solicitados al C.Penitenciario volverán a solicitar su ingreso al Juzgado. Aparte encontramos la dificultad del traslado del C.Penintenciario al CSS en caso de que el Juzgado lo apruebe. **Ante esto a Amalia se le ocurre preguntar en el C.P. si existe la posibilidad de trasladarlo a otro CP de Extremadura cuando le quede poco tiempo para finalizar su condena, pues desde aquí sería más factible trasladarlo al CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-04-04','TERESA: LLEGA EL AUTO EN LA QUE SE DECLARA LA FIRMEZA DE LA SENTENCIA PARA INTERNAMIENTO INVOLUNTARIO. EL MARTES LO VEO CON AMAMLIA PARA SOLICITAR INGRESO EN RESIDENCIA POR EMERGENCIA SOCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-04-02','De: Victoria Marroquin >info@mudanzasmarroquin.com> Enviado: miércoles, 27 de marzo de 2019 13:53 Para: Comisión Tutelar de Adultos Asunto: Visita Sr. Mercedes Pérez Pinna. Buenas tardes Sra. Amalia, He intentado hablar contigo en el día de hoy pero no me coge nadie el telf.. en el 924006030, Ayer por la tarde se le hizo la visita a la Sra. Mercedes, quería hablar contigo antes porque esta señora tiene muchísimo, no se si habéis ido en alguna ocasión a su vivienda. Era para comentar un poco como se le puede hacer la mudanza, por favor si eres tan amable de llamarme cuando tu puedas. Mi móvil también es el 652090916. Se acepta pto. empezaran el lunes','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2019-04-02','Ana: Realizo nuevamente llamada a Teo del Arce, TS del CRPS de CC.(927 23 21 06), en relación a la solicitud de revisión de su estado legal. Me dice que el informe psicosocial se lo pida por escrito a la siguiente dirección de email: tdearce.sanmiguel@hospitalarias.es ///// Me facilita el número de teléfono de Jesús: 633 44 71 72. ///// Llamo a Toni-FUTUEX, le facilito el número para que acuerden fecha de visita con Jesús. /////// *Envío a Teo, CRPS, correo solicitando Informe Psicosocial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2019-04-02','Ana: Recibimos escrito del Servicio de Prestaciones de Cáceres confirmando el derecho de José María a la PNC, como es perceptor de PFHC, nos envía anexo para elegir una de la dos. Lo pongo para firma de la D.Gerente para aceptar la PNC por resultar más beneficiosa (Misma cuantía pero 14 pagas). Pendiente hacer y registrar oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-04-03','Ana: Recibo llamada de Javier Civantos, hijo de J.Ramón. Ha hablado con su padre y éste está muy enfadado porque el último día que ha ido a su vivienda, al parecer había mucha humedades en la parte que recientemente ha arreglado el albañil. Llamaré a Paco para que acuda a la vivienda, lo corrobore y dé una solución en su caso.//////// Llamo a Paco Ortés, Albañil (638712004), dice que probablemente esas humedades habrán aparecido tras las últimas lluvias debido al estado de la cubierta del edificio, aún sin reparar, debe tener humedades. Se pasará por allí hoy./////// Envío correo a Pilar, TS SSB Valencia de Alcántara, informando de los últimos acontecimientos y recordandole que sigo a la espera de recibir su Informe Social.////// Realizo llamada a Vere, Directora de la R.Puente Real-San Vicente de Alcántara. J.Ramón sigue igual, con el deseo de comenzar a pernoctar en su domicilio. Acordamos que en la residencia irán anotando todas las incidencias que puedan surgir así como deficiencias que vayan observando en el autocuidado de J.R. (por ejemplo, ha traído ropa de su casa que no quería lavar y les costó mucho convencerle para que se quitara una cazadora muy muy sucia y cuando va al domicilio dice que come latas de comida precocinada) para hacerlos constar en un Informe cuando sea necesario.','2');
