insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2019-04-02','Ana: Recibimos un email de María García, Directora de la Residencia San Francisco de Asís, de Aldea del Cano, con el siguiente contenido: "Buenos días,Le escribo este correo respecto a dos usuarios del Centro:- Claudia Lorena Campus Ante: recibimos la sentencia de incapacitación en la que nos pedían una documentación que nosotros no teníamos. He intentado ponerme en contacto con su familia que se encuentra en Argentina y no he recibido contestación alguna. Con respecto a la información que piden podemos facilitarle último informe realziado en la residencia en noviembre de 2018, el número de cuenta, fotocopias de tarjeta de residencia y seguridad social y la cuota de residencia que paga mensualmente. No tenemos más datos de ella. Se lo adjunto a continuación. Cuota de residencia: 448,00€ mensuales Número de cuenta: ES40 2085 4501 1503 3094 9201"','2');
