insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-04-04','Ana: Paso a los Asesores Jurídicos la Diligencia del Juzgado para aclaración de la misma, llamarán al Juzgado. Desde aquí no se puede autorizar una salida de un tutelado que está cumpliendo medida judicial de internamiento. ///////// Tras llamada al juzgado correspondiente, Ángel, A.Jurídico, envía un fax al mismo, haciendo constar que la Comisión Tutelar se adhiere a lo que resuelva y autorice el Juez. ////// Realizo llamada al CSS y se lo comunico a Pilar, TS, y Rosa, Admtvo. Ésta úlitma me pide que le envíe por email el fax y así lo hago. No obstante me comunica que ya hay un plan previo de salidas aprobado por el Juez. Solicito que me lo haga llegar, pues nosotros no lo tenemos. ****** Recibimos escaneado el PLAN TERAPÉUTICO aprobado por el Juez.','2');
