insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-04-04','Ana: Llamo de nuevo varias veces a Mª Eugenia, TS módulo 10 del C. Penitenciario de Zuera (976738757), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-04-04','Ana: Recibo llamada de Vere, Residencia de San Vicente, me informa que J.R. aún saca dinero del banco sin problemas. Y hoy ha llamado a un chico que vendía un coche, tras ver el anuncio por internet. El chico se ha presentado en la residencia para enseñarle y probar el coche. Tras llamarme, Vere explica tanto a Ramón como al vendedor, que Julián está tutelado y no puede realizar ese tipo de compraventas sin ningún tipo de autorización desde la Comisión Tutelar. J.R. dice que él no está tutelado, que "eso es papel mojado", ella insiste y le vuelve a explicar. **** Hablaré con Alberto sobre la limitación de sus cuentas y Vere me enviará un presupuesto de gastos. ***J.R. tiene Permiso de Conducir vigente hasta 2023.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2019-04-04','Me pongo en contacto contigo para hablarte de Sandra González Escaso, usuaria de Plena Inclusión Montijo, y tutelada ahora por la CTAEX Esta chica vive en la vivienda tutelada desde 2007. Ha estado tutelada por su abuela hasta que ésta falleció en 2018. Como ahora es una tutelada vuestra os voy a pasar la planificación semestral de los viajes que realiza a su pueblo para visitar a sus tíos. Estos viajes lo hace con Cruz Roja. Sandra tiene novio que vive también en la vivienda tutelada de Plena Inclusión Montijo. Alguna vez se ha ido con su novio al pueblo de éste, que es Alonso de Ojeda, a casa de su madre. Nos preguntamos si va a poder seguir haciendo estas visitas ahora que está tutelada por vosotros, porque tiene pensado ir a pasar la semana santa, concretamente del 17 al 21 de abril. Cuando van al pueblo de su novio Sandra se muestra muy colaboradora y participativa en las tareas domésticas y en las relaciones interpersonales con la familia de Ángel, su novio. Se va a realizar un documental con la temática de CAPACITARTE que es una exposición de obras pictóricas en las que participó Sandra junto a otros/as compañeros/as. Son imágenes de archivo internos que se hicieron cuando se empezaron a realizar dichas obras, así como en los momentos de las exposiciones y demás. Hay algún inconveniente en que Sandra aparezca en estas imágenes?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-04-04','Ana: Mantengo conversación con Ángela, Directora de Placeat, en relación a la Autorización para la Oclusión Tubárica de MªRosa. Le explico lo tratado en equipo, tanto con las Trabajadoras Sociales como con los Asesores Jurídicos. El planteamiento es solicitar al Juzgado que reestudie el caso dado el cambio de Tutela y de circustancias. Ángela expresa que la médico de planificación familiar ya dijo en su día que no debía mantener por mucho tiempo los métodos hormonales. LLamaré para hablar con ella (Dra. Begoña, Centro de Planificación Luis de Toro de Plasencia). /////////// En cuanto al cobro de la residencia, aún no han pasado ningún recibo, como en la cuenta nueva aún no está cobrando nada, acordamos que actualizará la cartilla de la cuenta antigua y si hay saldo le pasará los recibos por esa y cuando comiencen a ingresarle las prestación/es en la cuenta nueva se hará un cambio de domiciliación bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-04-05','Ana: Realizo llamada a la Dra. Begoña Romo (74438)del C. de Planificación Familiar Luis de Toro de Plasencia (927 42 34 36). Begoña dice que no entiende por qué hay tanto lío con este caso, ella ya hizo los informes correspondientes, uno inicial y otro un mes después cuando desde el juzgado se le pidió que especificara aún más. María Rosa lleva ya muchos años tomando anticonceptivos hormonales y no debería prolongar esta ingesta mucho más tiempo por los riesgos que conlleva. Considera que en este caso la única alternativa adecuada es la intervención quirúgica. De entrada se muestra reacia a redactar un informe nuevo, pero sí accede a realizar uno en el que exponga que se reitera en lo expuesto en los informes previos en el caso de que de forma oficial así se le sollicitara.///////// Llamo a Ángela (Directora de PLACEAT: 927421950, Ext.102). Le informo sobre la conversación mantenida con la Dra. Begoña y le pido que nos envíe, al menos escaneada, la Autorización Judicial para la Oclusión Tubárica. //////// Recibo por fax los informes médicos emitidos por la Dra. Begoña Romo a fechas de 26/09/2017 y 27/11/2017 respectivamente, que remitió al Juzgado de ª Ins. e Instrucción Nº2 de Plasencia. /////// Tras hablarlo con los Asesores Jurídicos, pongo para firma el Consentimiento Informado para la Intervención Quirúrgica y la Solicitud de Lista de Espera para la misma. /////// Realizo oficio para adjuntar documentación y lo pongo para registro de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-04-05','Ana: De nuevo llamo a Mª Eugenia, TS, C.Penitenciario de Zaragoza(976738757), una compañera me dice que hoy no irá a trabajar, que vuelva a llamar el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2019-04-05','-GESTION DESDE LA PARTE ECONOMICA : Acabo de hablar con Laly, la tía de Jorge y Minerva Martín Blanco. El padre sigue ingresado y según ella sigue mal o peor. No le han hablado al padre de dinero pero han decidio que las 2 transferencias de 200 € de cada hermano vayan a la cuenta de la abuela. Por mi parte he cambiado las transferencias permanente a la ccc de la abuela, x 200 € a partir del 01/04/2019 y además les envío puntual de 150 € x hermano para ROPA. Le he comentado que estabas trabajando en algún tipo de recurso que iba a afectar a la situación de los hermanos sin concretar nada más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2019-04-05','-LLAMO A LALY PARA DARLE EL PESAME POR LA MUERTE DE SU HNO. LE COMUNICO QUE EL MARTES A LAS 10 VOY A VISITAR A LOS CHICOS , LA INVITO A QUE VENGA PARA CONOCER LA OPINION DE LA FAMILIA PATERNA . ME COMENTA QUE LA MADRE SE LOS HA LLEVADO A SU CASA. LA VISITA SERÁ EN EL PERI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2019-04-05','-INFORMACION DEL CENTRO , SE AUTORIZA : Buenos días Amalia. He intentado contactar contigo para hablar del tema de Eva Fermoselle. Como ya te comenté, a ella le gustaría poder pasar algún fin de semana en el piso de su amiga, también de aquí del centro, porque iría allí a cenar y ver la tele, actividad que es normal en personas de su edad. En algunas ocasiones también puede venir el novio de Eva para pasar algún fin de semana, aunque no siempre. Ya te dije que esta chica a Eva le aporta mucha tranquilidad y autocontrol de emociones, por lo que, en principio sí consideramos que es una relación sana. Desde vivienda estamos intentando que Eva haga actividades en la comunidad porque no sale de su habitación, se encuentra en un período de apatía, por lo que hasta que consigamos encontrar más actividades que le apetezca realizar,es bueno que siga realizando actividades con esta amiga que le aporta bienestar emocional. Esta amiga se casa en mayo y este sábado le van a organizar su familia la despedida de soltera. Van los compañeros de vivienda y, también está invitado el novio de Eva, que se quedará a dormir en el piso de esta chica, por lo que Eva nos solicita que hablemos con vosotros para pediros permiso para poder quedarse a dormir en ese piso. Siempre estará el monitor o la monitora de vivienda tutelada pendiente por si sucediera algún contratiempo. Si quieres hablar conmigo me puedes llamar a mi teléfono personal,porque yo salgo ahora del centro. Mi número es 647.616146','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2019-04-05','- SOLICITUD DEL CENTRO , SE AUTORIZA: quiere apuntarse a una comparsa de carnaval de Puebla de la Calzada. Tiene que pagar una cuota para poder inscriirse y le han comentado que tendría que hacer un ingreso de 20 euros al mes desde ahora hasta octubre. Él dice que va a empezar a ahorrar para poder pagar dicha cuota. La cuestión es si le autorizáis a que se apunte a dicha comparsa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2019-04-03','Ana: Recibo llamada de Aida (671 50 72 21), expresa que ya se puso en contacto con la Comisión por el mismo tema y se lo ha expresado en la última visita a la Delegada Tutelar (Gloria). Recientemente se ha enterado de que es adoptada y siente la necesidad de ir a visitar a su paddre y resto de familia a Segura de Toro, para lo que necesitará dinero extra. Añade que su Psiquiatra así lo recomienda. Le digo que miraré el expte., hablaré con otros profesionales (ESM) al respecto y miraré con los compañeros de la Sección Económica cómo es su situación. **Le devolveré la llamada en torno a 3-4 días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2019-04-05','Ana: Mantego conversación telefónica con Pilar, TS del ESM de Cáceres. En relación al deseo de Aida de ir a Segura de Toro, me dice que hay un informe de su Psiquiatra que recomienda este viaje. Le pido que me lo envíe. ****Recibo por fax el informe del Médico Pisquiatra (Consulta privada) de fecha de 12/02/19 con esta recomendación y un informe social suyo de fecha de 21/03/19. ///////// Hablo con Alberto, Responsable de la Sección Económica, miramos su situación económica: Aida tiene una pensión de poco más de 1000 €, desde aquí se gestiona el pago de la suministros (luz, agua y gas), Seguro de Hogar, Seguro de Salud- ASISA y teléfono. Ella tiene una asignación mensual de 675 €. Y continuamente está pidiendo extras para distintas cosas (viajes, gimnasio, cremas...)///// Vuelvo a llamar a Pilar, TS de ESM, y le expongo la situación económica y que debería administrarse mejor. Acordamos que si se le da dinero, la cuantía no será tan alta como pide (300 €) y se le inistirá de nuevo en el hecho de que no puede pedir extras con tanta frecuencia. Pido a Pilar que desde Salud Mental también trabajen esta cuestión. ////////// Llamo a Aida, le explico cual es la situación económica y que no se le puede dar extras cada dos por tres, que tendrá que administrar mejor su asignación mensual. Dadas las circustancias y teniendo en cuenta el informe del Psiquiatra a priori se hará una excepción y se autorizará un extra de 150 €, indicándole que deberá aportar las facturas del alojamiento y el tiquet de autobús, y que debe dejar de pedir extras y administrarse mejor pues no se le concederán a menos que sea extrictamente necesario.///////// Se lo paso a Alberto, harán las gestiones para que pueda sacar el dinero a partir del martes de la próxima semana (del 9 al 12 de abril)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='BARQUERO'and apellido2='MARTIN'),'2019-04-05','Ana: Se recibe fax de Blanca, TS CSS Mérida, comunicando que Antonio ha sido ingresado en el hospital de Mérida.','2');
