insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2019-03-28','miguel, pendiente de recibir solicitud de abogado de oficio definitiva para poder enviar la documentación reclamada por el abogado provisional','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-03-21','miguel, tras varias conversaciones telefónicas con Raúl y su abogado y con miguel su hno y con la notaria de J. Gimenez, requiero telefónicamente al abogado de Raúl para me remitan el certificado de defunción del hno José para poder tramitar la herencia(al juzgado y al banco) para pueda heredarlo nuestro tutelado José Lara Serrano. Al tiempo y tras conversación con la notaria, les requiero de varia documentación a efectos de poder solicitar autorización al juzgado para la herencia y la posterior venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-04-05','- Buenos días Amalia, en relación con Rosario Moreno, te vuelvo a pasar el teléfono de la cuidadodra que sustituyó a Miriam durante diez días para que contactes con ella para hacerle el pago correspondiente por su trabajo. 642849011. Como te dije, parece que esta persona estaría interesada en el trabajo con carácter permanente y tiene posibilidades de regularizarse. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2019-04-05','Informo sobre los ultimos datos que poseiamos a fecha de noviembre de 2018, información que recogimos , facilitada por el Ayuntamiento de Barcarrota, del cambio de domicilio de Trinidad y que seguía con su vida normalizada. Hemos logrado averiguar la nueva dirección, por lo menos la calle: Buenavista y el número no saben con seguridad si es el 7 ó 9 de Barcarrota. Nos aseguran que reside allí ya con su pareja y en condiciones óptimas. El número de móvil que se tiene de ella, no está ya disponible. Se planificará una visita para lograr contactar con ella y lograr también un nuevo número de contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2019-04-08','-CORREO APROSUBA 3 Hola Amalia: Hemos contacto con la Policía Nacional, para exponer la situación actual de Pilar y su madre y nos indican que es totalmente denunciable. Manifiestan que el hecho de que Pilar madre vaya por la calle y un individuo le insulte y humille verbalmente, se puede denunciar, porque es violencia de género y si conviven puede que haya indicio de violencia doméstica. Este hombre, recordamos, que vive junto con ellas en el domicilio de éstas sin su consentimiento, pero no tienen la fuerza para echarlo ni el valor para denunciarlo y se vaya. Seguimos pendientes de Pilar hija. Por ahora no hay nada que nos alerte de una situación de peligro inminente. NO obstante, no hay que olvidar que ambas tienen discapacidad intelectual. Sobre Pilar madre, no tenemos la certeza absoluta de que tenga reconocida la discapacidad, pero si dice que cobra una pensión de la Junta de Extremadura y que según sus palabras “la asistenta social le ha dicho varias veces que porque no va a un centro como el que va su hija”. Necesitamos saber cómo vais a proceder ante esta situación para saber cómo actuar desde Aprosuba. Gracias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2019-04-08','Ana:Correo de ASINDI- "El 05/04/2019 a las 15:56, Sonia Bernabé Fernández escribió: Hola, quería informaros que la hermana de Juan Gabriel Sobrino Tardío ha llamado para comunicarnos que vendrá a por él mañana. Disfrutará de unos días con la familia como suele hacer por estas fechas. No nos concreta día de regreso, pero piensa que pueden ser unos 15 días. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-04-08','Ana: A fecha de 05/04/19 se recibe un correo de Beatriz Martín Morgado, Subdirectora de Salud Mental y PPAA del SES: "Estimados compañeros: El motivo de este correo es convocaros a la Comisión Regional de Gestión de Casos que se celebrará en Mérida el próximo día 12 de abril a las 9:30 h de la mañana, en la sala de reuniones de la Unidad de Programas Asistenciales del SEPAD (1 planta), y que versará sobre la situación actual de Miguel Gamero Gómez. Ruego confirméis asistencia. Gracias de antemano por vuestra colaboración. Un afectuosos saludo." Respondo al correo confirmando mi asistenica en representación de la Comisión Tutelar.','2');
