insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2019-04-08','Ana: Recibo llamada de Aida (671 50 72 21), le informo que he recibido un correo de FUTUEX, con un informe de visita de 5/11/18, en el que ya sabía de la Adopción y pedía dinero para ir a ver a su padre. Y que también le autorizaron un extra para una visita familiar, pero dice que esa visita era por un motivo totalmente diferente, que era para asistir a una reunión anual que realizan las mujeres de su familia. Tras confirmar esta información con Juana, le llamo para comunicarle que podrá retirar el dinero que habíamos acordado entre el miércoles y el viernes de esta semana.//////// Respondo al correo de Toni-FUTUEX, al repecto y para que lo tengan en cuenta en próximas visitas y así puedan trabajar en el misma línea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-04-12','TERESA:VIENE HERMANO DE ADOLFO, lorenzo 678731543) ME COMENTA QUE QUIERE PONER EN MARCHA YA LA AYUDA A DOMICILIO QUE EL SE HACE CARGO DE LOS PAGOS HASTA QUE GENERE EL DERECHO SU HERMANO Y LO PAGUE LA JUNTA. COMENTA QUE LO QUIRE HACER CON LA EMPRESA DEPENDENCIA EN EXTREMADURA YA QUE CON LA DE ACUIDAR TUVO UNA MALA EXPERIENCIA. HABLO CON EL RESPONSABLE PARA PEDIR PRESUPUESTO EL CUAL NOS CUADRA ASI QUE COMENZAMOS A GESTINAR EL CONTRATO CON ESTA EMPRESA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-04-08','Ana: De nuevo llamo a Mª Eugenia, TS, C.Penitenciario de Zaragoza(976738757). El subsidio de excarcelación no se lo pueden pedir ella, pues la persona debe estar inscrita previamente como Demandante de Empleo. Cuando salga le entregarán su DNI y un Certificado de Cumplimiento de la Pena, con lo que podrá solicitar el subsidio. /////// En cuanto a la posibilidad de que lo trasladen a un C. Penitenciario de Extremadura, dice que no puede ser oblligatorio, que se lo propusieron a él en su día (cuando se revisó el grado) y dijo que no, que quería salir en Zaragoza, le preguntaron por qué, si allí no tenía a nadie, y él dijo que tenía amigos.****De cara a la excarcelación, dice que planteemos al Juzgado, no sólo el ingreso involuntario, sino una "Medida Cautelar de traslado al centro psiquiátrico por los cuerpos y fuerzas de seguridad del Estado", allí ya han tenido algún caso, pero dentro de la CCAA de Aragón. /////////// En cuanto a los informes pendientes solicitados, dice que enviarán I. Médicos, del Psicólogo y del Educador. Pedirá a la oficina de gestión que nos los adelantes por fax. ///////// Se recibe informes médico en que hacen constar que "Desde su ingreso no ha presentado clínica significativa." y "No se dispone de informes psiquiátricos recientes, ni Neurológicos".','2');
