insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2019-04-08','miguel,acudo con Cristofer a revisión de Forense, y me comenta que hay 3 procedimientos abiertos: procedimiento por agresión a 4 personas, entre ellos al hno de su ex; procedimiento por amenzas al padre, hno y a su ex (con navaja); procedimiento donde le han declarado en rebeldía(no nos aporta de este ninguna documentación, aunque se la hemos pedido varias veces).Este procedimiento corresponde a ir en moto conduciendo su actual novia sin carnet y él de acompañante.Me confirma que por este último procedimiento su actual novia y madre de su hija (nacida el 4/4/19), se encuentra ésta en arresto domiciliario 2 años por ir sin carnet, y que a él por ahora sólo le han puesto una multa de 200 euros. La visita a la Forense sin novedad (referido al procedimiento por amenzas al padre, hno y a su ex, quedando pendiente la vista del juicio para el 11/6/19). La anterior visita a la Forense de enero 2019, a la que asistimos Alberto y yo se refiere al procedimiento (procedimiento por agresión a 4 personas, entre ellos al hno de su ex)','2');
