insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-04-09','-SE REALIZA VISITA DOMICILIARIA JUNTO CON LA DELEGADA TUTELAR DE FUTUEX . SE FIRMA EL DOCUMENTO PARA EXTINGUIR EL USUFRUCTO QUE TENIA SOBRE LA VIVIENDA QUE OCUPA Y DE LA QUE ELLA TIENE LA NUDA PROPIEDAD PARA PROCEDER A LA VENTA DEL MISMO . Se intenta realizar inventario sobre los bienes muebles del domicilio. Dada la acumulación de los mismos , no le van a coger en su nuevo piso de alquiler , comenta que los ha donado a una persona que trabajaba con su madre a cambio de prestar servicios de limpieza en el domicilio . Y que una parte de los mismos los va a vender con la ayuda de esta señora por internet. Nos impide realizar dicho inventario . La mudanza comienza el mismo día . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2019-04-10','Ana: Llama Susana de Aprosuba3, pregunta si Antonia está tutelada por la Comisión, pues se le ha concedido plaza en C.O. y al pedir documentación a la madre, no se la quiere llevar y dice que la Tutora es ella, al notar algo raro nos llaman para contrastar la información. Le informo de que la aceptación del cargo tuvo lugar en noviembre de 2018. ***Le envío escaneado por email la Sentencia de Incapacitación, el Auto de Nombramiento y Aceptación del Cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2019-04-09','-Se realiza visita domiciliaria junto a delelgada tutelar en su casa familiar en el Peri para valorar alternativas dado el fallecimiento del padre. La vivienda se encuentra en un barrio marginal , la madre , su hermano y cuñados presentes en la reunion, solicitan que se trasladen a un barrio mejor y se deje esta vivienda que ocupan de alquiler de VPO . Quieren que los dos hermanos se queden en el domicilio familiar , acudiendo a Centro de Dia Minerva y Jorge a algun taller por ej . La Encina . Van a solicitar cita a la TS de SSB para tramites de alguna pension . Valorar si los chicos podrian tener PF + Orfandad . La madre tiene discapaciad intelectual y S. diogenes , sin diagnosticar, nunca ha pasado por el CADEX y no tiene ingesos ec. No tiene capacidad para administrar el dinero , por el momento lo va a administrar Diego , hno. de Victor . En la reunion se palpa el enfrentamiento entre el hno de Pepi ( madre ) y Lali ( tia paterna ) . Acude seguidamente a las oficinas de CTAEX con su mujer y ésta explica que en esa casa utilizan a Pepi, una vecina gitana del 2º para traficar con drogas . Y comenta que ella le ha visto los pechos morados a Minerva y es por incesto de la madre . Que le ha preguntado directamente a Jorge y le comentó " a mí tambien me toca " . Esto cambia toda la intervencion inicialmente propuesta . Traslado información a FUTUEX , para que programe visitas más permanentes y estén atentos a cualquier alarma de este tipo . Solicito visita con TS de Aprosuba 7 mañana sin falta en las oficinas del SEPAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2019-03-12','-Se hace visita de coordinacion en CRR . Está bien , sale mucho con un excompañero de CRR y come a veces con él . Practicamente está todo el día con el . comenta que en Talavera la Real habia una casa q él cree que era de la madre : Teresa Merchan Pozo , fallecida,y que si él es el heredero querria ir . Desconocemos estos datos . Según el situada en C/ Doctor Marañón , 17 . ??','2');
