insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2019-04-11','ME LLAMA LA ANA MURILLO PARA PLANTEARME PRESUPUESTO PARA VIAJAR DE VACACIONES, LE LLEVAN EN COCHE Y NECESITA 84€ PARA GASTOS DE GASOLINA. LO PASO A GESTION ECONÓMICA Del 15 al 17 de abril: o visita a las familias colaboradoras de Malpartida de Plasencia o tendría que pagar el kilometraje. Está a 223 km y le costaría ida/vta 84,74€ · Del 17 al 21 de abril o Salida del Cabeza del Buey por la tarde o Su madre Pastora y su tio se encargarían del transporte','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-04-10','miguel,habiendo revisado el expte con Alberto ctaex, quién me explica la urgencia de la venta porque desde Liberbank están apunto de embargar la finca por deudas hipotecarias y personales, habiéndoles hecho desde liberbank de una dación en pago. Tras varios intentos en días anteriores y hoy no logro hablar ni con el hermano del hijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-04-11','miguel, ante la imposibilidad de hablar telefónicamente ni con el hermano y padre, ni con el hijo, llamo a la inmobiliaria que tiene en venta el bien de c/ cuesta de la reina...Viprés, quién me comenta la dieron de baja porque a nuestro tutelado apareció en todos los medios de comunicación por encontrarle animales muertos y tener el sindrome de diogenes, tuvieron una mala experiencia por cuanto cuando fueron y vieron la casa,tuvo que ir la policía... Se ofrecen a ayudarnos, y así me confirman que la casa está para derruirla y el valor oscilaría no más de 40.000€. Por tanto y teniendo en cuenta que Liberbank aprieta para ejecutarla, y teniendo en cuenta las deudas son superiores a 70.000€, sería lógico ni intentar vender. En cuanto a la casa de c/ General Margallo,sita en el casco histórico de cáceres de unos 193 metros, tiene más valor, pero sin inscribir en registro de la propiedad, que según nos dijo nuestro tutelado falta por tramitarse la plusvalía para su inscripción (el problema es que será muy complicado acceder a las escrituras de compraventa y ver si están hecho el trámite de liquidación de impuestos, etc). Viprés tiene para vender el bajo de este edificio, y el piso de nuestro tutelado es el 2º, con lo que sería conveniente lo tasaran y tramitaran ellos la venta. Angel localiza vía catastro los titulares anteriores, quedando pendiente de hablar de nuevo con el tutelado y o bien nos hace llegar las escrituras o habría que solicitar duplicado a la notaria (y llevarla de nuevo, si no se hizo..., a liquidar el impuesto de transmisiones patrimoniales)','2');
