insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2019-04-01','-ACUEDE A LA OFICINA SU HERMANO JOAQUIN Y SU HIJA , LE HAN DADO EL ALTA EN CSS Y NO NOS LO HAN COMUNICADO , NI SIQUIERA LO SABIA LA TS DEL CSS . -EL PSIQUIATRA LE HA DADO EL ATA , A PESAR DE QUE EL ENTORNO FAMILIAR NO REUNE CONDICIONES PARA MANTENER A ESTE SEÑOR EN DOMICILIO , CON ALCOHOLISMO CRONICO Y CON MAS 20 AÑOS DE INGRESO EN PRISION ( MATÓ A SU MUJER ) Y EN CSS . -LA FAMILIA SOLO QUIERE SU PENSIÓN , SE LE COMENTA QUE SE LE VA A ADMINISTRAR PERO SU HNO. SE MUESTRA EN CONTRA. SE LE VAN A AUTORIZAR 300€ DEL A 1 AL 5 Y OTROS 300 A PARTIR DEL DIA 16 .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-04-12','Ana: Tiene lugar la COMISIÓN REGIONAL de Gestión de Casos. Se ha solicitado al C.Neuropsiquiátrico de Zaragoza nos de un mes más de plazo para buscar una solución. En la reunión se acuerda solicitar, desde la Subdirección de Salud Mental (SES) que le pasen el Test WAIS a Miguel y determinar el grado de discapacidad intelectual (en el que le pasaron en la UDAC dio Inteligencia Límite, motivo por el que dicen que no cumple el perfil de P.D.I.). Se convocará otra reunión una vez tengamos los resultados de dicha prueba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-04-10','Ana: Recibida solicitud firmada por Consoli y Oficio registrado, paso a Julio para que lo envíe por correo certificado al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-04-12','Ana: De nuevo recibo escrito del INSS en relación a la PFHC, vuelven a pedir que presentemos nuevo expediente (que YA ESTÁ ENVIADO) y además en esta ocasdión añaden que PROCEDEN A MECANIZAR LA BAJA del expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2019-04-12','-ENVIO EMAIL A PARTE ECO: -Buenas , te comento sobre nueva tutela ANTONIA PEREZ PEREZ En el inventario se recoge que sólo pericibe P. Orfandad(200€) , he contrastado esta información con el INSS y percibe además PFHC ( 392.00€/ MES ) . Por lo tanto hay que corregir este dato en el inventario ( es probable que el INSS facilitase mal la información ) . Las dos pensiones estan a nombre de la madre , necesito que procedáis a abrir nueva cuenta bancaria donde ingresar la nueva prestación que tengo que solicitar . Quedo a la espera de la misma . -HABLO CON APROSUBA 3, HA INGRESADO EL LUNES EN CO. PONGO CONTRATO Y DOCUMENTOS A LA FIRMA. MADRE CON DISCPACIDAD Y 8 HIJOS TODOS DISCAPACITADOS . FALLECIDOS 2 DE ELLOS Y EL PADRE. ESTUVO EN RAE HACE AÑOS EN APROSUBA 3 SE FUE DEJANDO UNA GRAN DEUDA EC. AD','2');
