insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2019-04-12','Ana: Realizo llamada a DOWN - CC. Elsa, Psicóloga (927227435) dice que ha intentado ponerse en contacto con nosotros (teléfonos de Pedro y Amalia), por lo que se le explica las circunstancias y se le facilita mis datos de contacto (email y teléfono). Acordamos que me enviará al ctutelar@ el Certificado de Prestación del Servicio para que lo devolvamos firmado y sellado por la D-Gerente. Se lo adelantaremos escaneado por mail. Pedirá a Andrés Talavero (Director Gerente) que hable con José Mª Tobar, pues tienen buena relación. ////// Realizo llamada a la Asoc. Nace (927233567), hablo con una de las hijas de José Mª Tobar, quien me facilita otro nº y un e-mail: 669 43 90 20 / asociacionace@hotmail.com. Llamo al número móvil y pone el manos libre, tanto ella y su mujer no están de acuerdo con la decición de que acuda a un CO y expresan además que Soledad no quiere ir a ese recurso. Consideran que desde su casa se está haciendo el servicio que le van a dar en DOWN. Dicen que no se tiene en cuenta ni su criterio ni la opinión de las personas a las que atienden. Dice José Mª "moveremos los hilos que haya que mover como ya estoy haciendo con el otro caso" "voy a hacer que se nos escuche, voy a argumentar, esto es dinero público y hay que ver si está bien o no gestionado" "Los mandan a Down, donde no dan ni el perfil","se va a gastar un dinero innecesario". Dicen que ellos no le van a dar la noticia a Soledad, que se lo digamos nosotros. Y que la cita para ir a Down la gestionemos desde aquí./////// Llamo a Elsa, Psicóloga de Down, le indico que no llamen a Down de momento y si hablan la próxima semana con Maite, de Discapacidad, que le pidan que excepcionalmente amplien el plazo para ocupar la plaza unos días para que podamos organizar la incorporación de Soledad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2019-04-12','- HE PEDIDO A SU HNA . LA SOLICITUD PARA REVISION DEL CADEX LE VENCE EL 30/04/2019. HAY QUE ENVIARLA AL INSS PARA MANTENER LA PENSION . SE ENVIA CON FECHA DE ENTRADA POR REGISTRO EL DIA 17/04/2019 AD','2');
