insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-04-15','RAFAEL FAUS LEMUNS ingresó en prisión el viernes . Baja a la transferencia economica a su tia y alta en cuenta peculio. 100€ mensuales , no sé si puede ser 50€ a principios de mes y otros a mitad . Me llma su tia 924109808 , quiere que le compremos una TV . Le comento que iremos comprando lo que desde el centro nos vayan indicando. Entra muy enganchado , con muchas penas pendiente. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-04-15','-TF JACKELINE . 642734183 es la persona que según ella ha quedado para ayudarla con la mudanza y limpieza. Hablo con ella por tf. la conoce de cuando cuidó a su madre durante dos años. lleva mas de 10 años en Badajoz y tiene dos hijos de 20 y 13 años. Según ella , quedó con Mercedes en echarle algún rato algun dia que pueda pero nada más pq trabaja por la mañana fija en una casa, por la tarde en los Montitos y por la noche cuidad de una persona mayor. Dice que le ha dado el mueble empotrado del cuarto de arriba, la comoda antigua del salón , lavadora , lavavajilla , la cama de la madre ( el armario es empotrado y las mesillas están para tirarse ) , una vitrina del salon. La secadora se la ha dado a Jesus . Todo lo demás se lo ha llevado . Dice que alguna vez le lleva un taper pq ella come bocadillos. LA LLAVE DE LA CASA DE LA C/ MAESTRO LA TIENE ELLA , LE HE PEDIDO QUE EN UNA SEMANA NOS LA TIENE QUE ENTREGAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2019-04-15','TERESA: NOS LLAMAN DEL CENTRO PARA INFORMAR QUE ESTÁN TENIENDO PROBLEMAS EN EL CENTRO CON NATALIA PORQUE NOS PIDEN AYUDA PARA VER COMO AFRONTAR EL PROBLEMA LE COMENTO QUE DESDE AQUI NOS PONEMOS A SU DISPOSICON. LE INDICO QUE PRUEBEN CON REFUERZO POSITIVO INCLUSO CON ALGUN INCENTIVO ECONONOMICO.... NOS COMENTA QUE SEGUIREMOS EN CONTACTO.','2');
