insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-04-15','-LLAMA LA TS (924491305) DE CASER RESIDENCIAL OLIVENZA. FUTUEX DICE Q NO PUEDE ACOMPAÑARLO A SACAR EL REINTEGRO MENSUAL , HACE 2 MESES QUE NO VAN. SE LES AUTORIZA PARA QUE VAYAN LA TS/ DTRA/ MONITORES. - ME COMENTA QUE ESTÁ INSISTIENDO EN SALIR DE LA RESI, LE EXPLICO Q ES CURATELA EC. Y QUE SE PUEDE IR CUANDO QUIERA . PERO QUE NO TIENE NINGUN SITIO DONDE IR. -VA A TRATAR DE CONSEGUIR I.MEDICOS CON LA INTENCION DE SUBIR LA CURATELA A TUTELA . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-04-15','-llamo por tf. a Victoria de la mudanza Marroquin , ya está todo terminado . Quedan algunos cuaadros que no ha permitido colgarlos. De lo que queda en la casa su primo Jesús y Jackeline se hacen cargo : mobiliario de la terraza del ático ( mesa, sillas y columpio de forja y maquinas de deporte ) , mueble empotrado de arriba y de las habitaciones , el cuarto de la madre , comoda del salon , ... Mandará la factura de la mudanza. Las llaves del piso las tiene Jackeline para recoger lo que le queda . Le he dicho que tiene una semana para ello porque tenemos que entregar las llaves al propietario. Supongo que se las entregará a Jesús . Sería conveniente contratar empresa de limpieza y comida, se le propondrá en la próxima reunión . Jackeline me ha confirmado que ella no tiene una hora libre al dia y que en ningun momento acordó nada de trabajar para ella . Que los muebles se les cedió vuluntariamente.','2');
