insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-04-17','miguel, tras conversación con el centro penitenciario de Badajoz, nos indican que el preso Rafael Faus Lemus ingresó el 12-4-19, el motivo por robo con fuerza en las cosas. Está en prisión provisional a espera de juicio. La causa se está llevando en el Juzgado de lo Penal de Badajoz nº1, procedimiento 20 causa 6 del 2019. Parece ser que un caso con repercusión y alarma social que salió en medios de comunicación (periódicos..)porque fue con objetos peligrosos (destornilladores, tijeras...) La pena caso de que fuera condenatoria no se sabe hasta se dicte...pero podría oscilar entre 2 y 3 años','2');
