insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-04-24','Ana: Reunión con Paula, CRR, y Alberto, Sección Eco: Tras la última incidencia de Ceferino (ha comprado a través de la compañía de tlf. 2 móviles por importe de 500€ apróx. cada uno, que ha acabado malvendiendo y a posteriori ha escrito una carta de "arrepentimiento") se acuerda que se devolverán los recibos, acabará en la Lista de Morosos y se quedará sin móvil de contrato. Así mismo se acepta la nueva propuesta de intervención terapéutica que plantean desde el CRR, a pesar de que supone aprobar un reintegro de efectivo mayor. Probarán una nueva vía de intervención, en la que tendrá que comprometerse a realizar otro tipo de actividades comunitarias normalizadas (cursos, academias, ect) y se le administrará todo el efectivo desde el centro, utilizando las asignaciones como refuerzos positivos. **A partir del 1 de mayo, podrán realizar una sóla retirar de efectivo mensual (350€) del 1 al 10 de cada mes SIEMPRE ACOMPAÑADO de un profesional del CRR.','2');
