insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-04-26','Ana: Paso a Julio para que envíe por correo certificado, a la T.S. de Miajadas, la solicitud de baja en el servicio de comedor del piso tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2019-04-26','-respuesta del centro de la Luz , ante la peticion del SSASB ( A.Nisa ) para que Miguel cambie de centro o al menos pase mas tiempo con sus hermanas . Le contesto en el sentido que ya se pidio centro mas cercano y q las hermanas no nos han pedido nada. Buenas Tardes, Amalia. Este asunto es para hablarlo personalmente no contestarte a través de correo electrónico. Creo que el Trabajador Social del SSB de Fuente del Maestre tiene la información sesgada. Las relaciones de Miguel con los cuidadores y con el personal del centro no están deterioradas. Miguel tiene dificultad para asumir normas (ya lo hemos hablado en otras ocasiones). Teniendo en cuenta la trayectoria de sus hermanas me parece que lo mejor es dejar las cosas como están. Sí solicitar a Miguel el traslado de Centro para así estar más cerca de su pueblo y sus hermanas pero no fortalecer el nivel de responsabilidad de sus hermanas hacia él. A nosotros tampoco nos han solicitado nada sus hermanas. Consideramos que es bueno que mantenga unos vínculos afectivos con ellas, porque son su familia. Aún así es conveniente que estas visitas cuenten con un seguimiento continuo. En mi opinión, dejaría las cosas como están y cursaría solicitud de traslado por estar más cerca de su pueblo y su familia pero lo más conveniente para él es estar en un centro con la atención especializada, apoyos y supervisión que necesita. No sé si te he contestado. Un saludo. Sole.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-04-26','Ana: Se recibe un correo Luis Sancho Polo, Director Técnico.- CRR y PS Salud Mental - FEAFES: "Estimado Pedro, Te envío este correo para comunicarte un hecho desafortunado que ocurrió ayer a mediodía, en relación con la tutelada Consuelo Nevado Pacheco. De manera completamente inesperada, se precipitó por un puente cercano al centro, en lo que pensamos que ha sido un intento de autolisis fruto de un acto impulsivo. Se encuentra hospitalizada y su estado no reviste riesgo, aunque tiene diversas lesiones a nivel de pie, tobillos y zona lumbar. En la primera valoración médica que realizaron en el hospital nos han informado que requerirá diversas intervenciones quirúrgicas que tendrán que valorar. De momento ha pasado la noche en la unidad de reanimación y esta mañana prevén su traslado a planta. Ella se encuentra estable, consciente y tranquila. Durante la tarde de ayer pudimos acompañarla en la medida en que el hospital nos lo permitió. También hemos informado a sus familiares (padres y hermano) y estamos en contacto con ellos. De momento hemos percibido que se encuentran tranquilos, dentro de la preocupación que este tipo de acontecimientos conlleva. Los médicos que nos informaron ayer, nos comentaron que necesitarán la firma vuestra en los consentimientos para los procedimientos que tengan que llevar a cabo. Os mantendremos informados de todo lo que vaya aconteciendo. Un saludo." Respondo al correo, seguiremos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2019-04-23','- SE PERSONANA EN OFICINA MERIDA MANUEL , SU PADRE Y SU TIO . TIENEN HOY EL JUICIO EN ZAFRA IMPUTADO POR MEJIAS DE LA MORENA , TB TUTELADA . EL JUICIO SE HA ARCHIVADO . TUVO UNA RELACIÓN SENTIMENTAL CON ELLA HACE AÑOS CUANDO ESTUVO EN P.SUPERVISADO DE ZAFRA. HA TENIDO INGRESOS EN CSS DE MERIDA . LA MADRE TB CON PATOLOGIA MENTAL , VIVE CON ALGUNOS HIJOS EN MORALEJA . ÉL Y SU PADRE VIVEN EN CORIA CON LA ABUELA MATERNA POR CONFLICTOS DE CONVIVENCIA. TIENE UNA HIJA DE 15 AÑOS QUE VIVE CON SU MADRE Y A LA Q PASA 100€ AL MES . BUENA RELACIÓN CON ELLA , LA VE CUANDO VA A MORALEJA.','1');
