insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-04-30','TERESA:LLAMA ISABEL DE ZAFRA PARA INFORMAR DE LA SALIDA DE JOSEFA AL DOMICILIO FAMILIAR DE PLASENCIA DEL DOS AL TRECE DE MAYO. COMENTA QUE AHORA SE ENCUENTRA ALGO MAS ESTABLE Y QUE SIGUE PENDIENTE DE LA DERIVACION A LA UDAC POR PARTE DE CONSTAZANZA LA PSIQUIATRA DE DE LA UHB DE LLERENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2019-04-30','Ana: Llamo a Jesús Rubio(644 803 001) , hermano de Javier, le doy el pésame. Me pasa con su hermana Rosa Rubio, le doy el pésame y me informa de cómo creen que fue el suceso: esa mañana Javier pasó por casa de su madre, iba ebrio y llevaba en la mano una bolsa con más bebidas alcohólicas, la madre no le abrió la puerta por la voces y golpes en la misma. Lo encontraron sentado en la cama con la cabeza entre las piernas y los brazos colgando. Tenía quemado un poco un pie y pierna. El incendio se originó en el comedor, creen que se quedó profundamente dormido en el brasero y al despertarse se desplazó como pudo hasta el cuarto y "sentado en la cama se quedó"·. Se lo llevaron al Anatómico-forense para practicarle la *AUTOPSIA. Le han **incinerado y de momento la urna la ha puesto en un sitio especial de la vivienda de la madre preparado por las hijas de Rosa. Ahí estará mientras la madre no decida otra cosa. No sabe si más adelante harán funeral. Tienen un nicho en propiedad en el que podrían enterrarlo. *Como no tenía Seguro de Deceso, desde la funeraria se están encargando de algunas gestiones, se pondrán en contacto con nosotros si fuera necesario o para enviar las facturas, le han facilitado nuestro correo electrónico y teléfonos de contacto. Si es necesario abonar diferencia, ella se encargará de pagarlo. /////*Ha solicitado el Cdo. de Defunción, pero aún no lo tiene. /////// Acordamos que en la Rendición Final se pondrá su nombre y números de contacto, por si lo necesitaran en el juzgado: 952 238 383 y 649 293 037 Reside en Málaga, pero volverá dentro de 2 meses apróx. para encargarse de las gestiones que aún queden pendientes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-04-26','-INCIDENTE EN AP3 , SE TIRA DEL FURGÓN DEL CENTRO DONDE IBA A UNA SALIDA Y AGREDE A DOS MONITORAS . EL 112 LA DERIVA UHB , SALDRÁ EN BREVE DE ALTA . SOLICITA AP3 QUE PASE A VISITARLOS , QUIERE QUE LE DIGA Q NO PUEDE TENER MOVIL . PROPONGO QUE LO PUEDA TENER UN DIA CONCERTADO . AD','2');
