insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2019-04-30','-ME LLAMA MAY , PARA OFRECER PLAZA RESIDENCIAL , TIENE GRADO 2. CONTACTO CON EL CRR DE MERIDA , LUISA NO ESTÁ ACTUALEMENTE EN BUENAS CONDICIONES PARA PASAR A PLAZA RESIDENCIAL . SE LO COMENTO A MAY Y A SONIA VENEGAS ( TECNICO PIA ) SE ACUERDA QUE MAY VA A ENVIAR A SONIA UN DOCUMENTO EN EL QUE SE SUSPENDE TODOS LOS CENTROS PEDIDOS ( ARROYO , ALMENDRALEJO Y EL PRADO EN MERIDA ) Y SE LE DA DE BAJA . CUANDO QUERAMOS VOLVER A PEDIR PLAZA RESIDENCIAL HAY QUE HACER UNA REVISION PIA CON UN CDO. DEL PSIQUIATRA INDICANDO QUE NO PRESENTA ALTERACIONES CONDUCTUALES. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-04-29','Ana: Recibo llamada de Vere, directora Residencia Puente Real-San Vicente Alc. Me informa de que J.Ramón cada vez acude con más frecuencia a su domilicio e incluso ha comenzado a pernoctar allí. Han intentado hablar con él, dado el derroche que supone el pagar la residencia y no hacer uso de ella y de tantos traslados (ida y vuelta en taxi) a su casa, pero él no escucha lo que no le interesa. Además, la última vez que ha ido **ha retirado 1.000€ del banco, con los que **ha comprado un coche de 20 años. Dice que para ir y volver de su casa. Le han dicho que no debería conducir, pero hace caso omiso. ///// Acuerdo con Vere que el ***viernes 3 acudiré a hacerle una visita a la residencia (antes no puede ella). Eso sí, no pueden asegurar que Ramón vaya a estar allí y cuando hace unos días le dijeron que desde la Comisión Tutelar quería ir a verlo y hablar con él, repitió "yo no estoy tutelado y no tengo que hablar con nadie"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-04-30','-HA DADO UN GRADO 1 DEPENDENCIA , NO PUEDE ACCEDER A R.MAYORES ( NO SE DA EN ESTE SERVICIO LA OPCION DE G.1 POR PROMOCION DE AUTONOMIA ) TIENE 62 AÑOS Y EL 66% G.DISCAPACIDAD . EN EL CRR NO SE PUEDE SOLICITAR COMO NUEVO USUARIO SI YA TIENE CUMPLIDO 60 AÑOS Y COMO FECHA MÁX. DE ALTA SON LOS 65 AÑOS ( SALVO EXCEPCIONES ) . HABRIA QUE ESPERAR UN EMPEORAMIENTO PARA VOLVER A PEDIR REVISION DE GRADO Y PIA. OTRA OPCION ES VENDER SU CASA Y BUSCAR PLAZA RESIDENCIAL PRIVADA . SE LO TRANSMITO AL DTROR PARA QUE LO HABLEN CON ELLA. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-04-30','Ana: Llamo a Pilar Márquez, T.S. del SSB de Valencia de Alcántara (927 580 326, ext.8) Le informo de los últimos acontecimientos y de mi próxima visita el día 3 de mayo. Tras visitar a Ramón en la Residencia acudiré a Valencia de Alcántara a hablar con ella. Las alternativas que planteo para Ramón son: Plaza en C.Día municipal (Valencia Alc.) para tener un mayor control de su alimentación y medicación y/o Ayuda a Domicilio, para limpieza de la vivienda y preparación de alimentos en caso de que se niegue a acudir a C.Día. Como última opción sería solicitar al juzgado ingreso involuntario en Residencia.////// Pilar aún no tiene listo en Informe Social, intentará tenerlo esta misma semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-04-30','TERESA: SE ENVÍA ACEPTACION PIA FIRMADA CON CONTRATO DE AYUDA A DOMICILIO DEBIDAMENTE FIRMADO, ME QUEDO UNA COPIA Y LA OTRA LA DEVUELVO A LA EMPRESA','2');
