insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-04-30','TERESA: LLAMA LA MADRE (MARISOL) PARA PREGUNTAR QUE TAL ESTA MARIA, LE COMENTO LO QUE SE ACORDO EN LA SUBCOMISION, ELLA COMENTA QUE NO ESTA LLENDO A CEDEX Y QUE SIGUE CONSUMIENDO CON LO CUAL NO ESTA CUMPLIENDO CON CONTRATO DE COMPROMISO QUE HABLO CON EL DOCTOR IDILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-04-30','Ana: Alberto, responsable de la Sección Eco. me comunica que le han pasado una factura a J.Pedro de Teleasistencia. Desde el área soc. no sabemos nada, además nos parece muy raro estando en el centro. *Llamo al Hogar de Nazareth (927 416 563), hablo con Raquel, me dice que no se ha contratado nada desde el centro. De todas formas el jueves le preguntará a Puerto, hoy no está. ****Se lo comunico a Alberto para que devuelva el recibo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-04-30','Ana: En relación al informe de la visita a Felipe remitido por Toni-Futuex. Consulto a los compañeros de la S.Jurídica sobre la titularidad de la vivienda que dejó en testamento a Felipe su madre. Miguel me corrobora que *la vivienda está a nombre de Felipe. //////// En cuanto a la cuestión económica, Juana me informa que la cuantía semanal autorizada para Felipe desde la Comisión son 50 €.////////// De ambas cosas informo a Toni para que puedan explicar y tranquilizar a Felipe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2019-04-30','TERESA: JULIA PLENA INCLUSION me pongo en contacto con ustedes para comunicarles que desde el pasado lunes día 22 de abril Saúl se encuentra hospitalizado en el Hospital de Mérida. Con fecha de hoy, día 24 de abril de 2019, su médico asignada, la Doctora Zapata, se pone en contacto conmigo para que me desplace hasta el hospital y así poder informarme de las novedades con respecto a Saúl. Me comunica a mí, y a su padre, el cual ha estado presente desde el primer momento del ingreso, que el estado de salud de Saúl es crítico. Está con tratamiento antibiótico a la espera de que mejore, pero la Doctora nos ha indicado que es muy probable que Saúl finalmente fallezca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2019-04-30','TERESA: HABLO CON JULIA Y ME COMENTA QUE HOY LE DAN EL ALTA PORUQE SE HA RECUPERADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2019-04-30','Ana: Puerto Barroso, TS del SSB-Plasencia, nos remitió por email una carta que les ha hecho llegar Carmen al Ayto. en el que pide "ayuda" porque la Comisión Tutelar no le manda dinero extra. *** Respondo al e-mail de Puerto-TS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-05-02','Ana: Recibo llamada de Puerto, Hogar de Nazareth de Plasencia, corroborando que desde que José P. está en la residencia no ha tenido el servicio de teleasistencia. /////// Aprovecho para preguntarle qué tal sigue J.Pedro y dice que está muy bien, participa en todas la actividades, come bien y se encuentra bien. Sólo se desestabiliza un poco cuando recibe visitas de los hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2019-05-02','-PTO. MENSUAL DEL PISO DE PROYECTO HOMBRE : Caso Manuel Domínguez MARIA MERCEDES CRUZ DUQUE>mcruz.cdmeba@caritas.es> Buenos días Amalia Soy Mercedes Cruz, la técnico que lleva el programa de viviendas de Cáritas en el que está a día de hoy Manuel Domínguez. Me comentó Ahinara que hablasteis el viernes. El número de cuenta al que habría que hacer el ingreso es: ES12 2085 4501 1403 3032 9827 y en concepto poner: Aportación del mes.... de Manuel Domínguez. Hemos comenzado a realizar algunas gestiones con él: Empadronamiento Asignación de médico de cabecera Tarjeta de demandante de empleo Él me ha hecho un planteamiento de gastos mensual, que sería el siguiente. 100€ para tabaco 45€ para gastos varios del día a día. 100€ manutención de su hija Alicia. 100€ aportación a la vivienda. 35€ mensualidad del gimnasio 50€ visita mensual a su pueblo. 60€ relaciones con chicas de alterne. Total: 490€, los 100€ que le faltan de lo que él cobra, se lo pondría su padre. Tenemos que tratar y trabajar con él varios puntos de su planificación, para empezar, no puede gastar más de lo que gana, y por otro lado, sus prioridades y necesidades. Nunca he trabajado con ningún participante que estuviese tutelado, por lo que no sé si vosotros tendréis que citarlo y sois quienes marcáis las líneas sobre su planificación económica o directamente vamos trabajándolo nosotros con él. En la vivienda se está adaptando bien, con miedos e incertidumbres por el cambio y lo desconocido, pero con apoyo de los compañeros y voluntarios. Tanto el voluntario como yo, estamos muy pendientes de él, le damos varias citas a la semana, se acude a la vivienda y se le está acompañando a las gestiones que va realizando. Por otro lado, sabemos que está a la espera de plaza en otro recurso, pero no sabemos nada de los tiempos (aproximados), que podría tardar y por lo tanto cuánto tiempo estaría en la vivienda. Si hay alguna indicación que debamos tener en cuenta, puedes contactar conmigo en los datos que aparecen abajo. Un saludo Mercedes Cruz Duque Técnico del Centro de Promoción y Empleo de Cáritas Diocesana Mérida-Badajoz Paseo de la Radio s/n Contacto: 607557412/ mcruz.cdmeba@caritas.es','2');
