insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CORBACHO'and apellido2='GALINDO'),'2019-05-02','-SE ENCUENTRA EN " LA GRANADILLA " , TIENE DETERIORO COGNITIVO . ESTÁ TB ALLI INGRESADA LA MUJER TB EN PROCEDIMIENTO INCAPACITACION . TIENE UN HIJO TOXICOMANO QUE LOS HA ENDEUDADO . TIENE UNA DEUDA DE 30OOO PQ LOS PUSO DE ABAL JUNTO CON SU EXMUJER. LES RECLAMAN ESE DINERO . TIENEN UNA CASA EN ENTRIN BAJO EN LA QUE VIVE EL HIJO , SE PODRÍA VALORAR VENDER LA CASA . A LA MUJER LE LLEGAN DEUDAS DE TRAFICO , EL COCHE ESTÁ A SU NOMBRE Y SON MULTAS DEL HIJO . PERCIBE UNA P.JUBILACION CON CPTO A MINIMOS DE LA QUE SE ABONA EL 65% PARA EL PAGO DE LAS DOS PLAZAS . LA TS VA A SOLICITAR PNC A LA MUJER , MIENTRAS SEGUIMOS IGUAL SE LE ABRIÓ UNA CUENTA NUEVA , DONDE APARECE ÉL SÓLO DE TITULAR .HAY QUE INCLUIR A CONSOLI , NO HAGO CAMBIO DE PENSIÓN PQ YA ESTÁ EN LA NUEVA. EN ESA CUENTA VAN A CARGAR PELUQUERIA Y PODOLOGIA , NO GASTAN NADA MAS . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-05-02','-HABLO CON JACKELINE , VINO MERCEDES A COMENTAR QUE LA IBA A CONTRATAR 2H AL DIA DE L A V POR 250€ . JACK. ME COMENTA QUE HA CAMBIADO DE OPINION Y NO VA A DEJAR SU TRABAJO POR MERCEDES PQ ES MUY INESTABLE, QUE ESTUVO AYER POR LA MAÑANA A LIMPIAR SU CASA . POR LA TARDE MERCEDES FUÉ A SU PISO Y VIO EN UNA VITRINA UNA VAJILLA DE LA MADRE QUE SEGÚN JACK ÉSTA LE REGALÓ . Y QUE A PARTIR DE AHÍ NO LA HA VUELTO A LLAMAR. AD','2');
