insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-05-03','-MIRYAM , LA INTERNA QUE TIENE ROSARIO SE QUEDA EN LAS MISMAS CONDICIONES EN LAS QUE ESTABA CON ROSARIO HASTA QUE SULLI OBTENGA SU REGULARIZAION PARA HACERLE CONTRATO DE INTERNA. Miryam consuelo ramirez rovira>miryamramirez@hotmail.com> Buenas tarde Amalia. Gracias por responder. Ya hablé con Inmaculada. En este sentido le informo que mi decisión es continuar con Rosario, en las mismas condiciones de hasta ahora. En consecuencia, luego le haré llegar la relación de horas pendientes. También hablé con el Sr. Rafael y ya está resuelto lo de mi fin de semana pendiente de marzo y el que corresponde al mes de abril. Ya hoy Elo me dió los 250 euros de la compra. Gracias por hacer efectivo el pago de mi sueldo que estaba pendiente. Por ahora, sin más novedades. Que le rinda su jornada','2');
