insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-05-03','TERESA: RECIBO EMAIL DE LA TS : He hablado con Mª Elena, a ella no le importaría venirse a Zafra de alquiler, tenemos otra usuaria que también tiene problemas económicos y estaría dispuesta ha compartir con Elena; el piso costaría 125 € al mes. También hemos hablado con Zafra Solidaria y ellos le podrían dar la cena de lunes a viernes y las comida y cena los fines de semana y de lunes a viernes comer con nosotros en el comedor, valdría 3 € al día (un total de 15 € a la semana) le saldría la comida en total a 60 € al mes aproximadamente, mas lo que ella tenga que comprar extra. LO PASO A SECCION ECONOMICA A LA ESPERA DE APROBACION','2');
