insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2019-05-03','Ana: Recibo correo de Luis Polo, director del CRR-Plas. en relación a Martín Miguel expresas: "...Martín Miguel Miranda Hernández. Ayer a las 15:00 h. acudió un funcionario del Ayuntamiento de Cáceres para notificar que a Martín le ha tocado ser presidente en una mesa electoral, de cara a las próximas elecciones europeas, autonómicas y locales. En ese momento no pudo entregar el funcionario la notificación y dejó sus datos para poder contactar con él. Todavía no hemos tenido oportunidad de abordar este tema con Martín, no sabemos si él querría o no estar como presidente de mesa electoral. Entendemos que el primer paso es trasladaros a la Comisión esta información para que podáis valorar o ver cómo abordar este tema con Martín. Por si acaso, te dejo los datos de contacto del funcionario del ayuntamiento y de su jefe: Funcionario: Oscar. Telf: 666 81 94 08 Jefe: Manolo Padilla. Telf: 927 255 870...." *Respondo al correo diciendo que lo pondré en conocimiento de los Asesores Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-05-06','Ana: Recibo llamada de Mª Eugenia, TS del CP Zaragoza (Zuera), se ha concedido el traslado al C.P. de Badajoz, en estos momentos está en tránsito en el Penitenciario de Valdemoro.///////////// Le pregunto por los informes pendientes, el del Psicólogo y el del Ed. Social, no los hemos recibido. Dice que tiene constancia de que se les solicitaron en el centro, pero si no se han enviado ya, como el expte. se ha enviado con el interno, ya no pueden enviarnos nada. Que lo pidamos a C.P. de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-05-06','TERESA: SE ACEPTA INGRESO EN UDAC QUEDA SUPEDITADO A AUTORIZACION DE INGRESO INVOLUNTARIO NO URGENTE ANTE EL JUZGADO. LO PASO A ANGEL PARA QUE LO SOLICITE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2019-05-06','TERESA: ME MANDAN EMAIL DESDE CENTRO RESIDENCIAL PARA VALORAR QUE PENSIN LE ES MAS FAVORABLE. LE INDICO QUE ORFANDAD MAS PFHC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-05-03','Ana: Acudo a la Residencia Puente Real de San Vicente de Alcántara, me reuno con Vere, Directora, y Carmen, Médica. Al poco de comenzar a hablar llega J.Ramón a la residencia, hecho que no esperábamos y se le invita a pasar y hablar con nosotras. Me presentan y J.Ramón comienza a alterarse un poco, dice que quién soy yo, que por qué tiene que hablar conmigo, que él no está tutelado, qué por qué tengo yo información y documentación suya que eso es ilegal, que qué juez ha dicho eso si él no ha ido a ningún juicio... Cuando se calma le explico por qué estoy allí, que lo único que queremos todas las persona implicadas es ayudarle. Dice que en la residencia se está muy bien, pero cuando esté arreglada la cubierta del edificio, en un mes máximo, se vuelve a su casa. Le planteo, que en ese caso sería conveniente que contara con algún tipo de apoyo diario y se le ofrece diversas opciones; centro de día, ayuda a domicilio, catering o combinación de algunas de ellas, pero su única respuesta para todas ella es NO. Dice que cuando a él le haga falta algo ya lo pedirá él personalmente. Dice que él se ha valido por sí mismo durante los últimos 20 años y que así quiere seguir haciéndolo. Al preguntarle qué come cuando está en su casa dice que comida precocinada. Por más que se le explica que tiene una cardiopatía y debería cuidarse y llevar una dieta sana y que su edad ya es avanzada, no hay forma de hacerle entrar en razón. **En cuanto a la Incapacidad para conducir, según sentencia, me la pide para leerla, dice que no puede ser, que tiene renovado su permiso de conducir, le explico que quizá eso en Tráfico no lo sabían o ha habido algún error. Ha venido conduciendo en el coche que compró hace unos días. **No tiene conciencia de enfermedad ni de su Incapacidad Judicial ni quiere aceptarlo. ***En cuanto a otros aspectos de su autocuidado, Ramón desprende un fuerte olor. A pesar de la alta temperatura del día acude con camiseta interior, jersey y cazadora abrochada hasta el pecho, una vez finalizada la converesación la médica le dice que debería ducharse, qué huele mal, pero de entrada él se niega, le cuesta un rato convencerlo y va medio obligado a la ducha, según nos informa después la Auxiliar llevaba puestos 2 pares de pantalones. Al parecer es una práctica habitual en él la de ponerse varias prendas de ropa superpuestas. **Por sí mismo no mantiene correctos hábitos de higine, se ducha cuando medio le obligan y les cuesta convencerlo para echar la ropa a lavar, para él nunca está sucia. **La medicación a pesar de que se la preparan en el pastillero, hay días que no la toma correctamente, porque llega a la residencia con pastillas "de sobra". ////////////// Acudo al SSB de Valencia de Alcántara, Pilar dice que de nuevo no ha podido finalizar el informe, si falta me lo enviará el lunes 6. Le informo de la entrevista mantenida con J.Ramón y que se niega a aceptar ninguno de los recursos planteados. Está claro que Ramón no presenta capacidad para volver a vivir solo en su domicilio sin ningún tipo de apoyo. //////// Hablo con uno de los policías municipales en relación a la incapacitación judicial para conducir y les comunico que los compañeros del Área Jurídica se encargarán de comunicarlo a tráfico.','2');
