insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-05-06','TERESA: ENVIO CONTRATOS PARA SERVICIO DE COMEDOR QUEDA PENDIEWTE DE VALORAR LA OPCION DE CENTRO DE DIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-03','Ana: Recibo un correo de Luis Sancho Polo, director CRR-Cáceres: "...en relación a Consuelo Nevado Pacheco, quería informarte que ayer por la mañana realizaron la primera intervención quirúrgica, en la que iban a tratar la vértebra lumbar que detectaron estaba dañada. La intervención fue larga (unas cinco horas) pero los médicos informaron al padre de Consuelo que todo salió muy bien y había sido un éxito. Por la tarde, una de nuestras monitoras pudo hablar con el padre y pudo ver también a Consuelo y se encontraba muy bien. El padre, Diego, que es quien está estos días en el hospital acompañando a Consuelo, nos comentó que necesitaban apoyo, porque él se encontraba muy cansado y por su situación de salud tampoco puede atender las necesidades actuales de Consuelo; y por otro lado, el hermano de Consuelo se encuentra en el pueblo cuidando de la madre, que también tiene una salud delicada." Respondo al correo, pregunto cuántas horas al día apróx. serían y si conocen alguna empresa que pueda prestar bien el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-06','Ana: Llamo a Luis Sancho, director CRR - CC. El planteamiento acompañamiento a Consuelo es el de un apoyo por las tardes principalmente, pues desde que le han ajustado la medicación está haciendo bien las noches y por las mañanas con la visita médica allí no dejan estar a nadie. Acordamos 4 horas diarías a ser posible no consecutivas (a la hora de la comida y luego más tarde). Me enviarán al email el contacto de una empresa.','2');
