insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-05-07','Creo que la tienda no tendrá problema en darnos mensulamente la factura y que se le pague por banco, y sí, la auxiliar puede ocuparse de la compra, aunque los fines de semana escapan a nuestro alcance por ahora (salvo que pudiésemos gestionar un SAD por dependencia para el fin de semana). Ya he presentado la incapacitación de la madre en la fiscalía el viernes pasado. ENVIADO POR TS DE GUADIANA DEL CAUDILLO . LA SEMANA PASADA LO VISITÉ EN SU DOMICILIO . VIVE CON LA MADRE EN UNA VIVIENDA QUE NO REUNE CONDICIONES DE HABITABILIDAD E HIGIENE . ALTO GRADO DE DISCAPACIDAD , NO LE DAN TUTELA SINO CURATELA EC. Y SALUD. FUMA 3 PAQUETES DIARIOS Y TOMA 2L COCA COLA . DESDE HACE UN MES ACUDE A COEMR AL CTRO DIA CON SU MADRE Y AL MENOS SE CONTROLA UN POCO LA ALIMENTACION DADO QUE ES DIABETICO . LA MADRE MUY MAYOR EN PROCESO DE INCAPACITACION. CON MUCHISIMAS DEUDAS , RECOMPRO LA CASA FAMILIAR TRAS EMBARGO DE LA MISMA . TIENE OTRA VVDA EN PROPIEDD CERRADA CON HIPOTECA ,HAY QUE VENDERLA O ALQUILARLA. PTE. HACER INVENTARIO. PFHC LE DAN DE BAJA CON FECHA 1 ABRIL . YA TENGO CTA BANCARIA NUEVA DONDE HACER NUEVA PFHC , EN ALEGACIONES SOLICICTAR QUE LE ABONEN ABRIL , MAY Y JUNIO .','2');
