insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2019-05-08','Ana: Se recibe correo de Julian-Cocenfe: "Buenas tardes. Informamos que Tomás ha acudido a una revisión óptica. Tras el examen optométrico que adjuntamos se recomienda el cambio de gafas por los motivos que se adjuntan en el informe. Tomás viene solicitando el cambio de gafas desde hace unos meses. Solicitamos que se apruebe presupuesto para poder realizar el cambio de gafas. Un saludo Julián Álvarez Delgado Gerente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-05-08','-LLAMA SU HNO. NO QUIERE QUE SE VENDA LA CASA PQ ÉL NO TIENE DONDE IR . SE LE INTENTA EXPLICAR LA SITUACIÓN DE SU HNA Y QUE SE VALORARÁN TODAS LAS ALTERNATIVAS POSIBLES. LLAMO AL DTOR . DEL CRR PARA CUADRAR UNA CITA , EL DIA 21 DE MAYO A LAS 12.00 , QUIERO SENTARLOS A LOS DOS HERMANOS Y VALORAR OPCIONES . QUE DECIDA ELLA ASUMIENDO LAS CONSECUENCIAS. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-05-08','TERESA: Mª CIELO: Estamos teniendo problemas con la organización que te conté con respecto a Mª Elena. El viernes por la tarde me llamo para decirme que no quiere irse de alquiler y ayer me dijo otra vez que sí, hoy ha dicho que quiere Piso Supervisado; nos tiene un poco confusos; y lo peor es que la chica con la que le planteamos compartir también tiene sus propios problemas y la esta mareando. Nosotros vamos a ver si somos capaces de reconducirla, pero no me atrevo a confirmar lo del alquiler porque no quiero que esto también afecte a la otra chica; que también tiene mucha necesidad. Por este motivo, creo que es mejor que se plantee también lo del piso supervisado; se puede remitir un informe junto a la derivación a piso supervisado hablando de la emergencia del caso o comunicarlo al juez y que sea por orden judicial; aunque no sea involuntario. ACUERDO CON ELLA SOLICITAR INGRESO INVOLUNTARIO AL JUEZ Y SOLICITAR RAL LA PSICÓLOGA LE VA A PROPONER IRSE A VIVIR CON SU HIJO A ZAFRA HASTA QUE RESOLVAMOS LA PLAZA PARA SACARLA DEL DOMICILIO CUANTO ANTES','2');
