insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-09','Ana: Recibo por mail presupuesto. Llamo a Luis Sancho, director CRR-CC (927 18 11 09 - 687 487 908), plantean 14,70€ la hora. Nos resulta un poco caro. ////// Llamo a Lucía, particular que ya ha colaborado en otras ocasiones con la Comisión haciendo acompañamientos. Se muestra disponible, cobra 10€/hora. Tras hablarlo con Alberto, Responsable de ECO y Luis Sancho, acordamos que será ella quién realice el acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-05-10','Ana: A última hora de ayer recibimos en el ctutelar@ correo de Lilia Ana, TS SSB de Aldea Moret: Buenos días. Reitero mi preocupación acerca de Paula Solana Guerra. Esta mañana ha acudido a los SS.SS. de Atención Social Básica de Aldea Moret en muy mal estado: mucho más delgada, con muy mal tono de piel, mucho más alterada de cómo acostumbra a venir, gritando, reiterándose mucho en sus delirios y sin poder mantener una conversación coherente con ella, manifiesta que está secuestrada y que le han roto los muebles. Ha acudido a un servicio privado de salud “Los Ángeles del Socorro” que le han diagnosticado una tendinitis. Hemos conseguido que acuda al centro de salud, donde la está atendiendo su médico de cabecera y donde la estaba esperando la trabajadora social para valorar un posible ingreso. Está empezando a aceptar la posibilidad de ingreso en residencia. Os he llamado en reiteradas ocasiones para comunicaros en el estado en que se encuentra. Os pido por favor que me llaméis cuando leáis este correo pero reitero que la situación es muy grave. Un saludo. LILIA ANA"//// Llamo a Lilia Ana 927-231295: Cuando acudió al SSB ayer Paula, llegó muy alterada, solicitando que la lleven "donde está Martina", la vio muy desmejorada; mucho más delgada, la tez muy blanca y despeinada. Consiguieron convencerla para que fuera al C.Salud, donde sí que llegó a atenderla su médico. Pero ya no sabe qué pasó después.//////// Llamo a Valentina, T.S. C.Salud Aldea Moret (52515). A Paula la ingresaron ayer en el Hptal. Virgen de la Montaña, la vió ya muy deteriorada y siendo así sí ve **conveniente ya su INGRESO en Residencia. De hecho la propia Paula vervalizó a las compañeras Aux.Admtivas. del C.Salud que se quería ir a un centro. **Me enviará informe médico de Urgencias de ayer. **Se reitera en que ella no puede hacer informe social por los motivos que ya argumentó en su día. Expresa que es claramente PACIENTE DE "PSIQUIÁTRICO DE TODA LA VIDA" ***Recibo el informe de Urgencias del HVM, lo escaneo guardo en su expte. ///////// Llamo a Mª José, TS del Hptal. Virgen de la Montaña - CC (56950), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-05-10','-AYER SE CELEBRÓ EN EL CRPS DE BADAJOZ SUBCOMISION DE CASOS A PETICION DEL ESM DE JEREZ DE LOS CABALLEROS. ACUDEN LA TS Y ENFERMERA DEL CENTRO , DELEGADA TUTELAR DE FUTUEX , AMALIA DE CTAEX . NO ASISTEN DE LA UNIDAD DE SALUD MENTAL DEL SEPAD NI LA PSIQUIATRA. LOS ACUERDOS LOS REENVIARÁ ANA DELFA( MIEMBRO PTE. DE LA SUBCOMISION ) A TODAS LAS PARTES PERO BREVEMENTE INDICO LOS SIGUIENTES : -EL DIA 31 DE MAYO TIENEN CITADA A PALOMA EN EL ESM , VAN A ABORDAR CON ELLA LA OPCION DE INTERNAMIENTO VOLUNTARIO EN LA URH DEL CSS. SI ESTO NO SURTE EFECTOS , DESDE LA CTAEX INICIAMOS PROCEDIMIENTO JUDICIAL DE INTERNAM. INVOLUNT. EN CSS CON INFORMES MEDICOS Y SOCIALES QUE YA OBRAN EN SU EXPEDIENTE. -A LA VEZ DESDE LA CTAEX , SE VA A SOLICITAR POR PIA INGRESO EN RAL/ V.T , PARA SABER SI EL CADEX DARÍA PERFIL . -DESDE EL ESM VAN A SOLICITAR A TRAVÉS DE ESTA SUBCOMISIÓN INGRESO EN CRR , PARA QUE LA VAYAN INCLUYENDO EN LA LISTA DE ESPERA , CON EL OBJETIVO DE QUE SEA UN RECURSO QUE GARANTICE LA CONTINUIDAD DE CUIDADOS. DESDE TODOS LOS SECTORES QUE ESTUVIMOS EN LA REUNION SE OPINA QUE HAY QUE PROCEDER A REALIZAR UN INGRESO . DESDE EL SSB Y CENTRO DE SALUD TENDRIAN QUE ABORDAR LA PROBLEMATICA DEL PADRE , UNA PERSONA MAYOR DEPENDIENTE A LA QUE CUIDA SU HIJA. AMALIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2019-05-10','Ana: Recibimos de la Gerencia Territorial del SEPAD-Plasencia Documento de conformidad con el PIA propuesto "Mantenimiento de plazas en Residencia y C.O. Vera". Lo pongo para la firma de la D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-10','Ana: Recibo llamada de Pablo, TS del ESM Plas. Ha hablado con la Médica-Psiquiatra y ésta dice que no puede hacer un informe en ese sentido pues a penas la conoce.///////// Ana: Llamo a Servicio Territorial de Cáceres, a Gestión de Centros II, hablo con Pedro, TS (927004239). Entiende la situación, Mª Luisa en principio sí da perfil para C.Residencial, pero según la instrucción sin el informe de psiquiatría pertinente en principio no se le puede adjudicar plaza. *Le enviaré por mail el informe emitido por las TS del C.Salud y del SSB en enero. ***Él hablará con Plácido Alejandre, Jefe de Sección a ver qué pueden hacer.////// Vuevle a llamar Pedro, de Serv.Terr.CC, su jefe le ha dicho que sin el informe de psiquiatría no se puede hacer nada. Necesitan 1- un diagnóstico claro y 2- que acrediten que no tiene alteraciones conductuales que dificulten el normal funcionamiento del centro. //////////// Vuelvo a llamar a Pablo, TS ESM, propongo que le den varias citas para diagnosticarla, pero dice que sin un INGRESO para que puedan diagnosticarla libre de condicionantes externos, la psiquiatra no puede establecer un diagnóstico y emitir informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-10','Ana: Hablo con Lucía (605 15 13 70). Acordamos que comenzará el próx. lunes 13, serán 5h/día de L-V, distribuidas en horario de 12:00 a 14:00 y de 17:30 a 20:30 h. *El lunes acudirá a Feafes para que le informen sobre aspectos importantes y así dar mejor servicio. Le confirmo que debe preguntar por Pedro, TO y que Consuelo se encuentra en la habitación 609 del hptal. San Pedro de Alcántara. //// Intento llamar a la habitación para hablar con el padre de Consuelo, pero me dicen que ese servicio sólo funciona por la tarde. ////// Llamo a su hermano, Manuel (643 352 548), hablo con él y con su padre, Diego, se muestran muy agradecidos por la gesión del acompañamiento hospitalario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-05-10','TERESA: HABLO CON ELENA Y ME INSISTE EN QUE NO QUIERE IRSE DE SU CASA, QUE NO HA VUELTO A PASAR NADA Y QUE LE HA DICHO A SU HERMANO QUE SI LA TOCA LO VA A DENUNCIAR. ME PIDE POR FAVOR QU LA DEJE EN SU CASA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2019-05-10','-REALIZO VISITA EN EL PISO DE CARITAS DE LA RED DE DROGAS. SE APRUEBA EL PTO. QUE NOS HABIAN ENVIADO ,QUEDO PTE. QUE LA PARTE ECO ME DIGA CUANTO PUEDE SACAR SEMANALMENTE , SEGURAMENTE SERÁ PARA EL DIA 20 DE MAYO Y HAY QUE AVISARLE A ÉL PARA QUE PUEDA IR A SACARLO. LA PNC NO LA CAMBIO DE CUENTA , SE MANTIENE EN LA CAIXABANK DONDE ESTABA , LO SACARÁ EN LA OFICINA DE Mª AUXILIADORA. HAY QUE COMUNICAR A PNC QUE SOMOS TUTORES PARA QUE NOS PASEN LA DECLARACION ANUAL . COMO MINIMO EN EL PISO PODRÍA ESTAR 6MESES SUPEDITADO A NORAMAS DE CONVIVENCIA , NO HAY UN MAXIMO . ESTAREMOS ATENTOS A LA LISTA DE P.SUPERVISADO S.M. ESTÁ EL 10 . SOLICITO QUE HAGAN TRASLADO AL ESM DE VALDEPASILLAS, Y SEGURAMENTE SOLICITEN DERIVACION A CRPS. EL PISO NO ACEPTA CONSUMO DROGAS ES MOTIVO DE EXPULSION. ANALITICAS EN CEDEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-05-10','-CORREO DE ESPERANZA , TS DEL ESM: Buenos dias, antes la imposibilidad de contactar con vosotros por via telefonica os escribo al unico correo que tengo del equipo .os rogaria que me proporcionarais un telefono con el que me pudiera comunicar cuando tengamos casos comunes.muchas gracias ahora paso ha explicarte el motivo de mis llamadas recibi la resoluccion de jose Maria valle Simon donde se indica que se acepta la derivacion del paciente a CRR por grado de dependecia II y queda en lista de espera ,pero indican que tiene que presentar una revision de PIA ya que essto es necesario para cuando le vayan a dar la plaza (quedo en vuestras manos para que se lo soliciteis ya que sois vosotros lo que teneis que firmar esa solicitud ) una vez cumplimentado podeis mandarlo a dependencia o enviarmelo a mi para que yo lo envie ,como lo veais mejor.','2');
