insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-05-10','Ana: Llamo a Pilar, TS de Valencia de Alcánara (627 34 11 19 / 927 580 326, ext.8). En relación al último informe de visita de Futuex, en el que expresan que denotaban una posible coacción por parte de su nieto, Pilar expresa que este caso siempre ha estado marcado por las malas relaciones familiares, que no le extrañaría que hubiera coacción, pero que también hay que tener en cuenta el deterioro que presenta Manuela y que el único cuiador es el nieto, por lo que es normal que siempre le mire a él antes de contestar. //////// La empresa que le presta el SAD es Servicios del Fresno (924 67 77 05) y la T.O. que hace el seguimiento del mismo se llama Eva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2019-05-14','TERESA:LLAMO AL PADRE FERNANDO POR PETICION SUYA A TRAVES DE EMAIL Y ME COMENTA QUE BASILIO SIGUE SIN PERMANECES EN EL CETRO PORQUE SE VA A SU CASA. DESDE EL JUEVES PASADO NO HA VUELTO AL CENTRO POR ELLO PUSO UNA DENUNCIA, LA GUARDIA CIVIL LO HA ENCONTRADO EN SU VIVIENDA EN LA CAMA, LLEVABA ALLI DOS DIAS. HA PASADO UN DIA EN EL CENTRO YA QUE NO SE ENCUENTRA BIEN DE SALUD, HOY LO HAN DERIVADO A PLASENCIA PARA QUE LO VEAN EN URGENCIAS PORQUE SE QUEJA DE DOLOR EN LA PIERNA, FISICAMENTE SE ENCUETRA MAL. FERNANDO NOS COMENTA QUE LA VIVIENDA SE ENCUENTRA EN CONDICIONES INFRAHUMANAS, NO POSEE CUARTO DE BAÑO NI LUZ ELECTRICA A PESAR DE ELLO BASILIO QUIERE SEGUIR VIVIENDA EN ELLA. FERNANDO NOS COMUNICA TODO ESTO PARA QUE TOMEMOS ALGUNA MEDIDA YA QUE LA SITUACION ES INSOSTENIBLE Y NO HAY MANERA DE RETENERLO EN EL CENTRO. LA GUARDIA CIVIL VA A PRECINTAR LA CASA DEBIDO A LAS CONDICIONES DE INSALUBRIDAD EN LA QUE SE ENCUENTRA. EL CASO ES COMPLICADO PORQUE EL QUIER VIVIR ASI. YO LE PROPONGO LA OPCION DE UN TRASLADO PERO TENEMOS EL INCOVENIENTE DE QUE TIENE UN GRADO I DE DEPENENCIA Y ECONOMICAMENTE SOLO RECIBE UNA PNC.','2');
