insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-05-15','Amalia, cuando puedas me llamas, he hablado con el banco y la situación está así: - No están ingresando la Seguridad Social los 392 € de la prestación familiar , allí consta en baja cuando ya habéis comunicado la situación de curatela. - Me dicen también que tienen una orden periódica de transferencia de la cuenta de la madre de Juan Carlos, a la suya propia de más de 1000 € mensuales, porque en la cuenta de la madre hay un embargo, y que todos los recibos se pagan desde la cuenta de Juan Carlos. - Este mes han devuelto el recibo del centro de día porque no hay saldo. - Juan Carlos aún sigue manejando sus cuentas, aunque ya aparece el nombre de la gerente del SEPAD, no han recibido ni la sentencia de curatela ni ninguna orden al respecto y por tanto él sigue sacando el dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2019-05-15','Ana: Recibimos correo de la Residencia Ciudad Jardín Parque del Príncipe - CC: "Buenos días: Hoy repasando expedientes hemos visto que las dos personas que están tutelados por la Comisión de Adultos, Jacinta Cabrera Mora y Rafael Fernández Bermejo, no tienen firmado algunos documentos del centro, como contrato, reglamento y orden de domiciliación de adeudo directo SEPA. ¿Cómo hacemos para que se firmen? Gracias, un saludo Maribel Trabajadora Social" Respondo al correo diciendo que puede hacernos llegar los documentos por correo postal ya firmados por la Residencia y cuando los tengamos firmados por D.Gerente, les devolveré sus copias por correo certificado. ///////////////// Recibo otro correo de Maribel, la TS de la Resid. Ciudad Jardin de CC: "Buenos días, Ana: He enviado a la comisión tutelar, sección económica, el presupuesto de lo que necesita Jacinta Cabrera. También te comento que el lunes 20 vienen a **valorarla del SEPAD por la ley de dependencia, ya te mantengo informada. En cuanto a los documentos te los remitiré por correo postal a la semana que viene. Un saludo Maribel"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2019-05-15','Ana: Recibimos correo de la Residencia Ciudad Jardín Parque del Príncipe - CC: "Buenos días: Hoy repasando expedientes hemos visto que las dos personas que están tutelados por la Comisión de Adultos, Jacinta Cabrera Mora y Rafael Fernández Bermejo, no tienen firmado algunos documentos del centro, como contrato, reglamento y orden de domiciliación de adeudo directo SEPA. ¿Cómo hacemos para que se firmen? Gracias, un saludo Maribel Trabajadora Social" Respondo al correo diciendo que puede hacernos llegar los documentos por correo postal ya firmados por la Residencia y cuando los tengamos firmados por D.Gerente, les devolveré sus copias por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2019-05-15','Hablamos, con el abogado Francisco Elías Rodríguez Plaza(606529869) y con la procuradora María Cristina de Campos Ginés (600576422-cristinadecamposgines@gmail.com), para que nos envíen el escrito que van a presentar con motivo del pago de los 60000 euros en concepto de responsabilidad civil, ante la Audiencia Provincial nº 2, de Cáceres (Pieza Individual del Condenado 2/2018).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2019-05-15','En relación con la herencia de la madre de Luisa y sus hermanos, hablo con Mercedes (694472202-estherrodriguez80@yahoo.es), porque no está conforme con el documento que han firmado todos los hermanos y nosotros, para el reparto de la herencia. Ella dice que el testamento es falso en la cláusula primera, donde indica que ella recibió en vida el ÍNTEGRO PRECIO, INCLUIDOS GASTOS NOTARIALES, REGISTRALES E IMPUESTOS DE LA COMPRA DE LA VIVIENDA DE DICHA HIJA SITA EN ELDA, INDICANDO QUE LA CANTIDAD DONADA POR LA TESTADORA, DEBIDAMENTE ACTUALIZADA SEGÚN EL IPC HASTA SU FALLECIMIENTO, SE TRAIGA A COLACIÓN Y SE LE IMPUTE A LA HERENCIA QUE PUDIERA CORRESPONDERLE A MERCEDES. Al no estar de acuerdo con este punto, dice que el testamento es falso y que ha redactado otro documento, porque tuvo que pedir un préstamo para la compra de la casa. Le hemos pedido que acredite documentalmente todo lo que recibió en vida de su madre, así como las escrituras de la compra de la vivienda, debido a que esas cantidades deben traerse a colación de la herencia. Asimismo, le indicamos que si cree que el testamento es falso, lo impugne vía judicial. Va a enviarnos al correo de la comisión documentación al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-14','Ana: Recibo llamada de Lucía - Acompañamiento hospitalario. El hermano de Consuelo ha preguntado si se puede quedar ella por las noches también, pues dice que necesita irse a descansar unos días y no quiere dejarla sola. Le explico que las horas acordadas de acompañamiento son las que son, pues nos informaron que Consuelo hace bien las noches y no necesita tener a nadie allí y por las mañanas tienen lugar las visitas médicas, por lo que tampoco puede estar nadie en la habitación. Ésto ya lo hablé también con el hermano y el padre de Consuelo. ////////// **Ayer le operaron de los tobillos, fue una operación larga, pero en principio todo fue bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-15','Ana: Recibo llamada de Cristina, Psicóloga CRR-CC. Probablemente le den el alta a Consuelo este viernes 17, pero necesitará estar al menos 3 mese encamada, por lo que así no puede volver al CRR. /////Llamo a las TS del Hptal. S Pedro de Alcántara - CC (927 25 63 41). Juani 56341 / Loli 56348. Hablo con Juani, no va a dar puntuación para plaza sociosanitaria y por sus posibilidades económicas tampoco temporal en residencia. Tendremos que solicitar plaza en Resid. Privada. Hablarña con Loli, TS que lleva la planta para que vaya a hablar con ella y explicarle./////// Lucía me comunica que quieren darle el alta mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-05-15','-SE PERSNA BRIGIDA Y OTRA COMPAÑERA DE SERVYSCOOP CON LAS FACTURAS DE ANDREA , ASCIENDEN A MÁS DE 1000€. SE LE EXPLICA QUE ESO NO LO PODEMOS PAGAR SIN ORDEN JUDICIAL , NO SÉ SI SE HABRÁ SOLICITADO. ELLA DICE QUE EL SERCICIO EN EL CENTRO SE LO PIDE ALGUIEN DEL CRR , Y ESE PTO . LO ACEPTÉ YO CON MARIA CLAROS , PENDIENTE QUE NOS ENVIARA EL PTO. PARA DAR EL OK DEFINITIVO. LUEGO PASA AL HOSPITAL , BRIGIDA DICE QUE SE LO PIDE LEONOR DEL CRR , LE DIGO QUE NO PQ LEO NO ESTABA EN ESA FECHA , ESTABA DE BAJA Y CON QUIEN YO HABLÉ FUE CON MARIA CLAROS. LUEGO RECTIFICA Y DICE QUE EFECTIVAMENTE AL PRINCIPIO HABLO CON MARIA . Y LUEGO FUE SU HNA TOÑI LA QUE CONTRATA EL SERVICIO , POR LO TANTO LE INDICO QUE DEBERÍA PEDIRSELO A LA HNA. HAY QUE CONCRETAR CÓMO SE VA A PROCEDER EN ESTE CASO. AD','1');
