insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2019-05-17','miguel, el día 11-6-19 tiene juicio en el jzdo merida nº2 por delitos leves de lesiones. Intento hablar por teléfono sin éxito con Juzgado de Mérida nº2 para hacerle saber el ingreso a efectos de que le notiquen a la penitenciaria de Badajoz (donde se encuentra desdes el 7/5/2019). Remito fax y adjunto justificante de ingreso en Penitenciaria de Badajoz y citación del Jzdo nº2 de Mérida para el 11/6/2019. Paralelamente solicitO del Jzdo de Mérida nº4, resolución del motivo por el que se encuentra ingresado en prisión preventiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-16','Ana: Llamo a Cristina, Psicóloga CRR-CC. (927 18 11 09 / 687 487 908)Como no consigo contactar envío un correo diciendo que comuniquen la situación al SEPAD-Salud Mental, para que planteen una alternativa temporal de recurso. /////// Me devuelve la llamada más tarde, dice que no consigue contactar con Mariluz Madrigal. Le indico que siga intentándolo, no obstante iré yo también a hablar con ella. ///////*Mariluz Madrigal me dice que en principio debería dar puntuación para plaza sociosanitaria, que además no tienen más alternativas. Llamaré a la TS del Hptal. para pedir que le pasen la herramienta./////////*Llamo a Luli, TS HSPA (Busca: 616 94 17 42) insiste en que esta paciente no cumple criterio para Plaza SocioSanitaria y no va a pedir a la enfermera que le pase la herramienta. Al solicitarle que no los comunique por escrito se niega. /////// Tras volver a hablarlo con Mariluz, solicito a Luli que nos remitan un informe médico en que especifiquen su estado de salud actual y las cuidados que necesita. Se lo pedirá al Traumatólogo.////// **Recibo por fax Informe de Alta del Serv. de Traumatología del Hptal. Pregunto a Luli, TS, quién es el Psiquiatra que ha visto a Consuelo, dice que cree que no ha habido Interconsulta, lo mirará bien y ya me dirá mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-05-14','miguel, tras conversación con el abogado de oficio me confirma que hay juicio. Llamo al Juzgado de Logrosán que me indica que no hemos sido citados y que si no nos lo han notificado es que no tenemos que asistir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-16','Ana: Pablo, TS ESM, me remite por fax informe en el que hacen constar las 3 veces que ha tenido consulta Mª Luisa en S.M. desde el año 1992 y en el que terminan diciendo: "...se trata una persona que hasta el momento actual no está diagnosticada de trastorno psiquiátrico ni ha realizado seguimiento en el ESM." //////// Ana: Llamo a Servicio Territorial de Cáceres, a Gestión de Centros II, hablo con Pedro, TS (927004239). Acordamos que le enviaré por email el Informe de Salud Mental que me ha enviado Pablo Cortés junto con el último informe de Medicina Interna. Cree que con esto podrán adjudicarle plaza. **Enviado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2019-05-16','Buenos días. Le adjunto los informes médicos de Basiliso. TERSA: NOS ENVIA FERNANDO EMIAL PARA INFORMAR DE SU ESTADO DE SALUD. EL médico de urgencias me enseñó la radiografía y es muy importante la artrosis que tiene en la cadera. Estaremos a la espera de la valoración de Traumatología. Él esta en silla de ruedas y de momento no puede marcharse. Seguiremos informando.ARCHIVO INFORME','2');
