insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-05-17','Ana: Llama Mercedes, TS de Plena Inclusión-Llerena, dice que Beatriz está fatal, llorando a todas horas, desde diciembre no ha vuelto a ver a su hija. Pregunta si se sabe algo del Régimen de visitas solicitado. Tras consultar a los compañeros de la Secc. Jurídica, informo a Mercedes de que el Juzgado aún no ha contestado. **Ángel, A.Jurídico, llamará hoy mismo al Juzgado. Les mantendremos informadas.','2');
