insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2019-05-15','Ana: Recibimos correo de Sonia - Asindi: "... comentarte que el padre de los hermanos Roberto y Justo Hernández Castaño está ingresado por lo que, aunque le correspondía ir este fin de semana a su casa, seguramente no puedan ir ya que la madre está con su marido en el hospital y no podrá atenderlos. Hemos quedado que mañana hablamos con ella para que nos confirme la situación y ver si pueden o no ir a verlos. Un saludo"','2');
