insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2019-05-17','Ana: Ayer recibí correo de Sonia Bernabé - ASINDI: "Hola, tras haber ido a consulta de planificación con Isabel Rodriguez Alcántara, adjunto os remito la autorización para la renovación del método anticonceptivo que utiliza. Un saludo" **Le adelanto por mail la autorización firmada y sellada escaneada. // Pongo oficio para registro de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2019-05-15','Ana: Recibo correo de Maribel, la TS de la Resid. Ciudad Jardin de CC: "Buenos días, Ana: He enviado a la comisión tutelar, sección económica, el presupuesto de lo que necesita Jacinta Cabrera. También te comento que el lunes 20 vienen a valorarla del SEPAD por la ley de dependencia, ya te mantengo informada. En cuanto a los documentos te los remitiré por correo postal a la semana que viene. Un saludo Maribel"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-05-17','-ficha que elaboro para el pto. : FICHA J.C. RUBIO GALAN -INGRESOS : 392€ PFHC * 12 M 207 € P. ORFANDAD * 14M La P. orfandad la percibe en otra cuenta diferente , donde tb se ingresa la p. jubiliación de la madre , unos 700€ . Mensualmente se transfieren estos 700 + la p. orfandad a la cuenta de J. Carlos pq la madre tiene un embargo . Hasta que seamos tutores de la madre , en proceso de incapacitación , tenemos que abordar esta cuenta en común , con la salvedad que la pensión de la madre no podríamos bloquearla. El objetivo es domiciliar en la cuenta de J.Carlos donde se ingresan todas las pensiones todos los suministros : -luz -agua -deudas OAR -plazas del Ctro. de Dia de ambos . -factura de la tienda de alimentación ( ya la tenéis ) Hay que bloquear la cuenta , para el mes que viene tendria que estar hecho para que no pueda sacar la extra. Las pensiones de este mes ya se las ha gastado . Hoy estaba citado en el SSASB y gracias a la colaboración con la compañera he conseguido aclarar que el dinero lo gasta además ,en rascas de la ONCE . Bloqueamos sus dos pensiones con las que se empezarán a pagar deudas y domiciliaciones. De la pensión de la madre , se está trabajando con la tienda de alimentación para que sea la Auxiliar de Ayuda a domicilio la que compre y la tienda nos envie la factura mensual. Igualmente con el estanco , estoy intentando conseguir que nos permita hacer lo mismo con el tabaco y que él solo pase a recogerlo . Echarle un vistazo y me decís que os parece esta idea y si sería viable . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-05-17','-TENGO PENDIENTE SOLICITAR LA PFHC , TENGO HASTA EL 30 DE MAYO PARA HACERLO , NO ANTES PARA EVITAR LA BAJA DE LA MISMA EN SS. CON RESPECTO A LA P.ORFANDAD HABRIA QUE CAMBIARLA A LA OTRA CUENTA , DONDE ESTÉ CONSOLI . ME LA TIENEN QUE DAR DESDE LA PARTE ECO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-17','Ana: Recibo llamada de Pedro Sánchez Sánches, TS Gestión de Centros - CC. Le han asignado PLAZA a Mª Luisa en la Residencia Juan Carlos Rodríguez Ibarra de Villafranca de los Barros. *Me enviará la resolución hoy por e-mail. **Pendiente organizar el Ingreso Involuntario cuando reciba la resolución.','2');
