insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2019-05-20','TERESA: RECIBO INFORME DE SALUD MENTAL DE SU CITA DEL 8 MAYO EN EL CUAL SOLO NOS ANOTA LA MEDICACION. FUTUEX NOS COMENTA QUE NO TIENE APENAS OCUPACIONES Y VEN CONVENIENTE QUE ESTUVIERA EN UNA VIVIENDA TUTELADA YA QUE LA RELACION CON SU MADRE ES TOXICA TAMBIEN NOS COMENTA QUE NECESITA DINERO PARA COMPRARSE ROPA SOBRE 150€','2');
