insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2019-05-20','Ana: Recibo llamada de Felix, dice que ha encontrado un comprador para la casa que tiene en Aceituna. Lo paso a la Secc. Jurídica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-05-20','TERESA: EMAIL DE FUTUEX Sobre las 11:10h de esta mañana, hemos recibido una llamada de Isabel, la trabajadora de Paloma. Nos ha comentado que cuando ha llegado a casa de Paloma, se ha encontrado la puerta abierta y no había nadie dentro. Ha llamado inmediatamente a Paloma y ésta le ha dicho que estaba en Zahinos con su padre. De hecho Isabel sospecha que se han ido hasta allí para sacar mas dinero porque la semana pasada Paloma estuvo en Badajoz con su padre y le confesó a Isabel que había vuelto a sacar dinero del banco. Isabel no ha sabido decir cuánto. El viaje de hoy a Zahinos creemos que es con la misma intención pero no estamos del todo seguras. Desde luego esta situación se ha ido completamente de las manos porque Paloma ha aprendido a irse a distintas localidades para sacar dinero y comprar lo que le parezca. Está totalmente fuera de control. Si nos entero de algo mas, seguirmos informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-05-17','Ana: Devuelvo a Juan la llamada, dice que necesita 10 € el lunes para acudir a la cita que tiene en el jdo. Se autorizará el extra. //// Por otro lado, dice que necesita 80€ para sacar el contador de la luz a la calle, que si no pueden hacerle la lectura se la van a cortar. Le digo que pida el presupuesto y nos lo envíen o que nos facilite el nº del empresario que conoce para ponernos en contacto y se niega a ambas cosas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2019-05-20','TERESA: HABLO CON TAMARA YA QUE NOS MANDAN EMAIL PORQUE EL TUTELADO SE ENCUETRA EN URGENCIAS DEL HOSPITAL, SU DUDA ES SI NO TIENE DINERO PARA EL ACOMPAÑAMIENTO COMO LO HACEMOS, LE HE DICHO QUE LO HABLE CON LA TS DEL HOSPITAL PARA QUE LAS AXULIARES TENGAN CONOCIMIENTO DE LA SITUACION ////// Ana: Tras convesaciones/correos varios finalmente recibimos este correo de Tamara - Mensajeros de la Paz: "Perfecto. Acabo de llegar del hospital de verlo y está tranquilo. He hablado con la médico que lo atiende y les he facilitado mi teléfono por si necesitan cualquier cosa. En principio se quedará solo ( como en otro ingreso que tubo anteriormente)ya que como vemos, su capacidad económica no es muy amplia para poder afrontar muchos días de ingreso, si se agita o necesita acompañamiento se le pondrá. Yo iré informándome diariamente de cómo se encuentra y acudiré a visitarlo cuando sea posible, para así informarme de su evolución médica Muchas gracias Reciba un cordial saludo Tamara Torres"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2019-05-20','TERESA: ME COMUNICA DEL CENTRO QUE HA SIDO DENUNCIADA POR UNA FAMILIA DEBIDO A UNA AGRESION EL DIA 15 DE MAYO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-20','Ana: El viernes recibí a última hora la Resolución de plaza en Res. Juan Carlos Rodríguez Ibarra de Vca. de los Barros.//// Hablo con Carmen, TS de la Residencia (20259), consultará con el equipo la mejor fecha para el ingreso. ///// Recibo llamada de Alfonso, Responsable Asistencial de la Res.Juan Carlos Rguez Ibarra (20270) manifiesta numerosas quejas con que Mª Luisa ingrese en su centro. Expongo la situación y le aclaro que desde aquí no asignamos recursos, que es en la Gerencia Territorial donde se encargan. ////// LLamo a Olga Rubio, TS del C.Salud de Plasencia (74523) Estña ocupada, me llamará luego.////// Llamo al Jefe de Sala del 112 (924 31 02 04). Dejarán la incidencia abierta para concretar el día antes el lugar de recogida de Mª Luisa. Envío por fax los documentos requeridos al 924 31 14 87.','2');
