insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-21','Ana: Recibo llamada de Olga, TS del C.Salud Plas (74523). Acordamos que tanteará tanto al hijo como a la hermana de Mª Luisa, sin decirle fecha ni centro, sobre su disponibilidad para apoyar el traslado a Residencia.//////// Recibo correo de Mª Carmen, TS de la Residencia P.Juan C.Rguez Ibarra(20259) con el listado de ropa que debe llevar Mª Luisa y además marcada. Llamo a Mª Carmen, entiende el caso y la situación. Acordamos que se le enviará todo lo que sea posible, no obstante, habrá prendas que estén deterioradas que tendrán que tirar y será necesario comprar ropa nueva. *Nos enviarán presupuesto o listado de prendas para que las compre la Delegada Tutelar. **Para el marcaje de la ropa contratarán el servicio por la zona y nos remitirán la factura. //////// Recibo llamada de la Comandancia de la Guardia Civil de CC, para confirmar la custodia de la ambulancia para el ingreso de Mª Luisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-05-21','Buenos día , ya hemos elaborado su ficha de presupuesto . Para el estanco hemos establecido 2 paquetes de tabaco al día , con un total màximo de 303€. Para la tienda , el pto. máx. sería de 300€ , no creo que gasten eso sólo para cenas y fines de semana. Y nada de reintegros , estaría todo cubierto. Sus dos pensiones se van a bloquear para pagar domiciliaciones y deudas ptes. De la pensión de la madre se cubre estanco y tienda de alimentación. Todo programado para empezar el próximo mes de Junio. Necesito que me reenvies la factura de la tienda , Alberto no la encuentra para empezar a abonar la deuda y comentar lo que se ha planteado desde aqúi. Sería la auxiliar la que se encargaría de las compras , tb tendría que saber cual es el pto. max. ¿ Qué te parece el plan de intervención economica fijado ?? consideras modificar algo ? Un saludo Amalia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PEDRO'and edp.apellido1='SAHAGUN'and apellido2='CHAMORRO'),'2019-05-21','miguel, nos remite Abogacia General resolución no firme del Jzdo nº1 de Jerez de los Caballeros, donde se llega a acuerdo en el Procedimiento de Liquidación de Sociedad de Gananciales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-21','Ana: Llamo a Citaciones del HSPA (56299) para gestionar la cita pendiente. A pesar de los múltiples ingresos no responden al teléfono. //////// Llamo al CRR varias veces. Ellos no pueden acercarse al hospital par hacer la gestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-05-21','Ana: Envío a Pedro Sánchez, TS Gerencia Territorial de CC - Gestión de Centros II (927004239) por email el Indice de Barthe y el Informe de Psiquiatría. Le llamo y como en ese momento no está hablo con un compañero, acordamos que le adelantaré escaneada la copia de la solicitud y todos los documentos que pueda del expte. de solicitud de plaza.////// Recibo llamada de Enrique, el Psiquiatra, dice estar preocupada por Paula y no entiende que aún no se le haya asignado plaza en residencia, se le explica el procedimiento, que hay que recabar todos los documentos necesarios y enviar la solicitud. Que ésta ya está enviada y que ahora hay que esperar que le asignen recurso. No obstante hablaré con los compañeros de Gestión de Centro.','2');
