insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-05-21','miguel, tras como fue hablado por Alberto y por mi con Liberbank (Javier), este nos remitió tasación de Tinsa y Certificado de total de deuda pendiente y la quita que le va a realizar Liberbank. Preparo la solicitud de Dación en Pago y los documentos accesorios y los envío a Secretaría General, para que ésta los remita a la Abogacía General, a efectos de presenten dicha Dación en Pago en el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2019-05-21','miguel, fax al juzgado de 1º inst. e instrucción nº4 de Plasencia, indicandoles que nosotros asistiremos por videoconferencia al juicio del dia 21/6/2019 a 11:15h. Que Jairo asistirá acompañado de alguien del socio-sanitario de Plasencia(comunico a Ana compañera TS, para que avise al Centro). Y solicito al Juzgado nombre abogado de guardia para representarle si fuese preciso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-05-22','-ACUDE COMO TODAS LAS SEMANAS AL SEPAD BADAJOZ. EN EL CONTRATO DE ALQUILER SE PUSO ESCALERA DERECHA Y ES IZQUIERDA . SE VA A HACER UN ANEXO Y VOLVEREMOS A FIRMARLO. ME LO TRAERÁ MERCEDES PARA QUE LO FIRME CONSOLI. YA SE HA EMPADRONADO EN LA NUEVA VVDA. EL JUEVES VA A QUEDAR CON MAR PARA IR A HACER EL CAMBIO EN AGUA Y LUZ , YA SE LO ENVIÉ EL Nº CUENTA , AUN ASI LO LLEVARA ELLA TB. VA A CONTRATAR A UNA CHICA PARA LIMPIEZA , AMIGA DE JACKELINE , SE LLAMA MAYRA . 250€/ MES , NO SABE CUANTAS HORAS . Y FINES DE SEMANA LE VA A DAR CLASES DE INFORMATICA Y TF. IMPOMOL ME LLAMA , ACUDE ALLÍ A DIARIO .','2');
