insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-05-22','Buenas tardes Amalia! Informar que Felisa Bruno será alta hospitalaria hoy por la tarde. La llevan a residencia San Javier en ambulancia. Comentarte que manifiesta estar muy arrepentida y avergonzada..ayer por la tarde acudió una de las educadoras agredidas al hospital para llevarle ropa y se mostró muy arrepentida, no parando de llorar y pedirle perdón. Hemos elaborado un programa específico para Felisa, en el cual se trabajaran los aspectos en los que más carencias tiene. Mañana a primera hora nos vamos a sentar con ella para tratar lo ocurrido y ver como se encuentra y que demandas hace. A su vez le explicaremos como vamos a trabajar ahora con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-05-22','-EMAIL RECIBIDO DE ESPERANZA GALLEGO , TS DEL ESM DE MERIDA : Buenos dias ,me dijo la psiquiatra que la ultima consulta Ruben no ha venido ni con ella ni con enfermeria y ella desconoce el estado actual del paciente y no sabe si esta tomando la medicacion. que ella os ha puesto en el informe que recomienda una valoracion valoracion preferente supongo que con la idea de si esta mal hacerle desde el hospital una derivacion a la UME. ya me dices si vas a visitarlo que decidis o hablas directamente con la psiquiatra ella viene el viernes aqui al centro de salud su extension es 85825 se llama Maria . un saludo -MI RESPUETA : Buenos días, la sentencia se ha aceptado el 9 de abril , tenemos 60 dias para proceder a realizar el inventario de bienes para enviarlo al juzgado. Aún no se han recibido todos los informes solicitados a distintos organismos para conocer la situación de este chico y proceder a realizar un Plan de Intervención con él . Desconozco cuál es el protocolo establecido por ese ESM en estos casos , pero si cree que pudiera estar descompensado tendriáis que activar el 112 , nosotros no somos psiquiatras para poder valorar ésto. Intentaré contactar con la psiquiatra el viernes. Un saludo.','2');
