insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CAYERO'and apellido2='AGUILAR'),'2019-05-24','TERESA: ME LLAMA MARIBEL TS DEL PI VILLANUEVA PARA COMUNICARME QUE HA SIDO DADO DE ALTA Y QUE LA NOCHE EN EL CENTRO HA SIDO MUY MALA, HAN TENIDO QUE LLAMAR POR TRES VECES A LOS SERVICIOS DE URGENCIA LE HAN INYECTADO TRANQUILIZANTES PERO NO CONSIGUEN QUE DEJE DE GRITAR LO QUE ESTA INFLUYENDO EN EL RESTO DE USUARIOS DEL CENTRO. LO HAN LLEVADO POR LA MAÑANA AL HOSPITAL YA QUE NO RESPONDE NI AL TRATAMIENTO DE CUIDADOS PALIATIVOS. ESTAN BUSCANDO POSIBLES SOLUCIONES YA QUE MARIBEL AFIRMA QUE EL YA NO PUEDE ESTAR EN ESTE CENTRO DEBIDO AL ESTADO EN QUE SE ENCUNTRA. SE PLANTEN DERIVAR A LA UNIDAD DE AGUDOS PERO NO ES VIABLE YA QUE ES UN PROBLEMA A NIVEL NEUROLOGICO Y NO DE SALUD MENTAL. LO HAN TENIDO QUE ATAR A LA CAMA Y DESDE EL HOSPITAL RECLAMAN UN CUIDADOR, MARIBEL LES PLANTEA LA SITUACION ECONOMICA DEL TUTELADO LA CUAL NO NOS PERMITE MANTENER UN CUIDADOS 24 HORAS DURANTE MUCHO TIEMPO. MARIBEL NOS PIDE QUE BUSQUEMOS UN RECURSO, LE COMENTO QUE ES DESDE DISCAPACIDAD DESDE DONDE LO TIENEN QUE ASIGANAR YA QUE ACTUALMENTE SE ENCUENTRA EN UN RECURSO DE DISCACIDAD, LE INDICO QUE HABLE CON MANUELA Y LE PONGA AL DIA DE LA SITUACIÓN HABLO CON MANUELA PARA COMENTARLE EL CASO, ELLA ME INDICA QUE MIREN LOS RECURSO DEL SES, SUGIERE CASA VERDE. QUEDO CON MARIBEL PARA IR EL MIERCOLES AL HOSPITAL PARA REUNIRNOS CON LA TS Y MEDICO PARA INFORMARNOS Y VER RECURSO','2');
