insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-05-24','Ana: Recibo la Resolución de Ingreso de Paula (También la han enviado a la Residencia La Coronada). /////// ***Las LLAVES de la casa se las queda la Mª José, TS HVM. **Confirmo con Toni-Futuex que el lunes la Delegada Tutelar pasará a recogerlas al hospital e irá al domicilio a recoger la ropa y otros enseres personales y se los llevará a la residencia. ////// Llamo a Residencia La Coronada (924 02 87 78)Directora, Mª Carmen, el ingreso ha ido muy bien, estaba tranquila y se ha quedado contenta y conforme. Le informo que el lunes la Delegada tutelar irá a recoger ropa y enseres y los llevará a la residencia.','2');
