insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-23','Ana: Llamo de nuevo a citaciones del HU y me confirman la **cita para el día 29/05/19 a las 10:05 Radiografía y a las 11:00 Consulta en Traumatología. /////// Comunico la cita mediante email a la residencia de mayores. Pendiente solicitar el acompañamiento a Lucía. /////// **Envío por correo certificado a la residencia el contrato y el reglamento de Regimen Interno ya firmados y sellados por la D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-05-27','Ana: Hablo con Lucía (605 15 13 70) Confirma que acompañará a Consuelo a la cita en el HU, ya se lo habían comentado en la Residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-05-27','Ana: Recibo llamada de Toni-Futuex, las delegadas están en el domicilio de Paula recogiendo la ropa. Me preguntan qué hacen con las LLAVES, le digo que la traigan a la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2019-05-27','Ana: Recibo llamad de Carmen, TS del CAMP Las Cruces, D. Benito. El día 15 recibieron Resolución de Plaza a nombre de Claudia Loren. Han estado intentando ponerse en contacto con la familia, sin éxito. Finalmente llamaron a la Ud. Gestión de Recursos, Discapacidad, y les informaron que estaba pendiente de asumirse la tutela por la Comisión Tutelar. *Le explico que ya se ha aceptado el cargo. ////////Llamo a María García, Direcotora de la Residencia para P. Discapac. San Fco. de Asís - Aldea del Cano (927 194 889). Desde el centro **van a intentar gestinar el traslado al CAMP, de hecho, si se lo aprueban en la Junta Directiva, ella y la psicóloga harán el acompañamiento. **Llamará al CAMP para coordinarse y organizarlo. Me mantendrán informada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2019-05-24','Ana: Acuerdo con el responsable de la Sección Económica aprobar el presupuesto para acompañamiento de Teodoro por las noches en el hptal por 70€/noche durante una semana. /////// Se lo comunico a Tamara, Directora de la Residencia. Hablaremos para valorar la necesidad de renovar o no a la semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2019-05-27','Ana: Devuelvo por mail a Tamara Torres, Directora Resid. Mensajero sde la Paz, firmado y sellado el Consentimiento Informado para PARACENTESIS. //////// Me informa de que hoy le han hecho una ecografía dada la inflamación abdominal. En ppio parece que no hay metástasis (Cáncer de próstata). Nos mantendrán informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-05-24','Ana: Recibimos un correo de Paula del CRR, con el siguiente contenido: "Buenos días, quería informaros acerca de Mª Antonia Bernardo puesto que sois sus tutores legales (incapacitada totalmente). Desde hace unos días Toñi se niega a tomar un medicamento concreto prescrito por su psiquiatra (antipsicótico) argumentando que dicha medicación le hace daño. Estamos en coordinación con el equipo de Salud Mental, que sabe esta situación y por ello han adelantado la cita con su psiquiatra al jueves día 30 de Mayo, para valorar. Por nuestra parte estamos observando cualquier situación que pudiera aparecer, si bien hasta el momento no hemos observado diferencias en su comportamiento. Os seguiremos informando, Si necesitáis cualquier cosa no dudéis en poneros en contacto con nosotros. Un saludo. Paula." /////// Contesto al correo y pido nos mantengan informados al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-05-23','Ana: Recibimos del INSS Resolución de aprobación de Prestación de ORFANDAD por cuantía de 207,00 €/mes x 14 pagas. En el primer periodo del 02/01/2019 - 31/05/2019 la suma de abonos a ingresar es de 1.028,33 € en la nueva cuenta de Liberbank. /////***Adjuntan además el Documento Informativo del Dcho a la ASISTENCIA SANITARIA. NASS: 10 10097085 01','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-05-24','Ana: Recibimos correo de PLACEAT: "Buenos días; Tengo a bien adjuntar solicitud con respecto a la usuaria María Rosa iglesias Calzas. En espera a su respuesta le saluda atentamente. Angela Bueno." ***La autorización es para derechos de imagen para leer en Pregón inaugural de las Ferias de Plasencia" ////// Tras consultarlo con los compañeros de la Secc. Jurídica llamo a Ángela (927 421 950 ext. 102) varias veces pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-05-27','-CORREO DESDE EL CRR , SE CIERRA LA PETICION : Como hablamos el lunes pasado, me acabo de reunir con Mari Loli con el objetivo que nos diga su decisión sobre la venta o no del piso y el ir a una residencia de mayores. Durante la conversación a diferencia de la mayoría de veces anteriores, esta ha sido breve y centrada en el tema que íbamos a tratar. Su decisión final ha sido esperar y no vender su piso. Aún así, le he hecho saber que un posible empeoramiento y si los profesionales consideramos que para ella seria oportuno un cambio de recurso, podríamos iniciar estos trámites. En todo momento se muestra de acuerdo con con las ideas claras. Por lo que por nuestra parte como profesionales nos concierne, si te parece el mensaje que tendremos que darle si vuelve a querer tratar este tema es "ya se ha hablado y tomaste una decisión la cual vamos a respetar". Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-05-28','Ana: Llamo a Ángela (927 421 950 ext. 102): Le comunico que ha llegado resolución aprobatoria de la P. Orfandad. //// en cuanto a la autorización de Dcho. de Imagen para el Pregón, le transmito la información facilitada por la Secc. Jurídica - Desde la Comisión no se puede AUTORIZAR, legalmente a priori no se puede. No obstante estudiaremos el caso. Dice que el Presidente de la Asociación, que es quién se lo ha comunicado a Consoli, seguro que la llamará. ////// Recibimos resolución de APROBACIÓN de PFHC; 392,00€/mes x 12 pagas, que tendrá efecto a fecha de 01/07/19. *Pendiente solicitar los atrasos al INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-05-28','Ana: Llamo a Mª Carmen, Directora de la Residencia La Coronada-Vca.de los Barros (924 02 87 78), dice que en principio Paula se está adaptando bien, pero ayer dijo que había llamado a un detective, un tal Jorge 927 26 92 12, saben que habló con alguien y según dijo ella para que la sacaran de allí, pero no saben nada más, de hecho después siguió tan tranquila. En cuanto a la medicación dijo que esa no era la suya, pero le explicaron que era la que le había dicho el médico y tampoco puso más objeciones. *Mañana me llamará con más calma en relación a la documentación que hay que firmar y el cobro de la residencia. ////// Llamo al supuesto detective, Jorge 927 26 92 12','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-24','Ana: Llamo a Valeriano, hermano de Mª Luisa (927 42 47 16), dice que se va a reunir con sus hermanas para hablar del ingreso y organizarse para apoyar el proceso. Le confirmo el día, la hora y la localidad a la que será trasladada. Asegura que irá Jesús, hijo de Mª Luisa, y al menos uno o dos de los hermanos/as. ////// Se lo comunico a Olga, TS del C.Salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2019-05-28','TERESA: AYER VISITE P I CABEZA DEL BUEY ESTUVE CON ANTONIO SE ENCUENRA BIEN ADAPATADO AL CENTRO Y CONTENTO,TIENE UNA AMIGA TEREAS LA CUAL CUIDA DE EL Y DESDE QUE SON AMIGO SU ACTITUD HACIA LAS TAREAS EN EL COMEDOR HA MEJORADO. ME TRAIGO CONTRATO PARA FIRMAR HABLAMOS DE LA GESTION DE LAS VISITAS A LA FAMILIA, POR UNA LADO LA FAMILIA EXTERNA ESLA Y M JOSE EN MALPARTIDA, ES UNA FAMILIA QUE COLABORA CON EL CENTRO Y EL LE GUSTA MUCHO VISITARLA Y LA OTRA VISITA ES A SU MADRE EN LLERENA.ME PLANTEAN QUE LAS VISITAS CON LA MADRE NO SABEN HASTA QUE PUENTO SON BENEFICIOSAS A PESAR DE QUE EL LA DEMANDA MUCHO. QUEDO EN HABLAR CON EL PROGRMA DE FAMILIAR PARA VER COMO SE ENCUTRA LA MADRE Y VER LA IDONIEDAD O NO DE ESTA VISITAS. VIRGINIA P. FAMILIA (606155151) ANTONIO REALIZA UNA LLAMADA SEMANAL A SU MADRE. ANTONIO HA REALIZADO UNA AGRESION NOS LLEGARA PARTE DE FALTAS POR EL JUZAGADO YA QUE LA CUIDADORA FUE AL CENTRO DE SALUD A CURARSE. QUEDO PENDIENTE GESTIONAR PF Y DARLE REGISTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2019-05-27','Ana: Recibo llamada de Mariví, TS CSS Plas. (24142). Al parecer el abogado de Ángel, Marido de Desideria, ha llamado para pedir información y documentación de Desi. Ya vendieron la casa del pueblo y han comprado un piso en Plasencia. *Lo comentaré con los Asesores Jurídicos, y en cuanto al abogado le digo que no faciliten información de Desideria, que llame aquí o lo solicite por escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-27','Ana: Recibo llamada del 112 (924 38 76 69). Confirmo que se le recogerá en su domicilio a las 10:00 h. ///// Hablo con Olga, el Médico que irá será el suyo de Att. Primaria, José Ángel. Mucho mejor porque la conoce y conoce la situación. ///// Intento ponerme en contacto con Jesús, hijo, y Valeriano, hermano, llamo numerosas veces y no obtengo respuesta en ninguno de los 2 teléfonos. ***Dejo mensajes de voz a Jesús, recordando que el ingreso es mañana, que irán a buscarla a las 10, e informo que acudirá su médico de familia, Jose Ángel, y Gloria, delegada tutelar. ////// Consigo hablar con Beatriz, su hermana, dice que ella no irá, que su sobrino y su hermano "son los dos unos sinvergüenzas, que vayan ellos" ///// Como último intento de confirmar, Olga, TS - C.Salud, intentará ponerse en contacto con la pareja de Jesús. ***Finalmente lo consiguió, confía en que ella medie para que Jesús acuda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-28','Ana: Varias llamadas de coordinación con Olga-TS y Toni-Futuex. /////// Tras varios intentos consigo contactar con Jesús a las 9:30, está llegando al domicilio de su madre, Gloria, Delegada, también está allí ya. //////// Olga me llama cuando Mª Luisa ya está de camino en la ambulancia, dice que ha habido un poco de revuelo, vecinas incluidas, pero Mª Luisa no se ha agitado demasiado ni ha puesto mucho impedimento, no obstante le ha dado un Orfidal y otro al hijo. Le ha susministrado otro al personal sanitario para que lo lleven a la Res. por si fuera necesario al ingreso. ///// Llamo a Mª Carmen, TS de la Residencia P.Juan C.Rguez Ibarra(20259), como no obtengo respuesta llamo a Alfonso, Responsable Asistencial de la Res. (20270). Me devuelven la llamada más tarde, Mª Luisa aún no ha llegado, le informo sobre como ha ido todo esta mañana y que va de camino acompañada de su hijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-05-28','miguel, Juana me confirma que la venta de la vivienda se hará el martes 4-6-19 en la notaria de Juan Manuel Angel Avila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORILLO'and apellido2='SANCHEZ'),'2019-05-28','BAJA DEL EXPTE. El Jzdo., mediante, DIOR de 16/05/2019, informa de la firmeza de la Sentencia (1/19, de 15 de enero). D. FRANCISCO MORILLO SANCHEZ ha sido designado tutor de D. Pedro. El Jzdo. informa que D. Francisco ha aceptado el cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-05-28','miguel, en días anteriores Amalia nos entrega unas fotocopias de la herencia del padre de Mercedes y fotocopia de unas escrituras de compraventa que Mercedes encuentra en su casas (al hacer la mudanza). Al leerlas quedaban dudas de qué bienes quedaban a nombre del padre y madre (hoy fallecidos), con lo que tras pedir notas simples de ambos, el registro de la propiedad indica que a nombre del padre queda una finca (rústica de 65 áreas)en Aguilar de la Frontera (Córdoba), mientras que a nombre de la madre hay 3 fincas en Córdoba (vivienda, garaje y trastero) y en Badajoz aparece como acreedora en dos anotaciones de embargo sobre dos fincas por importe de casi 16.000€ cada una. Dichas anotaciones hoy están caducadas con lo que habría que presentarse de nuevo por los interesados. Se ignora la situación bancaria de los padres fallecidos, qué cuentas hay, en qué entidades, y por qué importe. Queda pendiente de hacer la herencia de la madre fallecida Reunirme próximamente con la parte económica para decidir: si se puede pedir certificados de saldo de las cuentas de los padres. Y para decidir si tramitamos la herencia de la madre o se va a contratar un servicio externo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2019-05-28','Ana: Pongo para firma el Reglamento de Regimen Interior y el Contrato que me han remitido por correo ordinario de la Res.Ciudad Jardin-Parque del Príncipe. Sólo han remitido una copia original, ya firmada por la dirección del centro. *Hablo con Maribel, me los enviarás escaneados para poner a la firma 2 copias más, una de las cuáles me la devolverá firmada a posteriori. **Se lo enviaré todo junto con el PIA y el Alta a 3º.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2019-05-28','Ana: Pongo para firma el Reglamento de Regimen Interior y el Contrato que me han remitido por correo ordinario de la Res.Ciudad Jardin-Parque del Príncipe. Sólo han remitido una copia original, ya firmada por la dirección del centro. *Le pediré otra copia firmada en original para que la tengamos en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-05-27','Ana: Recibo llamada de Javier Civantos (658 806 037), hijo de J. Ramón. Su padre le ha enviado una imagen de un documento que ha recibido del SES, al parecer es una reclamación en relación a la ambulancia en la que se realizó uno de los dos traslados (o al hptal o a la Resid.) Me envía la imagen al correo, veré cómo podemos solucionarlo desde aquí.','2');
