insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-05-29','Ana: Llamo a Ángela, Directora de PLACEAT (927 421 950 ext. 102), le comunico: 1- La aprobación de la PFHC. 2- Tras haber vuelvo a valorarlo junto a los Asesores Jurídicos, hemos decidido enviar un escrito al Ministerio Fiscal en el que hagamos constar la serie de beneficios que reportaría, en este caso a Mª Rosa, el hecho de participar en actividades y actos sociales en un entorno normalizado. **Ayer ya le dijeron a María que no podía hacerlo, tuvo un mal día, pues se le juntaron varias cosas. Lo hablará con el equipo, le preocupa que el trámite se dilate mucho en el tiempo, pues la joven/es que sean tiene que prepararlo.','2');
