insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-29','Ana: Llamo a Mª Carmen, TS de la Residencia P.Juan C.Rguez Ibarra(20259) como no obtengo respuesta llamo a Alfonso, Responsable Asistencial de la Res. (20270), sin éxito de nuevo. /////// Mª Carmen me devuelve la llamada más tarde; Al ppio Marisa no se tomó muy bien el ingreso, decía que ella no se quería quedar allí y quería hablar con sus hermanos. Llamaron a Valeriano, pero cuando éste comenzó a decirlo lo mismo que la TS y la Psicóloga ella colgó el teléfono. Cuando le pasaron para hacer el reconocimiento médico no puso ningún problema, todo bien. La ducharon después y pusieron ropa que tenían allí, y también bien. Por la tarde estuvo paseando en el jardín, con puerta abierta y en ningún momento hizo amago de irse. La noche la ha pasado muy bien, al parecer ha dormido toda la noche. //// *Mª Carmen me pide que le envíe el Certificado del CADEX.','2');
