insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2019-05-29','TERESA: Buenas tardes. Me pongo en contacto para comunicarles que Antonio Manuel demanda constante e insistentemente poder visitar a su madre que aún permanece ingresada en el Hospital. Teniendo en cuenta, la unión y la relación tan estrecha que ambos mantenían hasta el ingreso de Antonio Manuel en nuestro Centro consideramos oportuno y beneficioso el hecho de que Antonio M. pudiese visitar a su madre cada 15 días. Esperamos su respuesta lo antes posible para poder organizar y planificar las salidas del tutelado de la forma más adecuada.','2');
