insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-05-29','-SOLICITO REUNION CON SU ESM. Buenos días, ayer estuve reunida con Rubén Montero y sus padres. La intervención va a resultar muy dificil , no hay conciencia de enfermedad ni del hijo ni de los padres. No hay forma de garantizar la adherencia al tratamiento , los padres no creen en su beneficio . Podriamos reunirmos contigo y su psiquiatra para abordar el caso y las posibles alternativas ?? Yo podría la semana que viene el dia 7 y de la siguiente el 13 y 14 . Quedo a la espera de que podáis cuadrar agendas. Un saludo','2');
