insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2019-05-29','-EMAIL DE CRISTINA , TS DE RM GRANADILLA DONDE ESTÁ : Buenos días Amalia. Comentarte que, me acaban de llamar del servicio de PNC, que necesitan el modelo de Alta a Terceros y un número de la seguridad social propio de Dª Isabel Parra Ochoa para poderle tramitar la PNC de jubilación. Un saludo Buenos días , no tenemos el inventario hecho de Isabel y desconozco mucha información. Qué pension está percibiendo actualmente ? el modelo de alta a 3º lo solicitamos nosotros a la entidad bancaria , pero antes tenemos que hacer las gestiones necesarias para incluir a Consolación en las cuentas . La PNC una vez que la tengas gestionada , tienes que enviarla a CTAEX para su firma por la gerente. Preguntaré en el CAISS para gestinoar el Nº de la SS propio. Un saludo -PIDO A PARTE ECO GESTIONES BANCARIAS.','2');
