insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-05-30','Ana: Recibo llamada de Mª Carmen, Dirertora Res.La Coronada (20211), hoy Paula tiene cita en Psiquiatría, como aún no se ha hecho efectivo el cambio en el SES, tiene que ir al HVM-CC, con el Dr. Juan Pedro Jiménez Cano. ***Paula dice que ella ya NO vuelve a la Residencia, ha PREPARADO sus maletas, dice que QUIERE QUEDARSE EN EL HOSPITAL. *Hablo con la Aux. que le va a acompañar, explico la situación para que informe al Médico y le pido que lleve último informe del Dr. Enrique Daniel. //// Finalmente la acompañarón en la ambulancia tanto la Auxiliar como Vanesa, T.O. y tras la consulta la convencieron para que regresara a la Residencia. ////*Mª Carmen me enviará el Informe de Psiquiatría escaneado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-05-30','Ana: Ángel, A. Jurídico, pone para registro y envía el escrito para el Ministerio Fiscal. ///////// Envío por REGISTRO DE ENTRADA Solicitud de ATRASOS de PFHC que corresponden a Mª Rosa. ////// Envío por email a Ángela-PLACEAT, documento Informativo de Dcho a Prestación Sanitaria de Mª Rosa, con su NASS propio, para que puedan solicitar nueva tarjeta sanitaria en su C. Salud.////// Llamo al INSS, consulto por la posibilidad de que a Mª Rosa se le conceda pensión de Orfandad Absoluta, me pasan con Toni, Jefa de Sección y me dice que envíe un escrito solicitando el estudio del expdiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CAYERO'and apellido2='AGUILAR'),'2019-05-30','TERESA: VISITO EL HOSPITAL DE VILLANUEVA DON BENITO DONDE SE ENCUTRA INGRESADO JOSE. ME REUNO CON LA TS VICTORIA Y MARIBEL DIRECTORA DEL CENTRO P.I. ALLI LA TS NOS COMENTA QUE SANITARIAMENTE NO SE PUEDE HACER NADA MAS POR EL Y QUE POR ESO LE DAN EL ALTA YA QUE CORRE EL RIESGO DE COGER UNA IFECCION. LO VISTAMOS EN SU HABITACION, SE ENCUENTRA ATADO DE PIES Y MANOS CON UNA CELADORA QUE LO ACOMPAÑA. NOS COMENTA QUE SE ENCUNTRA ALGO ALTERADO Y QUE APENAS DUERME. HABLAMOS CON EL MEDICO INTERNISTA Y NOS COMENTA QUE YA NO PUEDE HACER NADA MAS QUE SU ENFERMEDAD ESTA TRATADA Y NO HAY MAS MEDICACION Y QUE ESTA ASI PORQUE ESTA ENFERMEDAD GENERA UNA ENFERMEDAD PSQUIATRICA LA CUAL EL PSIQUIATRA DICE QUE YA ESTA TAMBIÉN TRATADA AJUNTANDOLE LA MEDICACIÓN POR LO TANTO LE VAS A DAR EL ALTA YA QUE CORRE UN ALTO RIESGO DE COGER UNA IFECCION Y YA SANITARIAMENTE NO SE PUEDE HACER NADA MAS. HABLO CON SORAYA Y ME COMENTA QUE BARAJA LA OPSCION DE LLEVARLO A UN CENTRO RESIDENCIAL PARA PERSONAS CON DETERIORO COGNITIVO Y PARA ELLO ME PIDE QUE SOLICITE INFORME AL NEUROLOGO. HABLO VICTORIA TS DEL HOSPITAL PARA SOLICITAR EL INFORME Y ME DICE QUE ESO NO SE PUEDE HACER DESDE EL HOSPITAL QUE TIENE QUE SE EN CONSULTAS EXTERNAS CON CITA. LE PIDO QUE ME ENVIE LOS INFORME QUE TIENE YA HECHO PARA VER SI ALGUNO ME SIRVE Y ME COMENTA QUE TIENE QEU VER SI LO PUEDE HACER POR EL TEMA DE PROCTECCION DE DATOS. ME QUEDO A LA ESPERA-. LLAMO A MARIBEL DIRECOTRA DEL CENTRO PARA QUE ELLA TAMBIÉN ME FALCILITE LOS INFORMES QUE POSEA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-05-30','TERESA: M LUISA SE ENCUENTRA BIEN EN LA RESIDENCIA, ME LLAMA PARA PODIRME DINERO. LA HIJA ESTA CAUSANDO PROBLEMAS PORQUE NO DEJA DE LLAMMAR A LA MADRE AL MOVIL Y DECIR QUE VA A IR A POR ELLA. HABLO CON LA TS PARA ACORDAR PRESUPUESTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2019-05-30','Buenos días Amalia. La PNC la tramité el 3-5-2019, antes de que saliera la sentencia de la incapacitación. Hasta entonces, no estaba cobrando ningún tipo de pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-05-30','Ana: Recibo llamada de Vere, Directora de la Res.Puente Real-San Vicente Alcant. El viernes pasado J.Ramón ya no acudió a la Res. a por medicación y por tanto tampoco se aseó, están en coordinación con la farmacia de debajo de su casa para las recetas, visados y que le organicen ellas el pastillero. Ramón les ha llamado para decirle que hasta después del verano no van a arreglar la cubierta del edificio, así que dice que se queda ya en su casa. **Acordamos dejar la Residencia, le abonarán la primera quincena de junio, pues así lo tienen estipulado (preaviso de 15 días). *lo comunico a Alberto, Jefe Sección Eco. ///// En cuanto a la gestión de la reclamación del SES del abono de la ambulancia que le llevó al hptal. lo está gestionando ella, ha enviado la hoja de Interconsulta de Urgencias solicitada al Centro de Salud.///////// **La próxima CITA en CARDIOLOGÍA la tiene el día 25 de junio en Clideba (Asisa-Badajoz) a las 8:00 tiene Análisis y la consulta a las 8:30 h. ** Puesto que yo iba a enviar la solicitud de cambio ordinario de entidad médica, decido no hacerlo aún, llamaré a Muface a ver cómo podemos hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-05-31','Ana: Llamo a Pilar, TS de Valencia de Alcánara (627 34 11 19 // 927 580 326, ext.8). Dice que ella está muy ocuapada,que está sola en el servicio y no tiene tiempo de hacer el informe. *Pongo en su conocimiento la situación actual de J.Ramón y dice actuemos nosotros. Y que si tenemos que solicitar ingreso involuntario que lo hagamos, que no es imprescindible el Informe Social y si el Juez se lo pide lo hará "encantada". ////// Llamo a MUFACE-CC (927 75 05 10), ahora es un buzón, dejo mensaje y solicito que se pongan en contacto con nosotros. Envío un correo con la misma solicitud: caceres@muface.es /////// Llamo a Asisa (927 24 90 65 - Paula / Gema) número facilitado por Vere, pero tampoco obtengo respuesta. ///////// Envío un correo a Javier, hijo de Ramón, informándole de la situación actual y las últimas acciones para que esté al corriente.','2');
