insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-05-31','Ana: Recibo llamada de Clara, TS del C.Salud de Guadalupe (Desde Logrosán: 53225), en relación a la Tarjeta de Transporte, Juan pasó por allí ayer, pedía que nos enviara por fax el modelo de solicitud, consulto en la Web portal del Ciudadano "Tarjeta de Transporte Subvencinado)introduciendo el DNI sin la letra, la tiene caducada desde 2012. Para reactivarla tiene que firmar el Anexo II, como es Curatela lo firma él. El lunes se lo explicará. ////// Vuelve a llamarme Clara, ha hablado con Raquel, TS del SSB, al parecer Juan perdió la tarjeta, por lo que hay que pedirle una nueva. Tiene llevar al banco el modelo 50 y pagar algo más de 6 €. Se lo dirá el lunes y que lo pague de su asignación semanal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2019-05-31','-ME REUNO CON PFHC ( GLORIA ) PARA ACLARAR SU PENSIÓN QUE HA VENIDO APROBADA SIN CPTO ATP. HASTA JULIO QUE SE MANTIENE LA PFHC ANTERIOR VIENE BIEN. PARA JULIO LO MODIFICARÁN PARA QUE LO PERCIBA , REGISTRO EL GRADO DE DEPEN. QUE FALTABA PQ NO TENIAMOS LA RESOLUCION. -VOY A SOLICITAR PNC INV , LO PONGO A FIRMA GERENTE. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-05-31','Enviamos a la Fiscalía de Plasencia, consentimiento previo para que María Rosa pueda participar en el pregón de las ferias y fiesta de Plasencia, a celebrar el 12 de junio de 2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2019-05-31','-HAGO EL CAMBIO DE DOMICILIACION BANCARIA ,LO PONGO A FIRMA , ENVIAR LUEGO AL CAISS BADAJOZ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-05-31','Ana: A primera hora, envío a Mª Carmen el número de cuenta y le pido que envíe el presupuesto al email ctutelar@ y que especifiquen la forma que quieran para acceso al dinero: transferencias o autorización para retirada de reitegros. ////// Hablo con Mª Carmen, TS de la Res. J.Carlos Rguez. Ibarra (20259). Enviarán un presupuesto apróx. de gastos, aunque aún no la conocen mucho, irán probando. Con el otro tutelado que hay en la Res. es el director quien está autorizado y saca dinero para administrarle 2-3 veces al año. Le digo que lo pidan en el correo junto con el presupusto de gastos. Lo enviará al ctutelar@ //////// Mª Luisa parece que se está adaptando bien, aunque dadas las circustancias y como fue el ingreso para ella no es fácil. Ya le han pasado a habitación compartida con otra mujer de su edad apróx. y en principio parece haber buena sintonía. La otra Sra. le ha regalado unos pendientes. Está entablando buenas relaciones tanto con el personal como con residentes. En cuanto a la alimetnación, está comiento muy bien, sobre todo el desayuno y la comida, la merienda y la cena las hace más ligeras **Hoy ha participado en una actividad conjunta con residentes de la Res. La Coronada - Desayuno en una churrería (ayer decía que no quería, pero finalmente se ha animado). **Ayer Gloria, Delegada Tutelar, le llevó las maletas con la ropa y Marisa colaboró en todo momento, tanto en sacarla, contarla y guardar la que no había que lavar (la maleta que trajeron de casa de su hermana). //////////***Llamo a Estrella, TS Vivienda-CC (927 01 74 89). Le comunico el ingreso de Mª Luisa, me enviarán el modelo de solicitud de baja en la vivienda, para que la envíe firmada por la D.Gerente. Cuando reciba este doc. llamará al hijo para que vayan a recoger muebles/enseres y devuelvan las llaves. //////// Llamo a Jesús, hijo, le informo sobre cómo está y evoluciona su madre y le transmito también la información que me ha facilitado Estrella, TS Vivienda: No puede mantenerla a nombre de su madre ni pasarla al suyo, hay que darla de baja. Podrán ir a recoger muebles y enseres y tendrá que devolver sus llaves. ///// *El otro juego de llaves lo tiene Gloria, Delegada Tutelar, le avisaré cuando tenga que ir a devolerlas.','2');
