insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-05-28','Ana: Recibo llamada de Pablo (676 78 31 01), nieto de Manuela, es el hermano del nieto que reside con Manuela, pero Pablo expresa literalmente "ese señor no tiene nada que ve conmigo". Llama bastante enfadado pues su heramno se ha vuelvo a llevar a su abuela a Madrid sin decirnos nada y nosotros deberíamos estar al tanto, no lo sabíamos. Le consta que está allí desde el jueves pasado. **Nosotros aquí no tenemos nada que confirme esa información. Dice también, que según le han dicho los vecinos de su abuela, en el domicilio de ésta a diario se oyen muchas voces. /// Le digo que en cuanto pueda llamaré a Pilar, TS del SSB y solicitaré informe.','2');
