insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-06-03','Ana: Recibo llamada de Camen - Muface CC (927 75 05 10) en respuesta al correo y mensaje que dejé. Acordamos que para que Ramón no pierda la cita en Cardiología, no enviaré la solicitud de cambio ordinario hasta ese mismo día tras la consulta. **Se lo haré llegar primero escaneado (mcarmen.muñoz@muface.es) y lo enviaré por correo certificado. Las copias de la Sentencia y Aceptación del Cargo deberán ser compulsadas. Dejo todo preparado para el envío el día 25/06/19.','2');
