insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-06-04','Ana: Recibo llamada de Lucía Conejero, vecina de José Pedro (C/Zapatería, nº 38 - 1ºA), el tutelado residía en el 2º A. Al parecer ya habló con Gloria, Delegada Tutelar, acerca de la tubería rota. Dice que uno de los hermanos de J.Pedro ha entrado en la vivienda hoy y ha tirado de la cadena, con lo que le han vuelto a mojar, mientras la llave de paso permanece cerrada no tiene este problema. Ya le han visto varias veces entrar con llaves, tanto en la vivienda de J.Pedro como en la de la hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2019-06-04','-LLAMO A SU HIJA IRIS , SU MADRE PREGUNTA MUCHO POR ELLAS Y HAY UNA SEÑORA QUE PODRIA LLAMARLAS CON SU MOVIL POR VIDEOCONFERNCIA. ACEPTA GUSTOSA . ESTE VERANO QUIERE LLEVARSELA A MADRID , LE DOY MI CONTACTO PARA QUE LO COMUNIQUE. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PEDRO'and edp.apellido1='SAHAGUN'and apellido2='CHAMORRO'),'2019-06-04','miguel, llega por carta certificada procedimiento de familia, solicitando ejecución de título judicial 410/2016, el cual fue archivado en el 2016 por ser desconocido el docmicilio del demandado. Tras confirmarme Elena del Jzdo de Jerez de los Caballeros nº1 estos extremos, me indica que tenemos 10 días desde que nos llegó la notificación (que es hoy4-6-2019) para contestar a la misma. Así que prepararé la contestación para ser firmada por Consolación y remitiré a la Abogacia General para que se personen y se opongan. Este procedimiento es independiente del de liquidación de sociedad de gananciales al que se llegó a un acuerdo, y cuya vista fue el 15-5-2019.','2');
