insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-06-05','Ana: Recibo por correo ordinario Informe Médico orginal de la Dra. de la Resid.Puente Real, Mª del Carmen Galán, esta vez con la fecha de emisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2019-06-05','Ana: En reunión mantenida ayer con Toni-Futuex, me entrega Informe Médico del Servicio de Neurología de la consulta del 20 de marzo. Lo escaneo y guardo en su expte. A parte de ésto, me informa de que desde la empresa "Dependencia Extremadura" le han comunicado a la Delegada Tutelar que **DEJAN DE PRESTAR EL SERVICIO DE AYUDA A DOMICILIO. *Lo extraño es que en el seguimiento telefónico realizado a finales de mayo la pareja de Josefa le dijo a Gloria, Delegada, sobre la auxiliar de SAD, que muy bien, que todo ha mejorado y está mucho más agusto. ///////// Llamo a Alberto, Empresa "Dependencia Extremadura" (687 784 906), dice que es la segunda auxiliar que se niega a acudir al domicilio, al parecer los animales siguen entrando en casa y haciendo sus necesidades en el sofá y en la bañera, por tanto han tomado la determinación de dejar de prestar el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-06-05','-CUADRADO PTO. MENSUAL , SE LO PASO A LA PARTE ECO. Buenos días Amalia, en contestación a tu llamada, te mando lo siguiente: - Facturas de alimentación pendientes de pago (la que te entregué en mano, y otra del mes pasado), en la factura se indica el número de cuenta y el teléfono de la tienda. Ya he hablado con la dueña para concretar el tope economico y qué puede consumir, y con la auxiliar para que se ocupe de las compras. En cuanto podais pagad esto porque es atrasado. - Te mando también una factura de luz que está pendiente. - He hablado con el estanco y no hay problemas en organizar el consumo del tabaco como ya hablamos, y me traerán una factura desde este mes. El teléfono del estanco es 617001356, la dueña se llama Juana. En la factura indicará el número de cuenta. Creo que ya está todo lo que hablamos, si necesitas que esta documentación te la mande también por correo me dices. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2019-06-05','Ana: En la reunión mantenida ayer con Toni de Futuex, me entrega los informes médicos y resultados de pruebas realizados en los últimos meses a Rosa en relación al tumor detectado. Puesto que en el último informe de Cirugía el especialista especifica que Rosa "niega su deseo a intervención quirúrgica" se **lo paso a los compañeros de la Sección Jurídica para que lo comuniquen al Juzgado. *Todos los documentos están escaneados en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-06-05','Ana: Recibimos por fax escrito del FISCAL DECANO, en el que expresa "...el fiscal nada tiene que objetar... a que participe en cualquier acto público..." //////// Lo escaneo, guardo en su expte. y envío por email a Ángela, Directora-PLACEAT. //////// Llamo a Ángela, Directora de PLACEAT (927 421 950 ext. 102). Confirma la recepción. Hoy mismo irá Mª Rosa irá a la radio.','2');
