insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2019-06-05','Ana: Recibo llamada del la Tamara, Direct.Res.Mensaj. Paz, le han llamado del hptal porque no han recibido el fax. Le informo que lo envié ayer y dio OK. Lo volveré a enviar al nº que facilitan: Fax Medicina Interna: 927 42 83 32. *Reporte OK.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2019-04-23','23/04/2019 Expediente - SE PERSONANA EN OFICINA MERIDA MANUEL , SU PADRE Y SU TIO . TIENEN HOY EL JUICIO EN ZAFRA IMPUTADO POR MEJIAS DE LA MORENA , TB TUTELADA . EL JUICIO SE HA ARCHIVADO . TUVO UNA RELACIÓN SENTIMENTAL CON ELLA HACE AÑOS CUANDO ESTUVO EN P.SUPERVISADO DE ZAFRA. HA TENIDO INGRESOS EN CSS DE MERIDA . LA MADRE TB CON PATOLOGIA MENTAL , VIVE CON ALGUNOS HIJOS EN MORALEJA . ÉL Y SU PADRE VIVEN EN CORIA CON LA ABUELA MATERNA POR CONFLICTOS DE CONVIVENCIA. TIENE UNA HIJA DE 15 AÑOS QUE VIVE CON SU MADRE Y A LA Q PASA 100€ AL MES . BUENA RELACIÓN CON ELLA , LA VE CUANDO VA A MORALEJA.','2');
