insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-06-06','Ana: Envío mediante e-mail escrito-solicitud a la Jefatura de Policía Local para que acudan al domicilio de Manuela para corroborar por escrito que su nieto se la ha llevado a otra provincia sin comunicado previo ni autorización de la Comisión. /////////**Al final de la mañana recibo email de la Policía Local: "Adjunto se remite informe relativo a lo solicitado con respecto a Dª MANUELA MORATO PICADO. Atentamente. Juan Antonio Morato Bonito Oficial Jefe de Policía Local" con el Informe en documento adjunto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-06-04','Ana: Cuando hablo con Belén, Secc. Eco, me comunica que ella está en contacton tanto con la farmacia como con el Podológo, al parecer es José Manuel quien está bloqueando los pagos, pues pidió que le entregaran a él las facturas en lugar de enviarlas a la Comisión (como habitualmente) y él no las envía para reclamar a posteriori que no se han abonado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-06-05','Ana: hablo con los compañeros de la Secc. Jurídica, puesto que no podemos demostrar documentalmente que José Manuel se ha llevado a su abuela sin autorización ni comunicación previa, y la Trabajadora Social no quiere acudir al domicilio, acordamos pediré a la Policía Municipal que acuda y nos corrobore por escrito que no está.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-06-06','Ana: Recibo llamada de Toni-Futuex, ayer Gloria visitó a José, al parecer quien está en domilio es Antonio, chico con el que mantiene algún tipo de relación, con el que afirma haber tenido discusiones recientemente. **El casero dice estar cansado de las numerosas quejas de los vecinos, entre otras cosas por los ruídos a altas horas de la madrugada. Afirma que como siga reicibiendo quejas le echa del piso. *Mañana acudirán a verle de nuevo Gloria y Toni e intentarán pasar por el domicilio a ver y hablar con Antonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-06-06','Ana: Recibimos carta informativa de la Dirección General de Sanidad, Pªs Soc, e Infancia y Familia. "...se ha procedido a incluirle en la base de datos de las pnc... como representante legal".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-06-10','-Ante la imposibilidad de contactar via teléfonica , envio email a la TS del CTro. Penit. -Buenos días , te estoy llamando para hablar de Rafael Cacho , creo que me comentaste que la fecha prevista de excarcelación era hoy dia 10 de Junio . Se solicitó desde la Comisión internamiento involuntario en CSS , sin los informes del Centro que no se han enviado aún , pero no hemos tenido respuesta . Un saludo Amalia TS de CTAEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-06-06','El Juzgado nº 4 de Badajoz nos devuelve el inventario porque argumenta que según sentencia (?) no hace falae que les enviemos ni inventario ni rendición de cuentas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-06-06','Ana: Pongo para firma de la D.Gerente la solicitud de renuncia de vivienda de promoción pública remitida por Estrella Duran, TS - Vivienda Plas. //////// Envío escaneada a Mª Carmen, TS de la Res. P.J.C.Rguez. Ibarra, la autorización para recabar datos de la Agencia Tributaria debidamente firmada y sellada por la D. Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2019-06-06','Ana: En relación al correo de Ángela-Placeat: "...Te comunico que si le han efectuado el pago de la PF en la cuenta antigua. Saldo a fecha de hoy, 636,21€ También te informo que ya también le gestione el cambio de domicilio, no es necesario firma de ustedes, pues al ser cambio dentro de la misma localidad , el documento lo firmó el representante de Placeat y efectuamos el cambio de los todos los nuevos ingresos realizados en el primer trimestre del año." Respondo: "...en cuanto a la tarjeta sanitaria, no lo digo sólo pora la dirección, sino por el número, pues si sigue con el número de beneficiaria (el que tenía antes) lo más adecuado es que ya se le solicite la tarjeta con su número propio, del que ya dispone"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-06-06','Ana: Recibo correo de Cristina - CRR Plas. Me envían escnaeada la cita para Radiografía de Consuelo para el próximo 26/06/19 a las 10:06. /// Reenvío la cita a Pilar Cerrillo, TS de la Res. San Jorge (618 908 506). Hablo con ella con respecto a la plaza de Consuelo, me comunica que tienen plazas libres concertadas por el SEPAD, que por qué no le pedimos la prestación vinculada al servicio para plaza temporal. Hablará con el Equipo de Depend. de CC. /////// Llamo a Lucía(605 15 13 70) para plantear el acompañamiento a la Radiografía. Confirma que acompañará a Consuelo a la cita en el HU.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2019-06-06','Ana: Recibo llamada de Chus (638 499 546), Pisos de Miajadas, Steve tiene cita en Salud Mental el próximo día 27 de junio en CC. Le han adelantado la cita porque en el último tiempo está teniendo alucinaciones y recientemente ha tenido 3 crisis en poco tiempo, en todas las ocasiones han llamado al 112, aunque no ha sido necesario el ingreso en UHB le recomendaron acudir a Salud Mental lo antes posible pues consideran que la medicación no está bien ajustada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-05-31','Ana: Recibo correo de Vere- Resid. Puente Real- San Vicente A.: "He hablado con un primo de Ramon que posiblemente lo acompañe a la cita de Cardilogia, lo que pasa es que la analítica tiene que ser antes y estamos pendientes que nos den la cita, ya te contare como lo resolvemos. Tambien he hablado con la farmacia de Valencia de Alcantara para que le organicen la medicación por semanas y la Dra de la residencia le hará las receta, mientras sea de compañía privada. Hoy ha venido y lo hemos duchado, afeitado….. Ya te voy contando. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-06-07','Ana: Llamo al CADEX-CC, Juani (21991) dice que no sabe por qué no se envió el Certificado cuando se solicitó en enero. Me adelantará copia por mail, aunque no está firmado, y en papel tanto el Cdo. como del Dictamen Técnico el miércoles próx. por correo postal, pues hasta entonces no estará el director para firmarlos. ///////// Llamo a Raquel,T.S. ESM-Trujillo (L-X-V en Cáceres:53334 y M-J en Trujillo:54509): Como Miguel no es paciente suyo, me enviarán documento en que conste por escrito. ////// Llamada al Centro de Salud de Trujillo (927 320 769), Ángel, TS (54503), hablará con el médico psiquiatra para ver si le han atendido y valorado alguna vez. *Volver a llamarle el lunes.','2');
