insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2019-06-07','TERESA: Buenas tardes, soy Lydia Prado, directora de residencia de plena inclusión Cabeza del Buey. Informaros que Antonio Jesús tiene pareja y quieren mantener relaciones. Las psicólogas están trabajando con él y su pareja este tema. ¿Hay inconveniente en que mantengan dichas relaciones? ¿Podría Antonio tener un gasto en preservativos? LE INDICO QUE LAS PUEDE MANTERNER Y CONSULTO A GESTION ECO EL TEMA DE GASTOS DE PRESERVATIVOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2019-06-10','TERESA: EN LA VISITA AL CENTRO ME COMENTA QUE ESTA TRABAJANOD EN LA HUERTA Y GRANJAM, TIENE BUENA RELACION CON SUS COMPAÑEROS Y ESTA BIEN ADAPTADO. EL DIA UNO VISITA A SU FAMILIA UNA PRIMA Y UN TIO EN MONTERRUBIO. NOS COMENTA QUE SALE POR EL PUEBLO Y AYUDA EN LOS BARES A TIRAR LA BASURA Y CON ELLO SE GANA UN DINERO EXTRA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-05-10','-HABLO CON LA TS DEL MODULO 1 DONDE SE ENCUENTRA ( ANGELA ) SOLICITO INFORMES PARA SOLICITAR EJV PARA EL INTERN INVOLUNT EN CSS PARA SU COMPENSACIÓN Y TTO. ESTABA ALLÍ JOSE MANUEL , SUBDIRECTOR DE RÉGIMEN AL QUE LE HACE LA CONSULTA Y ÉSTE CONTESTA QUE ESO YA SE INTENTÓ OTRA VEZ Y EL JDO. NO LO AUTORIZÓ Y QUE SUPONE UNA PERDIDA DE TIEMPO . INSISTO ENVIANDOLO POR FAX AL CTRO PENTI. ( 924289113) SUBDIRECTOR DE TTO ( VICTOR 924289102). LES PIDO TB INFORMACIÓN SOBRE EL DNI , ESTABAMOS A LA ESPERA DE QUE SE LO HICIERAN , ME LO ENVIA POR FAX. -PARA PODER SOLICITAR PNC ,( NO TIENE NINGUNA PRESTACIÓN) , NECESITAMOS ABRIR UN Nº CUENTA , PARA ELLO HAY QUE LLEVAR EL DNI ORIGINAL A LA ENTIDAD BANCARIA. SOLICITO AL CTRO QUE NOS LO ENVIEN PERO NO ES POSIBLE , COMO MUCHO TE LO DEJARIAN SACAR UNAS HORAS Y VOLVER A LLEVARLO SOLICITANDOLO POR ESCRITO. ME DICE LA TS QUE ELLAS LE DAN INFORMACIÓN PARA QUE TRAMITEN EL SUBSIDEO DE EXCARCELACIÓN DERIVÁNDOLO AL SEXPE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN DIEGO'and edp.apellido1='BAUTISTA'and apellido2='GOMEZ'),'2019-06-10','TERESA: EN LA VISITA AL CENTRO NOS COMENTA QUE TIENE ESCASA RELACION CON LA FAMILIA Y RECIBE POCAS VISITAS. ME TRAIGO EL PAIS PARA QUE LO FIRME CONSOLACION. ME SOLICITAN PRESUPUESTO PARA LA COMPRA DE JUGUETES YA QUE LOS QUE EL USA SON DEL CENTRO Y NO LOS PUEDE USAR SIEMPRE QUE QUIERE. PIDO PRESUPUESTO DE LO QUE HAY QUE COMPRAR PARA VER SI HAY POSIBILIDAD DE COMPRARSELOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-06-10','Ana: Llamo a Carmen, Directora Res.La Coronada - Vca.Barros (20211). Paula continúa bien, la pastilla que le recetó el psiquiatra en la última consulta la está tomando sin problema, ha aceptado que es por una enfermedad. No obstante le han pedido nueva cita en Psiquiatría en su área sanitaria, a propuesta del médico del centro. En cuanto a la renovación del DNI esperarán un poco para planteárselo. Y en relación al pago de la Resid. hablarán con Belén, área económica (de momento hay que abonar la parte proporcional de mayo) ***Solicito nos envíen Certificado de Ingreso para la comunicación al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2019-06-10','Ana: Llamo a Carmen, TS del CAMP Las Cruces-D.Benito (20113): De momento va adaptándose muy bien. En la entrevista inicial fue "bastante dicharachera", fue muy comunicativa. Las noches las está haciendo muy bien, las comidas también las está haciendo bien y a nivel conductual de momento tampoco ha surgido ninguna incidencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-06-10','Ana: Llamo A Ángel, TS del C. Salud de Trujillo (L - C.Saldud Valdefuentes: 927 38 85 50): Intentó hablar con Merche, TS del SSB, pero le dijeron que no estará hasta el martes. Hay algo anotado en Jara con respecto a su diagnóstico de psiquiatría, pero el acceso a Jara es restringido. Hablará hoy con el Dr. Julián Garrido Montero, Médico de Att. Primaria. Me informará al respecto. **Necesitamos un diagnóstico para la solicitud de plaza. Y si finalmente el ingreso fuera en C.Mayores, necesitaría el modelo médico de la solicitud por decreto. /////// Llamo al CADEX, Juani (21991), el certificado que me enviaron corresponde a otra persona, el Dictamen Técnico sí es el suyo. *NO obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-06-07','-Me acerco al Hostal el torero( 636186291) , ya no puede permitirse economicamente seguir ahí y sacar reintegros . Me informan que hace unas semanas que no está allí. El dueño le dijo que no podía pedir limosna y tabaco a los clientes , él se enfadó y se fué. Compruebo con la parte eco la última factura y está abonada. Desde el Hostal no nos han informado de nada. Durante la última semana he hecho gestiones con inmobiliarias de Mérida y en portales inmobiliarios con particulares intentando ayudarle en la busqueda de piso de alquiler . Nadie quiere alquilar a una persona con discapacidad , sin saber siquiera el motivo de ésta , y todos piden referencias antes de alquilar. ( Amalia )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2019-06-10','TERESA: EN LA VISITA AL CENTRO NOS COMENTA QUE HA FALLECITO EL PADRE HACE UNOS MESES, HA VISITADO A LA FAMILIA ACOMPAÑADO POR PERSONAL DEL CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2019-06-10','Ana: Llamo a Rosa, Admtvo. CSS (24145). Me confirman que le acompañarán desde el centro al Juicio que tiene el día 15 de julio a las 11:00. Desde aquí, los compañeros del Secc. Jurídica, asistirán por *Videoconferencia. *Le han solicitado abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2019-06-10','-Por lo que desde el 7/06/2019, permanece ingresado en la UHB de Mérida. (Amalia )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2019-06-10','En relación a la documentación de la defensa judicial de Mª DEL CARMEN ASENSIO GARCIA, comentarte que no nos corresponde pedir medidas cautelares de este expediente por cuanto, al haber sido el juicio el día 6-6-19, suponemos que nos habran nombrado a la comisión tutelar de adultos, para una tutela o curatela?. No podemos portanto intervenir como sabes pues no hay sentencia firme aceptada por esta Comisión tutelar de adultos. Por lo que he leído de la documentación que nos entregastes, veo que los servicios sociales de base están al corriente de la situación límite en que se encuentran por la edad de los padres, y los episodios de violencia que se suceden en el domicilio familiar. Por tanto, deben de ser ellos los que activen procedimientos de urgencia, vía el 112 por ejemplo. Lo más que podríamos hacer nosotros es remitir esta documentación al Ministerio Fiscal para que éste estudie la situación y decida qué puede hacer, pero ya digo, no nos corresponde. Miguel ( juridico CTAEX )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-06-10','TERESA: RECIBO EMAIL TS MERCEDES Me pongo en contacto para comentarles que la ex-pareja de Beatriz ha averiguado su número de teléfono y la semana pasada le envío mensajes vía whatsapp que ella me ha mostrado en los cuáles le dice que se olvide de su hija y que inmediatamente deje la relación sentimental que actualmente mantiene con un chico compañero de Plena Inclusión Llerena. Tiene bastantes audios en los que le amenaza con un tono desafiante y grosero ordenando que abandone la relación o no volverá a ver a su hija porque se lo va a decir al abogado. Aunque le hemos explicado a Beatriz que él no puede decidir esa cuestión ella desde que recibió los mensajes ( que Bea os puede enviar si lo consideráis necesario) siente mucha preocupación e intranquilidad y constantemente pregunta si ya sabemos algo de cuándo podrá ver a su hija. Os traslado esta información para que seáis conocedores de las amenazas que le hace el padre de la menor y se tomen las medidas que se consideren oportunas. Y aunque ya nos trasladasteis que en cuanto el juez resolviera las visitas de Beatriz a su hija nos informaríais y soy consciente de que son trámites muy lentos, os traslado la inquietud manifesta y perseverante de Beatriz con respecto al tema. LE INDICO QUE LE BLOQUEE EL TELEFONO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2019-06-10','TERESA: LLAMO AL CENTRO PARA PEDIR CERTIFICADO DE INGRESO Y ME COMENTA QUE EL VIERNES SE FUGO DEL CENTRO, CONSIGUIERON DAR CON EL Y QUE VOLVIERA AL CENTRO. MANIFIESTA INQUIETUD POR SU MADRE PUES COMENTA QUE YA ESTA EN LA RESIDENCIA Y NECESITA DINERO Y DOCUMENTANCION LA CUAL EL QUIERE LLEVARLE DE AHI QUE SE HAYA FUGADO. SE VAN A PONER EN CONTACTO CON LA TS DEL PUEBLO PARA AVERIGUAR ESTE TEMA Y ASI SE QUEDE TRANQUILO POR LO DEMAS SE ENCUNTRA BIEN ADAPTADO EN EL CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2019-06-10','Ana: Llamo a Longina, TS Ayto. de Madrigalejo (los lunes atiende en Campo Lugar: 927 35 00 02) Ella no sabía nada, me pregunta por el nombre de la aux. de ayuda a domiclio, para intentar hablar con ella, pero lo desconozco. *Intentará hablar con J. Antonio, pareja de Josefa, el miércoles que estará por Madrigalejo. ////// Llamo a "Mimos", empresa de ayuda a domicilio acreditada de Navalvillar de Pela (606 38 67 50), Isabel Mª Ojeda, acordamos el cambio de empresa para prestar el servicio, para intentar mantener M y J, 2,5 h/día (Las 20h mensuales que tiene concedidas por PIA) Explico la situación con los animales en el domicilio. Me enviarán la solicitud de cambio de empresa y el contrato a mi correo electrónico para ponerlo a la firma de la Gerente. // Le facilito el nº de Toni-Futuex, para que la primera visita la realicen acompñada de Gloria, Delegada. //Les facilito también el contacto de Alberto, de Dependencia Extremadura. /// Llamo a Toni-Futuex, le dejan nota para que me devuelva la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2019-06-10','(coral). teléfono de su hijo Abrahan 927 23 47 06 - 639 88 78 97 //////// Ana: Recibo llamada de Abraham, dice que le parece raro que no haya ido Carlos, TS del SSB de Aldea Moret a visitarles, de cara al informe que normalmente se le pide para la rendición anual al Jgdo. Añade que vive de alquiler y que hace años que tienen solicitada una vivienda social y que aún no saben nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-06-10','Ana: Llamo a la empresa SEYMA S.L., para comunicar la baja en el servicio. Ya se habían enterado por la propia auxiliar. El último recibo que han pasado corresponde al mes de mayo y no pasarán más. *No es necesario enviar ningún documento ni firmar nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-06-10','-Inmaculada , ts , se encarga de dar de baja la teleasistencia. -Pido a Futuex que cuando vaya , solicite informacion de la linea tf. para poder cambiarla desde allí , piden que se ponga al tf la titular de la linea. Amalia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-06-10','Ana: Recibo llamada de Toni-FUTUEX. El viernes estuvieron visitando a Jose, finalmente le acompañaron al domicilio, donde se encontraba Antonio ("pareja"), le invitaron a marcharse y éste cogió sus cosas y se fue sin poner mucho impedimento. José fua a pasar el fin de semana a su pueblo y hoy lunes vuelve a la pensión en la que se alojó anteriormente. Se dejará la vivienda. Gloria intentará trabjar con él, cuestiones relacionadas con las "relaciones saludables de pareja" e intentarán que le deriven a Salud Mental para abordar la cuestión en mayor profundidad. //////// Informo a Alberto, Secc. Eco, para que reajusten la asignación semanal y se encarguen del resto de cuestiones económicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-06-10','Ana: Llamo a Vere, Resid.Puente Real (924 411 032)varias veces, la única vez que me contestan me dicen que Vere no está, le dejarán nota.','2');
