insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2019-06-11','Ana: Conversación telefónica con Pilar, TS San Vicente de Paúl-Plas. Tienen un presupuesto económico para arreglo del baño de la vivienda de Mª Carmen pendiente de aprobar (lo paso a Alberto, área eco.) y una consulta sobre la posibiliad de hacer testamento, pues Mª Carmen así lo demanda (Lo paso al área jurídica). **La curatelada actualmente reside en el Piso de Semiautonomía de la Entidad. Ha comenzado a pasas algunos fines de semana en su domicilio junto a otra compañera.','2');
