insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='LUNA'and apellido2='SEGADOR'),'2019-06-12','TERESA: Tras hablar últimamente de su situación económica y de todos los gastos que ha tenido, principalmente en viajes y excursiones, hablamos con ella de las diferentes opciones que tenía para viajar este verano y tener vacaciones, y eligió, como sabéis, la opción de la convivencia de batucadas de Granada de este próximo fin de semana, renunciando a la semana en la playa de la que viene disfrutando desde hace años, entendiendo que prioriza actividades nuevas y dónde se relaciona con gente nueva y desconocida para ella. Pues bien, en todo este proceso, nos llega información sobre un campamento de verano del Instituto de la Juventud “Capacitados para disfrutar II” que se celebrará del 17 al 24 de Julio, en el Centro de Menores de Trujillo, específico para menores con discapacidad y de coste GRATUITO. Nos pusimos en contacto con el director del campamento y le propusimos la participación de Isabel, que aunque no es menor de edad, pensamos que le vendría muy bien participar de esta actividad y su perfil podría encajar muy bien. A ella le ha gustado mucho la idea y está encantada con la posibilidad de ir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-06-11','Ana: Recibimos un correo de Paula, T.O. del CRR_Plas. sobre Ceferino: "...Éste en cita con su psicóloga ha elaborado un documento en el que solicita que curséis el documento de solicitud de traslado a otro CRR. En él aparecen los argumentos que esgrime. Esta demanda es alternante. Nosotros en estos momentos estamos trabajando el objetivo de "perseverar en una tarea" de forma que inicie y termine la actividad o tarea que hayamos acordado, posibilitando que pueda tener acceso a actividades importantes para él (que en algunas ocasiones requieren algún tipo de presupuesto). Ya nos diréis qué valoráis respecto a tramitar o no dicha solicitud." /////// Llamo a Paula (927 42 33 37 // 927 42 39 78) Le dejan nota para que me llame cuando pueda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2019-06-11','Ana: Recibo un correo de Dependencia Extremadura: " Buenos dias Ana. Soy Alberto coordinador de zona Vegas Altas de la empresa Dependencia en Extremadura. Adjunto documento que tiene que firmar la usuaria Josefa Fernandez Serrano, el documento es como si lo hubiera elaborado ella, ya que ante un cambio de empresa, nosotros no podemos emitir este tipo de documentos. He estado hablando con Isabel, responsable de la otra empresa que realizara el servicio y hemos puesto como fecha de baja el 15/6/19 y ellos pondran como alta el 16/6/19. Sin mas un saludo, y ante cualquier duda tienes mi telefono, gracias." /////// Modifico el documento para que consten los datos de Consoli como Representante Legal y lo pongo para firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-06-12','TERESA:telefono de Carolina su hija por si te tienes que poner en contacto con ella para avisarla que a partir de agosto deberá abonar los recibos de la casa . El número es 643 918 831','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-06-12','Ana: Llamo varias veces a Juani, CADEX (21991), el certificado que me enviaron corresponde a otra persona, el Dictamen Técnico sí es el suyo. ***Ya tiene listos los 2 documentos para que los firme el Director y enviármelos por correo postal. ////// Llamo a Ángel, TS - Centro de Salud de Trujillo (54503) El médico de A.P. dice que no puede aportar mucho más. El Psiquiatra, Dr. Medina no le ha dado respuesta aún, intentará hablar de nuevo con él. **Necesito los informes para la solicitud de ingreso por vía decreto si finalmente se solicita plaza en Res.Mayores con Ud. de Psicogeriatría. /////// Llamo a Mercedes, TS-SSB Trujillo (927 65 93 91)No está, me pasan con su compañera Esperanza, el último informe lo envió ella por ausencia de Mercedes, pero dice que el caso lo sigue llevando Mercedes, le deja nota para que me llame. Por otra parte dice que si no recuerda mal Miguel estuvo hace mucho tiempo ingresaso en el CSS de Plasencia.////////// Llamo al CSS-Plas. (24145) Rosa busca en los expedientes y no hay nadie que corresponda a los datos. /////// Conversación telefónica con Ángel, TS C.Salud, el Psiquiatra dice que no hay nada en relación a este paciente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2019-06-12','Con motivo de la consulta realizada por Pilar Sánchez, Directora del hgsv de Plasencia, relativa a la posibilidad que María del Carmen pueda otorgar testamento, le indicamos, vía correo electrónico (direccion.hgsvplasencia@gmail.com) que, según los términos de la Sentencia que la incapacita, no puede hacerlo.','2');
