insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-06-12','Ana: Recibo llamada de Ceferino, pregunta por su solicitud de cambio de centro, le digo que hace poco tiempo que solicitó cambio, que sólo lleva allí desde octubre y que en los meses anteriores a su ingreso hizo distintas solicitudes de cambio de residencia. Lo ideal es que resida allí más tiempo y siga con las terapias que necesita. En ese caso dice que su novia (residente del CRR de Ba) quería irse a Plasencia con él, pero como estaba pendiente de operaciones renunció. Como lo primero es la salud, vamos a ver cómo evoluciona su pareja. ////// En cuanto al reintegro de la extra ya está en contacto Paula y los compañeros del área económica, hubo un problema con la recepción de la autorización en el banco. ////// Y en relación al aumento de las asignaciones diarias en el CRR, le recuerdo que desde el propio centro le están gestionando esa parte y que está en función del acuerdo que firmaron tras la incidencia de la compra-venta de teléfonos. ////// Por último pregunta que si puede comprarse un móvil tactil si ahorra, le indico que si es con sus ahorros y de PREPAGO, podría hacerlo. ////// Llamo a Paula, TO, pero está ocupada.','2');
