insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-06-12','Hola Amalia; el lunes hablé con ella y estaba muy cerrada, le deje la puerta abierta y le ofrecí el vernos. Esta mañana ha llamado para comentar que había revalorado el venir, he quedado en darle una cita la próxima semana, porque es cierto que las entradas previstas se ha cubierto con otras personas de la lista. Priorizaré para la próxima y hasta entonces la veré yo. Ana Delfa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-06-06','Ana: Recibo un correo de Pilar, TS de la Res.del Casar de Cáceres: "...Por otro lado , como te comenté esta mañana por teléfono, tenemos en la Residencia de casar a un tutelado vuestro, Pedro Román García García, nos ha devuelto dos recibos de estancia, el de abril y el de junio, motivo de la devolución: sin justificar. Ya hace tiempo envié un correo a la Comisión Tutelar para informar del tema, entonces solo era el recibo de abril, además en día posteriores hablé con dos compañeras de la Comisión que me dijeron que lo iban a mirar y se pondrían en contacto con nosotros, pero aun no sabemos nada. Te agradecería que lo hablases con quien corresponda o si es necesario que yo envíe un correo electrónico o las facturas o lo que necesitéis. Muchas gracias por tu atención Un saludo Pilar Cerrillo Hortet" *Le pido que envíe un correo al ctutelar@ recordándolo e igualmente se lo comunico a Alberto, Secc.Eco por escrito.','2');
