insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-06-18','-LLAMA LA MADRE POR TF. 696075874 , SIGUE SIN PODER RETIRAR LA PENSIÓN Y YA LE HA ADELANTADO A SU HIJO MUCHO DINERO. -ESTUVIERON EN EL ESM EL DIA 17 JUNIO , QUEDO PTE. HABLAR CON MARIA . SE QUEJA DE QUE LA PSIQUIATRA LE PREGUNTÓ A SU HIJO SI QUERIA INGRESAR EN EL CRR PERO QUE ÉL SE NEGÓ. NO LO ENTIENDE , DICE QUE ELLOS SE VAN A IR Y VAN A DEJAR SOLO A RUBÉN. QUIEREN QUE LA JUNTA SE HAGA CARGO DE ÉL PORQUE PARA ESO SOMOS SUS " TUTORES " . SE QUEJAN DE QUE NO SE LES HAYA NOMBRADO TUTORES A ELLOS Y QUE AHORA ESTÁN PEOR QUE ANTES. - NOS LLEGA UNA PROVIDENCIA, HAN PRESENTADO DENUNICIA POR EL TEMA DE LA PENSIÓN . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2019-06-18','Ana: Pongo para firma Solicitud de vivienda de promoción social del Ayto. de Miajadas y Anexo I (Solicitud de Ayuda complementaria al alquiler de viviendas en la C.A. de Extremadura), Solicitud de complemento para titulares de PNC que residan en una vivienda alquilada (Seg. Soc). /////// Llamo a Anabel Gil, TS del SSB - Ayto.Miajadas (927 34 70 00). Acordamos que en cuanto tenga los documentos firmados se los devolveré por correo certificado. En cuanto a Vanesa, expresa que su pareja "EJERCE MUCHA AUTORIDAD SOBRE ELLA. Es una persona muy vacilona que pasa de todo". Explica que cuando ella propuso la solicitud de Alimentos a Cáritas, más que por la necesidad era por ampliar su red de apoyo. Además en el domicilio y el día a día ella asume más gastos que él, cuando él percibe una pensión de mayor cuantía y se jacta de ello. Cuando realizó la visita al domicilio él no salió del dormitorio. Y aunque Vanesa es muy apañada en la cocina y organizada para las tareas del hogar, a su parecer necesita acompañamiento y mucho refuerzo. *Otra cuestión que le preocupa es la Planificación Familiar, no sabe qué medidas toma. **Le gustaría tener mayor coordinación con la Delegada tutelar para hecer el seguimiento. Le indico que hablaré con Toni-FUTUEX para que fijen de forma conjunta nueva fecha de visita. ///// Llamo a Toni y se lo comunico. Gloria se pondrá en contacto con Anabel.','2');
