insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-06-18','TERESA: RECIBO EMAIL DE TONI FUTUEEX: ayer sobre las 13:45h llamó la Dra. Constanza a la delegada de apoyo para decir que ibana a dar el alta a María Murillo porque ya no la podían retener más allí. Le contó que desde que llegó el viernes por la tarde, ya estaba diciendo que quería el alta. Así es que llegaría por la tarde a casa, suponemos. Además comentó que había hablado con la madre de María y ésta le había dicho que desde la Comisión se estaba iniciando un protocolo para retirarle el perro a María. Por lo que la madre de María le pedía a la Dra. Constanza si no podría tener ingresada más tiempo a María para que cuando se llevaran al perro, ella no estuviera en casa. La Dra. le dijo que no porque creía que iba a ser contraproducente que María apareciera en casa y el perro no estuviera porque podría hacer cualquier locura en el edificio o contra algún vecino. Ella proponía que cuando se hiciera la retirada estuviera presente la guardia civil para contenerla.','2');
