insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-06-25','Ana: Hablo con Juan, Enpresa Servicios del Fresno (924 677 705), hablará con Eva, T.O., para que nos envíe informe de los seguimientos efectuados del SAD. ////// Por otra parte me facilita una dirección de correo electrónico caceres@serviciosdelfresno.es para que solicitemos por escrito la información acerca tanto de los días y horarios de atención así como los datos de la Auxiliar que acude al domicilio. /// Procedo a enviar el correo realizando dicha solicitud. ////////// *Recibo llamada de Pablo Correa, nieto de Manuela (676 783 101), interesándose por su abuela y las gestiones que se están llevando a cabo. Me informa de que José Manuel tiene embargos y por eso no le interesa que haya constancia de los ingresos que pudiera tener. ////////// *Recibo llamada de José Manuel, nieto, dice haber acudido a solicitar el Certificado Catastral de la vivienda de su abuela, y le han dicho que tiene que solicitarlo la Representante Legal, pide que hagamos una autorización para que él pueda solicitarlo y/o lo pidamos desde aquí, pues lo necesita para la obra de rehabilitación de la viviena. En cuanto al hecho de no haber llegado a enviar presupuestos como se le indicó hace tiempo desde la comisión, argumenta que no lo ha hecho porque para la subvención lo que le tienen que aprobar es la obra en sí, pues los precios están estandarizados por la Junta de Extremadura en unos baremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-06-25','-SE RECIBE EMAIL DEL CRR: Buenos días, Desde hace un mes nos llega información referente a José María Guillen, usuario de CRR Grupo 5 (Mérida). Dicha información incluye a una persona llamada “Raquel”, siendo conocida en la residencia ya que estuvo realizando prácticas hace un tiempo. Supuestamente los relatos que nos hacen llegar a los profesionales del CRR son varios: Primero, a cambio de entregarle dinero a José María, hace que éste enseñe pisos a clientes o realice paseos a perros, (siendo conocedora de la situación de José María respecto a la gestión del dinero). Segundo (este si ha sido José María quien lo ha contado a tutora de referencia en CRR el día 19/06/2019) que esta señora, va a llevar a cabo en el “Hogar del Pensionista” unos talleres de cocina y para ello, necesita a cuatro personas, siendo los encargados de impartir estos talleres “sin cobrar absolutamente” según manifiesta José María. Dos de las cuatro personas pertenecen al CRR, uno es José María y otro es Emilia Morales. El pasado 21 de junio, aprovechando la visita de “Raquel” al CRR por motivos ajenos, desde el equipo técnico se habla con ella con respecto a estos temas. Desde el principio, esta persona reconoce tener contacto con José Mª, montando lo en su vehículo personal en varias ocasiones, darle dinero para algún café y acudiendo a un chalet que Raquel tiene en propiedad. Pero según verbaliza en ningún momento le ha pagado por realizar trabajos. Como comentaba desde el recurso, nos llega este tipo de información por varias vías, generando la desconfianza y la duda en la versión que Raquel nos da. A pesar de todo esto, no tenemos ninguna evidencia de que esto sea así. Por este motivo, destacar la importancia de informaos y que para que podáis valorar y decidir si intervenir. Para cualquier cosa, estamos a vuestra disposición. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-06-25','-LLama la TS de Guadiana , a la madre de J.C. , en procedimiento de incapacitación, le ha dado un inctus. Ha estado ingresada en el H.Perpetuo y el viernes por la tarde le han dado el alta. Han acudido con el enfermero que le ha pasado la herramienta para un T2. La derivo a los compañeros. -J.C. se quedaria solo en su casa , de momento en C. dia + SAD. Habria que solicitar revision de la sentencia para que pueda pasar a tutela y solicitar internamiento involuntario en centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2019-06-25','-visita a domicilio en Olivenza , C/ Honduras , nº1 , Puerta A , 2º planta. Acudo al domicilio con la TS de SSASB de Olivenza ( Manoli ) y con la delegada tutelar . Es un apartamento pequeño por el que paga 300€/ mes . Tenia una TV de segunda mano que dice que le han dejado en una tienda hasta que compre otra , la que habia en el piso no funciona y la ha llevado al punto limpio .Le indico que hable con el propietario si la TV no funciona para que se la cambie pero no quiere . Ha solicitado que le cambien al bajo , no funciona el ascensor . -Le explico el tema de sus gastos , gasta la pensión integra, no dispone de dinero para SAD privado y desde el Ayto lo tienen completo , pasaría a lista de espera. -Deudas ptes ,( según él ): Taxi Barcarrota. Molina . Tf 625130277 Se le deben 30€ Farmacia Barcarrota . Tf . 924736358 . Se le deben medicamentos que sacó la semana pasada. De las 5 lineas de Tf , dice que le quedan dos y se quedará con una . Quiere comprar una TV y una maquinilla de afeitar. -Se le solicitó desde el SSASB revisión PIa ; CO + ayuda a domicilio , aún sin respuesta. Le preguntaré a Manuela , aunuqe en esta esfera nosotros no intervenimos. solicitó SAD municipal , la TS le dice que hay lista de espera y no se le puede prestar el servicio . AD','2');
