insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2019-06-26','Ana: Recibo llama de Aída, dice que se le ha estropeado el ordenador, que ha pedido un presupuesto a una empresa para arreglarlo. Además quiere pedir un extra para vacaciones (dice haber estado muy enferma y que le vendrá bien para recuperarse). *Le digo que envíe los presupuestos al la cuenta de correo ctutelar@. En cuanto al viaje anterior a Segura de Toro, dice que finalmente fue con su amigo de EE.UU. y como iban a medias con los gastos no pidió factura de nada. Añade que como esta vez irá sola no volverá a ocurrir. ///// En cuanto a las dificultades de Gloria-Futuex, para visitarle, dice que habrá sido casualidad, que habrá coincidido con otras cuestiones y por ello no habrá podido recibirla.','2');
