insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-06-26','Ana: Conversación con Lucía (605 15 13 70), en la consulta de TRAUMATOLOGÍA de hoy, a Consuelo le han quitado la escayola, le han hecho placas de las piernas y columna, y evoluciona bien, pero le han dicho que debe seguir sin apoyar los pies, tan sólo puede apoyarlos en la silla de ruedas, pero nada más. La próxima cita será dentro de mes y medio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-06-27','Un saludo Inmaculada Sánchez Becerra>manveba2@badajoz.es> jue 20/06, 11:25Amalia Diaz Gonzalez Buenos días Amalia, un par de asuntos sobre Juan Carlos Rubio: 1º- Su madre está ingresada porque le ha dado un ictus, dependiendo de cómo evolucione la situación imagino que habrá que reconsiderar alguna de las determinaciones que se habían tomado. 2º-Creo que habría que reactivar el expediente de dependencia de Juan Carlos, en su momento fue valorado con grado I, y no se firmó PIA porque era inasumible el copago, pienso que habría que hacerlo, ahora que controlais sus cuentas, porque le daríamos un poco de estabilidad al servicio. 3º- Necesita comprarse unas zapatillas de deporte, ¿te parece que se las compre en una tienda de aquí y os envio la factura con nº de cuenta?. Espero tu respuesta. Buen día','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-06-26','Ana: Recibimos correo de Rosa del CSS-Plas. "Buenos días: Como habeis podido comprobar en el correo que enviamos sobre J.M. ROMERO MEDIAVILLA, se ha dictado orden de cumplimiento de medida de seguridad en el Hospital Psiquiátrico Penitenciario de Sevilla. El traslado se hará efectivo el viernes, 28 de los corrientes. Será recogido en este Centro por la Guardia Civil a las 7:30 h. Lo que comunicamos para vuestro conocimiento y efectos que procedan. Un saludo. Rosa Bravo. CSS. Plasencia"','2');
