insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2019-07-01','-LLAMO AL CSS PLASENCIA PARA INFORMARME SOBRE EL INCENDIO QUE LA MADRUGADA DEL SABADO HA PROVOCADO EN SU HABITACIÓN. NO HUBO DAÑOS PERSONALES PERO SÍ MATERIALES , SE TUVO QUE EVACUAR A 98 ENFERMOS. ÉL GRITABA QUE HABIA SIDO ÉL , QUE ALÁ ES GRANDE , Y SU OBJETIVO ES REGRESAR AL CTRO. PENIT. DE CC DONDE CONSUME HACHÍS. LA DIRECTORIA DEL CSS , DARÁ PARTE AL JDO. DE LO OCURRIDO . SOLICITA QUE SE LE TRASLADE A OTRO CENTRO O AL CSS MERIDA , LE COMENTO QUE EN MÉRIDA TB HAY OTRO PACIENTE QUE HA COMETIDO EL MISMO HECHO ( GAMERO ) AD AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2019-07-01','-Nos llega un escrito de Aqualia indicando cunsumo excesivo de agua, 170m e indican q puede ser por alguana tuberia rota. llamo a la pareja de la madre , la llave de la vvda la tiene un hno de la madre que irá a comprobarlo . Sugiere q puede ser q los vecinos se hayan enganchado al agua de esta vpo. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2019-07-01','-Email de Aprosuba 7 : Buenos días Amalia , ayer aprovechando la visita de Susana (FUTUEX) le informamos que según Minerva le han retirado la pastilla que tomaba y que actualmente según palabras textuales se tenía que pinchar. (INTUIMOS QUE ES DIABÉTICA). Desde el Servicio de Centro Ocupacional no podemos administrar ningún tipo de medicación y debemos de tener conocimiento de la medicación pautada, igual que tener cualquier cambio prescrito por el médico de referencia. En varias ocasiones hemos solicitado un documento del médico de cabecera a su progenitora, se ha comprometido a traerlo mañana aunque de igual manera lo ha hecho en otras ocasiones y nunca ha llegado a nuestras manos. No vemos un control de la familia con la misma intensidad que cuando su progenitor falleció, de igual manera hemos solicitado en muchas ocasiones que tiene que traer cambio de ropa para ducha los días de Educación Física y nunca lo hace. No sabemos dónde poner límites a sus obligaciones como responsable de su hija ni cómo proceder porque tratar con Pepi queda en el vacío. Nos preocupa la supervisión del mes de Agosto que estará en el período vacacional y aunque nosotros no tengamos autoridad sobre ella si podemos hacer una supervisión aun sin respuesta por su parte. Un saludo, Firma_BMG','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2019-07-01','-Llamo a Lali para comentarle el correo de Ap7 , la inyeccion es semanal y se la pone en casa . Voy a pedir a Ap7 que compre ropa y la tenga alli pq su madre no la va a llevar . La semana q viene la llamaré para ver si quieren cambiar la transf de 400€ que se les hace a la abuela para q Diego compre la comida , quiere hablarlo con los hnos. Cree que se han equivocado y q los chicos necesitan un centro . Me volveré a citar con ellos . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2019-06-24','-Visita en Caser Residencial de Olivenza donde permanece , en plaza T3 por 604€. Es el padre d Juan José y Antonio Martinez Perez que son tutelados y se encuentran en La Luz . Hay que mandarle 100€ a la cuñada para extra de ropa y se hará así cada vez q lo necesite por transferencia a la cuenta de esta mujer. Tiene una VPP en C/Grecia Nº 6 3·C en Cerro REyes de Badajoz . Creen q está ocupada por ocupas . Le quedaba poco por pagar . Informarme de ésto. Dar de baja a sus seguros de Mafre de vvivienda, carrefur.. No al de decesos que cubre tb a sus hijos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-06-24','-Lo visito en Caser residencial Olivenza. Se le ha explicado a Manolo el nuevo director como vamos a dar los extras para ropa . se acordó darle 150€ para que su sobrina le compre ropa pero de la resi aún no han ido a por el reintegro. En la reunion con los familiares de Jose´Martinez le reprochan q no hay personal en lavanderia y la ropa desaparece y tb los zapatos de los residentes. Está en plaza privada , está en lista para plaza publica . SEria necesario que tramitasen dependencia , se lo comunicaré a su sobrina para que lo haga si lo considera conveniente , es curatela eco. Ad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-07-02','-LO VISITÉ EL DIA 24 DE JUNIO EN LA RESIDENCIA CASER DE OLIVENZA. LE HEMOS AUTORIZADO 150€ PARA ROPA . ESTÁ EN EL Nº 2 PARA PLAZA PUBLICA ALBURQUERQUE Y EL 3 EN BARCARROTA , INDICO A SU SOBRINA CRISTINA QUE SOLICITE L.DEPEND AUNQUE NO CREO Q DE GRADO . CURATELA ECO EXCLUSIVAMENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-07-02','Se ha ido a Málaga , al Seranil, buscando al psiquiatra con el que está obsesionada. Para conseguir verlo dijo que queria ingresar . Allí no le permiten la estancia pero se puso a llorar y al ser las 15.00 de la tarde accedieron después de hablar con su primo Jesús para que se quedase hasta hoy allí. Le dieron una habitación compartida que ella rechazó y por lo tanto se fue . Le solicitaron un hostal que pagó con dinero que llevaba de la asignación semanal . El taxi la dejó allí pq no le pagó los 400€ del viaje. Va cargada con el perro y el gato . Hoy cuando la he llamado me han pasado directamente al tf de una habitación de un hotel de Cordoba. He hablado con ella y me dice que está genial , que ha dejado la medicación y se encuentra mucho mejor , que sólo con el inyectable le basta. Que sólo queria que la llamase para que le dijera la hora de la reunión que había concertado con el Jefe de Sección economica para mañana en Badajoz. LLamada de TS de Badajoz con la factura del taxista que la ha llevado a Malaga. Llamada del dueño del Hostal La Estacion , Ctra. Malaga-Almeria , Benajarafe 29790 Malaga. Se ha llevado la llave de la hab. y ha dejado allí una maleta enorme , un bolso y el gato . Va a llamar a la protectora de animales para que se lo lleven. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2019-07-03','En relación con el Juicio sobre delitos leves 64/2019, a celebrar en el Juzgado de Primera Instancia e Instrucción nº 3, de Plasencia, antes de entrar le han preguntado si quería continuar, al ser el denunciante, ha dicho que no, por lo que se ha archivado.','2');
