insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-07-10','-Email de Susana desde Ap3: Escribo para informar sobre suceso ocurrido con Felisa Bruno Saavedra (tutelada por la Comisión Tutelar) y usuaria de RAL de Aprosuba 3. El pasado domingo, debido al buen comportamiento que estaba teniendo desde que salió de UHB, se le concedió salir a tomar un refresco con su pareja (usuario de C.O.) otro compañero y una educadora de Residencia. Todo fue muy bien, hasta que por la noche comenzó a quejarse de dolor de barriga y ganas de vomitar. Al día siguiente comenzó a tener muy mala actitud (desafiante y amenazadora) con los trabajadores. Dijo que había mantenido relaciones sexuales con su pareja en los baños del bar donde habían estado (algo que es imposible pues en ningún momento estuvieron solos), pero ella insistía en que había pasado. Ella desde el domingo por la mañana estaba con la menstruación. Por la tarde su actitud iba de mal en peor, exigiendo que la llevaran al hospital para que la vieran o si no la iba a liar, palabras textuales de ella. Ante esta actitud y viendo que su estado de ansiedad iba en aumento, se llamó al 112. Cuando llegaron, lejos de mejorar su actitud, amenazó a los sanitarios exigiendo que la vieran médicos “de verdad” y amenazó en ese momento con que o la llevaban al hospital o iba a empezar a romper cristales y pegar. Tras estas amenazas, fue derivada al hospital, y tras valoración y exploración fue dada de alta sin cursar ingreso. Le han anticipado la cita para Salud Mental y adelantado el inyectable seplión del viernes 28 de junio al lunes 24 de junio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2019-06-26','-email de Ap 3: Os dejo información sobre una diligencia que nos ha llegado de Pilar: 16 mayo jueves, la madre llama sobre las 17:30 a Roberto, monitor de taller a preguntar si sabía que era lo que la niña tenía en el labio. Roberto, como no sabía de ninguna ocurrencia, le comento que debería de ser un herpes. 20 mayo lunes, Pilar trae un informe (se adjunta informe) y antibiótico para tomar, pero no hace ninguna referencia a ninguna situación que hubiera tenido lugar en el centro y la hubiera molestado. 25 de junio martes, nos llega del juzgado una diligencia (se adjunta9 solicitando informe Hablamos con la madre para saber si nos podía informar de algo, no tenía conocimiento de nada, …. Hablamos con la comisión tutelar, no tenía conocimiento de ninguna agresión Hablamos con Pilar, nos cuenta que la herida en el labio ha sido de un mordisco de su novio Jonathan (que a la fecha de hoy no es su novio), que no ha contado nada porque la madre así se lo dijo, que quien le ha acompañado al centro de salud, fue el actual compañero de su madre Hablamos con Jonathan, nos dice que si le ha mordido, sin querer, dando le un beso, cuando eran novios, que se lo dijo a la madre de Pilar y que no ha escuchado nada más sobre el tema. Quedo a disposición para más información. Mañana haremos el informe para el juzgado.','2');
