insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-07-11','(Pedro)Llamada de Constanza, Psiquiatra de la UHB de Llerena. +++D.Juan Antonio sigue ingresado en la Unidad, y va a tratar de mantenerlo ingresado para que de allí salga a una residencia de mayores. Ha tratado de solicitar al Juzgado su ingreso por emergencia, pero le han dicho que ella no puede solicitar dicha autoreización. +++Nos enviará inoformes explícitos, sociales y psiquiátricos en los que se vea claramente la neceesiad de ingreso en centro. Para ello, habra que seguir doble procedimiento: +++++Solcitar ampliación de la incapacidad (de curatela a tutela) y a la vez solcitar ingreso involuntario por emergencia social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-07-11','(Pedro) LLamada de Constanza, Psiaquiatra de la UHB de Llerena. +++Para ella María no tiene ninguna enfermedad mental, sino una psicopatía. +++No entiende por qué tiene que estar tutelada ya que es perfectamente consciente de lo que hace y tiene una enorme capacidad de manipulación. +++Se va a esperar el plazo de seis meses que se convino con ella tras la Subcomsiión de Casos y caso de no cumplir con el acuerdo se convocará una nueva subcomisión.','2');
