insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2019-07-12','(Pedro).LLamada de Blanca (CSS Mérida). +++Dice que Manuel quiere hablar con la Comisión porque quiere saber qué tiene que hacer para solicitar la remoción. +++Informo a Blanca de que esa información ya se la dí cuando se le dió el alta y se fue a un piso de alquiler. +++Por otra parte, comento que la alternativa del CRR es una buena medida y que es una lástima que no aceptara el de Plasencia en su momento. +++Blanca hablará con él sobre todo ello.','2');
