insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-07-12','TERESA: ME LLAMO PALOMA PORQUE QUERÍA DINERO DE LA PAGA EXTRA, MANDE A SUSANA PARA QUE VIERA COMO SE ENCUENTRA Y ME COMENTA QUE TIENE DINERO,. LA TS LE TIENE SEAPRADO EN SOBRES EL DIENRO PARA QUE LO GESTIONE POR SEMANAS Y LO ESTA CUMPLIENDO, COMENTA SUSANA QUE TIENE DOS SOBRES CON 50 EUROS CADA UNO Y QUE AUN CUENTA CON DINERO DE LA PENSION DE SU PADRE. PALOMA TIENE UN PROBLEMA QUE COMPRA COMPULSIVAMENTE PERO PARECE QEU CON LA MEDIDA QUE TOMADO LA TS LO TIENE MAS COTROLADO, ADEMAS COMENTA SUSANA QUE TAMBIÉN TENIA COMIDA EN CASA Y QUE MAÑANA VOLVERIA A HACER LA COMPRA ACOMPAÑADO DE LA AUXILIAR DE AYUDA A DOMICILIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-07-12','Buenos días Amalia, El día 5 de de Julio estuvo en consulta con Psiquiatría Mercedes P.P. Al comentar con su psiquiatra tras la cita de la paciente y valorar como la veía, considera el Dr. Galán que por motivos de su situación clínica se debe abrir expediente de incapacidad total. Él mismo facilitará informes. Saludos, Mar Sánchez','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-07-12','- RESPUESTA AL CORREO DE MAR : Buenos días , nos gustaría saber cuál es su situación clínica actual , si es posible , solicitamos el informe de la visita . La motivación para solicitar incapacitación total viene derivada por algún cambio en su situación clínica ? Está siguiendo el tratamiento pautado correctamente ? Llegó a comentar que había dejado de tomar unas pastillas . En vuestra opinión , cuál sería el objetivo de la incapacitación total ? poca diferencia habría en la práctica a la hora de la intervención desde la Comisión Tutelar .Siendo paciente de salud mental , el ingreso en recursos residenciales de esa red exige la voluntariedad . Un saludo . gracias .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2019-07-12','TERESA: LLAMA EL PADRE TENA PARA COMUNICARNOS QUE YA ESTA ESCANEADO EL DNI, NOS COMENTA QUE DURANTE EL MES DE AGOSTO CIERRAN EL CENTRO Y SE VAN A ISLA CRISTINA. FERNANDA SE VA CON ELLOS YA QUE NO TIENE FAMILIARES EN SEPTIEMBRE RETOMAREMOS EL CASO PARA VER LA DEUDAS PENDIENTES CON EL CENTRO Y PODER PAGAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-07-12','(Pedro)Se recibe enla Comisión correo electrónico (urgente) de Futuex relatando los últimos aconteciomientos en relación a Dª Mª Eugenia. +++SE encuentra en el Centro Vida de Cáceres (927-235082. Contacto Mamen. A partir del lunes, contacto Lucía) porque la madre de Antonio le ha dicho que no lo quiere con su hijo. ¿QUIÉN ES ANTONIO? Dª Eugenia vivía con Marcelino... +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mamen, de Centro Vida dse Cáceres. +++Dª EUgenia se encuentra en el centro, pero ya está diciendo que el lunes se va con Antonio a Malpartida de nuevo. +++Ruego a Mamen que le diga que hahablado conmigo y que se debe quedar en el centro hasta que nosotros tomemeos las decisiones oportunas.','2');
