insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERNANDO'and edp.apellido1='FEBLES'and apellido2='GONZALEZ'),'2019-07-15','Ana: Llevo a dar registro de ENTRADA, directamente en el Registro del SES, la solicitud de MATERIAL ORTOPROTÉSICO (Subvención SILLA RUEDAS) junto con toda la documentación que en la solicitud se especifica. ///// Envío a Felisa Custodio, TS del CAMF, escaneada por email, copia registrada de la solicitud.','2');
