insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-07-15','Ana: Hemos recibido varios documentos en los últimos días: *Informe Médico para valoración de Dependencia de la Dra. Fátima Díaz Torrado (Att.Primaria) // *Informe de Psiquiatría de la Dra. María Ríos Muñoz, en el que recomienda ingreso en RAL y especifica que NO presenta alternaciones de conducta y precisa supervisión de terceros. // *Requerimiento del Juzgado nº3 de CC, para que desde la Comisión Tutelar se adopten las medidas necesarias ante la situación de desamparo. //////// Llamo a Pilar, TS de ESM - CC: le enviaré el informe médico para revisión del grado de dependencia y la solicitud de revisión firmada y sellada. Ella elaborará informe social para solicitar la revisión por emergencia social. **Se lo paso,junto con el oficio, a los compañeros administrativos soc. para que lo envíen /////// Conversación con Eva, TS del SSB-Arroyo de la Luz. Le informo de los últimos acontecimientos y de los siguientes pasos en la intervención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-07-15','Ana: Escaneo, guardo en el expte. y envío por email a Soraya, Jefa de Ud. y a Mercedes, TS Trujillo, el acta de la reunión en Trujillo ya firmado por las tres partes. ///// Llamo a Toni-Futuex, pero no se encuentra. Le dejarán nota para que me devuelva la llamada. //////// Llamo a Toni-Futuex. Irán a hablar con "La Santera de la Parroquia de San Lázaro", quién suele tener contacto con Miguel y a veces le da comida y a visitar a Miguel con el objetivo recogido en el acta de la reunión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2019-07-10','TERESA: SE ENVIA A LA SECCION DE DEPENDENCIA DE ZAFRA ACEPTACION PIA SERVICIO ATENCION RESIDENCIAL DISCAPACIDAD','2');
