insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-07-15','TERESA: SE ENVIA SOLICITUD DE REVISION O COMUNICACION DE CAMBIO DE CIRCUNSTANCIAS EN LA QUE SE SOLICITA REVISION DEL GRADO Y NIVEL DE DEPENDENCIA Y REVISIO DEL PIA YA QUE LA SPSQUITRA CONSIDERA QUE JUAN ANTONIO DEBE IRSE A UNA RESIDENCIA YA QUE NO POSEE LA CAPACADIDAD PARA PODER SEGUIRI VIVIENDO EN SU DOMICILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2019-07-15','(Pedro)Llamada de María (T.Soc. CSS Mérida).INCIDENCIA. +++Al parecer, Andrés, en un momento en que Isabel (Psiquiatra) salió de su depacho, cogió el aparato dental que ella había dejado en su estuche y lo tiró a la basura. dado que Andrés confesó este hecho cuando ya se había efectuado la recogida de basura, dicho aparato se ha perdido e Isabel quiere recuperar su coste (400 euros aprox.) +++Han pesnsado que lo pague una vez cobre su pensión, también como medifda educativa para él. +++Le indico que nos hagan un escrito en el que se relate lo sudedido, fiemado ppor Isabel y que el pago se podrá hacer en un par de veces, para que no se quede sin dinero. +++Pendiente de recibir ese escrito.','2');
