insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCAS'and edp.apellido1='DIAZ'and apellido2='VAZQUEZ'),'2019-07-15','TERESA: HABLO CON ANA LA ABOGADA CON LA QUE A CONTACTADO LUCAS PARA TRASLADAR SUS QUEJAR Y PETICION DE CAMBIO DE CENTRO. LE INFORMO QUE ESTA TUTELADO. ELLA ME COMENTA QUE LO SOSPECHABA Y QUE SOLO LE DIJO QUE ESO LO TENIA QUE GESTIONAR CON LA DIRECCION DEL CENTRO ME AFIRMA QUE ELLOS NO VAN A PROCEDER A HACER NINGUNA INTERNVENCION CON LUCAS. LLAMO A MONTSE Y SE LO COMUNICO, ME COMENTA QUE VA A VER LOS CENTROS QUE HHAY PARA PROPONERLE A LUCAS UN TRASLADO.','2');
