insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-07-16','(Pedro)Visita de José Mª sin cita previa. +++Bajo a atenderlo a la entrada porque el subalterno sube y dice que no se va a marchar hasta que hable conmigo. +++Se le ve nervioso y pide ingrsar en la UHB. Me pide que lo acompañe. +++En Urgencias, Virginia,la Psiquiatra considera que no hay motivo de ingreso y que él quiere ingresar porque se ha gastado todo el dienero del mes. José Mª se altera, porque dice que no tiene dinero ni para sus medicinas, ni para comer, ni para nada. +++Pido que autoricen 100 euros para llegar a fin de mes, priorizando la asistencia a su Médico de Familia para que le recete sus medicamentos (Virginia le da las dosisi suficientes para hoy y mañana), pida cita en el ESM y compre comida para él. +++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='MANGAS'and apellido2='DE LA CRUZ'),'2019-07-16','Ana: Hablo con Ana, TS de la Res. Virgen de la Asunción (927 44 10 97), quiere saber cómo va la cuestión del abono de la Res. pues lleva allí ya 2 años y aún no se ha pagado nada, ni las mensualidades ni los gastos de farmacia. *Se lo paso a Juana, quién dice que está pendiente, mañana se pondrá con ello y llamará para informar.','2');
