insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2019-07-17','TERESA: LLAMA RAMON PIDIENDO DINERO PORQUE SE QUIERE COMPRAR UN VESPINO, SE LE EXPLICA QUE NO PUEDE CONDUCIR VEHICULOS A MOTOR. SE MUESTRA MUY ALTERADO Y CON AMENAZAS. EL JUEVES TIENE QUE VISITARLO SUSANA PORQUE LE TOCA EL INYECTABLE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2019-07-17','TERESA: comunica las vacaciones que disfrutará Antonia Campa Silguero, la cual se desplazará junto a su hijo Juan Carlos, a Cilleros ( Cáceres) , domicilio habitual de éste. Como ya sabéis es la mejor Terapia que hay para la situación de los dos, hemos comprobado como revierte esto en el estado anímico de ambos. Se marcharía el día 12 de Agosto, regresando el día 23','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2019-07-17','(Pedro)Conversación con Soraya, Directora del CSS de Plasencia (24104). +++Jairo ha dado un paso importante: se ha presentado a los exámenes de la UNED y, auqnque solamente ha a probado el comentario de texto, desea volver a presentarse en la próxima convocatoria. +++En relación a la conducta incendiaria de otro interno del CSS con la intención de que se le llevase a la cárcel,Jairo, en clara conducta de imitación, ha manifestado su intención de hacer lo mismo que aquel para poder ir a prisión y quedar libre cuando salga de ella (con la idea de no volver al CSS). Ya se le explicó a esta persona que la realidad no era esa. +++La Subcomisión pendiente se aplaza a septiembre. Llamaré a Soraya para fijar fecha y volver a convocar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2019-07-17','(Pedro) Conversación con Soraya (Directora del CSS de Plasencia, 24104). +++En estos momentos José María ha sido traladado a UME. +++NO ESTÁ CUMPLIENDO CONDENA NI TIENE PENDIENTE NINGUNA EN ESTE MOMENTO. +++Traslado a Centro Psiquiátrico Penitenciario. En estos momentos están pendiente de que el/la Médico-Forense vaya a reconocerlo. Si los hechos se consideran constitutivos de delito, será el Juzgado el que decida dónde debe cumplir la sentencia que se le imponga. DUDAS DE SORAYA: +++++¿Qué hacer con José María si no se considera delito lo sucedido? ¿Qué hacer con José María, en el caso de que se dicte una sentencia y pueda ir a un Psiquátrico Penitenciario, cuando haya cumplido la sentencia? +++José María dice unas veces que se quiere ir a Málaga, otras a Zaragoza...Dice sentirse más libre en la prisión que en el Centro y para ello sabe qué debe hacer (con el peligro que ello supone tanto para él como para terceros). Además, algún otro interno en el CSS ha manifestado su intención de hacer lo mismo que José María para poder ir a prisión y quedar libre cuando salga de ella (con la idea de no volver al CSS), actitud de imitación de la conducta que José María ha desarrollado. Ya se le explicó a esta persona que la realidad no era esa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-07-17','(Pedro) Conversación con Carmen Barquilla (Fiscal). +++Habló con la Jueza del Juzgado nº 3. Ya han abierto el procedimiento y nos comunicarán el régimen establecido. +++Me aconseja hablar con el Juzgado para insistir en la premura del caso. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++LLamo al Juzgado de 1ª Insatncia nº 3 de Cáceres (927-624406): la jueza ha estado de vacaciones, pero creen que se va a resolver en breve. Quedo en llamar pasado mañana para preguntar.','2');
