insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-07-17','TERESA: lleva ingresado varios días en la unidad de psiquiatría de Llerena . y tras numerosas gestiones , la psiquiatra sigue insistiendo en que su mejor propuesta es el ingreso en una residencia por la vía más urgente posible , por lo que la trabajadora social del Hospital: Isabel Pilar , se está encargando de las gestiones pertinentes , habiéndome demandado diversa documentación para tal objetivo por nuestra parte seguimos proponiendo lo ya acordado , una atención matinal para aseo personal y preparación para asistir al centro de día asistencia a centro de día caminando acompañado por su hermano, para así también favorecer la movilidad desayuno de ambos en el centro de día almuerzo de ambos en el centro de día , y ya diego se puede llevar la cena de ambos preparada , a partir de la 6 de la tarde , hora de llegada de Juan Antonio a su domicilio, se reforzarían las atenciones de su cuidadora ( Pilar ) incluso con la posibilidad de reforzarla con cierta ampliación de horas de atención pagadas de sus propios ingresos , en espera de nuevo PIA REFUERZO DE HORAS EN FIN DE SEMANA De hecho tendrá que ser así , ya que no creo que se logre un ingreso en residencia inmediato ingreso en residencia por la via de urgencia. solicitud de modificación de PIA de ayuda a domicilio a ingreso en residencia y por empeoramiento , para lograr mas intensidad en el recurso DESDE LA COMISION TUTELAR SE VA A PROMOVER LA AMPLIACION DE LA INCAPACIDAD Y EL INGRESO INVOLUNTARIO EN CENTRO RESIDENCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-07-17','Ana: Recibo llamada de Pablo, nieto de Manuela, me informa de que a principios de mes ha comenzado a asisitir al domicilio una auxiliar "Quini Cepa", que antes no iba. Quiere que sigamos con las averiguaciones para constatar que durante muchos meses no ha estado yendo ninguna auxiliar y está dispuesto a Denunciar, acudir a la Seg.Social y donde haga falta. Le gustaría venir para hablarlo directamente con Marco, Jefe de Ud. Dependencia. Le indico que ahora está de vacaciones, pero tengo pendiente hablar con él cuando vuelva y se lo puedo plantear. /////////// *Casualmente tenemos un correo en el ctutelar@ de Manu Guerrero, Empresa Servicios del Fresno, a fecha de 1 de julio, diciendo que la Aux. es Joaquina Cepa González con DNI 07.046.010-Y. *Hablaré con Marco cuando vuelva de vacaciones.','2');
