insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-07-18','-Incidencia en CRR : El pasado 15 de julio del 2019, Jose Mª acude a su banco de manera autónoma y retira los 480€ de extras que se habían solicitado para poder hacer frente al pago de las vacaciones de verano, siendo totalmente ajenos a esta información por parte del equipo de profesionales del CRR de Mérida. Una vez retirada la totalidad de esta cantidad, JM no reconoce haber hecho esto hasta el 17 de julio del 2019, que en una cita con dirección, reconoce haber hecho un uso indebido de este dinero, gastando la totalidad del miso en Comidas, café, alguna cerveza, máquinas tragaperras y realizar visita a su madre en Cáceres. El mismo día 15, JM tiene un comportamiento normalizado, no realizando ningún tipo de comportamiento que diese lugar a que pudiésemos pensar por parte de los profesionales que había retirado esta cantidad del banco. El día 16 de julio del 2019, JM, sale del CRR a las 7.20 de la mañana, solicitando llevarse la medicación del desayuno. A lo largo de la mañana se le hacen varias llamadas a su teléfono móvil, estando este apagado. Sobre las 17.00 desde la dirección del CRR se da la alerta al 091 de la desaparición de esta persona ya que no tenemos información de su paradero desde la mañana. Sobre las 21.00, seguimos sin tener información por lo que se toma la decisión de interponer denuncia de desaparición, aunque durante este proceso se logra contactar con JM, informando este solamente de que volverá a las 23.00 al CRR, por lo que se decide posponer la denuncia hasta esta hora en caso de que no volviese. Finalmente JM acude al centro a las 23.00. Mostrando se estable clínicamente, al mismo tiempo que poco colaborativo con los profesionales. Como consecuencia de esto, se establece junto a JM el método de devolución de los 480€ de los cuales ha hecho un gasto indebido, pudiendo acudir a las vacaciones si puede ahorrar la cantidad requerida para esto, antes de la fecha de las mismas (15/09/2019). Estas consecuencias son: - No tendrá asignación hasta el 15-09-19 (4 euros diarios) - Dispondrá de 4 paquetes menso de tabaco a la semana, hasta el 15-09-19. - El día 22 y 23 de septiembre tampoco tendrá asignación diaria. Esto hace un total de 380€ cantidad necesaria para pagar el viaje. Por lo que el resto de dinero (100€), los devolverá a partir del 24 de septiembre reduciendo su asignación y tabaco durante 5 semanas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2019-07-18','Ana: solicito a Toni-Futuex informe de la visita que se le realizó a María a primeros de abril. Lo recibo por email y lo guardo en su expte. La semana que viene volverán a visitarla. *Se trabajará con ella entre otras cuestiones el hecho de que llegado el momento puede ser necesario su ingreso Residencia de Mayores (a lo que se negó teniendo plaza concedida en marzo). En la visita dijo que sí quería ingresar. **Envío correo a Toni con indicaciones para la Delegada de Apoyo. ////// Llamo a Alicia Toro, TS - Ayto. Torreorgaz (927 20 50 01). No llegaron a elaborar el presupuesto. En estos últimos meses la cosa ha estado tranquila, no han surgido incidencias. Tras valorar la situación, la propuesta para que María pueda permanecer en el domicilio, tal y como desea, es la de reorganizar mejor los recursos de apoyo en el domicilio, visitarla con mayor frecuencia y realizar los acompañamientos a las citas médicas con especializas, aparte de limitar su cuenta y autorizar a alguna persona (Aux. de SAD o Delegada Tutelar) Alicia me facilita datos de contacto: Empresa de Ayuda a Domicilio = Adiex: David- 691 20 94 16. Médica de Atención Primaria - Esther.(Consultorio 927 20 42 15)','2');
