insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-07-18','TERESA: SOLICITAN AUTORIZACIN PARA SALIDA AL DOMICILIO FAMILIAR DEL 5 AL 12 DE AGOSTO. LA VA A LLEVAR SUSANA EL DIA EL 5 Y EN FUNCION DE COMO SE ENCUENTRE EL DOMICILIO SE PODRA QUEDAR TODA LA SEMANA O SOLO 48 HORAS. LA VUELTA LA HARA EN TAXI POR UN IMPORTE DE 140 EUROS. AL ESTA MERCEDES DE VACACIONES HAREMOS LAS GESTIONES CON LA GERENTE ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Urbano (Técnico del Servicio de infancia y familia de Cáceres. 927-004355). +++Preguntado sobre el seguimineto de la hija de Beatriz: solicitó en su día se efectuase el seguimiento del caso desde Servicios Sociales pero hasta la fecha no le han comunicado nada sobre si se está efectuando o no.','2');
