insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2019-07-19','Ana: Llamo a David-ADIEX, empresa de SAD (691 20 94 16). Le parece muy bien que Vale, Aux. SAD, realice la compra de María un día en semana, pero no ve factible el dividir el horario para que acuda a ponerle el pañal por las noches, pues a María hay que levantarla, ducharla y hacerle la comida además de limpiar en la casa, con lo que considera que son necesarias las 2h y cuarto para ello. David se ofrece a estar el día que acuda la Delegada a visitar a María la semana que viene. //////// Llamo a Toni-Futuex, acordamos que Gloria hará la visita en el horario de la Aux. de SAD (10:00 - 12:15) y avisarán a David de Adiex cuando haya fijado día por si puede pasarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-07-19','TERESA: VAMOS A RECURRIR EL REGIMEN DE VISITAS YA QUE SE HA ESTABLECIDO EN EL DOMICILIO DE LA ABUELA Y NO VEMOS QUE ESE SEA UN SITIO IDONE DEBIDO A LAS AMENAZAS QUE SUFRE BEATRIZ POR PARTE DEL PADRE DE SU HIJA. SE PRESENTA ESCRITO APORTANDO LOS WASUP DEL PADRE DE LA NIÑA JUNTO CON INFORME DEL CENTRO QUE APOYA LA NO IDENEIDAD DE QUE SEA ALLI EL ENCUENTRO. PROPONES EN EL CENTRO DE PLENA INCLUSIO O BIEN EN ALGUN SITIO PUBLICO HABILITADO PARA TAL FIN YA QUE EN TRUJILLO NO EXISTE PUNTO DE ENCUENTRO ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conversación con Mercedes (T. Soc. del SSB de Trujillo/927-659391). +++En el ayto. no existe la posibilidadde habilitar un punto de encuentro. Planteo la posibilidad de si se podría hacer cargo de ello el Programa de Familia, pero me dice que no depebdenbde del Ayto. sino de la Mancomunidad. +++Llamo a la Mancomunidad (927-323315), a Paulina (Educadora) y Teresa (Psicóloga), que ya intervinieron en el caso de Beatriz desde el Programa de familia. LLAMARÉ EL LUNES OTRA VEZ. +++++No están ninguna de las dos. Hablo con Sara, del Servicio de Igualdad. Cree que la Mancomunidad no va a disponer del recurso necesario para llevar a cabo los encuentros entre madre e hija, pero me proporciona el teléfono de la ASOCIACIÓN EXTREMEÑA PARA LA MEDIACIÓN , siendo ANA la persona de contacto. +++Conversación con ANA RODRÍGUEZ, responsable de la ASOCIACIÓN EXTREMEÑA para la MEDIACIÓN FAMILIAR (658-322909). Llevan también los puntos de encuentro de la Comunidad Autónoma en Cáceres y Mérida. +++++SÍ PODRÍAN ACTUAR COMO PUNTO DE ENCUENTRO, CON HORARIO FLEXIBLE TANTO DE MAÑANA COMO DE TARDE. +++++Supervisarían las visitas y las adaptarían según evolucionasen las misma','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-07-18','TERESA: ME LLAMA JULIETA PORQUE SE ENCUENTRA EN URGENCCIAS CON JOSE, ME COMENTA QUE TIENE DE NUEVO UNA OBSTRUCCION INTESTINAL, EN UNAS HORAS LE DARAN EL ALTA. ME COMENTA QUE NECESITA ROPA DE VERANO, LE INDICO QUE HAGA LA COMPRA COMO SIEMPRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-07-19','(Pedro) Conversación con Mercedes (T. Soc. del SSB de Trujillo/927-659391). +++En el ayto. no existe la posibilidadde habilitar un punto de encuentro. Planteo la posibilidad de si se podría hacer cargo de ello el Programa de Familia, pero me dice que no depebdenbde del Ayto. sino de la Mancomunidad. +++Llamo a la Mancomunidad (927-323315), a Paulina (Educadora) y Teresa (Psicóloga), que ya intervinieron en el caso de Beatriz desde el Programa de familia. LLAMARÉ EL LUNES OTRA VEZ. +++++No están ninguna de las dos. Hablo con Sara, del Servicio de Igualdad. Cree que la Mancomunidad no va a disponer del recurso necesario para llevar a cabo los encuentros entre madre e hija, pero me proporciona el teléfono de la ASOCIACIÓN EXTREMEÑA PARA LA MEDIACIÓN , siendo ANA la persona de contacto. +++Conversación con ANA RODRÍGUEZ, responsable de la ASOCIACIÓN EXTREMEÑA para la MEDIACIÓN FAMILIAR (658-322909). Llevan también los puntos de encuentro de la Comunidad Autónoma en Cáceres y Mérida. +++++SÍ PODRÍAN ACTUAR COMO PUNTO DE ENCUENTRO, CON HORARIO FLEXIBLE TANTO DE MAÑANA COMO DE TARDE. +++++Supervisarían las visitas y las adaptarían según evolucionasen las mismas.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-07-19','Ana: Recibo llamada de Lucía, Consuelo ha tendio hoy la cita en Psiquiatría. Evoluciona bien, le ha reducido un poco la medicación (tanto la inyección como el rivotril). Dice que de ánimos la ve bien, "es muy cariñosa, necesita mucha atención. Lo único es que se aburre en la residencia". En cuanto a la piernas, le están haciendo fisioterapia en la Residencia y están pendientes de la próxima cita en Traumatología. **Pido que cuando vuelvan a la Residencia me envíen escaneado el informe de psiquiatría que le han dado. /////// A última hora recibimos por fax "Nota de Tratamiento" de Psiquiatría, pero no un informe médico como tal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2019-07-19','TERESA: AUTORIZO REINTEGRO DE 20 EUROS ME LLAMA AGUEDA LA TRABAJADORA SOCIAL QUE SE ENCUENTRA EN SU DESPACHO DE SALIDA Y NO TIENE DINERO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2019-07-19','(Pedro) LLamada de Ana, Psiquiatra de Francisco en el CSS de Plasencia (24172). +++Plantea la conveniencia para Francisco de un alta parcial, con supervisión desde el CSS, donde desayunaría y comería, para volver a su piso. +++Plantea piso de alquiler compartido con otro paciente del CSS. Le indico las limitaciones en el alquiler: económicas, el estar tutelado y la falta de medios de supervisión en el medio. +++Le propongo que haga la propuesta por escrito, lo más explícita posible. Al parecer, LA EVOLUCIÓN DE FRANCISCO ESTÁ SIENDO TAN BUENA COMO PARA PLANTEAR ESTA ALTERNATIVA, EN SU BENEFICIO E INCLUSO, SI DIESE UN RESULTADO POSITIVO, ANA PLANTEA LA POSIBILIDAD DE PLANTEAR EN UN FUTURO UNA POSSIBLE RECUPERACIÓN DE LA CAPACIDAD (PARCIAL O TOTAL).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-07-19','Ana: Envío correo a Eva Luz, TS Arroyo de la Luz (evajimenez@tajosalor.es // Tlf. personal: 655 093 822), para informarle de que Mª Eugenia tiene cita el día 23 de agosto en el CADEX para una revisión del grado y ver si da perfil para C. Discapacidad. ////// Llamo a Pilar, TS de ESM-CC (54612), para informarle de la fecha de la revisión, pero no responde al teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='LOPEZ'and apellido2='CORRALES'),'2019-07-19','TERESA: ARCHIVO INFORME DELEGADA TUTELAR . VISITA PLANIFICADA AL CENTRO RESIDENCIAL. LA RECIBE ANA AGUILAR LA TRABAJADORA SOCIAL. INGRESAOD EN EL CENTRO HOGAR SANTA TERESA JORNET DESDE EL 6 DE JUNIO DE 2008 POR PROBLEMAS DE ALCOHOLISMO Y ABANDONO. SOLO TIENE UN HERMANO DEL CUAL RECIBE ALGUNAS VISITAS. SE ENCUENTRA BIEN ADAPADO Y PARTIPA EN ACTIVIDADES TIENE 74 AÑOS. AGRADECEN LA VISITA Y DEMANDA QUE SEA MAS FRECUENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2019-07-19','Ana: Llamo a la Residencia S.Pedro de Alcántara (927580624), me pasan con Sonia, Enfermera, me comenta que Rosa es autónoma, está bien, no tiene molestias ni requiere muchos cuidados. En relación a la demanda que realiza Rosa, de domiciliación en cuenta bancaria de teléfono móvil, no sabe nada. Como la directora no está, le dejará nota para que me llame la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2019-07-19','TERESA: INFORME DELEGADA VISITA REALIZADA EN EL DOMICILIO FAMILIAR DE M FE DONDE RESIDE CON SUS HERMANOS MANUELA JUANA Y EMILIANO. BEATRIZ LA TS INFORMA QUE LA VIVIENDA HA SIDO LIMPIADA A FONDO Y PINTADA. NO HAN PODIDO ENTRAR AL NO HABER NADIE EN CASA. LA ENCUENTRAN EN EL MERCADILLO HACIENDO COMPRAS SE OBSERVA RETRASO MADURATIVO Y DIFICULTAD EN EL LENGUAJE. LA FAMILIA TIENE NULO CONTACTO CON EL ENTORNO NO ACUDEN A NINGUN RECURSO. NIEGNA CUALQUIER AYUDA EN EL DOMICILIO SOLO PERMITEN LA LIMIEZA PUNTUAL EN EL DOMICILIO. PRESENTA NECESIDAD DE APOYO PUE POR SI SOLA NO ES CAPAZ ES SU HERMANA JUANA LA QUE TOMA LAS DECISIONES PERO EN CONDICIONES PRECARIAS. DESDE LOS SERVICIOS SOCILAES ESTAN DISPUESTOS A COLABORAR EN TODOS LOS ASPECTOS.','2');
