insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-07-22','miguel, nos llega nuevo email de Liberbank preguntando cómo va este expte. Hablo con Pedro Gracia, y solicita a la abogacia general los datos que tenga de este expte, sólo sabemos fecha de presentación 24-6-19 en jzdo de Plasencia. LLamo al Juzgado 1ºinstancia nº2 de Plasencia, donde se supone que está el expte y me comentan que todavía estan pendiente de reparto las incoaciones de esa fecha por parte del secretario judicial con lo que tardarán unos días en dar número de procedimiento','2');
