insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2019-07-22','Ana: hablo con Paz, TS de Los hermanos de la Cruz Blanca - CC (927 24 68 52) A Antonio le operan el viernes 26 a las 9:00h en la Clínica Quirón (Centralita: 927 18 13 60). Dr. Gómez, Urólogo. ///////// Llamo a la Clínica Quirón, al ser tutela administrativa no es necesario que asista representante legal, con que lleve el Consentimiento Informado firmado es suficiente. ///////// Se lo comunico a Paz, Hermanos de la Cruz Blanca, en principio al ingreso le acompañarán desde el centro. Para el acompañamiento posthospitalario valorarán mañana si alguien de la entidad que libre en fin de semana le interera hacer el acompañamiento. Enviar al correo ctutelar@ la propuesta. *Mañana me confirmarán ambas cosas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-07-22','Ana: Recibimos escrito de Servicio Territorial de CC - Secc. de Apoyo y recursos para la infancia y famlia, solicituando informe social de Felisi, con el fin de utilizarlo en el procedimiento de incapacitación judicial de su hijo Aitor, quien próximamente cumplirá la mayoría de edad. /////// Llamo varias veces a la técnico de referencia al número indicado: 927 00 43 62, pero no obtengo respuesta.','2');
