insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-06-27','TERESA: INFORME FUTUEX SOLICITA QUE SE LE ENTREGUE UN EXTRA YA QUE NO TIENE SUFICIENTE CON LA ASIGNACION ESTABLECIDA. QUIERE IRSE A VIVIR CON SU PAREJA Y COMPRAR UN PISO LO QUE VIEDNE A DESMOSTRAR QUE AURORA HACE LO QUE EL DICE Y DISPONE. ACTUALMENTE VIVE EN LA CASA SIN APORTAR NADA PERO EXIGIENDO Y ADEMAS LA CONVIVENCIA CON SUS HERMANOS ES MALA.EL NOVIO ES TOXICOMANO CON ANTECEDENTES PENALES Y CON UN HIJO ACOGIDO EN CENTRO DE MENORES POR LA JUNTA DE EXTREMADURA. LE OBLIGA A PEDIR DINERO INCLUSO A PRESTAMISTAS CON LOS ITERESSES QUE ESO GENERA LOS CUALES LOS PAGA SU AMIGO ANTONIO Y SIENDO AMENZADO POR ALGUNO DE ELLOS POR NO PAGARLOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-07-23','Ana: Toni-Futuex me envió por email una nota de la gestión de Gloria, Delegada de apoyo, en la casa de José Pedro. Acompañó al TÉCNICO DEL SEGURO para valorar el problemas de las humedades de la vecina de abajo. Estableció que la mancha de uno de los baños es una mancha antigua y por tanto ya no hay nada que hacer, y en el otro sí que está mal sellada la bañera. El seguro cubrirá esto último. En relación al mal estado de las tuberías, recomienda que se dé de baja el agua, pues en cualquer momento podrían reventar. **Belén, Secc. Eco, se encargará de esta gestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-07-22','Ana: Llamo a Pilar-TS ESM CC.(54612) Comunico que finalmente no se convocará Subcomisión Regional de Casos, pero se ha solicitado revisión del grado de discapacidad. La cita será el día 23 de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-07-22','Ana: Toni-Futuex, nos facilitó la siguiente documentación: "Recibí entrega de llaves y resolución de contrato de arrendamiento" y "Comunicación de Condición de Beneficiario del bono social térmico" por parte de la Secretaría de Estado de Energía. /////// En relación al Bono Soc. Térmico, llamo al IMAS CC (927 21 23 35 ext. 2) distintas veces a lo largo de la mañana, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2019-07-23','(Pedro) Llamada de Julián (COCEMFE CC). +++El Inofmre solicitado se refiere al periodo entre el último emitido y el momento actual para la Rendición Anual.LO enviarán en uno o dos días. Pido que lo hagan tanto por correo ordinario como electrónico. +++TERAPIA CELULAR: desde el servicio de fisioterapia han llamdo al Hospital Puerta de Hierro de Madrid para interesarse por el tema. Al parecer tienen muchas solcitudes para aplicar esta terapia, pero no aclararon si Tomás podría ser un potencial beneficiario de la misma. +++++Volverán a llamar y ruego planteen el diagnóstico de Tomás así como que, si es susceptible de ser incluido en el protocolo, que nos indiquen la vía para solcitar su inclusión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2019-07-24','Ana: Llamo al EVD de Plasencia - Sonia TS (24112), ya intenté contactar en ocasiones anteriores, de nuevo no obtengo respuesta.///// Llamo a Gloria, T.O. EVD Plasen. (927 638 011 ext. 24111) Me informa que está todo bien, la solicitud está aún pendiente de resolver, van por las de marzo-abril de 2018. Es cuestión de esperar. No obstante se lo comentará a la compañera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-07-23','(Pedro)Llamada de Marisa , T. Soc. de Vfca. de Los Barros (924-527822). +++D. Adolfo conoció a una persona por internet y se marchó por su cuenta a Sevilla. Allí fue atendido por los Servicios Sociales, quienes tras la atención lo orientaron para que volviese a su localidad en autobús. +++Marisa nos envía el informe de la intervención que tuvieron con él para que quede constancia de la misma. +++En estos momentos se encuentra en su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-07-23','(Pedro)Llamada de Constanza, Psiquiatra UHB de Llerena (47157). +++Quería saber cómo están los trámites para solcitar plaza residencial. +++Le informo de que la petición al Juzgado para autorizar ingreso está a punto de salir, así como la petción para la ampliación de la incapacidad. +++TEMOR de Constanza: "Ahora D. Juan Antonio está muy bien y no tenemos problemas de camas en estos momentos, pero yo me voy de vacaciones el viernes y temo que haya alguna avalancha de ingresos que nos obliguen a darle el alta. Voy a poner en su Historia que en la medida de lo posible no le de Rubén (mi suplente) el alta para que pueda ir directamente al centro que se le asigne." +++Para contactar le dejo mi extensión y la de Teresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2019-07-24','Ana: Recibo llamada de Ivvone, Directora Res. S. Pedro de Alcántara de Valencia de Al. (690 96 29 55 = Nº personal). Comunica que Rosa pide continuamente dinero a otros residentes. Físicamente está muy bien y a diario acude a su vivienda, donde además tiene un perro. **No necesita teléfono móvil, pues en la residencai hay teléfono, donde podrían llamarla y desde el que podría llamar. Además a ella apenas se le entiende cuando habla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-07-24','Ana: recibo llamada de Isabel Pino, TS del SSB Miajadas (927 34 70 00), Felipe ha acudido sin cita a su despacho, como tenía que esperar porque había personas con cita se ha ido a casa y ha llamado después por teléfono. Le ha inforamdo de que ha arreglado la bicicleta y tiene pendiente abonar la factura y que además se le ha roto el móvil. Dice habérselo dicho a Gloria, Delegada Tutelar. ///////// Llamo a Toni-Futuex, Gloria no tiene factura ni nada de la bicicleta, hablarán con él y trabajarán el hecho de que debe solicitar los extras de forma previa a hacer el gasto. En cuanto al teléfono, Felipe últimamente se ha quejado mucho, pero tener tiene teléfono, cuando vuelvan a visitarlo mirarán que funciona y si se hubiera roto, se podría pedir presupuesto y valorar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-07-23','Ana: Vuelvo a llamar Menores - CC (927 00 43 62 // Mara 927 00 43 49), en relación al informe que solicitan, pero no obtengo respuesta. /////// Desde Futuex me informan que han cambiado las profesionales del **Equipo de Familia, ahora son Raquel y María y el nº de contacto: 609 382 439.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2019-07-23','Ana: Recibo llamada de Teresa-Novaforma CC, la madre de Álvaro (ingresada en UME en el CSS de Plasen.) tiene persmiso para ir a su casa del 25 al 1. La idea es que Álvaro pueda ir a visitar a su casa, pero la psicóloga del CSS no ve conveniente que Álvaro pernocte allí. Lo que plantean desde Novaforma es que Álvaro pueda ir a pasar un par de días con ella (ida y vuelta en el día). **Le digo que no habría problema. Mañana volverán a llamar para decirme se sería necesario retirar algún extra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-07-23','Ana: Recibo llamada de Noelia, TS Resi. Cervantes (927 00 55 75 / 22237)pregunta si finalmente se redujo la asignación de Mª Luisa, pues ésta no ha ido a quejarse ni decirle nada. Quiere saber también si ha vulto a retirar efectivo. Por lo demás me informa de que está bien, aunque pasa toda la mañana dormida, dice que después de desayunar entra sueño. En cuanto a si pasa buena noche, ella responde según quién le pregunte, a veces dice que sí y otras que no. ////// Iciar, Secc. Eco., me informa de que hace dos semanas que tiene limitada la cuenta. Justo ha retirado efectivo los dos últimos lunes, 15 y 22, los 25 € semanales que se aprobaron. /// Llamo a Noelia para informarle, pero no obtengo respuesta. Volveré a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-07-24','Ana: Informan desde Futuex, que finalmente J. Ramón ha accedido a contratar Ayuda a Domicilio, como aún no le han valorado de dependencia, se contratará una empresa privada. En el Ayto. sale muy caro y la TS no se ha mostrado muy colaboradora. *Envían presupuesto de Servicios del Fresno, por lo que llamo a Toni y le digo que por favor soliciten otro presupuesto a otra empresa dados los antecedentes con esta empresa y otra tutelada.','2');
