insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2019-07-23','TERESA: VISITA AL CENTRI P.I. ZAFRA JACINTO TIENE RETRASO MENTAL MODERADO Y DISCAPACIDAD INTELECTUAL. HA PARTICIPADO EN LA OBRA SANSON Y DALILA EN EL FESTIVAL DE TEATRO ROMANO DE MERIDA. ESTA PENDIENTE UN TEMA DE HERENCIA DE SUS PADRES LO PRENGUNTO EN DEPARTAMENTO JURIDICO. LOS FINES DE SEMANA VIAJA AL DOMICILIO MATERNO EN OLIVA DE FRONTERA. SE ENUCENTRA BIEN ADAPTADO Y CONTENTO EN EL CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-07-23','TERESA: VITA AL CENTRO P.I. ZAFRA JOSEFA TIENE RETRASO MENTAL LEVE Y TRASTORNO LIMITE DE LA PERSONALIDAD. (PATOLOGIA DUAL? ESTA PENDIENTE DE INGRESO IVOLUNTARIO EN LA UDAC PLASENCIA, YA TENEMOS RESOLUCION JUDICIAL PRESENTE ALTERACIONES DE CONDUCTA CON EPISODIOS DE AGRESIVIDAD. EN LA ENTREVISTA QUE MANTENGO CON ELLA, MUESTRA SU DISCONFORMIDAD CON EL CENTRO NO SE ENCUENTRA AGUSTO, NO PARTICIPA EN NADA NI SE RELACIONA CON SUS COMPAÑEROS. ME INSISTE QUE SE QUIERE IR DE ALLI PERO QUE NO QUIERE IR A UN PSQUIATRICO POQUE ALLI LA ATAN Y LE IYECTAN. MANIFIESTA SU DESEO DE IR A PLACEAT EN PLASENCIA. ANA LA TS COMENTA QUE UNA VEZ TERMINE SU ESTANCIA EN LA UDAC HABRIA QUE BUSCAR OTRO RECURSO PORQUE ELLOS NO TIENEN LOS MEDIOS PARA PODER TRABAJAR CON ELLA Y ADEMAS PONE EN PELIGRO AL RESTO DE COMPAÑEROS. JOSEFA ABANDONA EL DESPACHO ALGO ALTERADA Y LLORANDO.','2');
