insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2019-07-24','Ana: Llamo a Isabel Ojeda, Empresa SAD MIMOS (606 38 67 50), me informa que la primera auxiliar no se adaptó muy bien, por lo que cambiaron y la con la actual todo va muy bien. Se muestran muy contentos tanto Josefa y la pareja como la Aux. ///// Hablo con Eduardo, Dependencia (Dircc. Gerencia), como aún no tienen constancia del cambio de empresa ni copia del contrato (en teoría la empresa nueva lo ha notificado, pero aún no les ha llegado) REGISTRO DE ENTRADA la Comunicación de Cambio de Circustancias con la copia del contrato y se lo llevo directamente a Eduardo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2019-07-24','TERESA: VISITA A P.I. ZAFRA NATALIA TENE TRASTORNO BIPOLAR Y DISCAPACIDAD INTELECTUAL (PAOTOLOGIA DUAL) PRESENTA PROBLEMAS DE CONDUCTA EJERCIENDO PRESION TANTO CON LOS PROFESIONALES COMO CON SU COMPAÑEROS. EN LAS VACACIONES DE LA PLAYA NO HA TENIDO UN BUEN COMPORTAMIENTO Y LE HAN REDUCIDO LOS DIAS DE SALIDA PARA IR A VER A SU ABUELA. SE LO COMENTAN DELANTE DE MI Y PARACE RECONOCERLO Y ACEPTARLO. ME PLANTEAN COMO REPARTIR LAS VACACIONES DE AGOSTO YA QUE ELLA PIDE IRSE EL MES ENTERO Y DESDE EL EQUIPO NO LO VEN VIABLE. SE PLANTEA EMPEZAR CON FINES DE SEMANAS Y EN FUNCION DE SU COMPORTAMIENTO AMPLIAR MAS DIAS YA QUE EL AÑO PASADO LE CONCEDIERON EL MES ENTERO Y SE TUVO QUE VENIR POR PROBLEMAS DE COMPORTAMIENTO. LA ABUELA TAMBIEN MANFIESTA QUE TODO EL MES ES MUCHO TIEMPO. SE LE PLANTE LAS VACACIONES Y NO LE HACE MUCHA GRACIA, SE PONE TRISTE Y A LLORAR. NOS MANIFIETA QUE QUIERE IRSE CON SU MADRE QUE AHORA ESTA MUY BIEN Y QUE SU MADRE VA A SOLICITAR AL JUEZ LA REMOCION DE LA TUTELA MANIFEISTA QUE ELLA NO QUEIRE ESTAR ALLI TODA SU VIDA Y QUE NO CONSIDERA JUSTA LA VIDA QUE LLEVA. SE MARCHA LLORANDO DEL DESPACHO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2019-07-24','TERESA: VISITA A PLENA INCLUSION ZAFRA JUANA TIENE RETRASO MENTAL LEVE Y DISCAPACIDAD INTELECTUAL. HA TENIDO PROBLEMAS DE CONSUCTA PERO AHORA SE ENCUENTRA MAS TRANQUILA. HAN TENIDO PROBLEMAS EN EL CENTRO POR PEQUEÑOS HURTOS QUE HA COMETIOD. JUANA TIENE PROBLEMAS CON LAS COMPRAS PORQUE LO HACE DE MANERA COMPULSIVA POR ELLO HAY QUE TENERLE UN CONTROL DEL GASTO. ELLA VE ALGO QUE LE GUSTA Y SE LO COMPRA SIN MAS. SE ENCUENTRA BIEN ADAPTADA Y FELIZ EN EL CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-07-24','Ana: Llamo al IMAS CC (927 21 23 35 ext. 2), en relación al bono social térmico, me informan que ésto no ha habido que solicitarlo, lo gestionaba directamente el Ministerio. Y como corresponde al invierno pasado, que sí ha estado en el piso de alquiler, no hay que comunicar nada. *Lo cobrará dentro de meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2019-07-24','TERESA: VISTA A P.I. ZAFRA ROSA TIENE RETRASO MENTAL Y TRASTORNO DE LA PERSONALIDAD (PATOLOGIA DUAL) TUVO PROBLEMAS DE CONDUCTA PERO ACTUALMENTE SE ENCUENTRA BIEN ADAPATADA EN EL CENTRO. PARTICIPA EN LOS TALLERES Y SE MUESTRA CONTENTA POR HABERLA IDO A VISITAR. ME PREGUNTA MUY INSISTENTE QUE QUIEN ES SU TUTORA. SE VA A SU CASA LOS FINES DE SEMANA Y EL MES DE AGOSTO LO PASA ENTERO EN EL DOMICILIO PATERNO EN VILLAFRANCA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JOSE'and edp.apellido1='TORO'and apellido2='PEREZ'),'2019-07-24','TERESA: VISTA A PLENA INCLUSION ZAFRA FRANCISCO JOSE TIENE RETRASO MENTAL MODERADO Y DISCAPACIDAD INTELECTUAL. SE ENCUENTRA BIEN ADAPTADO AL CENTRO Y FUNCIONA BIEN. HA PARTICIPADO EN LA OBRA SANSON Y DALILA DEL FESTIVAL DE TEATRO DE MERIDA. ACUDE A TOSOS LOS CUMPLEAÑOS DE SUS SOBRINOS Y LES SUELE LLEVAR UN REGALO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-07-24','(Pedro)Visita programada de Emilia. +++Presenta presupuesto para comprar unas gafas porque al parecer le ha cambiado la graduación.Tiene mucha urgencia en la respuesta porque ha quedado con la óptica en responder esta mañana (la tranquilizo al respecto). +++++Llamo al CRR de Mérida. Hablo con Raquel. Le cuento la situación y me confirma que estuvo ayer viendo presupuesto. Hablará conb Gisela para ver la NECESIDAD o no de dicha compra y me contestarán por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2019-07-24','(Pedro) Visita programada de Isabel. +++Necesita comprarse calzado adecuado para poder caminar: le han dicho que tiene colesterol y que es bueno que camine. Se le insiste en que hable con la ortopedista de su farmacia para que le aconseje los que mejor le vengan a ella. Se le autorizan 100€ para su compra, pero se insiste en que si precisara algo más que nos lo diga. Se reitera que lo gaste en el calzado. +++FAMILIA: hace unos días recibió la visita de su HIJA SARA (acompañaba a un grupo de usuarios de PROINES)y aqunque estuvo poco tiempo con ella le alegró mucho. +++++Comenta que lleva 9 años sin saber nada de su familia y que no conoce a sus nietos pequeños. +++++Le da un poco de miedo ir a Don Benito porque teme encontrase a la gente que conoce allí. Se le propone ir acompañada de FUtuex alguna vez pero dice que se lo pensara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2019-07-24','Ana: Recibo llamada de Teresa, Novaforma (662 337 460) Han acoradado que Álvaro finalmente vaya con su madre del 26 al 31 de julio en horario de 11:30 a 20:30. Le recogerá y le llevará de vuelta su madre en taxi. Pedirán y nos enviarán todos los tiquets para justificar el gasto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-07-24','Ana: Llama Noelia, TS - C.R. Cervantes. Le confirmo el reintegro semanal que tiene aprobado (los 25€/semanales que se acordó) y las últimas retiradas que ha hecho. Dice que mañana hablará con ella al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-07-24','Ana: Hablo con María, Programa de familia, me confirma que Aitor (hijo de Felisi) pasará con Felisi todo el verano. De momento la convivencia es buena, se nota que Aitor está medicado y está tranquilo. Corrobora la necesidad de la demanda que realiza Felisi para comprar algo de ropa (bañadores para ella y su hijo, sandalias y alguna otra prenda de vestir), para adquirir abonos para la piscina municipal y de aportar algo más de dinero en el domicilio del Casar por el gasto extra que supone que esté allí Aitor. ****Acuerdo con Alberto, Secc. Eco., aprobar un extra de 150€ para este viernes 26 y dentro de 2-3 semanas otro de unos 30€. ///// *Se lo comunico a Toni-Futuex mediante email para que se lo expliquen a Felisi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-09-02','Hablar con Constanza sobre la convocatoria de la Subcomisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-07-25','strjhsfg','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2019-07-24','(Pedro)Llamada de Manuel. Quiere hablar con Amalia sobre un negocio que quiere montar. Volverá a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='LOPEZ'and apellido2='RUIZ'),'2019-07-23','TERESA: ME LLAMA VERONICA TECNICO PIA DE VILLANUEVA PARA COMENTARME QUE NO CONSIGUE QUE LE MANDEN EL CONTRATO DE LA RESIDENCIA CON LA TARIFA VISADA QUE POR FAVOR ME PONGA EN CONTACTO CON LA RESIDENCIA PARA QUE ME LO HAGAN LLEGAR Y SE LO DEVUELVA A ELLA YA FIRMADO POR CONSOLACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2019-07-25','TERESA: EMAIL DE LOLA TS P.INCLUSCION La hermana de Antonio J quiere llevárselo a Badajoz el 27 hasta el 2 de agosto Dice que vendría a por él y lo traería He pensado, si te parece bien, que de vuelta en vez de traerlo a Cabeza del Buey lo deje en Llerena con su madre para evitar tanto viaje Y esté con ella una semana HE HABLADO CON LOLA Y ME COMENTA QUE HA HABLADO CON VIRGINIA DEL PROGRAMA DE FAMILIA Y CONSIDERA QUE LA MADRE ESTA BIEN PARA PODER HACERSE CARGO DE ANTONIO, POR LO TANTO SE AUTORIZA LA SALIDA. ME COMENTA QUE DURANTE ESA SEMANA ESTARA SUPEVISADO POR VIRGINIA Y LOLA ESTARA EN CONTACTO CON ELLA POR SI ALGO NO FUERA BIEN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2019-07-25','Ana: llamo a Paz Boticario, TS de Los hermanos de la Cruz Blanca - CC (927 24 68 52), en relación al correo que envió ayer acerca de la cirujía de Antonio. Tras varias consultas con los compañeros de la Secc. Eco. Le llama Iciar y confirman el acompañamiento del viernes por la tarde (en principio es cirujía menor ambulatoria) y en caso de que tuverira que pasar allí el fin de semana, se autoriza también el acompañamiento, lo haría otro trabajador habitual de la Cruz Blanca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-07-25','Ana: Recibo llamada de Pilar, TS ESM CC (54612), ya ha recibido la documetación que le enviamos para la Revisión de Dependencia, va a marcar la REVISIÓN PÍA, pues lo que queremos es que se le vuelva a valorar el recurso que se negoció anteriormente (RAL)y adjuntará informe social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2019-07-25','Ana: Hablo con Teresa, Novaforma (662 337 460). Finalmente gestionarán el taxi desde la Asociación, han hablado con un taxista que conocen. Les indico que deben enviarnos al correo electrónico factura a nombre de Álvaro y el CCC del taxista para hacerle la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-07-25','En relación con la venta del inmueble de los hermanos, estamos pendientes de recibir el Auto firme aprobando judicialmente la herencia de su madre. Se lo he pedido a Curro. Una vez lo recibamos, hay que enviárselo a Malen Zancas, para que lo lleve al REgistro de la Propiedad y se inscriba el inmueble a nombre de los hermanos. Posteriormente, hay que pedir autorización judicial de venta del inmueble.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2019-07-25','TERESA: VISITA A HOSPITAL SANTIAGO ZAFRA LOLA TIENE ESQUIZOFRENIA Y RETRASO MENTAL (PATOLOGIA DUAL) NO SE ENCUETRA MUY ADAPTADA AL CENTRO Y PRESENTA ESPISODIOS DE AGRESIVIDAD. HABLO CON ELLA Y ME DEMANDAN UNA VESTIDO NUEVO. LE CUESTA ACEPTAR LA NOSRMAS DEL CENTRO. COME SOLA EN OTRA HABITACION DEBIDO A QUE TIENE CONTINUOS PENSAMIENTOS DE QUE LE VAN A HACER DAÑO. ME COMENTA EL PADRE TENA QUE ES MUY COMPLICADO TRABAJAR CON ELLA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2019-07-25','TERESA: VISITA AL HOSPITAL SANTIAGO ZAFRA M FERNANDA TIENE RETRASO MENTAL Y ESPISODIOS PSICOTICOS(PATOLOGIA DUAL) LLEVA POCO TIEMPO TUTELADA POR LA COMISICION. AL VERME SE ACERCA A MI Y ME SALUDA. LE PREGUNTO QUE TAL SE ENCUENTRA Y ME DICE QUE BIEN Y SEGUIDAMENTE ME PIDE PERMISO PARA IRSE A COMER.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2019-07-25','TERESA: VISITA A PISO TUTELADO ZAFRA FRANCISCO EN LA VISITA SE MUESTRA SERIO Y POCO ACCESIBLE, NOS DEMANDA QUE QUIERE UNA TABLET SAMSUNG QUE VALE 300€, LE PREGUNTO QUE PARA QUE LA NECESITA Y QUE PORQUE TIENE QUE SER SAMSUNG Y ME DICE QUE PORQUE LE GUSTA Y PORQUE HACE MUCHO QUE NO SACA DINERO DE LA COMISION. HABLO CON EL MONITOR JUAN DIEGO Y ESTA DE ACUERDO CONMIGO EN QUE NO LE COMPREMOS LA TABLET. ME COMENTA QUE HA CAMBIADO DE GIMNASIO PERO QUE LA CUOTA HA PAGAR ES LA MISMA. ME COMENTA QUE LA ADAPTACION AL PISO ESTA SIENDO RELATIVAMENTE BUENA, QUE EL GIMNASIO LE VIENE BIEN PARA DECASGAR, QUE HAY MUCHO QUE TRABJAR CON EL PERO QUE EN FUTURO INCLUSO PODRIA CONSEGUIR VIVIR SOLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-07-25','Ana: Vuelvo a llamar Menores - CC (927 00 43 62 // Mara 927 00 43 49), en relación al informe que solicitan, pero no obtengo respuesta. ////////////// A última hora recibo una llamada de Felisi (722494033), hablo con ella y con Jesús, su pareja. Se quejan de que "la nueva delegada", Gloria, "no hace nada" y cuando la llaman no les coge el teléfono ni les devuelve la llamada, dicen que prefieren a la anterior. Solicitan dinero, porque Aitor, hijo de Felisi, lleva ya 3 semanas en su casa y no se les ha dado dinero extra, que además "come mucho". Se le informa que se ha autorizado un extra de 150€ que podrán retirar de la oficina bancaria de Navas del Madroño, se quejan porque quieren sacar el dinero en el Casar. Les explico la distribución del dinero y que con el Carnet Joven de Aitor, que dicen que sí lo tiene, les costará aún menos el bono de la piscina y podrán disponer de algo más para otros gastos. Jesús dice que con el Certif. de Discap. de Felisi también resulta más barato el abono de la piscina y me piden copia, pues afirman no tenerla, mañana se la daré a Toni-Futuex, aprovechando que tenemos reunión. Habla también de que en la casa de Felisi la cisterna del baño de abajo está rota y que habría que arreglarla (¿Seguro?) y que no hay extractor, que se les llena todo de humo al cocinar. También pregunta cuánto falta por pagar para poder adquirir la vivienda, le informo que envié un escrito a Vivienda el 9 de mayo, estamos a la espera de la respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2019-07-25','TERESA: VISITA PISO TUTELADO ZAFRA M DEL MAR TIENE ESQUIZOFRENIA EN LA VISITA AL PISO SE MUESTRA TRISTE PORQUE LLEVA MUCHOS AÑOS EN RECURSOS, INSISTE EN QUE TIENE PADRE Y MADRE Y NO QUIER SEGUIR VIVIENDO EN NINGUN RECURSO. NOS COMENTA QUE NECESITA UN TELEFONO YA QUE CUANDO SE VA LOS FINES DE SEMANA ESTA INCOMUNICADA, SE AUTORIZA EL PAGO DEL MOVIL CON TARJETA TODO SUMA 150 € JUAN DIEGO EL MONITOR ME COMENTA QUE M DEL MAR TIENE MUCHO DETERIORO Y QUE NO VA A PODER ESTAR NUNCA DESLIGADA DE UNA INSTITUCION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2019-07-26','TERESA: AUTORIZO a Antonio Jesús Morales Esquivel a desplazarse de Cabeza del Buey a Badajoz del 27 de julio al 3 de agosto de 2019, a pasar unos días de vacaciones con su hermana Sandra que reside en Badajoz. No tiene coste del desplazamiento porque su hermana viene a por él y le trae de vuelta en su coche particular.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2019-07-26','TERESA:Buenos días Me pongo en contacto con uds. para informarles de la evolución de Basiliso Jiménez Hernández. Hoy lo visitó su médico de cabecera debido a que la analgesia no estaba siendo efectiva y refiere mucho dolor, así como decaimiento del estado general y anorexia más acentuada. Se le ha añadido MST oral más analgesia de rescate. También se lo servicio de Cuidados Paliativos se han puesto hoy en contacto para comentar los resultados de la analítica realizada el día 19 de julio, todo está en valores normales dentro de su patología de base y se coincide en el aumento de tratamiento realizado por su médico de Atención Primaria. El estado general de Basiliso ha empeorado significativamente en las últimas semanas. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2019-07-26','Ana: Recibimos correo de Cintia Dorado, Educadora de la Asoc. Vera (educadorasocial@asociacionvera.com): "Buenos días, nos ponemos en contacto con ustedes para informarles que ha habido modificaciones en las vacaciones de Mª del Carmen Mellado, se va desde el 8 de agosto hasta el 23 de agosto. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2019-07-26','Ana: recibimos un correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "...que Ignacio e Isabel Rodríguez Alcántara quieren ir a visitar a su familia al pueblo y su madre nos indica que la mejor fecha es el 24 de Agosto que son las ferias allí. Además, con un poco de suerte, pueden coincidir con su hermano y su sobrina pequeña a la que hace tiempo que no ven. Creemos que es positivo para ellos." Se da el Ok a la visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2019-07-26','Ana: recibimos un correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "...que Ignacio e Isabel Rodríguez Alcántara quieren ir a visitar a su familia al pueblo y su madre nos indica que la mejor fecha es el 24 de Agosto que son las ferias allí. Además, con un poco de suerte, pueden coincidir con su hermano y su sobrina pequeña a la que hace tiempo que no ven. Creemos que es positivo para ellos." Se da el Ok a la visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-07-26','TERESA: ARCHIVO INFORME DE LA ATENCION RECIBIDA EN URGENCENCIAS EN SEVILLA YA QUE LO ENCONTRARON EN SEVILLA DESORIENTADO HIPERACTIVO TEMEROSO... HA VIAJADO DESDE VILLAFRANCA A SEVILLA EN TAXI POR LO QUE HA PAGADO 175 EUROS PARA VER A UNA CHICA QUE HA CONOCIDO POR INTERNET, UNA VEZ ALLI NO HA ENCONTRADO A NADIE. DESDE EL EQUIPO DE EMERGENCAS LO ATEIENDEN Y LO LLEVAN A LA ESTACION DA AUTOBUSES PARA QUE PUEDA VOLVER A SU CASA QUE ES SU DESEO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2019-07-29','TERESA: Se comunica a la Comisión Tutelar de Adultos de la Junta de Extremadura, que la usuaria del Piso Supervisado de Zafra, Dª. María del Mar Gordillo Santana, pasará unos días con su hermana en Usagre (Badajoz) del 28/07/19 al 02/08/19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-07-29','Ana: recibo llamada de Isabel Pino, TS del SSB Miajadas (927 34 70 00), Felipe ha acudido de nuevo hoy a su despacho acompañado de la Aux. de SAD. Le informo que se abonará la factura del arreglo de la bicicleta, pero nos tiene que enviar el nº de cuenta, pues no lo tenemos. Irán al taller a pedirlo y lo enviarán a ctutelar@. En cuanto a la maquinilla de cortar el pelo, Felipe dice que ya no le hace falta, pues su hermano ha comprado una y la usan los dos. Por último, se autorizará a la compra de un terminal móvil nuevo. Lo tiene con contrato, pero es su hermana quién paga la factura. *Belén, Secc. Eco., hoy mismo hará ambas transferencias si envían en nº de cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CAYERO'and apellido2='AGUILAR'),'2019-07-26','EXITUS EL 26/07/2019','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-07-29','Ana: Recibo llamada de Victoria Rajo, Directora CRR-CC (687 487 908). Han valorado y han con Antonia, la posibilidad de asistir a Resi. Privada de Mayores. Todos están de acuerdo. Confirmo con Juana, Secc. Eco, las posibilidades económicas y no habría problema. Valorarán con ella si tiene preferencia por alguna zona o residencia concretas antes de pedir presupuestos. ***En cuanto la documentación que se les envió firmada y que entregaron a Pilar, TS ESM, para los diversos trámites, como ella no está al tanto, le dirá Pedro, TO, que me llame.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-07-29','Ana: Hablo con Noelia, TS Res. Cervantes CC (22237). Dice que habló con Mª Luisa, que ésta expresó que le habían bloqueado la cuenta, por lo que Noelia le explicó que su cuenta estaba limitada y que ahora tenía una asignación semanal de 25€, no preguntó más ni puso ningún problema. Sí que preguntó cómo iba a comprarse ropa, por lo que Noelia le recordó que de eso, de ahora en adelante, tenía que hablarlo con su hermana que es quién se va a encargar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2019-07-29','(Pedro)Llamada de Juan Pedro, Psicólogo del CSS de Mérida (24052). +++PROPUESTA: Pedro ha establecido una relación de pareja con otra paciente del centro (no incapacitada) y el Equipo cree que su deseo de compartir un piso de alquiler en Mérida y seguir con el control del CSS puede ser una alternativa que dé resultado. +++Ya están viendo pisos de alquiler y han localizado uno en el centro que no les gustaría perder y quieren dar la fianza: ella puede hacerlo sin problema, pero él neceista la revisión del contrato y la firma de la Gerencia. +++Pido que remitan un Informe a la Comisión que justifique y avale la oportunidad de la medida propuesta y con la finalidad de comunicar la misma al Juzgado. Remitirán dicho Informe. +++Quedamos en plantear visita al CSS a finales de agosto principios de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2019-07-29','TERESA: RECIBO DOCUMENTACION PARA ARCHIVAR SOLICITUD PLAZA T2 JUNTO CON LA DOCUMENTACION QUE PIDEN IFORME DE ALTA INFORME DE ALTA ENFERMERIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2019-07-29','(Pedro)Llamada de Sonia (698-742953), hija de Concepción. +++Quiere que su madre vaya unos días a casa. Le digo que, como en otras ocasiones, lo plantee en el centro y desde allí pedirán a la Comisión autorización para la visita. +++Muestra intereés por saber si la junta se va a quedar el dinero de la herencia (casa) de la abuela y si cunado muera su madre ("...que sea en muchos años...") si la Junta y el centro se van a quedar lo que deje. Se le repite que ni el centro ni la Junta se van a quedar con nada: todo pasará a los herederos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2019-07-29','Disponemos de la autorización judicial para vender la casa sita en c/. Ronda del Río, 9rincón del obispo, de Coria, por como mínimo 68.320 euros, aunque NO ES FIRME AÚN. Intento hablar con notaría de Moraleja (927691644) pero no lo consigo. Llamo a Erica (678541463), sobrina y que trabaja en la notaría. Tampoco puedo hablar con ella. Le envío un correo electrónico (emateos@despacho.notariado.org).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2019-07-29','Ana: Iciar, Secc. Eco. me confirma que ya está solucionado el problema del banco. Ya hay autorización para que, o bien la Aux. de SAD o bien la Mª José, TS, puedan retirar los 60€/quincena. *Iciar llama a Mª José para comunicárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-07-29','En relación con la autorización de ingreso involuntario en la Udac, de Plasencia, enviamos correo electrónico a la Abogacía General, para que nos remitan el Auto dictado por el Juzgado nº 2, de Zafra, en expediente 182/18,autorizando el mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-07-30','Ana: Llamo a Lidia, TS del C.Salud de Valencia de Alcántara (54209), informa de que la tutelada está bien atendida por su nieto y de que la vivienda es pequeña, pero para dos personas está bien, además está limpia y rehune condiciones de habitabilidad. Le solicito informe, me lo enviará por fax. //// Llamo a la Dra. Sandra Borrero (C. Salud: 927 580 295 / 54298 /// Dra. 54208). Hace dos semanas apróx. que vio a Manuela, dice presentar buen estado de salud en relación a su edad, a nivel anímico depende del día, dada su demencia, algunas veces le da besos y abrazos y otros se muestra muy alterada. Me enciará por fax Informe Clínico. ////**Recibimos ambos informes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-07-30','TERESA: RECIBO RESOLUCION PARA INTERNAMIENTO EN UHDAC, SE LO PASO ANA PLENA INCLUSION PARA QUE LO GESTIONE. ARCHIVO RESOLUCION ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Mª Paz (24180), Psicóloga de la UHDAC. UHDAC (24183). +++Respecto a la fecha de ingreso en la Unidad, Mª Paz me informa de que en estos momentos solamente HAY 1 PLAZA VACANTE: "...Estamos pendientes tambie´n del ingreso de otra paciente que se encuentra en la UHB y de la priorización que se haga desde esta Unidad y desde Mérida..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-07-30','TERESA: PALOMA HA VUELTO A SACAR 500€ DEL BBVA DE BADAJOZ, LA PENSION DE ESTE MES YA SE VA A INGRESAR EN LA NUEVA CUENTA QUE SE HA ABIERTO EN LIBERBANK','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2019-07-24','(Pedro)Correo-e de Julián. Sobre la terapia celular nos han hecho legar desde Toledo esta carta, te la envío de foto de whatsapp. Ver en Expedientes/Patología/Informes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-07-29','Ana: Recibo llamada de Jesús, pareja de Felisi (722 494 033), comunica 2 cuestiones: por un lado le han llamado de Vivienda para informar de que irán a visitarla mañana a las 12:00h. Por otra parte, el viernes pasado Felisi reiró en el banco el extra de 150€, pero no le dieron los 80€ semanales habituales. //// Informo a Juana, Secc. Económica, quién escribe a la sucursal banaria y pide que permitan retirar el efectivo la próxima vez que Felisi acuda al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-07-30','Ana: Hablo con Felisi y con Jesús (722 494 033), les explico que se ha escrito al banco y en teoría no tienen que tener problema para retirar el efectivo pendiente. ///// Jesús vuelve a preguntar cuándo le darán más dinero, pues Aitor supone mucho gasto. Le digo que aún tienen que tener dinero del extra, que los abonos les han salido más baratos con el Carnet Joven y el Certificado de Discapacidad (él mismo me dice que compraron los tres abonos, para Felisi, Aitor y para su hermano por "setenta y pico") y además hoy podrán retirar los otros 80€ pendientes. Se les dará otro extra el día 9 de agosto. Pregunta sí se les puede dar algo más, pues las fiestas de Navas del M. comienzan el día 14. **Se valorará la posibilidad con el Jefe del área económica. ////////////////////// Llamo a menores, hablo con Gema (927 00 43 49), en relación a la carta en que nos solicitaban Informe Social, ella no es quién lleva el caso de Aitor, hablará con las compañeras para averiguar quién es y que se pongan en contacto conmigo si lo necesita. *Le explico que el Informe que solicitan deben pedirlo al SSB y resto de serivicios de proximidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2019-07-30','TERESA: ENVIO CONTRATO DE ACDESO AL PROGRAMA DE ORIENTACION E INSERCION LABORAL Y DECLARACION DE CONSENTIMIENTO DE UTILIZACION DE INFORMACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2019-07-30','TERESA. ENVIO AUTORIZACION PARA DESPLAZARSE DE CABEZA DEL BUEY A BADAJOZ DEL 27 DE JULIO AL 3 DE AGOSTO PARA PASAR UNOS DIAS CON SU HERMANA SANDRA QUE RESIDE EN BADAJOZ. SU HERMANA SE ENCARGA DE IR A POR EL Y LLEVARLO DE VUELTA AL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2019-07-30','Ana: Recibimos, del CAMF de Alcuescar, solicitud del Programa de Vacaciones de COCEMFE, subvencionado por el IMSERSO. Lo pongo para la firma de la Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2019-07-30','(CORAL)Teléfno de Dr del Centro 3º EDAD MADRE FRANCISCA 68792439 NOMBRE JESÚS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-07-30','Ana: Recibo llamada de Pedro, TO CRR-CC (687 487 675), hablará con Pilar, TS del ESM-Plas, bien para que dé curso a las solicitudes/trámites pendientes, bien para hacer de nuevo las gestiones. // Le recuerdo también que estoy a la espera de que me informen de las prioridades de Antonia para poder buscar residencia privada y hacer las gestiones correspondientes. //// Por último aprovecho para preguntarle por el deseo de Antonia de pasar mensualmente un dinero a su hermano que está en situación de desempleo. Pedro dice que esto es intermitente, en ocasiones nice que sí y en otras que no... hablarán también de ello. Le explico que si finalmente quisiera, desde aquí habría que solicitar autorización judicial, pues sería una transferencia periódica y una cantidad importante anual, y por tanto necesitarimos informe que justifique la necesidad de su hermano y justificantes de los ingresos económicos de éste.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-07-30','BELEN; LLAMA ADELA DE PNC, NOS INDICA QUE QUITARÁ A CONSOLACIÓN PARA PODER ABONAR LAS PENSIONES QUE LE CONSTA COMO PENDIENTES.NOS ENVIARÁ RESOLUCIÓN POR ESCRITO. ELLA CONTACTA CON LA MADRE, CONSIDERA QUE DESDE LA COMISIÓN TAMBIÉN LLAMEMOS A LA MADRE. CON FECHA 26 Y 29/07/2019 ESTÁ ENVIADO A CAIXABANK DE SEVILLA, EL TESTIMONIO DE ACEPTACIÓN DEL CARGO DE TUTOR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-07-30','Ana: Hablo con Miguel, Asesor Jurídico, acerca de la compra-venta del coche comprado por Civantos hace unos meses, llama a Alfredo, de la Gestoría Galavís (927 58 02 18), con quién previamente había contactado la delegada tutelar, Gloria. *Le pide que lleven la documentación del coche. /////// Llamo a Toni-Futuex, para que cuando Gloria vaya a visitar a Ramón, le solicite la documentación del vehículo y la lleven a la Asesoría. ***No interesa venderlo por menos de 500€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2019-07-30','Ana: Hablo con Toni-Futuex, acudirán a ver la vivienda, concretamente la pared y muro de la casa que comparte con la vecina (María Rodríguez), pedirán valoración y presupuesto a algún profesional (Empresa de Construccón).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-07-30','Ana: Llamo a Toni, Futuex (600 56 42 14). Gloría sí que fue ya a visitar a Miguel, consiguió verle y hablar con él, le informó de su nueva situación y del fallecimiento de su hermana. Estuvo poco tiempo con él, pues él se marchó como de costumbre, no consiguieron que se quedara más tiempo. Gloria tiene pendiente elaborar y enviar la Nota Informativa, ahora está de vacaciones. Seguirán visitándolo una vez a la semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2019-07-26','(Pedro)Visita de los padres de Cristopher. +++Dicen haber ido al piso de Cristopher y que se lo han encontrado ocupado por otras personas que habían cambiado incluso la cerradura. +++Dicen haber hablado con Nuria, T. Soc. de Vivienda, sobre ello y que había que denunciar esta situación. +++Me pondré en contacto con Vivienda.','2');
