insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2019-07-30','(Pedro)Vuelvo a intentar varias veces ponerme en contacto con Nuria, T. Social de Vivienda. +++No consigo comunicar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2019-07-31','TERESA: Desde nuestra entidad indicamos que estará durante el mes de agosto de 2019 en la urbanización Urbasur, en Isla Cristina (HUelva), en la dirección: C/San Sebastián, 28. El teléfono de contacto es: 639015282.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-07-26','(Pedro) Visita de Ildefonso. +++Querría volver al Hostal pero allí no lo aceptan si no cumple las normas. +++SE llama varias veces al Hostal pero no localizo a Antonio, el encargado.... +++Se le inmsiste en la importancia de acudir a la Consulta del ESM de Mérida. +++++LLamo a Esperanza, T. Soc. del ESM de Mérida (85832 y 924-487229). No lo han visto todavía allí. tenía una consulta en mayo y no se presentó. LO CITAN el 16 DE AGOSTO a las 10:30h para consulta con el Dr. Periáñez. +++JUZGADOS: se tiene que presentar en el Nº 2 de Mérida el DÍA 1 DE CADA MES. +++MÉDICO DE FAMILIA: Dra. Mª del Mar Álvarez Díaz (C.S. Urbano I, en el Polígono).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2019-07-31','miguel, tras conversaciòn con Tere TS, me pide tramitemos Autorización de venta (me da un tlfno 627-044985 de inmobiliaria de Villafranca de los Barros-Angel Garcia Calle). Paralelamente y ante los continuos emails de Camilo el albañil que está reparando la vivienda que pide reparar más cosas, pregunto al Jzdo Don Benito nº2, proced 226/2019 quién me indica que están pendiente les asignen desdel el Colegio de Abogados abogado y procurador de oficio. Voy pidiendo nota simple para ir preparando documentación para Autorización de Venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-07-31','(Pedro) Visita de Ildefonso. +++Pregunta por el Hostal. No he podido localizar al encargado y él no quiere volver por allí. Dice que intentará buscar otro hostal. Si lo hace, nos los comunicará para el pago. +++Se le insiste en la importancia de respetar la cita con el Psiquiatra por dos motivos: +++++control de su tratamiento y +++++plantear su deseo de ingresar en CRR. +++Comenta que lleva dos o tres días en Badajoz, hablando con antiguos compañeros del CSS y que ha hablado con algunos que están en el CRR y que le gustaría ir a ese Centro porque "...Badajoz es una ciudad muy bonita...". Se le explica que eso depende de la existencia de plazas en cada momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2019-07-31','(Juana/Pedro) Visita de Castillo y Ángel. +++Juana les entrega la Tarjeta de Caja Extremadura. +++Los padres de ängel han fallecido hace unos meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-07-31','(Pedro)Llamada de Rubén Catalán, Psiquiatra UHB de Llerena (47157). +++Pendiente de la situación de D. Juan Antonio, se le informa que se ha enviado la petición de ingreso involuntario al Juzgado. +++Mantendrá ingreso hasta traslado a Residencia si las circunstancias lo permiten. +++Le dejo el contacto de Teresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-07-31','Ana: Llamo a Susana, TS del EVD de S.Vicente de Alcántara (689 57 57 15), en relación a la solicitud de valoración de Depdendencia de Ramón (Reactivación del Expte. - registrada a fecha de 29/03/19), pondrá una anotación en el SIDEX, pero me dice que llame a Carmen Gallego, Jefa de Secc.Depend.I., (927 00 43 39) pues estas anotaciones no las ven desde el Call Center que gestiona las citas ahora. ///// Llamo a Carmen Gallego, me dice que no es necesario que le adelante la comunicación de variación de domicilio por email. ////////// Llevo a Registro (ENTRADA) la Comunicación de Variación de Circustancias por cambio de domicilio habitual (*En la solicitud anterior se puso la Residencia de San Vicente de Alcántara) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro).ACCIONES A DESARROLLAR. +++Solicitar Informe Técnico Municipal sobre el estado del inmueble en el que vive D. Julián, basado en el Informe del albañil que realizó la obra del falso techo y el de la Guardia Civil. +++FUTUEx: visitar a D. Julián, en coordinación con el SSB, con los siguinetes objetivos: +++++ganarse la confianza de D. Julián. +++++que vea la necdidad de aceptar ayuda externa. +++++que vea la necesidad de permitir nuevos arreglos en su casa +++++que acepte la limpieza de su casa (podría estarm mientras se efectúa en la residencia o bien en casa de unos de sus hijos (contando con el acuerdo de ambos).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-07-31','miguel, envío a Secretaría General email Solicitando la Intervención de Abogacía General para recurrir en apelación el régimen de visitas al Jzdo de 1º inst e instrucción nº3 de Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-07-31','(Pedro).ACCIONES A DESARROLLAR. +++Solicitar Informe Técnico Municipal sobre el estado del inmueble en el que vive D. Julián, basado en el Informe del albañil que realizó la obra del falso techo y el de la Guardia Civil. +++FUTUEx: visitar a D. Julián, en coordinación con el SSB, con los siguinetes objetivos: +++++ganarse la confianza de D. Julián. +++++que vea la necdidad de aceptar ayuda externa. +++++que vea la necesidad de permitir nuevos arreglos en su casa +++++que acepte la limpieza de su casa (podría estarm mientras se efectúa en la residencia o bien en casa de unos de sus hijos (contando con el acuerdo de ambos).','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2019-08-01','EXITUS EL 31/07/2019 A LAS 12 HORAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-08-01','(Pedro) Conversación con Pilar Márquez, T. Soc. del SSB de Valencia de Álcantara (927-580326 Ext 8). +++Situación actual: se encuentra mucho mejor, está siguiendo el tratamiento. +++Alternativas: no ve una residencia como necesidad en este momento (la CTAEx tampoco). Sí el SAD (privado hasta que tenga Dependencia) o bien Centro de Día. +++FUTUEx: trabajando la confianza, y que él llegue a ver la neceidad de aceptar la ayuda externa. +++LIMPIEZA DE LA CASA: fundamental para estabilizar la situación, pero debría aceptarlo él. La posibilidad de que durante el tiempo que durase se fuese con alguno de sus hijos Pilar lo cree improbable, pero siempre está la alternativa de la residencia de manera temporal. +++SITUACIÓN DEL INMUEBLE. Comento con Pilar el informe del albañil al respecto de este tema y que lo sucedido en el piso de D. Julián probablemnete sea responsabilidad de la Comunidad. Le informo de que vamos a pedir al Ayuntamiento un Informe Técnico para valorar la situación del inmueble y, llegado el caso, no creemos que D. Julián tueviese inconveniente en salir de él durante las obras (visto que en el episodio anterior no puso objección alguna). Pilar dice que no hay problema en solictar dicho informe por escrito. +++RENDICIÓN ANUAL. Le pido que nos envíe el Informe Social para y me dice que incluirá la descripción del suceso de la vivienda. Le pido que en ese Informe plantee las alternativas y propuestas que considere oportunas en este caso.Se marcha de vacaciones la ultima semana de agosto y la primera de septiembre. A ver si podemos tener el informe antes de estas fechas. /////////////////////////////////////////////////////////////////// Ana: Llamo al SEPEI, "Bomberos" (927627528). Mª Jesús dice que el compañero que me atención, Fernándo Álvarez, está de vacaciones, a ella le suena algo al respecto, pero que no sabe nada sobre el informe solicitado. Lo preguntará y me devolverá la llamada. / Me devuelve la llamada, pregunta dónde enviamos la solicitud, pues no les ha llegado nada. Le digo que a la dirección que aparecía en la solicitud, a la atención del Jefe del Dpto. del SEPEI. **Me pide que cumplimente una nueva solicitud y se la envíe por correo, para ir agilizando mientras que aparece la solicitud enviada en marzo por correo certificado. ****Le envío la solicitud de informe de actuación firmada por la D.Gerente a la siguiente dirección: administracion.sepei@dip-caceres.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-08-01','(Pedro) Conversación con Pilar Márquez, T. Soc. del SSB de Valencia de Álcantara (927-580326 Ext 8)','1');
