insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-08-01','(Pedro) Conversación con Pilar Márquez, T. Soc. del SSB de Valencia de Álcantara (927-580326 Ext 8). +++Respecto de la Dependencia, le han llegado "rumores" de que si la empresa podía estar pagando la asistencia directamente al nieto (eso supondría estar dado de alta en S.S.). +++Le informo de que hace unos días ha empezado a ir una Axuliar de la Empresa. +++Pilar asegura que, al margen de otras cuestiones (incluídas las de la familia extensa), Dª Manuela está bien cuidada, opinión que también reflejan los informes recibidos del C.Salud. ////////////////////////////////////// Ana: Bajo con Pedro a hablar con Clara y Marco A. Lobo (Dependencia). Según Marco no podemos solicitar las altas a la seguridad social y en cualquier caso no podríamos demostrar si la aux. ha estado acudiendo o no al domicilio, pues constan las altas en la empresa, pero no los domicilios a los que atiende, y a todos los efectos la empresa está justificando todo ante el SEPAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-08-01','TERESA: ARCHIVO DOCUMENTO DE ACEPTACION DERIVACION A LA UHDAC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-08-01','(Pedro)Conversación con el Subteniente de la Guardia Civil de Trujillo, D. Alberto Guillén (927-321004). +++Aunque están con pocos Agentes por las vacaciones, estarán pendientes de la situación de Beatriz en la medida de lo posible. Dadas las limitaciones de personal, propone que también hablemos con la Policía Local.Además de mi teléfono dejo también el de Teresa. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a la Policía Local de TRujillo para que lo ponga en conocimiento de la Policía Local. Explico el caso y estarán atentos.Además de mi teléfono dejo también el de Teresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2019-08-01','-Tras hablar con la TS de VVda de Badajoz ( Isabel ) , me dice que el expediente sigue en alta. Me indica que envie un cdo indicando la fecha de ingreso en la residencia y se le descontarán todos esos recibos . Asi mismo procede a la baja del expediente . Nos indicará si existiese factura pte. anterior al ingreso . AD','2');
