insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-08-01','Ana: Recibo llamada de Juan, dice que la semana que viene son las fiestas en el pueblo y necesita dinero para ocio. Pide 100€. Le informo que el jefe de la Secc. Eco. no está. Veré con las compañeras la situación económica y veremos a ver qué se le puede dar. *Quiere retirar el dinero el próximo lunes día 5. Ese mismo día lo hablaré con Alberto.','2');
