insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2019-08-01','miguel, tras la recepción de una sóla nota simple del registro de la propiedad de Almendralejo(en catastro aparecen dos propiedades de la tutelada), compruebo que las 3 fincas tienen direcciones diferentes. Tras consultar con el Ayuntamiento de Villafranca de los Barros me confirman que la dirección de la nota simple (c/ Diez de Agosto 20)y de una de las fincas de catastro(c/ Lopez de Ayala 22, hoy C/ Lopez de Ayala 20) es la misma finca. Pido emitan un certificado de callejero actual y me piden lo solicite para lo registren con entrada. Daré salida y remitiré mañana 2/8/2019','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2019-08-01','Ana: Recibimos correo de Sonia Bernabé-ASINDI (trabajosocial@asindi.e.telefonica.net)"Buenos días, os escribo para informaros que Juan Gabriel Sobrino, se ha ido a pasar el mes de agosto con su familia. El se marcha como siempre muy contento y con ganas de estar con su familia. Su hermana Araceli ha pedido hablar conmigo para comentarme que le gustaría ver la posibilidad de solicitar el traslado de Juan a un Centro más cercano a Mérida porque a ella, que viene a por él en periodos de vacaciones, cada vez le cuesta más la distancia. No tiene a otro familiar que pudiera hacer el trayecto. Le he dicho que lo tiene que hablar con vosotros y, seguramente se acerca un día de estos a explicaros la situación. Un saludo" Respondo al correo agradeciendo la información y preguntando por el deseo de J.Gabriel de permanecer o cambiar de centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-08-02','Ana: Llamo a Isabel Pino, TS Ayto. Miajadas, le confirmo que el día 31 de julio se hicieron efectivas tanto la transferncia para abonar el arreglo de la bicicleta como la de la compra del móvil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATIAS'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2019-08-02','TERESA: SE ACEPTA PRESUPUESTO PARA ARREGLO DENTAL POR IMPORTE DE 420€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-08-02','Ana: Recibimos Notificación del CADEX con citación. Han modificado la fecha, finalmente la valorarán el día 22 de agosto a las 11:30h. // Se lo comunico a Toni-Futuex, y le envío por email escaneada la citación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2019-08-02','TERESA: INFORME FUTUEX HA IDO A DENUNCIAR EL ROBO Y DEPUES A LOS SERVICIOS SOCIALES PARA CONTARLE A LA TS LO SUCEDIDO CANDI COMENTA QUE TENIA LOS 500 EUROS PORQUE SU HERMANO LE HA MANDADO UN GIRO POSTAL PARA QUE SE LO GUARDARA YA QUE VA A VERNIR A PASAR UNOS DIAS A ALMENDRALEJO. SUSANA AFIRMA QUE EL DINERO ESTABA MUY ESCONDIDO POR LO QUE EL ROBAR ESE DINERO NO ERA ALGO FACIL, COMENTA SE LE VE MUY AFECTADO POR ELLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-08-02','(Pedro)Visita no programada de Emilia. +++Acude muy triste, llorando, porque se quiere ir del CRR porque "no me tratan bien...". +++Hablamos sobre ello, reconoce que ella no siempre se comporta correctamente y entiende que las normas son necesarias para que sea posible la convivencia. +++Con José Mª G. tiene una relación de "amor/odio". Ya le he comentado en otras ocasiones que si se siente mal con él o le obliga a hacer algo que ella no quiera debe decírselo a los compañeros del CRR. +++SE le van a comprar las gafas, a pesar de que rompió las otras el pasado fin de semana: se le hace ver lo negativo de ese comportamiento, que reconoce, y del coste que ello le va a suponer. +++Se marcha ya más tranquila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-08-02','TERESA: INFORME FUTUEX LE COMENTA A SUSANA SU DESEO DE TENER UN MOVIL YA QUE EL FIJO DE CASA SE LE HA ROTO. QUEDO PENDIENTE HABLAR CON VODAFONE PARA SOLVENTAR EL PROBLEMA DIEGO HA SACADO 500 EUROS DEL BANCO Y SE HABIA IDO A ZAFRA, SUSANA CONSGIUE HABLAR CON EL YA EN SU CASA Y LE PREGUNTA POR EL DINERO. EL COMENTA QUE LE DEBIA DINERO A SUS AMIGOS Y QUE NECESITA MAS DINERO DE LO QUE SE LE DA ACTUALMENTE ADEMAS RECLAMA DINERO PARA LAS FIESTAS DE SANTIAGO. TIENE TODOS LOS DIAS BROCAS CON PILAR POR EL TEMA DE DINERO DISPONE DE MUCHO TIEMPO LIBRE Y LO GASTA LLENDO A BARES Y GATANDO EN EXCESO, SE MUESTRA POCO COLABORADOR. SUSANA ACONSEJA QUE SE LE ACOMPAÑE A SACAR LOS 500 EUROS MENSUALES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-08-02','(Pedro)Se recibe en la Comisión el siguinete correo-e del CRR de Mérida: +++Buenas noches, Me indican los compañeros que José María Guillén no se encuentra en el CRR y tiene su teléfono móvil apagado. Hemos dado aviso a la Policía haciendo especial hincapié en que se trata de una persona tutelada. En cuanto tengamos novedades les informo y, en cualquier caso, a primera hora de la mañana vuelvo a ponerme en contacto con ustedes. Muchas gracias, Un saludo. +++Me pongo en contacto con el Centro a primera hora pero José Mª no ha regresado todavía.Les pido que pongan la denuncia de manera formal enate la Policía. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a D. MIguel Ángel Guillén, hermano de José Mª. +++Ayer sus hermanos estuvieron hablndo con él y no notaron nada que se saliera de lo habitual. Esta mañana lo han estado llmadndo sin poder hablar con él. El contestador del teléfono saltaba y los mensajes aparecían como no recibidos. +++También ha llamado a Emi su "novia" y tampoco sabía nada de él. +++Cree que se ha podido ir con un amigo que tiene coche. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a José Mª Guillén (626-267655) pero no coge el teléfono (a las 10:09 y a las 13:23h)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-08-02','TERESA: INFORME FUTUEX JUAN ANTONIO ESTA INGRESADO EN UHB DESDE EL DIA 20/6/19, CADA VEZ ES MAS AUTONOMO Y SE ENCUENTRA ESTABLE. ESTA PENDIETE DE QUE NOS CONTESTE EL JUZGADO SOBRE LA AMPLIACION DE SU INCAPACIDAD E INGRESO INVOLUNTARIO EN CENTRO RESIDENCIAL PARA MAYORES POR CAMBIO DE PIA. ME ESCRIBE NATI UN EMAIL EN EL QUE COMENTA QUE SEGUN MAY NO VE MUY CLARO QUE SEA PERFIL DE RESIDENCIA DE ANCIANOS. VA A HABLAR PEDRO CON MAY.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-08-02','TERESA: INFORME FUTUEX ALDOLFO CONVIVE CON SU MADRE Y SU HERMANO LO MESES QUE NO ESTA TRABAJANDO FUERA. HE MEJORADO SU APECTO PERO LA HIGIENE CORPORAL NO ES LA ADECUADA. LE COMENTA ESATAR ARREPENTIDO DE HABER IDO A SEVILLA Y PERDILER TANTO DINERO A SU MADRE. SUSANA INTENTA QUE LO VEAN EL EN CENTRO DE SALUD EN EL AREA DE PSIQUIATRIA PERO NO LO COSIGUE. QUESA PENDIETE UNA VISITA A DOMICILIO DE LA PSQUIATRA DE LA LOCALIDAD. LA DOCTORA ROSA SUSANA COMENTA QUE SERIA CONVENIENTE QUE INGRESARA EN UN CENTRO PARA QUE SE LE CONTROLARA LA MEDICACION Y ESTUVIERA MAS ESTABLE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2019-08-02','-Las dos hermanas tienen Grado III , se le confirma a APNABA. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2019-08-02','TERESA: SE AUTORIZA RETIRAR 80 EUROS PARA LA COMPRA DE UNOS ZAPATOS NOS HA ENVIADO PREVIAMENTE LA FACTURA YA QUE EL DINERO SE LO HA ADELANTADO SU SOBRINO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2019-08-02','TERESA: INFORME FUTUEX ROSARIO RESIDE CON SU MADRE LUISA EN UNA CASA ANTIGUA, ESTA MUY DESORGANIZADA. HUELE A HUMEDAD Y A CONCENTRACION. ROSARIO SE HA CAIDO POR LA CALLE Y SE HA DAÑADO EL HOMBRO IZDO NO TIENE MUHCA RELACION CON EL ENTORNO SALVO LA ESTRICTAMENTE COMERCIAL EN LA VISITA ESTUVO CAMINANDO CON ROSARIO POR EL PUEBLO LE COMENTA QUE ESTA MEJOR Y QUE SALE A PASEAR CON SU MADRE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2019-08-02','-Llamo al CADEX de Caceres para confirmar la recepcion de la documentacion enviada y me dicen que alli no hay nada. LLamo a Rgto Merida , tiene registro de salida el dia 8 de julio , me dicen q pregunte en CADEX bjoz. por si estuviese equivocado el envio. Llamo a Bjoz y efectivamente estaba allí , lo han reenviado a CC ayer .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-08-01','Ana: Pedro, Jefe de Secc. CTAEX, me comunica que en conversación mantenida con Soraya Masa (Jefa de Ud. de RR.AA.) se acuerda renunciar a la plaza concedida previamente a Miguel en la Res. de la Granadilla y solicitar plaza en la Res. Felipe Trigo de Vva. de la Serena, en la Ud. de Psicogeriatría (*esta decisión fue tomada previamente por Soraya Masa y Victor Ruiz, Jefe de Ud. de Gestión de Control de la Actividad ASistencial).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-08-02','Ana: Llevo a registro (ENTRADA)la renuncia a la plaza en la Res. La Granadilla una vez firmada por Consoli. Pedro le supe copia registrada a May (Margarita Masegosa), Jefa de Secc. Admón. Gral. Mayores. /////// También se registra de ENTRADA la Solicitud de plaza residencial en Res. Felipe Trigo, pero May le dice Pedro que no se la dé a ella y se envíe a la Gerencia Territorial de CC. *Así se hace. Dejamos copia en el expte. del Miguel de la solicitud y todo lo que se adjunta. //////////////////////// Envío un mail a Toni-FUTUEX, para que intensifiquen las visitas a Miguel y trabanen con él el hecho del ingreso en centro. ////////////// Llamo a Pedro, TS de la Gerencia Territorial-CC (927 00 42 39) le comunico que hemos enviado la nueva solicitud de plaza de Miguel. Agradece que le informe y expresa que no comparte para nada esta decisión, María León, Jefa de Secc. de Mayores anterior, asignó plaza en La Granadilla porque entendía que no un centro en régimen cerrado o semicerrado no era el recurso adecuado para Miguel, quién está acostumbrado a estar al aire libre y anda bastantes km diarios, quién además no tiene un "diagnóstico filiado".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2019-08-02','TERESA: ENVÍO PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-08-02','El 5 de agosto, a las 10 horas, toman declaración a José Manuel, en el procedimiento 351/2019, como investigado, desde el Juzgado de Primera Instancia e Instrución nº 1, de Plasencia, a través de videoconferencia desde el Hospital Psiquiátrico de Sevilla. No tenemos que estar presentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2019-08-05','TERESA: el padre de Agustín falleció ayer sábado. Llamó la familia para comunicarlo al centro y se fue para casa en un taxi y un cuidador le acompañó, el cual se regresó cuando Agustín se quedó tranquilo con su familia. Regresará al centro mañana lunes o martes, ya se pondrá la familia en contacto con el centro para confirmarlo. El lleva medicación para más días por cualquier imprevisto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-08-05','Ana: Llamo la TS del EVD de Trujillo, Nuria Carrasco (689575719 / nuria.carrascos@salud-juntaex.es), dice que tiene un PIA pendiente de Juan con solicitud de plaza en Piso Supervisado de Grupo 5 - Mérida. Le digo que Juan ya estuvo en este recurso y pidió el alta voluntaria. Pregunta qué alternativa proponemos. En nuestra opinión un Piso Supervisado era la mejor alternativa, pero si él no quiere no lo podemos obligar. Le informo que estamos pendientes de la Resolución del Juzgado tras el juicio para la revisión de su Capaciad Legal. De momento volverán a hacerle visitas periódicas desde FUTUEX, se intentará trabajar con él la idoneidad de acceder a un recursos residencial (piso supervisado o CRR) y esperaremos a que llegue la resolución judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2019-08-05','TERESA: ENVIO ATURIZACION FIRMADA PARA CONTINUAR CON LA TERAPIA CON PERROS','2');
