insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PURIFICACION'and edp.apellido1='GALLARDO'and apellido2='LOPEZ'),'2019-08-05','miguel, voy con Juana al Liberbank a entregar la documentación necesaria para desbloqueo, reparto de las cuentas del hermano José.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-08-05','miguel, envío al Jzdo1ºinstancia e instrucción3 de Cáceres contestación al requerimiento de información sobre localización de centros para esta tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-08-05','miguel, remito a fiscalía de Mérida a efectos del cumplimiento de Ley Organica del derecho de imagen, acuerdo de la directora gerente de autorizar a la polícia la emisión de la imagen en redes sociales de este tutelado, para su localización urgente. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo-e de CRR de Mérida. +++Respecto a José María, la denuncia está retirada y su familia está avisada desde el mismo momento en que se presentó en el CRR. Si estáis de acuerdo hemos pensado retirarle el DNI ya que ha reconocido que fue así como consiguió sacar el dinero del banco. Comentarte, además, que le llevamos a urgencias el sábado para valoración psiquiátrica y no lo permitieron por "no tratarse de una urgencia médica". He hablado con Mérida Norte para concertar cita con su Psiquiatra de referencia y, actualmente, se encuentra de vacaciones. La primera disponible sería para dentro de 2 meses. Vamos a tratar de gestionarlo con MAP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-08-05','-FUGADO EL DIA 4 DE AGOSTO , REGRESANDO A LAS HORAS . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-08-05','TERESA: ENVIO FAX AL 112 CON LA DOCUMENTANCION, TAMMBIEN LO ENVIO A PLENA INCLUSION Y A LA UHDAC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-08-05','TERESA: ENTREGO PIA CON INFORME SOCIAL POR EMERGENCIA PARA SACAR PERFIL, QUEDA PENDIENTE VER QUE NECESITA DEL PADRE DE PALOMA PARA PODER ACCEDER AL MODOULO FAMILIAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-08-06','TERESA: Ayer Susana, la delegada tutelar de Futuex acompañó a Beatriz Muñoz Ruiz, a su casa para pasar unos días en familia. comenta Susana que en el informe ha expresado que tiene buenas impresiones, a diferencia de la visita anterior las instalaciones se ven limpian y recogidas en cierta medida, dado el enorme volumen de cosas que tienen. Parece que han puesto interés en que la casa tenga buena presencia para poder alargar las vacaciones familiares en casa. POR TODO ELLO SE LE AMPLIA LAS VACACIONES HASTA EL DIA DOCE COMO HABIAS ACORDADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICETA'and edp.apellido1='PIZARRO'and apellido2='DEL BARCO'),'2019-08-06','Ana: Llamo a Pillar Cerrillo, TS del Centro Residencial Virgen de la Montaña de Cáceres. (618 908 506), puesto que Aniceta se encuentra encamada y su estado de salud es delicado, está claro que no va volver al domicilio, por lo que se decide dar de baja los suministros del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-08-06','Ana: Hablo con Pilar Cerrillo, TS Residencia Virgen de la Montaña - Casar de CC (618 908 506). Pregunta cómo van las gestiones económicas, pues van a volver a devolverles recibos de Pedro Román. Aún no se ha recuperado el dinero del Fondo de Inversión, se lo recordaré a Alberto, Jefe Secc. Eco, cuando vuelva de vacaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2019-08-05','Ana: Llamo varias veces a lo largo de la mañana al IMAS (927 21 23 35), para preguntar acerca de Martín, si lo han vuelto a atender en alguna ocasión en Servicios Sociales y en ese caso solicitar un informe social actual, pues a parte de para hacer seguimiento, se requiere para la Rendición Anual (ya se ha pedido por escrito en otras ocasiones, pero no lo han enviado ni han contestado). No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2019-08-06','Ana: De nuevo llamo varias veces a lo largo de la mañana al IMAS (927 21 23 35). No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-08-06','miguel, tras conversación con Mely, hermana del tutelado donde me pregunta si tenemos ya toda la documentación para se pueda firmar la herencia, le comento seguimos igual...pendientes nos remita la notaria borrador de herencia (ya hablaremos de venta cuando finalicemos la herencia).En cuanto a la no inscripción nuestra en registro civil, la comento por email me remita el certificado de nacimiento del tutelado(hablo también con Jzdo de Plasencia nº4, quien me confirma que remitieron al Rgtro Civil de Albacete nuestro nombramiento, ya que tienen un lío de procedimientos por que le aparecen procedimiento nº 141/2007 del jzdo nº2 de Plasencia-los del 4 van a preguntar a los del 2 en qué registro civil debe estar todo inscrito y que me llamará para decirmelo).Yo por mi parte localizo en el expte físico DNI donde resulta que este tutelado es nacido en Plasencia, por lo que entiendo que todo debería estar en el Rgtro civil de Plasencia. En cuanto a las inscripciones en registro civil me explican desde el Jzdo nº 4 que la inscripción de la incapacitación debe aparecer en su certificado de nacimiento, siento en otra sección del registro civil donde se inscriben las diferentes tutelas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-08-06','Ana: Llamo a Pablo Correa, nieto de Manuela (676 783 101), comunico lo que nos ha dicho Marco A. Lobo, Jefe de Ud. Pablo insiste en que en torno a 2 años no ha acudido nadie al domicilio de su abuela a prestar el SAD y que quiere denunciar en la Seguridad Social. Me pide que lo hable con Pedro, Jefe de Secc., cuando éste vuelva de vacaciones y le informemos al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2019-08-06','TERESA: ME LLAMA LOLA LA TS DEL PLENA INCLUSION PARA DECIRME QUE ANTONIO HA PEGADO A SU MADRE. ME PREGUNTA COMO IR A POR EL.ACORDAMOS QUE VAYA UNA CUIDADORA CON UN COCHE DE EMPRESA Y NOS PASE LOS GASTOS QUE GENERE EL ACOMPAÑAMIENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2019-08-06','-LLAMOO A ADELA PNC PARA PREGUNTAR DONDE ENVIO EL MODELO ALTA A 3º QUE VUELVEN A PEDIR . TODA LA DOCUMENTACION SE ENVIO EN MAYO . ME DICE QUE NO APARECE DE ALTA COMO TUTELADA, LE ENVIO EL MODELO A SU ATENCIÓN. AVERIGUARÁ EL CASO . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-08-05','Ana: En reunión de coordinación con Carolina, Psicóloga y Paula, T.O. del CRR de Plas., me informan de que Antonia continúa sin tomar la medicación prescrita por su Psiquiatra, Dra. Carmen Parrado. A pesar de ello no han observado ningún cambio en "Toñi" desde que ingresó en el CRR. Mañana tiene cita en salud mental ***les pido que mañana soliciten a la Psiquiatra un informe en el que haga constar esta situación, además del estado y evolución de Toñi, para poder informar al Juzgado. ////////////////////// Por lo demás, "Toñi" está bien, participa en actividades del centro (Baile, cocina, citas con Psicóloga y T.O.) y además sale a diario a pasear y economómicamente administra muy bien su asignación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-08-06','Ana: Recibo llamada de Paula, T.O. del CRR Plas. En la consulta de hoy en Salud Mental, la Psiquiatra Carmen Parrado ha retirado a Antonia la medicación que se negaba a tomar. **Le pido a Paula que igualmente, dadas las circunstancias, le pidan informe a la Dra. y nos lo hagan llegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2019-08-05','Ana: En reunión mantendia con Paula, T.O. y Carolina, Psicóloga del C.R.R., me comunican que a día de hoy están trabajando la "mejora de su autogestión económica".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-08-05','Ana: En reunión mantenida con Paula, T.O. y Carolina, Psicóloga, del CRR de Plasencia, me comunican que "Conchi" está evolucionando favorablemente. A futuro quiere volver a integrarse en la comunidad. Tiene una vivienda en propiedad en Madroñera, pero está en mal estado. En esta misma casa es en la que residió y falleció su hijo. Tiene una hija de 6-7 años, por la que pasa a su expareja una pensión compensatoria de 100€. Tiene una hermana que vive en Trujillo, de quién ha recibido algo de apoyo. **Para que en un futuro pueda volver a vivir de forma independiente, se plantean la posibilidad de que pase a Piso Supervisado como paso intermedio, consideran que está preparada para ello y que podría funcionar muy bien. ///////////// En cuanto a la Revisión de Grado que se solicitó en 2017 no sabemos nada. Llamaré al EVD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2019-08-13','TERESA: INFORME VISITA FUTUEX VIVE SOLA EN UN PISO DESDE HACE POCO TIEMPO, EL PISO A PESAR DE SER VIEJO LO TIENE LIMPIO Y BIEN CUIDADO ACUDE A DIARIO A FEAFES A REALIZAR ACTIVIDADES Y SE ESTA SACADO LA ESO A DISTANCIA,. TIENE UNA RELACION SENTIMETAL DESDE HACE CUATRO MESES CON UN VECINO DEL BLOQUE . SUSANA COMENTA QUE BEA SE ENCUENTRA MUY NERVIOSA Y ALTERADA YA QUE TIENE AMIGOS VIVIENDO EN SU CASA LOS FINES DE SEMANA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-08-06','Ana: Recibo llamada de Paula, TO CRR Plas. Han hablado con "Conchi" y se ha puesto muy contenta con la idea de ir al piso semiautónomo como paso intermedio, para ella ha supuesto mucha motivación. *En principio le han dicho que tendrá que gestinar bien su asignación, pues de momento no se le va a aumentar y en el piso tendrá que aportar dinero para comida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2019-08-07','TERESA: CARMELO VERA ES UNA CURATELA, EN EL INFORME SOCIAL DE LA TS NOS RECLAMA UNA MAYOR ATENCION POR PARTE DE LA COMISIÓN, ESTA PERSONA ES UNA CURATELA ECONÓMICA ASI QUE SERÍA NECESARIO EXPLICARLE QUE ES CURATELADO Y EN QUE CONSISTE LA CURATELA YA QUE MUESTRA SENTIRSE ABANDAONA POR ESTA COMISION TUTELAR. LE INDICO A FUTUEX QUE VAYA A VISITARLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2019-08-07','TERESA:ESTA PERSONA ES UNA CURATELA, CONVIVE CON SU MADRE Y HAY MALA CONVIVENCIA ADEMAS NO ACEPTAN NINGÚN TIPO DE AYUDA DE LAS QUE DESDE EL SSB SE LE OFRECE. NECESITO INFORMACION SOBRE SI ESTA ASISTIENDO A LAS CITAS DE SALUD MENTAL Y SI ESTA TOMANDOSE AL MEDICACION YA QUE ESTE PUEDE SER LO QUE ESTA OCACIONANDO ESTOS PROBLEMAS DE CONVIVENCIA. PIDO A FUTUEX QUE VAYA A VISITARLO','2');
