insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-08-07','Ana: Llamo al EVD de Cáceres (927 00 67 88 / 22058), Marisa me comunica que hay una Resolución Desestimatoria de Revisión de Grado a fecha de 22/03/19. Deben haberla enviado al domicilio de Mª Concepción. *Se le ha mantenido Grado y Recurso. *No tienen en el expte. la Sentencia de Incapacitación ni la Aceptación del Cargo. **Me pide que envíe el documento de Comunicación de Variaciones, para incorporar la dirección de la Comisión a efectos de comunicaciones por estar tutelada y adjuntar las Sentencia. ///////////// *Envío correo a Paula, TO del CRR y se lo comunico.','2');
