insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-08-07','TERESA: INFORME FUTUEX. LA CASA DE MARIA ES UN DESASTRE, HA COMPRADO UN FRIGORIFICO Y TIENE INTENCION DE COMPRAR UN TELE. EN EL MOMENTO DE LA VISITA MARIA ESTA BAJO LOS EFECTOS DEL ALCOHOL Y LAS DROGAS. COMENTA QUE AHORA NO SE REALACIONA CON NADIE DEL PUEBLO SALVO SU VECINA QUE SALEN JUNTAS A PASEAR LOS PERROS. SUSANA COMENTA QUE MARIA SE ENCUENTRA MUY PERJUDICADA YA QUE HA ESTADO DE FIESTA CON UNOS AMIGOS EN VILLAFRANCA, MANIFIESTA QUE SUELE FALTAR A LAS CITAS CON EL CEDEX Y NO SE PREOUCPA POR ELLO.','2');
