insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2019-08-07','Ana: Paula, T.O. del CRR Plas. pregunta en un mail(tocupacional.crrplasencia@grupo5.net): "...Teníamos pendiente información acerca de Guadalupe Barragán, confirmar cómo estaba la revisión de grado y Pia, por si puedes averiguar algo." *Contesto al mail e informo de que está pendiente de resolver.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-08-07','-Llamo a la madre para comunicarle que le van a ingresar las nominas de mayo y junio ( con extra ) con la nomina de agosto. Queda pte julio que aún no está devuelta del banco a PNC . Para septiembre si el banco no ha resuelto el problema seguiremos igual . Me comenta que su hijo en la ultima cita en julio co la psiquiatra le dijo q queria ingresar en CRR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2019-08-07','TERESA: INFORME FUTUEX VIVE CON SU TIA, MARIA ANTONIA SE ENCARGA DE PRESTARLE CUIDADOS. SU ESTADO DE SALUD ES BUENO PERO TIENE ANEMIA Y TIENE LA AZUCAR MUY DESCONTROLADA ACUDE A PLENA INCLUSION ZAFRA Y LA TARDE LA PASA CON SU TIA Y PRIMAS . SUSANA CONCLUYE DICIENCI QUE SUS PRIMAS SIEMPRE ETAN HACIENDO CHANCHULLOS CON EL DINERO Y QUE NO SON UNA BUENA INFLUENCIA PARA ELLA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-08-07','-Hablo con la madre para que vaya al médico y solicite informe para tramitar dependencia que no está valorado . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2019-08-07','Ana: Llamo a la Res. Femar de Logrosán (927 360 430) para interesarme por el estado de Valentina. Pilar Manzano, Coordinadora del Centro, me informa de que Valentina está bien, está integrada en el centro. Lo único que tienen que cambiarle las gafas, enviarán próximamente el presupuesto y que está pendiente de unas pruebas médicas, pues comenzó a sangrar un poquito por el ano. Me mantendrá informada de futuras revisiones y pruebas médicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-08-02','Ana: Recibo por email (administracion.sepei@dip-caceres.es) el informe de actuaciones del SEPEI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-08-07','Ana: Pido a Toni, Futuex, por email, que soliciten cita con el Médico de Atención Primaria y que acompañen a la misma a J. Ramón, para que deriven tanto a Cardiología como a Psiquiatría. Le envío adjuntos los últimos informes de Clideva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-08-07','TERESA: ME COMENTA MANUELA QUE NECESITAMOS BURTHER Y PFIFFER PARA PODER VALORA AL PADRE DE PALOMA, ME PONGO EN CONTACO CON LA TS DE DEPENDENCIA ISABEL (689575714)DE JEREZ DE LOS CABALLEROS PARA VER SI TIENEN ESA DOCUMENTACION DE CUANDO FUE VALORADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-08-07','TERESA: INFORME FUTUEX PALOMA RESIDE CON SU PADRE FRANCISCO RODRIGUEZ, EL CUAL TIENE PROBLEMAS DE MOVILIDAD DEBIDO A UN ICTUS QUE SUFRIO. PALOMA SE ENCARGA DE LAS TAREAS DOMESTICAS PERO ULTIMAMENTE NO HACE ABSOLUTAMENTE NADA. PALOMA TIENE POCA RELACION CON SU ENTORNO Y NO SABE GESTIONAR EL DINERO SE GASTA TODO EN LAS DOS PRIMERAS SEMANAS DEL MES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2019-08-07','TERESA: INFORME FUTUEX CONVIVE CON SU HERMANO Y SU MADRE, ENTRE LOS DOS ORGANIZAN LA CASA CON LA AYUDA DE UNA AUXILIAR DE AYUDA A DOMCILIO, LA CASA TIENE DOS PLANTAS LA DE ABAJO ESTA BIEN CUDIDA PERO LA DE ARRIBA ESTA SUCIA Y CON EXCREMENTOS DE PERRO. TIENE BUENA RELACION CON EL ENTORNO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2019-08-07','Ana: Recibo Nota de la Delegada de Apoyo de fecha de 1/08/19: "Se recibe una llamada de Juan Antonio, marido de Pepa, comenta que la trabajadora social ha preguntado si se le ha enviado la solicitud firmada para que les pueda pedir la ayuda para la reforma de la casa, se le dice que se va a consultar y se le dará respuesta. También establece que Pepa no ha podido cobrar la extra de junio porque no se ha mandado la autorización al banco, se le dice que puede ser porque haya habido algún error o porque no se crea conveniente, pero que se le responderá también a ello." Llamo a Longina, TS del Ayto. de Madrigalejo (672 614 686), pero me dicen que está de vacacines, volver a llamar la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-08-05','Ana: En reunión mantenida con Carolina, Psicóloga y Paula, T.O. del CRR de Plas., me informan que Ceferino pide dinero tanto a los compañeros del centro como en la calle. Le cuesta participar en actividades grupales y se "escaquea" de las tareas del centro. No finaliza nada de lo que comienza. Actualmente le gestionan el dinero desde el centro diariamente, pues semanalmente se gastaba todo el mismo día que se lo daban. Le dan 3€/día. A pesar de todo, están observando pequeños cambios positivos y últimamente no presenta conductas disruptivas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2019-08-08','TERESA: RECIBO INFORME DE LA PSICOLOAGA DE PLENA INCLUSION ( M TERESA DELGADO) EN EL CUAL PONE DE MANIFIESTO QUE LAS VACACIONES CON LA FAMILIA COLABORADORA Y CON SU HERMANA SE DAN DESARROLLADO CON NORMALIDAD Y JOSE ANTONIO HA ESTADO CONTETO Y AGUSTO Y EN CAMBIO EN EL PERIODO QUE HA ESTADO CON SU MADRE SE HA PRODUCIDO UNA AGRESION. ARCHIVO INFORME LA PSICÓLOGA AFIRMA QUE NO LE HA VENIDO BIEN PASAR TANTOS DIAS CON SU MADRE YA QUE TENIENDO EN CUENTA LA CARTACTERISTICAS DE LA MADRE NO TIENE CAPACIDAD PARA LLEVAR A CABO LAS PAUTAS QUE JOSE ANTONIO NECESITA PARA EVITAR QUE SE ALTERE. CONSIDERA QUE NO ES CONVENIENTE QUE ANTONIO PASE PERIODOS CON PERNOCTA YA QUE LAS CARACTERISTICAS DE SU MADRE PUEDEN ALTERAR EL BIENSTAR EMOCIONAL DE ANTONIO SI VE CONVENIENTE CONTINUAR CON LA LLAMADAS SIEMPRE QUE EL LO DESEE ASI COMO REALIZAR VISITAS TANTO AL CENTRO COMO A SU HOGAR CON PERSONAS DE APOYO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-08-08','TERESA: el fin de semana su hermano tuvo una pelea con su hijo, sufriendo lesiones este ultimo (no ha habido denuncias). Desde ese día, el hijo de Mª Elena no vive en el domicilio familiar y pernocta en una habitación en Zafra; tras conversar con el telefónicamente, nos comenta que no tiene pensamiento de volver al domicilio familiar y que esta preocupado por dejar a su madre sola.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-08-08','TERESA: EMAIL FUTUEX el pasado jueves día 1 de Agosto, pasamos por casa de Paloma para hablar con ella. Le comentamos que la Comisión había intentado ponerse en contacto con ella pero no habían sido capaces. Le comenté que la Comisión ya sabía que el día 22 de Julio había ido a un BBVA de Badajoz y había sacado 500€ de su cuenta. Ella nos dijo que si, que era cierto y no mostró ningún tipo de arrepentimiento ni se disculpó ni nada por el estilo. Le preguntamos que por qué lo había hecho y nos dijo que porque necesitaba comprarse ropa y no le daban un extra. Nosotros le contestamos que 500€ es mucho dinero para comprarse solo ropa y nos dijo que también se había comprado una paletilla de jamón de 60€. Le comentamos que lo que había hecho estaba mal, que últimamente iba por buen camino y estaba demostrando que podía ser más independiente pero que había retrocedido muchos pasos con esa acción. Ella no nos decía nada, solo estaba callada e intentaba cambiar de conversación. Le dijimos también que con ese dinero que había cogido, se comprara la ropa que necesitara porque en una larga temporada no se le iban a conceder extras. Luego le comentamos que si cuando sacó el dinero no se había dado cuenta que no podía dejar la cuenta a cero porque tenían que coger para pagar el alquiler del piso. Y antes de que termináramos la frase nos dijo que ella había cogido el dinero el 22 y sabía que el 25 volvía a tener dinero en el banco y habría bastante para el alquiler. Así es que lo tenía todo más que calculado SE LE HA ABIERTO UNA CUENTA EN IBERCARJA YA QUE EN LA DEL BBVA NO DEJA DE SACAR DINERO, LA PENSION DE ESTE MES YA LE HA ENTRADO EN IBERCAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2019-08-08','TERESA: EMAIL FUTUEX que a nosotros nos conste si acude a las citas de salud mental y se toma habitualmente la medicación, es una relación amor-odio, constante la que tienen, en la que tratamos de intervenir en cada visita, pero está muy vicida la relación, no quieren estar juntos pero tampocoo separados..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-08-08','TERESA: ME PIDE MANUELA QUE NECESITAN PARA VALORAR AL PADRE DE PALOMA EL BURTHER T PFEIFFER, SE LO PIDO A MARIOLA ME LO ENVIARA POR CORREO ELECTRONICO Y POR CORREO ORIDNIARIO, ME COMENTA QUE ME HA ENVIADO A TRAVES DEL CAD EL INFORME SOCIAL FIRMADO PARA ADJUNTARLO AL PIA QUE TIENE YA MANUELA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-08-08','Ana: Recibo llamada de Pilar, TS del ESM - CC (54612), dice que no llegó a tramitar la documentación (solicitudes de revisión de grado de discapac. y depend. y plaza residencia por decreto) porque un día Antonia le dijo que no quería que tramitara nada. Le recuerdo que Antonia está tutelada, por lo que las revisiones de grados si tiene que tramitarlas, pues se han firmado desde aquí. Y la plaza residencial, es Antonia quien lo ha pedido en el centro. *Finalmente, dice que va a registrarlo todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2019-08-08','Ana: Recibo llamada de Pilar Martín, TS del ESM de CC (54612). Agustín le ha llevado informe médico para la revisión del grado de dependencia por empeoramiento. Acordamos que cumplimentaré el modelo y cuando lo tenga firmado por el nuevo D.Gerente se lo enviaré por correo certificado junto a la compia de la sentencia de incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-08-08','-Acude al SEPAD exigiendo dinero , ha gastado el dinero semanal . Se le da cita para mañna con Alberto pero se niega a irse , se queda en el holl pegando patadas a la papelera. Se le dice a Seguridad que avise a la policia si es necesario para que se lo lleven . Percibe pension de incap Abs , llamo al CSMental de Merida para que me pasen copia de se tarjeta sanitaria pero la TS me dice que no la tiene . Como mucho tendrá que abonar 8€ para medicación. Está en lista para CRR , Nº12 . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-08-08','-Hablo con la TS del ESM MERIDA , la psiquiatra va a pasar a coordinadora de larga estancia del CSS Merida, quiere ingresarlo allí. Por eso no lo ha derivado a CRR . -PONGO A FIRMA GERENTE SOLICITUD DEPENDENCIA QUE NADIE SE LA HA TRAMITADO AÚN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMAN'and apellido2='JIMENEZ'),'2019-08-07','Ana: Recibo nota de la visita de la Delegada Tutelar-FUTUEX, María dice que lleva siempre puesto el colgante de Cruz Roja, sólo se que lo quita para dormir y lo cuelga en el cabecero de la cama./ *La delegada ha hablado con la Médica de Cabecera, aunque se muestra reticente al principio, accede a ir a verla y derivarla a los expecialistas. / En cuanto al presupuesto de gastos *lo que necesitamos saber es el dinero que necesita de bolsillo, para hacer la autorización al banco. Se lo digo a Toni-FUTUEX, hablará con Gloria, Delegada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-08-08','TERESA: INGRESA EN LA UHDAC, HA LLEGADO TRANQUILA YA SE ENCUENTRA EN LA UNIDAD Y ESTA ESTABLE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-08-08','-NUEVO ESCRITO DE PFHC , FECHA EFECTOS DE LOS 392€ EL 1/7/19','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2019-08-09','miguel, remito a secretaría general para su remisión a Abogacía General contestación al requerimiento del Jzdo de 1ªInst. e Instrucc. nº2 de Mérida a la incoacción de procedimiento de revisión y asignación de tutela al hermano. Confirmado con Amalia que por parte de la Comisión no nos oponemos a que asuma su hermano la tutela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-08-08','Ana: Recibo llamada de Isabel Pino, TS de Miajadas (927 34 70 00), está allí con ella Felipe y la Aux. de SAD, Felipe está nervioso pidiendo que se lleven a su hermano de su casa. Han vuelto a discutir y está fatal. Le digo a Pilar que nosotros no podemos hacer nada con el hermano, además la casa, según Nota Simple, es suya al 100%, no de Felipe. Pilar se lo transmite a Felipe, que insiste en que la casa es suya. Pilar le dice también que si su hermano está alterado acuda al centro de salud y se lo comunique a su médico. //////////////// Reviso con Alberto las cuentas, actualizamos la ficha y se aumenta la asignación semanal a 65€, que se harán efectivo a partir del día 19 de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-08-09','-PROXIMA EXCARCELACION DEL HOSPITAL PSIQUIATRICO PENITENCIRIO DE SEVILA EL 4/11/2019. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-08-09','Ana: Llamo a Isabel Pino, TS de Miajadas (927 34 70 00), ayer se fue muy enfadado. La Aux. le contaba ayer que se enfadan por cualquier cosa y discuten, la convivencia no es buena. //////// Con respecto a la cuestión económica, le comunico que a partir del día 19 Felipe podrá retirar los 65€/semana.','2');
