insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='RODRIGUEZ'and apellido2='MARTIN'),'2019-08-09','Ana: Llamo a Marta Hdez., TS de "Rivera de Fresnedosa" (927 30 33 66), en relación a los dos hermanos de Ceclavín. Los días que atiende en Ceclavín son lunes y miércoles. Acompañará a la primera visita que se haga en el domicilio. En relación a la autorización para retirada de efectivo, acordamos que cada uno de los hermanos pueda retirar semanalmente 50€ para comida y gastos de bolsillo. Y la semana que viene un extra para las fiestas del pueblo. // **Manuel cobra P. Orfandad Absoluta y PFHC. //////////////////// Hablo con Juana, Secc. Eco, Manuel tiene sólo 600€ en la cuenta. Su hermano Juan Mª no tiene nada, por lo que el extra (40€) lo retirará sólo él. ///////////////// *En cuanto la CURATELA, es ECONÓMICA y para las "cuestiones relativas a TRATAMIENTOS MÉDICOS a los que deba someterse".','2');
