insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2019-08-08','-Ingresado en UHB CACERES , pq en Mérida no habia camas .Email de Crr : Ayer por la tarde un compañero fue a visitar a Ángel Pinilla a UHB de Cáceres donde se encuentra ingresado. En ese momento no se encontraba bien y fue necesaria la contención. Hoy he vuelto a contactar con su Psiquiatra y me comenta que está mucho más colaborador, con mejor ánimo y junto al resto de compañeros. Seguimos sin poder avisar a su hermano ya que no encontramos el teléfono suyo. El lunes, si todo va bien, iré a visitarle y os informo sobre su situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-08-09','Ana: Recibo correo de Paula, T.O. - CRR Plas.: "... Respecto a Conchi concretar que la próxima semana, el día 12 iniciaría el proceso de incorporación a piso supervisado en concepto de prueba, por lo que irá durante el mes de septiembre pernoctando algunas noches y participando algunos días de las actividades del mismo. Si la experiencia resulta positiva, algo que esperamos, os concretaríamos fecha de paso a piso (plaza en piso). Un saludo, Paula."','2');
