insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-08-14','Ana: Se recibe un correo de la Empresa de SAD "Atención a la Dependencia Extremeña" comunicando que el contrato con la emprea ha rescindido, por lo que ahora no está recibiendo ningún servicio. Ya lo han comunicado a los SSB. /////////////////// Llamo de Marisa , T.S. de Vfca. de Los Barros (924-527822)No obtengo respuesta. /////////// Llamo a la empresa SAD (699 37 42 29)Luisa me comunica que por ese domicilio ya han pasado muchas Auxiliares y que siempre ha habido muchos problemas. A día de hoy no encuentran a nadie que quiera trabajar allí. Y en el último caso, que la Aux. sí que quería y parecía que iba a funcionar, ha sido Adolfo quién se ha negado a que vaya la Aux.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-08-14','Ana: Llamada de Isabel Pino, TS de Miajadas (927 34 70 00 ext. 3216). Finalmente Felipe tiene PREPAGO en el tlf. móvil. Cuesta 7€/mes. *Se acuerda con Alberto, Área Eco., tras hacer cuentas, que se le aumentará la asisgnación semanal 2€ más, de modo que a partir del día 19 de agosto podrá retirar 67€/semana. *Se lo cominico a Isabel Pino que se lo explicará a Felipe y a su Aux.','2');
