insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2019-08-14','Ana: Recibimos correo de Carmen Franco, Directora del CSS de Mérida: "Buenos días: Os envío una consulta para obtener información de Ramón Gilés Salazar que se encuentra ingresado en nuestro centro desde el 26/06/2017, a la espera de plaza en centro de personas con discapacidad intelectual y condicionando su ingreso a la misma. Solicito información sobre plazos y fechas en las que se prevé la concesión de la misma. Gracias . Un saludo" //////////// Respondo al correo informando acerca de la última gestión realizada por Teresa. (Solicitud de Centros)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-08-13','Ana: Recibo correo de Toni-Futuex: en la tarde de ayer Mª Augenia volvió a discutir con Antonio y éste pedía que se fuera de allí. Finalmente lo arreglaron y continúa en la casita del campo. Desde Futuex contactaron con el Centro de Transeuntes de Cáritas-CC por si fuera necesario volver a utilizar el recurso y en éste pusieron más inconvenientes que la vez anterior, esgrimiendo el argumento de que en la vez anterior presentó problemas de conducta, cuestión que nadie manifestó en ningún momento a ningunas de las personas que hablamos tanto con la T.S. como con la Ed. Soc. *De momento no es necesario pedir plaza (en este caso habría que aportar informe)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-08-16','Ana: Recibo llamada de Sonia, Programa de Familia Mancom. Tajo-Salor (609 382 439), no es la que lleva el caso, pero sus compañeras están de vacaciones. Dice haber recibido una llamada de la T.S. del Ayto. diciendo que el miércoles, decidieron darle a Felisi los bonos para los toros dejándolos a deber, entendían que eran "circustancias excepcionales" y que como era fiesta el viernes en el Casar, no podrían retirar el dinero del banco (argumento que le dieron Jesús y Felisi). Quieren que le demos un extra para ello (Son 25€ cada bono). **Le explico que el mismo miércoles yo hablé con Jesús y Felisi y les dije que no se les podía dar más extras. Se les dio uno el vienes 26 y otro el viernes pasado día 9. De hecho el miércoles Jesús me dijo que todavía le quedaban 80€. Además este mismo día Virgina de Futuex les acompañó al banco al final de la mañana a retirar los 80€ de la asignación semanal. ////////////// Llamo a Felisi y Jesús, dice que la semana que viene irán al Ayto. a pagar los bonos. Les digo que acudan hoy mismo a explicarlo. //////// Informo al respecto a Sonia.','2');
