insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-08-20','Ana: Llamo a Isabel Pino, TS de Miajadas (927 34 70 00 ext. 3216). En relació a los ingresos de Felipe, estoy valorando solicitarle PNC con ATP o mantener la PFHC y solicitar Orfandad. Según informe social del Inventario, la madre, de la que no tenemos ningún dato, falleció en 1993. Del padre no sabemos nada. *Isabel intentará averiguar todo lo posible y me llamará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2019-08-14','Ana: Clara. Jefa de Ud. de Gestión de Recursos, Dispositivos y Servicios del SEPAD, pregunta por la dirección de José Aº, cree que hay un error, pues es la del SEPAD. Le explico que esa es la dirección a efectos de comunicaciones (la de la CTAEX) y les facilito la dirección habitual para cuando tengan que valorarle.','2');
