insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2019-08-19','Ana: Recibimos correo: "Buenas tardes, Le escribo de la farmacia de María San Pedro Ledesma (Cáceres). Tenemos un paciente tutelado por la Junta que nos pide Mitosyl pomada protectora y un nebulizador de agua de mar, ambos excluidos de la financiación por el SNS. ¿La Junta se haría cargo del coste de ambos como hace con la medicación prescrita a dicho paciente?Esperamos su respuesta, gracias." ///////////////// Respondo al correo con aclaraciones y preguntando de qué tutelado se trata. *Tras varios correos y conversaciones con la farmacia (927226829), así como valoración con la Secc. Ecca., dado que económicamente no está bien y que los productos que solicita no son imprescindibles, se decide que no se le autorizará dicha compra. *Iciar, Secc. Ecca., llamará a Jesus M. para comunicárselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-08-22','Ana: Tras varios días de búsqueda por parte de Virginia-Futuex y gestiones por mi partes, se decide que Mª Eugenia se alojará en el Hostal La Rosa de CC (Presupuestos y Normas en su expte. PC). Podrá entrar hoy a partir de la 13:30 h. ////////// La Secc. Ecca. se encargará del resto de gestiones referidas a facturas y transferencias. /////////////////**Por otra parte, Virginia acompañará a Mª Eugenia a casa de Antonio a recoger sus pertenencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-08-14','miguel, Rosa (de la notaria de Villajoyosa) me remite borrador de herencia para su revisión por nosotros, junto con el certificado de nacimiento, que es emitido por Sevilla, donde está la anotación de incapacidad por el Rgtro Civil de Sevilla y la tutoria anterior anotada en el Rgtro Civil de Albacete. No aparecemos nosotros como tutores en dicho Certificado Civil de Nacimiento por lo que volveré a hablar con el Jzdo de Plasencia nº4 para que notifique en vez del Rgtro Civil de Albacete (como ya lo hicieron anteriormente), lo hagan al Rgtro Civil de Sevilla','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-08-22','miguel, revisado el borrador remito email con los defectos del mismo a la notaria de Villajoyosa. Quedo pendiente firmen la herencia y nos remitan copia para su ratificación en notaria de Mérida, una vez lo cual solicitaremos autorización judicial para aprobación de la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-08-23','Iciar. Solicitamos al Registro Civil de Miajadas cdo de nacimiento para poder averiguar nombre y apellidos de los padres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2019-08-23','Ana: Recibimos 2 escritos de la Secc. de Prestaciones: Uno con el documento de "Opción por prestación incompatible", que pongo para la firma del D.Gerente eligeindo la PNC. Y otro soliciando que envíemos el Alta a Terceros. Se lo solicito a Coral, Secc. Ecca. que lo sacará y lo pondrá para la firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2019-08-23','Ana: Recibo llamada de Noelia, TS del CR Cervantes-CC(22237). Dice que Victoriana necesitará ropa para el otoño-invierno y pregunta cómo tienen que proceder. Informo de que se autoriza la compra. *Irán a la tienda desde dónde nos enviarán presupuesto y factura a posteriori para hacer transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-08-23','Ana: La semana Pasada Mai Masegosa acude de nuevo a hablar conmigo, se lo han pensado mejor y no van a dar plaza a Miguel en El Cuartillo, pues está enfrente de la Universidad y no quieren generar problemas. Le asignarán plaza en la R. Felipe Trigo - Vva. de la Serena. ////////////// Hoy recibo llamada de Pepa, Administrativo de la R. Felipe Trigo, le han enviado la resolución de plaza de Miguel Trinidad y le han informado de que urge el ingreso. Nieves, la T.S. está de vacaciones. Le indico la forma de procecer en el ingreso involuntario. **Nos llamarán para confirmar qué día les viene mejor que se produzca el mismo para activar el 112. *El horario que consideramos mejor para recoger a Miguel es sobre las 9:30, por lo tanto llegaría a la Res. entre 10:30-11:00. /// Le facilito algunos datos que le faltaban y el envío por mail la copia del DNI. **La tarjeta sanitaria no la tenemos. /////////////////////// Ana: Llamo a Mercedes, TS-SSB Trujillo (927 65 93 91), Esperanza, su compañera, me dice que está de vacaciones hasta el 10 de septiembre, por lo que no podemos contar con su colaboración para el ingreso. *Le pregunto por la tarjeta sanitaria y tampoco tienen copia en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-08-23','-Escribo a Pedro y Alberto para ver qué decisión se plantea a este caso : Sulli , la persona que estabamos esperando para poder contratarla como interna y que nos comentó que tendría en breve la documentación en regla , la he vuelto a llamar y aún no dispone de la misma. No podemos mantener a la interna actual por más tiempo , no está regularizada y en su día , cuando Rosario la contrató no tenía documentación. Fue la única solución para poder mantenerla en el domicilio .La TS del pueblo ha intentado localizar a alguien interesada en ese servicio y nadie del pueblo quiere hacerlo. Los presupuestos que nos ha pasado la empresa ASINDE ascienden a más de 3000€ , lo que hace inviable economicamente la contratación. Estoy solicitando ptos. a otras empresas , Serviscoop comenta que es dificil el servicio de internas en pueblos , las auxiliares que tienen no tienen medios de transportes. En abril solicité a la parte jurídica que se solicitase internamiento involuntario , le pasé toda la documentación incluido I.social de la TS del pueblo a Angel . Los he llamado para ver cómo va este expediente y no recuerda si ha tramitado el intern. involuntario. Quedo pte. que me confirme fecha para poder calcular cuántos meses tendríamos que seguir manteniendo a Rosario en domicilio . Si no encontramos a nadie en domicilio y no tenemos orden judicial de ingreso en centro , solo con el C. Dia no se cubren necesidades , necesita cuidados de 24h/ dia con Alzheimer muy avanzado . ( Amalia )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-08-26','Ana: Recibo llamada de Pepa, Amtvo. R. Felipe Trigo (20353), han organizado todo para que el ingreso se produzca mañana. ////////////// Como no tengo la Resolución subo a hablar con Mai, está de vacaciones, pero las compañeras me dan una copia de la Resolución. ////////////////// Llamo a FUTUEX, Teresa me dice que Miguel está asignado a Virginia. Le comunicará que debe estar allí mañana entre 9:00 - 9:30, hará por localizar la documentación de Miguel (DNI y Tarjeta Sanitaria). //////////// Llamo a la Jefa de Sala del 112, quien toma nota. Acordamos y les envío fax solictando se proceda al internamiento involuntario y por mail (112@juntaex.es) los documentos adjuntos siguientes: Testimonio de Auto de Remoción y Nombramiento de Tutor, Acuerto de Aceptación del Cargo, Auto de medidas cautelares de ingreso involuntario y Resolución de Plaza en Centro Residencial junto con el fax y reporte del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-08-26','Ana: Juana, Secc. Ecca. me entrega el Alta a Terceros. Lo envío por correo certificado junto con la Comunicación de Variaciones a la Gerencia Territorial del SEPAD de Ba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-08-26','Ana: Recibo llamada de Mercedes, Plena Inclusión Llerena (637 029 217), para interesarse por la Recurso interpuesto por el Régimen de Visitas de Beatriz a su hija, para que se hiciera en un Punto de Encuentro. Pregunto a los compañeros del Área Juríd., como Agosto es un mes inhabil en el juzgado hay que esperar a Septiembre. Mercedes pide que por favor le llamemos en cuanto sepa algo. Dice que Beatriz está fatal y no deja de llorar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-08-23','Ana: Recibo llamada de Juan (625 89 53 94) solicita dinero para sus gastos para las fiestas de septiembre. Pide 100 €. Lo hablo con Alberto, Jefe Secc. Ecca., se le autorizarán 80 € que podrá retirar el martes 27.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-08-26','Ana: Llamo a Nuria, Enfermera del ESM-Trujillo (54508), confirma que Juan asistió a ponerse el inyectable el pasado 22 de agosto. Lo que no tuvo es consulta porque el Psiquiatra estaba de vacaciones. *La próx. cita para inyectable y CONSULTA será el día 22 de noviembre. //**Cdo. el Psiquiatra regrese de vacaciones nos enviarán un informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-08-26','Ana: Recibo llamada de Lucía, Acompañante (605 15 13 70), me comunica que Consuelo ya se pone de pie y está caminando, esta decición la han tomado en la Res. la Dirección y la Fisioterapeuta, a pesar de que el Traumatólogo dijo que hasta que no asistiera a consulta y le hicieran nuevas placas no debía caminar...///////// La nueva cita de Traumatología la tiene el día 4 de septiembre, a las 8:45 la radiografía y sobre las 12 la consulta. ////////////////////////////////////// Llamo a Mariola, Res.San Jorge (927 24 34 95 / 927 62 80 10) Me dicen que no está, que la llame mañana a partir de las 10. La TS tampoco está.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2019-08-26','Llamo a Mª José Polo, TS de Zarza de Granadilla (664 01 82 09 / 927 48 60 04 ext.5), en relación a la cita para renovar el DNI de Florencia, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2019-08-23','Ana: Llamo a Adela, PNC (924 00 59 95). A Guillermo se le extiguió la PNC por no cumplir lor requisitos, convivía con un hermano y no se habían tenido en cuenta los ingresos de éste (por Ud. de Conviviencia). Desde el momento que ingresó en la Res. se le podía haber solicitado de nuevo. **Haré la solicitud de PNC. Además, como tiene un 79% de Discapacidad y Grado II de Dependencia tiene derecho a complemento ATP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2019-08-26','Ana: Pregunto a Juana, Secc. Ecca. por la Deuda de Guillermo por Cobros Indebidos. Dice que NO le están pasando nada y no disponemos de más información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2019-08-27','Ana: Llamo a la Resid. Pablo Naranjo, Romangordo (927 57 65 23), el Director está de vacaciones. Hablo con Javier, Fisioterapeuta, estos días está él al "cargo". Dice que Guillermo sigue bien, continúa muy bien adaptado. **Me facilita su nº de Seg. Soc.: 061012881273. ////// **Solicito a Javier un Certificado de Ingreso en Residencia para aportarlo a la solicitud de PNC. //// Recibo llamada del Ayto. de Romangordo (927 57 65 81), puesto que el Director de la Res. está de vacaciones hasta medidados de septiembre, la semana que viene me enviarán el certificado firmado por el Secretario (qua esta semana tampoco está). Me lo adelantarán por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-08-03','Correo-e de CRR de Mérida. +++Buenas noches Pedro, Solamente informarte que José María acaba de llegar al CRR. Se encuentra bien, muy cansado pero ha llegado en buenas condiciones incluso aseado. Comenta haber estado en Cáceres y ha devuelto 270 euros de los 480 euros que sacó. Mañana iremos juntos a retirar la denuncia, he avisado a la Policía de su aparición. Los compañeros han avisado a su hermano porque así nos lo ha pedido. Muchas gracias por todo, Saludos. ________________________________________ Recibimos documento de reirada de dencuncia del CRR. Se archiva en expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-08-05','Correo-e del CRR de Mérida. +++Informarte que Emi sigue ingresada pero tanto sábado como domingo la devolución que nos dan desde UHB es que se encuentra bien, hoy le asignarán Psiquiatra. Le hemos llevado productos de aseo y ropa para que tenga durante el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-08-06','CRR de Mérida. +++Comunican por correo-e el alta de UHB ayer día 5 de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2019-08-09','Correo-e del CRR de Mérida. +++Buenos días, Ayer por la tarde un compañero fue a visitar a Ángel Pinilla a UHB de Cáceres donde se encuentra ingresado. En ese momento no se encontraba bien y fue necesaria la contención. Hoy he vuelto a contactar con su Psiquiatra y me comenta que está mucho más colaborador, con mejor ánimo y junto al resto de compañeros. Seguimos sin poder avisar a su hermano ya que no encontramos el teléfono suyo. El lunes, si todo va bien, iré a visitarle y os informo sobre su situación. Muchas gracias y buen fin de semana. ________________________________________','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2019-08-06','Correo-e del CRR de Mérida. +++Ayer por la tarde, sobre las 18/19h, Ángel pidió que llamásemos al 112 porque tenía ideas autolíticas bastante bien planificadas. Esa misma mañana al notarle que no estaba bien acudimos a cita con su Psiquiatra de referencia y le cambió el tratamiento. Tras una larga charla intentando tranquilizarle y entender lo que estaba sucediendo no conseguimos que se sintiese mejor, seguía pidiendo ayuda. Llamamos al 112 y la Psiquiatra que le atendió no tuvo dudas, está ingresado en Cáceres por no haber camas disponibles en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2019-08-23','Cooreo-e de Amalia. +++Tenemos pendiente dar una solución a este caso , cuando estemos de regreso seria conveniente reunirnos con el resto de secciones , económica y jurídica para valorar opciones. Sulli , la persona que estabamos esperando para poder contratarla como interna y que nos comentó que tendría en breve la documentación en regla , la he vuelto a llamar y aún no dispone de la misma. No podemos mantener a la interna actual por más tiempo , no está regularizada y en su día , cuando Rosario la contrató no tenía documentación. Fue la única solución para poder mantenerla en el domicilio .La TS del pueblo ha intentado localizar a alguien interesada en ese servicio y nadie del pueblo quiere hacerlo. Los presupuestos que nos ha pasado la empresa ASINDE ascienden a más de 3000€ , lo que hace inviable economicamente la contratación. Estoy solicitando ptos. a otras empresas , Serviscoop comenta que es dificil el servicio de internas en pueblos , las auxiliares que tienen no tienen medios de transportes. En abril solicité a la parte jurídica que se solicitase internamiento involuntario , le pasé toda la documentación incluido I.social de la TS del pueblo a Angel . Los he llamado para ver cómo va este expediente y no recuerda si ha tramitado el intern. involuntario. Quedo pte. que me confirme fecha para poder calcular cuántos meses tendríamos que seguir manteniendo a Rosario en domicilio . Si no encontramos a nadie en domicilio y no tenemos orden judicial de ingreso en centro , solo con el C. Dia no se cubren necesidades , necesita cuidados de 24h/ dia con Alzheimer muy avanzado . ( Amalia )','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2019-08-27','Ana: Recibo llamada de Sonia Bernabé, TS de Asindi ( 927 39 01 93), Roberto no ha vuelto de la salida con la familia. Justo, su hermano, sí, pero él no ha querido vovler. Ha llamado a su padre y dice que sí, que está en casa. Como ya ocurrió en otra ocasión, nos solicitan permiso para proceder de la misma manera, avisarán a un taxista de confianza que conoce a los hermanos y le enviarán con algún incentivo desde el centro para convencerlo. Me mantendrán informada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-08-27','Ana: Recibo llamada de Teresa-Futuex, Virginia, Delegada, estaba preocupada, porque no llegaba la ambulancia, la Guardia Civil también se ha retrasado 45 min. Llamé a la Jefa de Sala del 112, la ambulancia ya había llegado (más de 1 hora tarde), pero Miguel ya se había ido, no han coseguido retenerle por las buenas más tiempo. Van a intentar localizar a Miguel. ///////////////// Finalmente localizaron a Miguel caminando por la carretera. Tras hablar con él Virginia, aunque sí se le puso un inyectable, no fue necesaria la intervención de la Guardia Civil. //////////// Llamo a Pepa, Amtvo. R. Felipe Trigo (20353), Miguel llegó bien, estaban esperándolo para la acogida, el aseo y la atención de enfermería. Ahora le verá el Médico. De momento todo bien. ***La habitación que le han asignado es de Psicogeriatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-07-01','DIRECCIÓN ACTUAL DEL PISO DE ALQUILER : C/ Fernando Caston nº 3, Escalera Derecha, piso 4 A.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2019-08-28','SALIDA El Css de Mérida remite correo electrónico: "Os adelanto que Antonio Pereo saldrá a ver a su madre a la residencia de Felipe Trigo, en principio está programada para mañana por la mañana. Lo hará en el coche del centro y acompañado de dos auxiliares. tiene autorización de su psiquiatra. Aunque tenemos autorización para estas salidas, pero al ser un caso especial os lo comunico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2019-08-27','SALIDA Entre el 27/08/2019 y el 02/09/2019. P. I. Llerena remite correo electrónico: "Buenos días.. Me pongo en contacto para informar de la salida de Libertad García Marquez al domicilio familiar desde hoy dia 27 hasta el lunes dia 2 de septiembre. Hoy la recoge su hermano en coche particular y el lunes si no puede su hermano traerla se desplazará en autobus."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-08-27','Ana: Marta, actual Jefa de Ngdo. de Valoraciones - Mayores (68515), me informa de que finalmente se le va a conceder plaza a Juan Antonio en la Residenica de Mayores de Los Santos de Maimona. Cuando tengan la resolución nos la traerán. ///// Llamo a Isabel Pilar, TS, del Hptal. de Llerena (47085 // Busca: 47000), le comunico que a Juan Aº le concederán plaza en la Res. de Los Santos. Ella dice que no ha vuelto a visitarlo, pues la Psiquiatra no lo consideró oportuno. El día 23 le fue a valorar la Técnica de Dependencia. ***Da puntuación para Plaza T2. ///Le digo que Pedro, Jefe de Secc. CTAEX, quiere hablar también con ella, le llamará más tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-08-19','Ana: Recibo llamada de Isabel Pilar, TS del Hptal. de Llerena (47085), para interesarse sobre cómo iba la situación y los procedimientos relativos a Juan Aº, quien de momento sigue allí igresado. Ella ya ha hablado con Mai Masegosa (día 5), con Nuria Paniaguas (Responsable de T.S. S.E.S.) y con Antonio Nisa, TS Fuente del Maestre. /// Le informo de que están todos los trámites hechos, ahora sólo queda esperar a que respondan del Juzgado y a que asignen plaza residencial solicitada por emergencia social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-08-27','SE ha puesto el inyectable el 22 de agosto de 2019. Queda con Alberto en que comrará un móvil de prepago. Traerá presupuesto.Si su familia llama para preguntar por él, SOLO LE PODEMOS DAR SU TELÉFONO A SU MADRE Y A SU HERMANA ARACELI.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-08-19','-La semana pasada se fugó de la resi y estuvo fuera dos dias . El director puso denuncia . Lo encontraron en el casco antiguo en estado de embriaguez . Agresivo con el personal pero no activaron el 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-08-27','-Recibo la llamada de la farmacia que se ubica en frente del hospital Perpetuo Socorro , se hace el enfermo para que me llamen por tf , al cogerlo insulta y exige su dinero. Llamo a la Resi para comunicar donde está , vuelve por la noche en ambulancia desde el Perpetuo donde ingresó diciendo que se habia ido de una residencia. Utiliza los recursos a su conveniencia , en este caso a modo de taxi. Amalia -','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-08-27','-Se solicitó a FUTUEX visita domiciliaria,tras varias semanas intentando contactar en el tf. que nos facilitó la madre ( Pepi ) y ante la imposibilidad de acordar la cita , solicito a Futuex que procedan a la visita sin avisar. Acuden hoy Teresa y la nueva TS de FUTUEX. Estoy en contacto con ellas toda la mañana y me informan de todos los pasos. Se reúnen con el Alcalde y la TS .Están muy asustados por el comportaminto del chico y del padre. Confirman que hace unos días ha tratado de agredir a su madre con un cuchillo. Interviene la GC que llevan a Ruben al hospital donde permanece ingresado en la UHB. No han podido contactar ni ver a los padres . Hablo con Gema ( TS de la UHB ) para comentarle el caso y para que antes del alta hospitalaria contacten con Maria la psiquitra de referencia del ESM ( que ha sido tb coordinadora de la UHB) para que valoren un ingreso en UME si así lo consideran en función de su estado de salud Vuelve a llamarme , la coordinadora de la UHB ( Virginia ) ya ha hablado con Maria y es conocedora del caso. Ahora mismo prevalecerá la sanción judicial con posibilidad de ingreso en centro penitenciario. ( Amalia )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-08-27','(Pedro) Acude a la cita programada. +++SE ha puesto el inyectable el 23 de agosto de 2019. PRÓXIMA CONSULTA PSIQUIATRÍA: 27-NOV-2019 (09:00h). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Trae factura del teléfono prepago que ha comprado. Nº de TELÉFONO: 695-893358.Si su familia llama para preguntar por él, SOLO LE PODEMOS DAR SU TELÉFONO A SU MADRE Y A SU HERMANA ARACELI. +++PEDIRÁ CITA en le PODÓLOGO: Consulta Podología SOSA (924-313304). +++Se le aconseja que pida nueva cita en el ESM para valorar su deseo de ingreso en CRR.Dice que lo hará, porque se acerca a la vejez "...y la soledad es muy mala, ¿verdad, Pedro?..." +++SE le aconseja que vaya a la óptica para pedir presupuesto de unas gafas (todo lo que lee se lo acerca casi hasta la nariz), lo traerá para valorar y en su caso comprar. +++También se le indica que vaya a su Médico de Familia para valorar salud bucodental (esto ya no parece dispuesto a hacerlo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-08-27','TELÉFONO DE ILDEFONSO: 695-893358','2');
