insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2019-08-28','-Quiere ir a su casa a ver en qué estado se encuentra , las llaves las tiene él en el CSS Merida. La direccion de la casa es C/ Ollerias , 32 , 06900 LLerena. El día que se acuerde con el centro irá la Delegada Tutelar. ( AD )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-08-28','-Respuesta de Serviscoop al servicio solicitado : Mié 28/08/2019 12:40 Brígida López >serviscoop@outlook.es> Buenas , entiendo , el tema de las comunicaciones lo hace inviable. Pero tendrían libre desde las 9.00 h de la mañana hasta las 17.00 de la tarde de lunes a viernes , y fines de semana enteros excepto los que libren. Un saludo. Gracias -------------------------------------------------------------------------------- De: Brígida López >serviscoop@outlook.es> Enviado: martes, 27 de agosto de 2019 12:34 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: SERVICIO DE INTERNA PUEBLO Buenos días Amalia, Hemos estado hablando con las auxiliares que nosotros solemos trabajar para los turnos de interna y personal de los curriculums que tenemos y todas nos han comentado lo mismo, que si fuera para Badajoz que sin problema pero a los pueblos no quieren ir de interna ya que la combinación de los autobuses para venir los fines de semana es muy mala y las dos horas libres que tienen diarias al estar en el pueblo no pueden venirse hasta aquí. De hecho nosotros dejamos hace tiempo el tema de los internos en los pueblos por ese motivo precisamente, las auxiliares se quejaban de los horarios a la hora de coger el bus que no les cuadraba. Siento no haber podido ayudarte con este tema como yo hubiera querido, espero poder ayudarte en otra ocasión. Un fuerte abrazo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PARRA'and apellido2='OCHOA'),'2019-08-28','-RESOLUCION DE APROBACION DE LA PNC. CUANTIA MENSUAL 392€ , EFECTOS DES JUNIO , ATRASOS 784 €. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-08-28','TERESA: HABLO CON MERCEDES PARA PREGUNTAR QUE TAL LAS VACACIONES DE BEA CON LA FAMILIA ME COMENTA QUE TODO HA TRANSCURRIDO CON NORMALIDAD VIENE CONTENTA PERO SIGUE MAL POR EL TEMA DE SU HIJA. LE COMENTO QUE SEGUIMOS A LA ESPERA DE QUE EL JUZGADO NOS RESPONDA.','2');
