insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2019-08-28','(Pedro) Llamada de Dª Ignacia Soto Pacheco, madre de Gustavo. +++"Manoli, la T. Soc. de Sevilla, me ha dicho que tengo que ir a verles y llevar no sé qué informes, pero yo estoy enferma y si es necesario voy, pero si no lo es..." +++Mis hijos no se hablan conmigo...si yo no fuera tan mayor, claro que no hubiera consentido en que mi hijo pasase a cargo de la Junta..." +++Le tranquilizo al respecto y le propongo hablar con Manoli desde la Comisión Tutelar. Si necesitamos algo de ella nos pondremos en contacto con la madre de Gustavo. +++TELÉFONO DE Dª IGNACIA: 652-528620. +++TELÉFONO DE MANOLI (T.SOC.PSIQ.PEN.SEVILLA):955-616666-Ext.135 y 954-856048','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2019-08-28','Ana: Recibo mail de Felisa Custodio, TS de CAMF-Alcuescar, comunicando que han recibido informe de la T.S. de Alcuescar y comunicado de la Concejalía de Bienestar Soc, informando de que en las últimas semanas una vecina del pueblo muestra interés y acercamiento económico hacia Isbel. En entrevista con la tutelada, ésta lo niega, pero desde el centro plantean la reducción de su asignación mensual. ///////// Acuerdo con Felisa, TS, que se reducirá la asignación mensual a la mitad: 40 €. Pide que le enviemos un correo de confirmación. ////// Envío el correo y solicito además que le *administren la asignación a razón de 10€/semana. ///////////// **Habitualmente retiran el dinero los jueves en el propio centro en la Ud. Móvil de Liberbank.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2019-08-28','TERESA: SALIDA DEL 22 de agosto al 3 de septiembre, quedándose responsable su madre Dora. Además, ha sido derivado al Programa de Orientación e inserción Laboral, desde dicho programa me solicitan dos documentos del usuario de los que no dispongo. Son los siguientes: - El certificado de Pensión - Documento de Incapacidad Civil, .','2');
