insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-08-29','TERESA: denuncia cursada por Diego , con mi acompañamiento en nombre de la comisión , para que el acto pueda ser tenido en cuenta en la noche del jueves al viernes porracearon la puerta de su domicilio un vecino de la localidad que tiene importantes problemas de desequilibrios mentales y problemas de adicción , Diego s se asoma a la ventana para ver que pasa y le manda a su casa , y este otro empieza a amenazarle e insultarle a lo que Diego no contesta , pero hace que se sienta mal de hecho el supuesto agresor pasó el resto de la noche frente a la vivienda en el banco de la estación de autobuses , cuando este se va Diego sale de la vivienda y puede ver como le han prendido fuego a la persiana de su ventana se da la circunstancia que el supuesto agresor estamos tramitando o intentando tramitar la incapacitación y el ingreso involuntario en una institución rehabilitadora o de cualquier tipo ante el riesgo que corre el mismo y todo su entorno','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2019-08-28','Ana: Al cumplimentar la solicitud de PNC, me doy cuenta de que Guillermo tiene más de 65 años. Ya no se puede pedir la PNC por Invalidez. /// Llamo a Marina Cintas, Jefa de Secc. PNC, pregunto si existe alguna salvedad, pero me dice que NO. *Sólo podemos pedir la de Jubilación y ya no tendría derecho al Complemento A.T.P. ////////// Llamo a Paco Romero, Jefe de Secc. de Prestaciones, Direcc. Prov.Ba, SÍ podemos pedir el Complemento A.T.P. de la PFHC, sólo hay que enviar un escrito y adjuntar el Certificado de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2019-08-29','TERESA: LLAMO A MARIA CHAVEZ (663 93 02 69) LA TS DEL SSB VILLANUEVA PARA CONVOCARLA A SUBCOMISION PARA TRATAR EL CASO DE ADRIAN ORTIGOSA EL PROXIMO 20 DE SEPBRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-08-22','Ana: Recibo llamada de Mª Luisa (643 91 85 86), quiere solicitar traslado a alguna residencia Don Benito. Al preguntarle el motivo, dice que la comida no le gusta y además quiere estar, textualmente "en un entorno más familiar, cerca de mi hermana". Le explico que no es tan sencillo, que ella está allí con una orden judicial, que ya conoce los motivos y que en todo caso tendríamos que valorarlo en equipo y los trámites llevan su tiempo, hoy por hoy no puede ser.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-08-23','Ana: Recibo llamada de Noelia, TS de la Re. Cervantes, el día 21 habló con Mª Luisa. Le explicó el motivo por el que estaba ingresada en ese centro. / Cree que su demanda se debe a que la hija está llamándola continuamente para pedirle dinero, le dice que no tiene dinero para pagar la luz./ En cuanto al dinero de bolsillo que retira ella misma del banco, se lo gasta el mismo día y luego anda pidiendo dinero y tabaco a todo el mundo. / Por otra parte Mª Luisa le ha contado que ha hecho dos amigas fuera de la residencia, Noelia indagará al respecto. / Por último, con respecto a la comida del centro, depende del día y de quién le pregunte. Hay días que ve salir al personal de cocina y expresa que "estaba buenísimo"////////////// Recibo otra llamada de Mª Luisa, insistiendo que hagamos "los trámites" para pedirle cambio de centro. Vuelvo a recordarle el motivo por el que está en el centro y que de momento no se le puede cambiar a otro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-08-29','Ana: Llamo a Noelia, TS Res. Cervantes CC (22237)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2019-08-29','miguel, tras conversación telefónica con su primo Manuel me comenta que hay que hacer la herencia del padre, madre y hermano de Inés. El bajará (vive entre Madrid e Inglaterra) y tiene una carpeta o sobre en manos de la directora del Centro donde está Inés. Irá a por esa documentación. En cuanto la tenga vendrá a verme para empecemos a recabar lo que le falte para hacer las 3 herencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2019-08-29','Ana: Llamo a la U.R.E. (Ud. de Recaudación Ejecutiva) de la Seg. Soc. de Zafra, 924 55 32 01. Me informan de que las deudas prescriben a los 4 años, a no ser que se inicie alguna acción de pago o embargo, con lo que comenzaría a contar el tiempo de nuevo. Dado el tiempo que hace, el expte. debe estar en Apremio (o la deuda ha prescrito). *Las PFHC son inembargables, pero de las PNC suelen embargar las pagas extras (si aún no ha prescrito). /////////////////// Tras hacer cálculos con Juana, Secc. Ecca., vemos que económicamente, descontando los pagos a la residencia, queda igual si le pedimos PNC-Jubilación o Complemento ATP de la PFHC, por lo que solicitaré éste último ///////////////****Pongo para firma la Comunicación de Variaciones PFHC a los efectos de cobrar el A.T.P. ////////////// Solicito por nota interior a Clara Gómez (UGRDS) CERTIFICADO DE DEPENDENCIA, pues no lo tenemos en el expte., hay que adjuntar copia a la Comunicación de Variaciones de PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2019-08-29','(Pedro)Intento hablar con manoli, T. Soc. penitenciario de Sevilla, pero no se enecuentra disponible en este momento. Volveré a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-08-29','TERESA: VAMOS A VALORAR LA POSIBILIDA DE UN INGRESO INVOLUNTARIO ANTE LA SITUACION ACTUAL DE ADOLFO. LLAMO A MARISA LA TS Y ME COMENTA QUE VAN A PONERLE ALGUIEN DE FORMA PRIVADA A VER SI FUNCIONA, EL HERMANO ESTA AL TANTO DE TODO. LE SOLICITO INFORME SOCIAL Y ELLA TAMBIÉN VE LA MEJOR OPICON EL INGRESO EN UN CENTRO. LLAMO A SALUD METAL PERO SOLO ESTAN LOS MARTES QUEDO PENDIENTE LA LLAMADA PARA SOLICITAR A LA TS Y AL PSQUIATRA INFORMES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2019-08-29','Ana: Llamo a Pepa, Amtvo. Res. Felipe Trigo (20353), para preguntar cómo han ido los dos primeros días de Miguel en el centro. Pepa me pasa con la Coordinadora, María (35254) en principio parece que se está adaptando bien, está muy tranquilo. El primer día accedió a ducharse de buen grado. Me facilita el nº de Luisa Ferreras, Médica (32670) por si algún día queremos hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2019-08-22','Ana: Recibo llamada de Luisa Dorado, madre la Tutelada (924703155), dice que necesitan dinero pues tienen que ir al Traumatólogo a Zafra el virnes. Rosario se rompió el hombro hace 4 meses, no se le puede operar, sólo toma analgésicos para el dolor. ////////////////////////Llamo a Rita, T.S. del SSB de Segura de León (924703011), expresa que se desvinculó un poco del caso desde que comenzaron a visitarla de Futuex, pero que el caso le preocupa, agradece que nos pongamos en contacto. Últimamente Luisa va a verla más amenudo. Informa de que las relaciones madre-hija no son buenas, discuten mucho, no obstante cree que no ha vuelto a ocurrir ningún episodio grave. *No saben administrarse Luisa cobra P. Viudedad y PFHC por Rosario. Además desde la Comisión hay autorizada una retirada mensual de efectivo de 100€ de la P.Orfandad de Rosario (207€). Se gastan todo enseguida. Desde el banco suelen adelantarle dinero, de modo que a veces cuando van a cobrar las pensiones ya no les queda mucho. **En cuanto a la salud e higiene de Rosario, "está obesa y suele ir muy sucia". No tiene habitos saludables de ningún tipo, "se levanta cuando quiere, come lo que quiere y hace lo que quiere, pasa casi todo el día viendo telenovelas". Tienen el SAD municipal 1h/semana. *No quieren ningún recurso. En el pueblo hay un centro para personas con discapacidad "Cristo de la Reja" al que acudía Rosario hace tiempo, hasta que se negó a asistir, "es muy perezosa". Considera que sería muy positivo para ella retomarlo. Rosa es la Directora. Rita, TS, plantea que podríamos enviar un escrito a Rosario y a ella diciendo que tiene que volver a asistir al mencionado centro, pues sino habrá que tomar medidas para proceder a un ingrso en centro y con eso podría convencerla. /*Con respecto a la cita en Traumatología del V.23, se le autorizarán 12€ para pagar el autobús. *Se lo comunico a Luisa y a Rosario. Dicen que necesitan más dinero para la Rehabilitación, les digo que cuando tengan fecha para la misma nos lo comuniquen a través de la T.S. (Aún no saben cuándo será). Y que el informe que les dé el traumatógolo se lo lleven también a Rita para que nos envíe una copia. /////////////// IMPORTANTE: Cambiar la PFHC, Expte. nuevo a nombre del D. Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2019-08-30','Ana: Recibo el Certificado de Dependencia de Guillermo. Lo escaneo y guardo en su expte. //////// Pongo para REGISTRO DE ENTRADA, para la Dirección Prov. de la Seg.Soc. de Ba, la Comunicación de variaciones para solicitar el Complemento A.T.P. de la PFHC con copia compulsada del Grado de Dependencia, y copias de: DNI del D.Gerente, Nombramiento y Mantenimiento de competencias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2019-08-30','Ana: Llamo a Longina, TS del Ayto. de Madrigalejo (672 614 686). Me comunican que ha cogido el día de Asuntos propios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2019-08-30','TERESA: ENVÍO ESCRITO OPTANDO POR PNC YA QUE ES MAS BENEFICIOSO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-08-30','Ana: Como desde el CRR, Paula, TO, finalmente no nos remitió Informe Médico de la consulta de Psiquiatría, sino un modelo de solicitud del Hptal./////////////////// Llamo a Pablo, TS del E.S.M.-Plasencia (L-J 74955), la próxima cita es el día 10 de octubre, cada vez que asiste tiene tres consultas: Psiquiatría, Enfermería y Trabajo Social. Solicito a Pablo que pida a la Dra. Parrado Informe Clínico de Evolución de la paciente en que haga constar el cambio en la medicación. Pide que llamemos de nuevo el lunes porque no sabe si podemos pedirlo por fax, mail o registro, pero por escrito seguro. Hablará con la Psiquiatra y nos informará al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2019-08-30','Ana: Llamo a Mª Ángeles, Empresa de SAD Depend.ex. (927 22 15 02) Confirman que la Aux. podría hacer la comida a Julián Ramón, si finalmente así se estipulara. Le informo de que no confirmaremos el servicio ni se podrá formalizar el contrato posiblemente hasta mediados de septiembre, estamos pendiente de presupuesto de empresa de limpieza, para realizarla antes de que comenzara el SAD. ///////// Envío un correo a Toni-Futuex. Antes de formalizar el contrato hay que hacer la limpieza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-09-02','(Pedro)llamada de Agustín (643-733413), novio de la hija de María Luisa. +++Reclama el pago del recibo de la luz, que le han cortado, en base al acuerdo al que dice se llegó con la Comisión para que Mª Luisa siguise pagándolo. +++Se les dió dos meses de plazo para que asumieran la titularidad de del recibo y, dado que esto no se produjo, se ha procedido al corte de luz por las razones que se le han indicado: Mª Luisa ya no vive en la casa y por lo tanto no tiene que hacerse cargo de los consumos. +++Inoformo de las conpetencias de la CTAEx y dada su situación, los dirijo al SSB por si pudiesen ser benefivciarios de algún tipo de recurso a nive4l económico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-09-02','TERESA: ME LLAMA LA DOCOTRA SEVILLA Y ME COMENTA QUE VAN A ESPERAR HASTA TENER EL INGRESO INVOLUNTARIO VA HA LLAMAR AL JUZGADO PARA QUE LO TRAMITEN LO ANTES POSBILE ME LLAMA PILA TS DEL HOSPITAL 47085 Y ME COMENTA QUE YA TIENE LA RESOLUCION DE PLAZA EN RESIDENCIA DESDE EL DIA 27 POR LO TANTO EL PLAZO PARA INGRESAR CUMPLE EL 11 DE SEPBRE, LE INFORMO DE LO ULTIMAS NOVEDADES SOBRE EL CASO. ME FACILITA EN NUMERO DE LA DIRECTORA DE LA RESIDENIA DE LOS SANTOS DE MAIMONA PARA QUE ME PONGA EN COTACTO CON ELLA Y LE PONGA AL DIA DEL CASO. ISABEL IBAÑEZ DIRECTORA 924029562 / 607 33 20 05','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2019-08-31','-Amalia: comunican del CSS de Mérida que se ha fugado , han activado protocolo de fuga .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-09-02','-Amalia : LLama Juanjo , TS de UHB Hospital Universitario Bjoz , está ingresado allí , activaron el 112 desde el Centro Residencial. Hablo con la TS de la residencia , mientras esté en UHB guardaremos la plaza, si lo derivan a CSS daremos de baja a la misma.','2');
